local quotes = {
    { text = "Part of patience is knowing your truth and staying loyal to it you just can't allow your face to betray what an attack on it actually makes you feel.", book = "In Limbo", author = "A.D. Aliwat" },
    { text = "Being a stoic does not mean being a robot. Being a stoic means remaining calm both at the height of pleasure and the depths of misery.", book = "7 Billion Gods: Humans Above All", author = "Abhijit Naskar" },
    { text = "There was no meaning in why he was here, but he was, and that was enough.", book = "", author = "Akshat Thakur" },
    { text = "At the heart of stoicism lay the desire to disappoint oneself before someone else had the chance to do so. Stoicism was a crude defense against the dangers of the affections of others, dangers that would take more endurance than a life in the desert to be able to face.", book = "On Love", author = "Alain de Botton" },
    { text = "Melancholy isn't always a disorder that needs to be cured. It can be a species of intelligent grief which arises when we come face-to-face with the certainty that disappointment is written into the script from the start.", book = "The Course of Love", author = "Alain de Botton" },
    { text = "The modern expectation is that there will be equality in all things in the couple - which means, at heart, an equality of suffering. But calibrating grief to ensure an equal dosage is no easy task: misery is experienced subjectively, and there is always a temptation for each party to form a sincere yet competitive conviction that, in truth, his or her life really is more cursed - in ways that the partner seems uninclined to acknowledge or atone for. It takes a superhuman wisdom to avoid the consoling conclusion that one has the harder life.", book = "The Course of Love", author = "Alain de Botton" },
    { text = "Sometimes in life we must fight not only without fear, but also without hope.", book = "", author = "Alessandro Pertini" },
    { text = "The qualities of stoic self-denial, self-sacrifice for others, patient labour, expiation for past error, willing acceptance of the burdens of life, were for him nobler manifestations of humanity than ostentatious feats of bravery, death-defying deeds of heroism or a life ruled by passions. He was persuaded that moral strength could best be displayed by silent endurance rather than by vehement anger and passionate rebellion.", book = "Tales of Old Vienna and Other Prose", author = "Alexander Stillmark" },
    { text = "As the still dawn breaks and first light graces the horizon, we humans are presented with tremendous opportunity. We are gifted with a fresh start, a blank canvas upon which we can paint however we choose.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "By meditating on our thoughts, feelings, and desires, we are encouraging a sense of self-awareness and self-mastery. We observe the whimsical and impulsive movements of our mind without getting caught up in them, and in doing so we develop a greater understanding of ourselves.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "Humans are not made for sitting at a desk all day. We have been evolving for millions of years to hunt animals through dense forest and vast plains. To walk huge distances in search of water. To spend hours searching for edible fruit to bring home to our families. The sedentary lifestyle many of us lead these days is no more than a by-product of the last few centuries.", book = "", author = "Alexander Zenon" },
    { text = "In an era characterized by incessant noise and constant distraction, we often find our minds pulled from one thought to another like a leaf in an October breeze. We are so preoccupied by modern living that we become totally disconnected from our ancient human roots in the natural world.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "Our minds are a sanctuary, a safe haven which is totally impregnable to the outside world. It is only when we allow external problems and anxieties to enter our mind that this sanctuary becomes vulnerable.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "The afternoon presents an intersection where the momentum that we have gained in the morning may be either sustained or lost - where we can choose to either build on the morning's foundations and embrace our challenges, or allow the stress and frustration of the day to ruin all our hard work.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "The events that may befall you tomorrow are not new or novel, and the emotions that you will experience have been felt by countless others throughout the crashing torrent of time. They survived. Why can't you?", book = "", author = "Alexander Zenon" },
    { text = "The only good and evil in your life lies within you - in your choices.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "To the Stoics, a good life meant living in accordance with nature, both universal nature - accepting the world for what it is, not resisting it because we think it should be different - and our own nature as human beings.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "Tomorrow will arrive, come what may. The sun will rise, as it has always done, and will set in the evening when nature commands it.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "We are existing in a thin sliver of light between two potentially infinite portions of darkness.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "We human beings are not hive animals. We aren't like bees or ants who just work constantly for the good of the community.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "When we first wake up our minds are clear, which makes this the opportune time to direct our focus inwards, to organize our thoughts and to set our daily intentions through a few moments of meditation. Our duties and obligations have not yet begun to crowd our schedule, and the clarity of the dawn creates an open, undistracted mental space.", book = "The Stoic Handbook: A Practical Guide for Modern Life", author = "Alexander Zenon" },
    { text = "People hide their truest nature. I understood that; I even applauded it. What sort of world would it be if people bled all over the sidewalks, if they wept under trees, smacked whomever they despised, kissed strangers, revealed themselves?", book = "The Ice Queen", author = "Alice Hoffman" },
    { text = "You never know what will be the consequence of misfortune; or, you never know what will be the consequences of good fortune.", book = "stoicism", author = "Allan Watts" },
    { text = "Common man's patience will bring him more happiness than common man's power.", book = "Wealth of Words", author = "Amit Kalantri" },
    { text = "Milo's Way - A Haiku: Strength sought in small steps, Like Milo's calf on shoulders, Grow with steady will.", book = "On My Way To Infinity: A Seeker's Poetic Pilgrimage", author = "Amogh Swamy" },
    { text = "Patience is the antidote to the restless poison of the Ego. Without it we all become ego-maniacal bulls in china shops, destroying our future happiness as we blindly rush in where angels fear to tread. In these out-of-control moments, we bulldoze through the best possible outcomes for our lives, only to return to the scene of the crime later to cry over spilt milk.", book = "Divine Living: The Essential Guide To Your True Destiny", author = "Anthon St. Maarten" },
    { text = "...That's exactly it, my dear friend,'' the future rector had once told him regarding Existentialism, when he was already doing postgraduate work in psychology to achieve his doctorate,''for this is nothing but a noögenic neuroses due to which such people end up feeling as if they were lost in space and time.''''That which the Greek Stoics used to call agnoia, isn't it, or the spiritual ignorance of Man,'' the future professor had answered while they were in the university canteen having a coffee together.''Correct. In fact, noögenic neuroses do not emerge from conflicts between drives and instincts but rather from spiritual and existential problems...", book = "Paceville and Metanoia", author = "Anton Sammut" },
    { text = "... we find a complete contradiction in our wishing to live without suffering, a contradiction that is therefore implied by the frequently used phrase blessed life. This will certainly be clear to the person who has fully grasped my discussion that follows. This contradiction is revealed in this ethic of pure reason itself by the fact that the Stoic is compelled to insert a recommendation of suicide in his guide to the blissful life (for this is what his ethics always remains). This is like the costly phial of poison to be found among the magnificent ornaments and apparel of oriental despots, and is for the case where the sufferings of the body, incapable of being philosophized away by any principles and syllogisms, are paramount and incurable. Thus its sole purpose, namely blessedness, is frustrated, and nothing remains as a means of escape from pain except death. But then death must be taken with unconcern, just as is any other medicine. Here a marked contrast is evident between the Stoic ethics and all those other ethical systems mentioned above. These ethical systems make virtue directly and in itself the aim and object, even with the most grievous sufferings, and will not allow a man to end his life in order to escape from suffering. But not one of them knew how to express the true reason for rejecting suicide, but they laboriously collected fictitious arguments of every kind. This true reason will appear in the fourth book in connexion with our discussion. But the above-mentioned contrast reveals and confirms just that essential difference to be found in the fundamental principle between the Stoa, really only a special form of eudaemonism, and the doctrines just mentioned, although both often agree in their results, and are apparently related. But the above-mentioned inner contradiction, with which the Stoic ethics is affected even in its fundamental idea, further shows itself in the fact that its ideal, the Stoic sage as represented by this ethical system, could never obtain life or inner poetical truth, but remains a wooden, stiff lay-figure with whom one can do nothing. He himself does not know where to go with his wisdom, and his perfect peace, contentment, and blessedness directly contradict the nature of mankind, and do not enable us to arrive at any perceptive representation thereof. Compared with him, how entirely different appear the overcomers of the world and voluntary penitents, who are revealed to us, and are actually produced, by the wisdom of India; how different even the Saviour of Christianity, that excellent form full of the depth of life, of the greatest poetical truth and highest significance, who stands before us with perfect virtue, holiness, and sublimity, yet in a state of supreme suffering.", book = "The World as Will and Representation, Volume I", author = "Arthur Schopenhauer" },
    { text = "If you come across any special trait of meanness or stupidity you must be careful not to let it annoy or distress you, but to look upon it merely as an addition to your knowledge - a new fact to be considered in studying the character of humanity. Your attitude towards it will be that of the mineralogist who stumbles upon a very characteristic specimen of a mineral.", book = "", author = "Arthur Schopenhauer" },
    { text = "In conformity with this spirit and aim of the Stoa, Epictetus begins with it and constantly returns to it as the kernel of his philosophy, that we should bear in mind and distinguish what depends on us and what does not, and thus should not count on the latter at all. In this way we shall certainly remain free from all pain, suffering, and anxiety. Now what depends on us is the will alone, and here there gradually takes place a transition to a doctrine of virtue, since it is noticed that, as the external world that is independent of us determines good and bad fortune, so inner satisfaction or dissatisfaction with ourselves proceeds from the will. But later it was asked whether we should attribute the names *bonum et malum* to the two former or to the two latter. This was really arbitrary and a matter of choice, and made no difference. But yet the Stoics argued incessantly about this with the Peripatetics and Epicureans, and amused themselves with the inadmissible comparison of two wholly incommensurable quantities and with the contrary and paradoxical judgements arising therefrom, which they cast on one another. An interesting collection of these is afforded us from the Stoic side by the *Paradoxa* of Cicero. from_The World as Will and Representation_. Translated from the German by E. F. J. Paye in two volumes: volume I, pp. 88-89", book = "", author = "Arthur Schopenhauer" },
    { text = "Now this was possible only by a man determining himself entirely *rationally* according to concepts, not according to changing impressions and moods. But as only the maxims of our conduct, not the consequences or circumstances, are in our power, to be capable of always remaining consistent we must take as our object only the maxims, not the consequences and circumstances, and thus the doctrine of virtue is again introduced. from_The World as Will and Representation_. Translated from the German by E. F. J. Paye in two volumes: volume I, p. 89", book = "", author = "Arthur Schopenhauer" },
    { text = "Engineers can prove that a bumblebee, with its heavy body and little bitty wings, can't fly. But nobody tells the bumblebees ... and they fly just fine.", book = "", author = "Bill Bowerman" },
    { text = "Life is 99 percent attitude. Yet for the majority of people, it is the remaining one percent that dominates 99 percent of their life.", book = "", author = "Bill Madden" },
    { text = "Stoicism is Buddhism without the dogma.", book = "", author = "Bill Madden" },
    { text = "The most common act of violence is the relentless mental violence we perpetrate upon ourselves with nothing other than our thoughts.", book = "", author = "Bill Madden" },
    { text = "Ill Fortune is of more use to men than Good Fortune.", book = "The Consolation of Philosophy", author = "Boethius" },
    { text = "Nature is content with few things, and with a very little of these.", book = "The Consolation of Philosophy", author = "Boethius" },
    { text = "Life will question you in its vital moments. It's up to you in how you'll respond. You might have drifted from the principles that you once followed. You could've indulged in vices or fallen into unthinking habits. It's your choice to start your practice again. Remind yourself of what's valuable and then act. You still have a choice to be brave, temperate, and wise.", book = "Stoic Practice", author = "Bremer Acosta" },
    { text = "Progress daily in your own uncertainty. Live in awareness of the questions.", book = "Stoic Practice", author = "Bremer Acosta" },
    { text = "When you give your items away, don't keep the excess of your pride.", book = "Stoic Practice", author = "Bremer Acosta" },
    { text = "When you pursue wisdom, you will soon realize how much you don't know. Your knowledge will be incomplete, but continually developing through your curiosity. Arrogance blocks new information from coming in. When you're conceited, you'll resist change, and struggle to preserve your fixed image. Don't fall into smug idleness, used to comfort. Challenge what you think you know, not caring if other people see you as a fool. Progress daily in your own uncertainty.", book = "Stoic Practice", author = "Bremer Acosta" },
    { text = "We can't choose what the world throws at us, but we can control how we react to it, and that makes all the difference.", book = "", author = "Brian Reese" },
    { text = "You are more likely to feel an inner disturbance if you set your heart and mind on something that is beyond your control to obtain.", book = "Reasons Not to Worry: How to Be Stoic in Chaotic Times", author = "Brigid Delaney" },
    { text = "She (the First Lady, entering the room with her gravely wounded husband) would admit fear but not despair.", book = "Destiny of the Republic: A Tale of Madness, Medicine and the Murder of a President", author = "Candice Millard" },
    { text = "Stoical is the best word to describe her reaction to these compliments, Emma putting up with them as if they were one of my unfortunate foibles.", book = "To Die For", author = "Carol Lee" },
    { text = "For some reason, there is this facade that life should be full of happiness and without its suffering. Which, actually makes us suffer even more. Because when we get sad or something bad happens, we do not only feel bad about the thing itself but we also feel bad because our life is not the way it is supposed to be. Not realizing suffering and sadness is just a part of life and they are inevitable.", book = "Modern Human's Handbook", author = "Cave Man" },
    { text = "Nothing can affect a person's mind if he chooses not to be affected by it.", book = "Modern Human's Handbook", author = "Cave Man" },
    { text = "Unless you learn your lesson, it will keep hurting. Not only it will never stop, it will also keep increasing the amount, so you won't get used to it.", book = "Modern Human's Handbook", author = "Cave Man" },
    { text = "Indeed this gentleman's stoicism was of that not uncommon kind, which enables a man to bear with exemplary fortitude the afflictions of his friends, but renders him, by way of counterpoise, rather selfish and sensitive in respect of any that happen to befall himself.", book = "Barnaby Rudge", author = "Charles Dickens" },
    { text = "...when I asked him if he forgave me, he answered that he was not in the habit of cherishing the remembrance of vexation; that he had nothing to forgive; not having been offended.", book = "Jane Eyre", author = "Charlotte Brontë" },
    { text = "She looks as if she were thinking of something beyond her punishment - beyond her situation: of something not round nor before her.", book = "Jane Eyre", author = "Charlotte Brontë" },
    { text = "What a singularly deep impression her injustice seems to have made on your heart! No ill-usage so brands its record on my feelings. Would you not be happier if you tried to forget her severity, together with the passionate emotions it excited? Life appears to me too short to be spent in nursing animosity, or registering wrongs.", book = "Jane Eyre", author = "Charlotte Brontë" },
    { text = "There is a switch in the air tonight. It's not suffocating, like breakups all those years ago, but clean and clear. He does not want me anymore so I tilt my head, take a breath and say, Okay. I understand. It's calm now. My heart didn't break, it kept on beating like a stoic marching forward without looking back, and I will be a writer now. I love so many people, still. I think I will write about them forever.", book = "He loved me some days. I'm sure he did: 99 essays on growth through loss", author = "Charlotte Eriksson" },
    { text = "You will never see me surrender, never see me cry, but you will often see me walk away. Turn around and just leave, without looking back.", book = "Empty Roads & Broken Bottles: in search for The Great Perhaps", author = "Charlotte Eriksson" },
    { text = "Circadian disruption, chronic stress, obesity, gut inflammation and inactivity are the enemy.", book = "Strong Medicine: How to Conquer Chronic Disease and Achieve Your Full Athletic Potential", author = "Chris Hardy,Marty Gallagher" },
    { text = "Cook with coconut oil for a 'dose' of medium chain triglycerides to help keep your brain cells healthy, especially if you have a family history or early signs of Alzheimer’s disease.", book = "Strong Medicine: How to Conquer Chronic Disease and Achieve Your Full Athletic Potential", author = "Chris Hardy,Marty Gallagher" },
    { text = "Long-term inflammation and oxidative stress are the underlying causes for chronic preventable diseases.", book = "Strong Medicine: How to Conquer Chronic Disease and Achieve Your Full Athletic Potential", author = "Chris Hardy,Marty Gallagher" },
    { text = "The Art of Fermentation by Sandor Katz and for beginners, Cultured: Making Health Fermented Foods at Home by Kevin Gianni. Both are highly recommended. Go try some kimchi.", book = "Strong Medicine: How to Conquer Chronic Disease and Achieve Your Full Athletic Potential", author = "Chris Hardy,Marty Gallagher" },
    { text = "A good isn’t increased by the addition of time, but if one is wise for even a moment, they will be no less happy than the person who exercises virtue for all time and happily passes their life in it.", book = "Against The Stoics On Common Conceptions", author = "Chrysippus" },
    { text = "This is the very thing which makes up the virtue of the happy person and a well-flowing life - when the affairs of life are in every way tuned to the harmony between the individual divine spirit and the will of the director of the universe.", book = "Lives Of The Eminent Philosophers", author = "Chrysippus" },
    { text = "There is, I assure you, a medical art for the soul. It is philosophy, whose aid need not be sought, as in bodily diseases, from outside ourselves. We must endeavor with all our resources and all our strength to become capable of doctoring ourselves.", book = "", author = "Cicero" },
    { text = "Lead me, O Zeus, and thou O Destiny, the way that I am bid by you to go: To follow I am ready. If I choose not, I make myself a wretch, and still must follow.", book = "", author = "Cleanthes" },
    { text = "The willing are led by fate, the reluctant are dragged.", book = "Hymn to Zeus", author = "Cleanthes of Assos" },
    { text = "I've come to the point where I never feel the need to stop and evaluate whether or not I am happy. I'm just being, and without question, by default, it works.", book = "Diotima, Battery, Electric Personality", author = "Criss Jami" },
    { text = "A shallow reading of a problem begets outrage; a detailed approach to a problem encourages moderation.", book = "Fortitude: American Resilience in the Era of Outrage", author = "Dan Crenshaw" },
    { text = "A still person has the ability to stop, look at a news story or another person's arguments, and ask objective questions without emotional overreaction or assumptions of ill intent. One is centered, rational, and respected; the other is frantic, unhappy, and intellectually stagnant. Don't be the latter.", book = "Fortitude: American Resilience in the Era of Outrage", author = "Dan Crenshaw" },
    { text = "Be someone who is cool under pressure. Value serenity instead of outrage. It seems that our culture is moving in the wrong direction here. If you are blessed enough to not be on social media, you might be surprised to learn that the angriest, most passionate public figures are rewarded with the most clicks and biggest audiences. Our culture has begun to confuse passion with substance, reward the loudest and angriest voices, and thus incentivize behavior wholly at odds with Stoic wisdom. The number of decibels your voice hits as you scream about how right you are is not necessarily an indicator of how much sense you are making. As a society founded on reason and Western Enlightenment ideals, we must hold ourselves to a higher standard. We have to collectively stop allowing emotion and passion to pass for reason and factual debate.", book = "Fortitude: American Resilience in the Era of Outrage", author = "Dan Crenshaw" },
    { text = "Run down the list of those who felt intense anger at something: the most famous, the most unfortunate, the most hated, the most whatever: Where is all that now? Smoke, dust, legend or not even a legend. Think of all the examples. And how trivial the things we want so passionately are. An emotional response is a human response, I get it. I too have succumbed to emotion, more often than I care to admit. But it is also a futile response. It isn't an objectively beneficial response. This is central to Stoicism.", book = "Fortitude: American Resilience in the Era of Outrage", author = "Dan Crenshaw" },
    { text = "The media's goal is to literally challenge your ability to be still. A tough American, intent on improving upon their current self, is not tricked into an emotional reaction by these headlines. You do not write an angry tweet, you do not hurl an insult. You are cool and measured, and skeptical. You are curious what the agenda of the journalist might be and what facts or context they might be leaving out. You seek out a different story on the same topic from an opposing view, and you find out that many of the claims made in the original story were convincingly debunked. And just like that, you are a Zen master of stillness and Stoicism.", book = "Fortitude: American Resilience in the Era of Outrage", author = "Dan Crenshaw" },
    { text = "A fool is a man who disregards legacy.", book = "", author = "Daniel V Chappell" },
    { text = "I began to care a lot less about embarrassment after running into somebody who for months, I feared I would, and realizing afterward that my life was no different after the encounter than before.", book = "", author = "Daniel V Chappell" },
    { text = "It's with a heavy heart that I assure you that regardless of how lasting your fortune feels, it can be taken from you before you can even think to try to hold on.", book = "", author = "Daniel V Chappell" },
    { text = "The most effective way to understand the dissonance between our thoughts about reality and reality itself, is to consider how many times we've felt like our world is ending and how many times it actually has.", book = "", author = "Daniel V Chappell" },
    { text = "We're never unhappy until we remember why we're supposed to be unhappy.", book = "", author = "Daniel V Chappell" },
    { text = "Don’t explain your philosophy. Embody it.", book = "", author = "Epictetus" },
    { text = "Don't seek for everything to happen as you wish it would, but rather wish that everything happens as it actually will  then your life will flow well.", book = "Discourses and Selected Writings", author = "Epictetus" },
    { text = "Don’t seek that all that comes about should come about as you wish, but wish that everything that comes about should come about just as it does, and then you’ll have a calm and happy life.", book = "", author = "Epictetus" },
    { text = "Don’t trust in your reputation, money, or position, but in the strength that is yours—namely, your judgments about the things that you control and don’t control. For this alone is what makes us free and unfettered, that picks us up by the neck from the depths and lifts us eye to eye with the rich and powerful.", book = "Discourses", author = "Epictetus" },
    { text = "Don’t you know life is like a military campaign? One must serve on watch, another in reconnaissance, another on the front line.... So it is for us—each person’s life is a kind of battle, and a long and varied one too. You must keep watch like a soldier and do everything commanded.... You have been stationed in a key post, not some lowly place, and not for a short time but for life.", book = "Discourses", author = "Epictetus" },
    { text = "Don't concern yourself with other people's business. It's his problem if he receives you badly. And you cannot suffer for another person's fault. So don't worry about the behavior of other.", book = "", author = "Epictetus" },
    { text = "Don't hope that events will turn out the way you want, welcome events in whichever way they happen: this is the path to peace.", book = "", author = "Epictetus" },
    { text = "Don't just say you have read books. Show that through them you have learned to think better, to be a more discriminating and reflective person. Books are the training weights of the mind. They are very helpful, but it would be a bad mistake to suppose that one has made progress simply by having internalized their contents.", book = "THE ART OF LIVING", author = "Epictetus" },
    { text = "Don't live by your own rules, but in harmony with nature.", book = "", author = "Epictetus" },
    { text = "Don't put your purpose in one place and expect to see progress made somewhere else.", book = "", author = "Epictetus" },
    { text = "Don't seek to have events happen as you wish, but wish them to happen as they do happen, and all will be well with you.", book = "", author = "Epictetus" },
    { text = "Eat like a human being, drink like a human being, dress up, marry, have children, get politically active—suffer abuse, bear with a headstrong brother, father, son, neighbor, or companion. Show us these things so we can see that you truly have learned from the philosophers.", book = "Discourses", author = "Epictetus" },
    { text = "Either God wants to abolish evil, and cannot; or he can, but does not want to.", book = "", author = "Epictetus" },
    { text = "Epictetus being asked how a man should give pain to his enemy answered, By preparing himself to live the best life that he can.", book = "", author = "Epictetus" },
    { text = "Even as the Sun doth not wait for prayers and incantations to rise, but shines forth and is welcomed by all: so thou also wait not for clapping of hands and shouts and praise to do thy duty; nay, do good of thine own accord, and thou wilt be loved like the Sun.", book = "", author = "Epictetus" },
    { text = "Events do not just happen, but arrive by appointment.", book = "", author = "Epictetus" },
    { text = "Every circumstance comes with two handles, which one of which you can hold it, while with the other conditions are insupportable.", book = "", author = "Epictetus" },
    { text = "Every event has two handles—one by which it can be carried, and one by which it can’t. If your brother does you wrong, don’t grab it by his wronging, because this is the handle incapable of lifting it. Instead, use the other—that he is your brother, that you were raised together, and then you will have hold of the handle that carries.", book = "Enchiridion", author = "Epictetus" },
    { text = "Every great power is dangerous for the beginner. You must therefore wield them as you are able, but in harmony with nature.", book = "Discourses", author = "Epictetus" },
    { text = "Every habit and capability is confirmed and grows in its corresponding actions, walking by walking, and running by running... therefore, if you want to do something make a habit of it, if you don’t want to do that, don’t, but make a habit of something else instead. The same principle is at work in our state of mind. When you get angry, you’ve not only experienced that evil, but you’ve also reinforced a bad habit, adding fuel to the fire.", book = "Discourses", author = "Epictetus" },
    { text = "Everyone's life is a warfare, and that long and various.", book = "", author = "Epictetus" },
    { text = "Faced with pain, you will discover the power of endurance. If you are insulted, you will discover patience. In time, you will grow to be confident that there is not a single impression that you will not have the moral means to tolerate.", book = "", author = "Epictetus" },
    { text = "Faithfulness is the antidote to bitterness and confusion.", book = "", author = "Epictetus" },
    { text = "Finally, when he crowns it off by becoming a senator, then he becomes a slave in fine company, then he experiences the poshest and most prestigious form of enslavement.", book = "", author = "Epictetus" },
    { text = "First learn the meaning of what you say, and then speak.", book = "", author = "Epictetus" },
    { text = "First off, don’t let the force of the impression carry you away. Say to it, ‘hold up a bit and let me see who you are and where you are from—let me put you to the test’...", book = "Discourses", author = "Epictetus" },
    { text = "First practice not letting people know who you are—keep your philosophy to yourself for a bit. In just the manner that fruit is produced—the seed buried for a season, hidden, growing gradually so it may come to full maturity. But if the grain sprouts before the stalk is fully developed, it will never ripen.... That is the kind of plant you are, displaying fruit too soon, and the winter will kill you.", book = "Discourses", author = "Epictetus" },
    { text = "First say to yourself what you would be, and then do what you have to do.", book = "", author = "Epictetus" },
    { text = "First tell yourself what kind of person you want to be, then do what you have to do. For in nearly every pursuit we see this to be the case. Those in athletic pursuit first choose the sport they want, and then do that work.", book = "Discourses", author = "Epictetus" },
    { text = "For I am not everlasting, but a human being, a part of the whole as an hour is a part of the day. Like an hour I must come, and like an hour pass away.", book = "Discourses, Fragments, Handbook", author = "Epictetus" },
    { text = "For if a person shifts their caution to their own reasoned choices and the acts of those choices, they will at the same time gain the will to avoid, but if they shift their caution away from their own reasoned choices to things not under their control, seeking to avoid what is controlled by others, they will then be agitated, fearful, and unstable.", book = "Discourses", author = "Epictetus" },
    { text = "For if we had any sense, what else should we do, both in public and in private, than sing hymns and praise the deity, and recount all the favours that he has conferred!", book = "", author = "Epictetus" },
    { text = "For in this Case, we are not to give Credit to the Many, who say, that none ought to be educated but the Free; but rather to the Philosophers, who say, that the Well-educated alone are free.", book = "All the Works of Epictetus", author = "Epictetus" },
    { text = "For it is not death or pain that is to be feared, but the fear of pain or death.", book = "", author = "Epictetus" },
    { text = "For making a good voyage a pilot and wind are necessary: and for happiness, reason and art.", book = "Fragments", author = "Epictetus" },
    { text = "For nothing outside my reasoned choice can hinder or harm it—my reasoned choice alone can do this to itself. If we would lean this way whenever we fail, and would blame only ourselves and remember that nothing but opinion is the cause of a troubled mind and uneasiness, then by God, I swear we would be making progress.", book = "Discourses", author = "Epictetus" },
    { text = "For sheep don't throw up the grass to show the shepherds how much they have eaten; but, inwardly digesting their food, they outwardly produce wool and milk.", book = "", author = "Epictetus" },
    { text = "For there are two rules to keep at the ready—that there is nothing good or bad outside my own reasoned choice, and that we shouldn’t try to lead events but to follow them.", book = "Discourses", author = "Epictetus" },
    { text = "For what else is tragedy than the portrayal in tragic verse of the sufferings of men who have attached high value to external things?", book = "", author = "Epictetus" },
    { text = "For when you have subjected to externals what is your own, then be a slave and do not resist, and do not sometimes choose to be a slave, and sometimes not choose, but with all your mind be one or the other.", book = "Discourses", author = "Epictetus" },
    { text = "For where you find unrest, grief, fear, frustrated desire, failed aversion, jealousy and envy, happiness has no room for admittance. And where values are false, these passions inevitably follow.", book = "", author = "Epictetus" },
    { text = "For your part, do not desire to be a general, or a senator, or a consul, but to be free; and the only way to this is a disregard of things which lie not within our own power.", book = "", author = "Epictetus" },
    { text = "Fortify yourself with contentment for this is an impregnable fortress.", book = "", author = "Epictetus" },
    { text = "Free is the person who lives as he wishes and cannot be coerced, impeded or compelled, whose impulses cannot be thwarted, who always gets what he desires and never has to experience what he would rather avoid.", book = "", author = "Epictetus" },
    { text = "Freedom is not archived by satisfying desire, but by eliminating it.", book = "", author = "Epictetus" },
    { text = "Freedom is not procured by a full enjoyment of what is desired, but by controlling the desire.", book = "", author = "Epictetus" },
    { text = "Freedom is secured not by the fulfilling of men's desires, but by the removal of desire.", book = "", author = "Epictetus" },
    { text = "Freedom is the only worthy goal in life. It is won by disregarding things that lie beyond our control.", book = "", author = "Epictetus" },
    { text = "Freedom, you see, is having events go in accordance with our will, never contrary to it.", book = "", author = "Epictetus" },
    { text = "Friend, lay hold with a desperate grasp, ere it is too late, on Freedom, on Tranquility, on Greatness of soul!", book = "", author = "Epictetus" },
    { text = "From the very beginning, make it your practice to say to every harsh impression, ‘you are an impression and not at all what you appear to be.’ Next, examine and test it by the rules you possess, the first and greatest of which is this—whether it belongs to the things in our control or not in our control, and if the latter, be prepared to respond, ‘It is nothing to me.’", book = "Enchiridion", author = "Epictetus" },
    { text = "From this instant, then, choose to act like the worthy and capable person you are. Follow unwaveringly what reason tells you is the best course.", book = "", author = "Epictetus" },
    { text = "Give me by all means the shorter and nobler life, instead of one that is longer but of less account!", book = "", author = "Epictetus" },
    { text = "God has entrusted me with myself. No man is free who is not master of himself. A man should so live that his happiness shall depend as little as possible on external things. The world turns aside to let any man pass who knows where he is going.", book = "", author = "Epictetus" },
    { text = "God laid down this law, saying: if you want some good, get it from yourself.", book = "Discourses", author = "Epictetus" },
    { text = "God save me from fools with a little philosophy—no one is more difficult to reach.", book = "", author = "Epictetus" },
    { text = "Goodness exists independently of our conception of it. The good is out there and it always has been out there, even before we began to exist.", book = "", author = "Epictetus" },
    { text = "Grammar will tell you how to write; but whether to write or not, grammar will not tell.", book = "", author = "Epictetus" },
    { text = "Greatness of reason is measured not by height or length, but by the quality of its judgements.", book = "", author = "Epictetus" },
    { text = "Happiness and freedom begin with a clear understanding of one principle: Some things are within our control, and some things are not.", book = "", author = "Epictetus" },
    { text = "He can anger you only when you permit yourself to be disturbed by him.", book = "", author = "Epictetus" },
    { text = "He is a wise man who does not grieve for the things which he has not, but rejoices for those which he has.", book = "", author = "Epictetus" },
    { text = "He wants what he cannot have, and does not want what he can't refuse — and isn't aware of it. He doesn't know the difference between his own possessions and others'. Because, if he did, he would never be thwarted of disappointed. Or nervous.", book = "", author = "Epictetus" },
    { text = "He was sent to prison. But the observation ‘he has suffered evil,’ is an addition coming from you.", book = "Discourses", author = "Epictetus" },
    { text = "He who exercises wisdom, exercises the knowledge which is about God.", book = "", author = "Epictetus" },
    { text = "He who laughs at himself never runs out of things to laugh at.", book = "", author = "Epictetus" },
    { text = "Here are thieves and robbers and tribunals: and they that are called tyrants, who deem that they have after a fashion power over us, because of the miserable body and what appertains to it. Let us show them that they have power over none.", book = "", author = "Epictetus" },
    { text = "How appropriate that the gods put under our control only the most powerful ability that governs all the rest—the ability to make the right use of external appearances—and that they didn’t put anything else under our control. Was this simply because they weren’t willing to give us more? I think if it had been possible they would have given us more, but it was impossible.", book = "Discourses", author = "Epictetus" },
    { text = "I am your teacher and you are learning in my school. My aim is to bring you to completion, unhindered, free from compulsive behavior, unrestrained, without shame, free, flourishing, and happy, looking to God in things great and small—your aim is to learn and diligently practice all these things. Why then don’t you complete the work, if you have the right aim and I have both the right aim and right preparation? What is missing?... The work is quite feasible, and is the only thing in our power.... Let go of the past. We must only begin. Believe me and you will see.", book = "Discourses", author = "Epictetus" },
    { text = "I can’t call a person a hard worker just because I hear they read and write, even if working at it all night. Until I know what a person is working for, I can’t deem them industrious.... I <em>can</em> if the end they work for is their own ruling principle, having it be and remain in constant harmony with Nature.", book = "Discourses", author = "Epictetus" },
    { text = "I have learned to see that whatever comes about is nothing to me if it lies beyond the sphere of choice.", book = "", author = "Epictetus" },
    { text = "I laugh at those who think they can damage me. They do not know who I am, they do not know what I think, they cannot even touch the things which are really mine and with which I live.", book = "", author = "Epictetus" },
    { text = "I must die. Must I then die lamenting? I must be put in chains. Must I then also lament? I must go into exile. Does any man then hinder me from going with smiles and cheerfulness and contentment?", book = "", author = "Epictetus" },
    { text = "I tell you, you only have to learn to live like the healthy person does... living with complete confidence. What confidence? The only one worth holding, in what is trustworthy, unhindered, and can’t be taken away—your own reasoned choice.", book = "Discourses", author = "Epictetus" },
    { text = "I want to die, even though I don't have to.", book = "", author = "Epictetus" },
    { text = "If a man has reported to you, that a certain person speaks ill of you, do not make any defense to what has been told you: but reply, The man did not know the rest of my faults, for he would not have mentioned these only.", book = "", author = "Epictetus" },
    { text = "If a person gave away your body to some passerby, you’d be furious. Yet you hand over your mind to anyone who comes along, so they may abuse you, leaving it disturbed and troubled—have you no shame in that?", book = "Enchiridion", author = "Epictetus" },
    { text = "If any be unhappy, let him remember that he is unhappy by reason of himself alone. For God hath made all men to enjoy felicity and constancy of good.", book = "", author = "Epictetus" },
    { text = "If any one trusted your body to the first man he met, you would be indignant, but yet you trust your mind to the chance comer, and allow it to be disturbed and confounded if he revile you; are you not ashamed to do so?", book = "", author = "Epictetus" },
    { text = "If anyone tells you that a certain person speaks ill of you, do not make excuses about what is said of you but answer, “He was ignorant of my other faults, else he would not have mentioned these alone.", book = "", author = "Epictetus" },
    { text = "If evil be said of thee, and if it be true, correct thyself; if it be a lie, laugh at it.", book = "", author = "Epictetus" },
    { text = "If it pleases the gods, so be it. They may well kill me, but they can’t hurt me.", book = "Enchiridion", author = "Epictetus" },
    { text = "If it should ever happen to you to be turned to externals in order to please some person, you must know that you have lost your purpose in life.", book = "Discourse of Epictetus: Selections", author = "Epictetus" },
    { text = "If someone speaks badly of you, do not defend yourself against the accusations, but reply;  you obviously don't know about my other vices, otherwise you would have mentioned these as well. ", book = "", author = "Epictetus" },
    { text = "If the Divine is faithful, he also must be faithful; if free, he also must be free; if beneficent, he also must be beneficent; if magnanimous, he also must be magnanimous. Thus as an imitator of God must he follow Him in every deed and word.", book = "", author = "Epictetus" },
    { text = "If then you desire (aim at) such great things remember that you must not (attempt to) lay hold of them with a small effort.", book = "", author = "Epictetus" },
    { text = "If they are wise, do not quarrel with them; if they are fools, ignore them.", book = "", author = "Epictetus" },
    { text = "If thy brother wrongs thee, remember not so much his wrong-doing, but more than ever that he is thy brother.", book = "", author = "Epictetus" },
    { text = "If what charms you is nothing but abstract principles, sit down and turn them over quietly in your mind: but never dub yourself a Philosopher, nor suffer others to call you so. Say rather: He is in error; for my desires, my impulses are unaltered. I give in my adhesion to what I did before; nor has my mode of dealing with the things of sense undergone any change.", book = "", author = "Epictetus" },
    { text = "If what philosophers say of the kinship of God and Man be true, what remains for men to do but as Socrates did:—never, when asked one's country, to answer,  I am an Athenian or a Corinthian,  but  I am a citizen of the world. ", book = "", author = "Epictetus" },
    { text = "If you are defeated once and tell yourself you will overcome, but carry on as before, know in the end you’ll be so ill and weakened that eventually you won’t even notice your mistake and will begin to rationalize your behavior.", book = "Discourses", author = "Epictetus" },
    { text = "If you are told that such an one speaks ill of you, make no defence against what was said, but answer, He surely knew not my other faults, else he would not have mentioned these only!", book = "", author = "Epictetus" },
    { text = "If you choose, you are free; if you choose, you need blame no man—accuse no man. All things will be at once according to your mind and according to the Mind of God.", book = "", author = "Epictetus" },
    { text = "If you don’t wish to be a hot-head, don’t feed your habit. Try as a first step to remain calm and count the days you haven’t been angry. I used to be angry every day, now every other day, then every third or fourth... if you make it as far as 30 days, thank God! For habit is first weakened and then obliterated. When you can say ‘I didn’t lose my temper today, or the next day, or for three or four months, but kept my cool under provocation,’ you will know you are in better health.", book = "Discourses", author = "Epictetus" },
    { text = "If you gape after externals, you must of necessity ramble up and down in obedience to the will of your master. And who is the master? He who has the power over the things which you seek to gain or try to avoid.", book = "The Discourses", author = "Epictetus" },
    { text = "If you have assumed any character beyond your strength, you have both demeaned yourself ill in that and quitted one which you might have supported.", book = "Enchiridion", author = "Epictetus" },
    { text = "If you must be affected by other people's misfortunes, show them pity instead of contempt. Drop this readiness to hate and take offence.", book = "", author = "Epictetus" },
    { text = "If you seek Truth, you will not seek to gain a victory by every possible means; and when you have found Truth, you need not fear being defeated.", book = "", author = "Epictetus" },
    { text = "If you should ever turn your will to things outside your control in order to impress someone, be sure that you have wrecked your whole purpose in life. Be content, then, to be a philosopher in all that you do, and if you wish also to be seen as one, show yourself first that you are and you will succeed.", book = "Enchiridion", author = "Epictetus" },
    { text = "If you want to improve, you must be content to be thought foolish and stupid.", book = "", author = "Epictetus" },
    { text = "If you want to make progress, put up with being perceived as ignorant or naive in worldly matters, don't aspire to a reputation for sagacity. If you do impress others as somebody, don't altogether believe it. You have to realize, it isn't easy to keep your will in agreement with nature, as well as externals. Caring about the one inevitably means you are going to shortchange the other.", book = "The Art of Living: The Classical Manual on Virtue, Happiness and Effectiveness", author = "Epictetus" },
    { text = "If you wish it, you are free; if you wish it, you’ll find fault with no one, you’ll cast blame on no one, and everything that comes about will do so in accordance with your own will and that of God.", book = "", author = "Epictetus" },
    { text = "If you wish to be a writer; write!", book = "", author = "Epictetus" },
    { text = "If you wish to be good, first believe that you are bad.", book = "", author = "Epictetus" },
    { text = "If you wish to improve, be content to appear clueless or stupid in extraneous matters—don’t wish to seem knowledgeable. And if some regard you as important, distrust yourself.", book = "Enchiridion", author = "Epictetus" },
    { text = "If you would be a reader, read; if a writer, write.", book = "", author = "Epictetus" },
    { text = "If you would cure anger, do not feed it. Say to yourself: 'I used to be angry every day; then every other day; now only every third or fourth day.' When you reach thirty days offer a sacrifice of thanksgiving to the gods.", book = "", author = "Epictetus" },
    { text = "I'll show you that I’m master.  —How will you do that? Zeus has set me free. Do you really suppose that he would allow his own son to be turned into a slave? You’re master of my carcass, take that.", book = "", author = "Epictetus" },
    { text = "Imagine for yourself a character, a model personality, whose example you determine to follow, in private as well as in public.", book = "", author = "Epictetus" },
    { text = "In banquets remember that you entertain two guests, body and soul: and whatever you shall have given to the body you soon eject: but what you shall have given to the soul, you keep always.", book = "", author = "Epictetus" },
    { text = "In life our first job is this, to divide and distinguish things into two categories: externals that I cannot control, but the choices I make with regard to them I do control. Where will I find food and bad? In me, in my choices.", book = "", author = "Epictetus" },
    { text = "In literature, too, it is not great achievement to memorize what you have read while not formulating an opinion of your own.", book = "", author = "Epictetus" },
    { text = "In prosperity it is very easy to find a friend; but in adversity it is most difficult of all things.", book = "", author = "Epictetus" },
    { text = "In short, we do not abandon any discipline for despair of ever being the best in it.", book = "", author = "Epictetus" },
    { text = "In short, you must remember this—that if you hold anything dear outside of your own reasoned choice, you will have destroyed your capacity for choice.", book = "Discourses", author = "Epictetus" },
    { text = "In the long run, every man will pay the penalty for his own misdeeds. The man who remembers this will be angry with no one, indignant with no one, revile no one, blame no one, offend no one, hate no one.", book = "", author = "Epictetus" },
    { text = "In this way you must understand how laughable it is to say, ‘Tell me what to do!’ What advice could I possibly give? No, a far better request is, ‘Train my mind to adapt to any circumstance.’... In this way, if circumstances take you off script... you won’t be desperate for a new prompting.", book = "Discourses", author = "Epictetus" },
    { text = "Is freedom anything else than the right to live as we wish? Nothing else.", book = "", author = "Epictetus" },
    { text = "Is it not the same distance to God everywhere?", book = "", author = "Epictetus" },
    { text = "Is the child or wife of another dead? There is no one who would not say, This is an accident of mortality. But if anyone's own child happens to die, it is immediately, Alas! how wretched am I! It should be always remembered how we are affected on hearing the same thing concerning others.", book = "Enchiridion", author = "Epictetus" },
    { text = "Is then the fruit of a fig-tree not perfect suddenly and in one hour, and would you possess the fruit of a man's mind in so short a time and so easily?", book = "", author = "Epictetus" },
    { text = "Is you naturally entitled, then, to a good father? No, only to a father.", book = "", author = "Epictetus" },
    { text = "It has been ordained that there be summer and winter, abundance and dearth, virtue and vice, and all such opposites for the harmony of the whole, and (Zeus) has given each of us a body, property, and companions.", book = "", author = "Epictetus" },
    { text = "It is a universal law — have no illusion — that every creature alive is attached to nothing so much as to its own self-interest.", book = "", author = "Epictetus" },
    { text = "It is always our choice whether or not we wish to pay the price for life's rewards. And often it is best for us not to pay the price, for the price might be our integrity.", book = "", author = "Epictetus" },
    { text = "It is better to die of hunger having lived without grief and fear, than to live with a troubled spirit, amid abundance.", book = "", author = "Epictetus" },
    { text = "It is better to do wrong seldom and to own it, and to act right for the most part, than seldom to admit that you have done wrong and to do wrong often.", book = "", author = "Epictetus" },
    { text = "It is easy to praise providence for anything that may happen if you have two qualities: a complete view of what has actually happened in each instance and a sense of gratitude. Without gratitude what is the point of seeing, and without seeing what is the object of gratitude?", book = "Discourses", author = "Epictetus" },
    { text = "It is impossible for a man to learn what he thinks he already knows.", book = "", author = "Epictetus" },
    { text = "It is impossible to begin to learn that which one thinks one already knows.", book = "", author = "Epictetus" },
    { text = "It is more necessary for the soul to be cured than the body for it is better to die than to live badly.", book = "", author = "Epictetus" },
    { text = "It is much better to die of hunger unhindered by grief and fear than to live affluently beset with worry, dread, suspicion and unchecked desire.", book = "", author = "Epictetus" },
    { text = "It is not events that disturb people, it is their judgements concerning them.", book = "", author = "Epictetus" },
    { text = "It is not so much what happens to you as how you think about what happens.", book = "", author = "Epictetus" },
    { text = "It is our attitude toward events, not events themselves, which we can control. Nothing is by its own nature calamitous -- even death is terrible only if we fear it.", book = "", author = "Epictetus" },
    { text = "It is quite impossible to unite happiness with a yearning for what we don’t have. Happiness has all that it wants, and resembling the well-fed, there shouldn’t be hunger or thirst.", book = "Discourses", author = "Epictetus" },
    { text = "It is the act of an ill-instructed man to blame others for his own bad condition; it is the act of one who has begun to be instructed, to lay blame on himself; and of one whose instruction is completed, neither to blame another, nor himself.", book = "", author = "Epictetus" },
    { text = "It is unrealistc to expect people to see you as you see yourself.", book = "", author = "Epictetus" },
    { text = "It isn’t events themselves that disturb people, but only their judgments about them.", book = "Enchiridion", author = "Epictetus" },
    { text = "It isn't death, pain, exile or anything else you care to mention that accounts for the way we act, only our opinion about death, pain and the rest.", book = "", author = "Epictetus" },
    { text = "It was the first and most striking characteristic of Socrates never to become heated in discourse, never to utter an injurious or insulting word - on the contrary, he persistently bore insult from others and thus put an end to the fray.", book = "", author = "Epictetus" },
    { text = "It’s not what happens to you, but how you react to it that matters.", book = "", author = "Epictetus" },
    { text = "Just as what is considered rational or irrational differs for each person, in the same way what is good or evil and useful or useless differs for each person. This is why we need education, so that we might learn how to adjust our preconceived notions of the rational and irrational in harmony with nature. In sorting this out, we don’t simply rely on our estimate of the value of external things, but also apply the rule of what is in keeping with one’s character.", book = "Discourses", author = "Epictetus" },
    { text = "Keep constant guard over your perceptions, for it is no small thing you are protecting, but your respect, trustworthiness and steadiness, peace of mind, freedom from pain and fear, in a word your freedom. For what would you sell these things?", book = "Discourses", author = "Epictetus" },
    { text = "Keep death and exile before your eyes each day, along with everything that seems terrible—by doing so, you’ll never have a base thought nor will you have excessive desire.", book = "Enchiridion", author = "Epictetus" },
    { text = "Keep in mind that it isn’t the one who has it in for you and takes a swipe that harms you, but rather the harm comes from your own belief about the abuse. So when someone arouses your anger, know that it’s really your own opinion fueling it. Instead, make it your first response not to be carried away by such impressions, for with time and distance self-mastery is more easily achieved.", book = "Enchiridion", author = "Epictetus" },
    { text = "Keep the prospect of death, exile and all such apparent tragedies before you every day – especially death – and you will never have an abject thought, or desire anything to excess.", book = "", author = "Epictetus" },
    { text = "Keep this thought at the ready at daybreak, and through the day and night—there is only one path to happiness, and that is in giving up all outside of your sphere of choice, regarding nothing else as your possession, surrendering all else to God and Fortune.", book = "Discourses", author = "Epictetus" },
    { text = "Know you not that a good man does nothing for appearance sake, but for the sake of having done right?", book = "", author = "Epictetus" },
    { text = "Know, first, who you are, and then adorn yourself accordingly.", book = "", author = "Epictetus" },
    { text = "Let death and exile and every other thing which appears dreadful be daily before your eyes but most of all death: and you will never think of anything mean nor will you desire anything extravagantly.", book = "Enchiridion", author = "Epictetus" },
    { text = "Let silence be your general rule; or say only what is necessary and in few words.", book = "", author = "Epictetus" },
    { text = "Let whatever appears to be the best be to you an inviolable law. And if any instance of pain or pleasure, glory or disgrace, be set before you, remember that now is the combat, now the Olympiad comes on, nor can it be put off; and that by one failure and defeat honor may be lost or ”won.", book = "Enchiridion", author = "Epictetus" },
    { text = "Let your will to avoid have no concern with what is not in man's power; direct it only to things in man's power that are contrary to nature.", book = "", author = "Epictetus" },
    { text = "Life is a piece of music, and you’re supposed to be dancing.", book = "", author = "Epictetus" },
    { text = "Lucky is the man who dies at work.", book = "", author = "Epictetus" },
    { text = "Make it your goal never to fail in your desires or experience things you would rather avoid; try never to err in impulse and repulsion; aim to be perfect also in the practice of attention and withholding judgment.", book = "", author = "Epictetus" },
    { text = "Man is disturbed not by things, but by the views he takes of them.", book = "", author = "Epictetus" },
    { text = "Man is not worried by real problems so much as by his imagined anxieties about real problems.", book = "", author = "Epictetus" },
    { text = "Man is troubled not by events, but by the meaning he gives to them.", book = "", author = "Epictetus" },
    { text = "Man, consider first what the matter is (which you propose to do), then your own nature also, what it is able to bear. If you are a wrestler, look at your shoulders, your thighs, your loins: for different men are naturally formed for different things.", book = "Discourses and Selected Writings of Epictetus", author = "Epictetus" },
    { text = "Man, if you are anything, both walk alone and talk to yourself, and do not hide yourself in the chorus. Examine a little at last, look around, stir yourself up, that you may know who you are.", book = "", author = "Epictetus" },
    { text = "Man, the rational animal, can put up with anything except what seems to him irrational; whatever is rational is tolerable.", book = "", author = "Epictetus" },
    { text = "Man, what are you talking about? Me in chains? You may fetter my leg but my will, not even Zeus himself can overpower.", book = "", author = "Epictetus" },
    { text = "Men are disturbed not by things, but by the view which they take of them.", book = "", author = "Epictetus" },
    { text = "Men are disturbed, not by things, but by the principles and notions which they form concerning things.", book = "", author = "Epictetus" },
    { text = "Men are not afraid of things, but of how they view them.", book = "", author = "Epictetus" },
    { text = "Men, the philosopher’s lecture-hall is a hospital—you shouldn’t walk out of it feeling pleasure, but pain, for you aren’t well when you enter it.", book = "Discourses", author = "Epictetus" },
    { text = "Most people are impulsive, however, and having committed to the thing, they persist, just making more confusion for themselves and others until it all end in mutual recrimination.", book = "", author = "Epictetus" },
    { text = "Nature has given to men one tongue, but two ears, that we may hear from others twice as much as we speak.", book = "Fragments", author = "Epictetus" },
    { text = "Neither should a ship rely on one small anchor, nor should life rest on a single hope.", book = "", author = "Epictetus" },
    { text = "Never call yourself a philosopher, nor talk a great deal among the unlearned about theorems, but act conformably to them. Thus, at an entertainment, don't talk how persons ought to eat, but eat as you ought. For remember that in this manner Socrates also universally avoided all ostentation. And when persons came to him and desired to be recommended by him to philosophers, he took and recommended them, so well did he bear being overlooked. So that if ever any talk should happen among the unlearned concerning philosophic theorems, be you, for the most part, silent. For there is great danger in immediately throwing out what you have not digested. And, if anyone tells you that you know nothing, and you are not nettled at it, then you may be sure that you have begun your business. For sheep don't throw up the grass to show the shepherds how much they have eaten; but, inwardly digesting their food, they outwardly produce wool and milk. Thus, therefore, do you likewise not show theorems to the unlearned, but the actions produced by them after they have been digested.", book = "The Enchiridion & Discourses of Epictetus", author = "Epictetus" },
    { text = "Never praise or blame people on common grounds; look to their judgements exclusively. Because that is the determining factor, which makes everyone's actions either good or bad.", book = "", author = "Epictetus" },
    { text = "Never say about anything, I have lost it, but only I have given it back.", book = "", author = "Epictetus" },
    { text = "No great thing is created suddenly, any more than a bunch of grapes or a fig. If you tell me that you desire a fig, I answer that there must be time. Let it first blossom, then bear fruit, then ripen.", book = "", author = "Epictetus" },
    { text = "No man can rob us of our Will—no man can lord it over that!", book = "", author = "Epictetus" },
    { text = "No man is free unless he is the master of himself.", book = "", author = "Epictetus" },
    { text = "No one is ever unhappy because of someone else.", book = "", author = "Epictetus" },
    { text = "No person is free who is not master of themselves.", book = "", author = "Epictetus" },
    { text = "No, it is events that give rise to fear -- when another has the power over them or can prevent them, that person becomes able to inspire fear. How is the fortress destroyed? Not by iron or fire, but by judgments... here is where we must begin, and it is from this front that we must seize the fortress and throw out tyrants.", book = "Discourses and Enchiridion", author = "Epictetus" },
    { text = "Nothing great is produced suddenly, since not even the grape or the fig is. If you say to me now that you want a fig, I will answer to you that it requires time: let it flower first, then put forth fruit, and then ripen. Is then the fruit of a fig-tree not perfected suddenly and in one hour, and would you possess the fruit of a man's mind in so short a time and so easily? Do not expect it, even if I tell you.", book = "Discourses of Epictetus with the Encheiridion and Fragments", author = "Epictetus" },
    { text = "Of all the things that are, some are good, others bad, and yet others indifferent. The good are virtues and all that share in them; the bad are the vices and all that indulge them; the indifferent lie in between virtue and vice and include wealth, health, life, death, pleasure, and pain.", book = "Discourses", author = "Epictetus" },
    { text = "On the occasion of every accident (event) that befalls you, remember to turn to yourself and inquire what power you have for turning it to use.", book = "", author = "Epictetus" },
    { text = "Once I was liable to the same mistakes, but, thanks to God, no longer …’ Well, isn’t it just as worthwhile to have devoted and applied yourself to this goal as to have read or written fifty pages?", book = "", author = "Epictetus" },
    { text = "Only consider at what price you sell your own will: if for no other reason, at least for this, that you sell it not for a small sum.", book = "", author = "Epictetus" },
    { text = "Only the educated are free.", book = "", author = "Epictetus" },
    { text = "Other people's views and troubles can be contagious. Don't sabotage yourself by unwittingly adopting negative, unproductive attitudes through your associations with others.", book = "", author = "Epictetus" },
    { text = "Ought not then this robber and this adulterer to be destroyed? By no means say so, but speak rather this way: This man who has been mistaken and deceived about the most important things, and blinded, not in the faculty of vision which distinguishes white and black, but in the faculty which distinguishes good and bad, should we destroy him? If you speak thus you will see how inhuman this is which you say, and that it is just as if you would say, Ought we not destroy this blind and deaf man?", book = "Discourses of Epictetus with the Encheiridion and Fragments", author = "Epictetus" },
    { text = "People are not disturbed by things, but by the views they take of them.", book = "", author = "Epictetus" },
    { text = "People are ready to acknowledge some of their faults, but will admit to others only with reluctance.", book = "", author = "Epictetus" },
    { text = "People find particular things, however, frightening; and it's when someone is able to threaten or entice us with those that the man himself becomes frightening.", book = "", author = "Epictetus" },
    { text = "People with a strong physical constitution can tolerate extremes of hot and cold; people of strong mental health can handle anger, grief, joy and the other emotions.", book = "", author = "Epictetus" },
    { text = "Philosophy does not claim to get a person any external possession. To do so would be beyond its field. As wood is to the carpenter, bronze to the sculptor, so our own lives are the proper material in the art of living.", book = "Discourses", author = "Epictetus" },
    { text = "Philosophy does not promise to secure anything external for man, otherwise it would be admitting something that lies beyond its proper subject-matter. For as the material of the carpenter is wood, and that of statuary bronze, so the subject-matter of the art of living is each person's own life.", book = "", author = "Epictetus" },
    { text = "Preach not to others what they should eat, but eat as becomes you and be silent.", book = "", author = "Epictetus" },
    { text = "Prefer enduring satisfaction to immediate gratification.", book = "", author = "Epictetus" },
    { text = "Protect what belongs to you at all costs; don't desire what belongs to another.", book = "", author = "Epictetus" },
    { text = "Protect your own good in all that you do, and as concerns everything else take what is given as far as you can make reasoned use of it. If you don’t, you’ll be unlucky, prone to failure, hindered and stymied.", book = "Discourses", author = "Epictetus" },
    { text = "Reading should serve the goal of attaining peace; if it doesn’t make you peaceful, what good is it?", book = "", author = "Epictetus" },
    { text = "Remember from now on whenever something tends to make you unhappy, draw on this principle: 'This is no misfortune; but bearing with it bravely is a blessing.", book = "", author = "Epictetus" },
    { text = "Remember that it’s not only the desire for wealth and position that debases and subjugates us, but also the desire for peace, leisure, travel, and learning. It doesn’t matter what the external thing is, the value we place on it subjugates us to another... where our heart is set, there our impediment lies.", book = "Discourses", author = "Epictetus" },
    { text = "Remember that the divine order is intelligent and fundamentally good. Life is not a series of random, meaningless episodes, but an ordered, elegant whole that follows ultimately comprehensible laws.", book = "", author = "Epictetus" },
    { text = "Remember that you are an actor in a play, playing a character according to the will of the playwright—if a short play, then it’s short; if long, long. If he wishes you to play the beggar, play even that role well, just as you would if it were a cripple, a honcho, or an everyday person. For this is your duty, to perform well the character assigned you. That selection belongs to another.", book = "Enchiridion", author = "Epictetus" },
    { text = "Remember that you must behave in life as at a dinner party. Is anything brought around to you? Put out your hand and take your share with moderation. Does it pass by you? Don't stop it. Is it not yet come? Don't stretch your desire towards it, but wait till it reaches you. Do this with regard to children, to a wife, to public posts, to riches, and you will eventually be a worthy partner of the feasts of the gods. And if you don't even take the things which are set before you, but are able even to reject them, then you will not only be a partner at the feasts of the gods, but also of their empire.", book = "The Enchiridion & Discourses of Epictetus", author = "Epictetus" },
    { text = "Remember that you ought to behave in life as you would at a banquet. As something is being passed around it comes to you; stretch out your hand, take a portion of it politely. It passes on; do not detain it. Or it has not come to you yet; do not project your desire to meet it, but wait until it comes in front of you. So act toward children, so toward a wife, so toward office, so toward wealth.", book = "", author = "Epictetus" },
    { text = "Remember to act always as if you were at a symposium. When the food or drink comes around, reach out and take some politely; if it passes you by don't try pulling it back. And if it has not reached you yet, don't let your desire run ahead of you, be patient until your turn comes. Adopt a similar attitude with regard to children, wife, wealth and status, and in time, you will be entitled to dine with the gods. Go further and decline these goods even when they are on offer and you will have a share in the gods' power as well as their company. That is how Diogenes, Heraclitus and philosophers like them came to be called, and considered, divine.", book = "The Art of Living: The Classical Manual on Virtue, Happiness and Effectiveness", author = "Epictetus" },
    { text = "Remember to conduct yourself in life as if at a banquet. As something being passed around comes to you, reach out your hand and take a moderate helping. Does it pass you by? Don’t stop it. It hasn’t yet come? Don’t burn in desire for it, but wait until it arrives in front of you. Act this way with children, a spouse, toward position, with wealth—one day it will make you worthy of a banquet with the gods.", book = "Enchiridion", author = "Epictetus" },
    { text = "Remember, it is not enough to be hit or insulted to be harmed, you must believe that you are being harmed. If someone succeeds in provoking you, realize that your mind is complicit in the provocation. Which is why it is essential that we not respond impulsively to impressions; take a moment before reacting, and you will find it easier to maintain control.", book = "The Art of Living: The Classical Manual on Virtue, Happiness and Effectiveness", author = "Epictetus" },
    { text = "Remember, then, if you deem what is by nature slavish to be free, and what is not your own to be yours, you will be shackled and miserable, blaming both gods and other people. But if you deem as your own only what is yours, and what belongs to others as truly not yours, then no one will ever be able to coerce or to stop you, you will find no one to blame or accuse, you will do nothing against your will, you will have no enemy, no one will harm you, because no harm can affect you.", book = "Enchiridion", author = "Epictetus" },
    { text = "Remind thyself that he whom thou lovest is mortal  that what thou lovest is not thine own; it is given thee for the present, not irrevocably nor for ever, but even as a fig or a bunch of grapes at the appointed season of the year.", book = "", author = "Epictetus" },
    { text = "Remind yourself that what you love is mortal 'at the very moment you are taking joy in something, present yourself with the opposite impressions. What harm is it, just when you are kissing your little child, to say: Tomorrow you will die, or to your friend similarly: Tomorrow one of us will go away, and we shall not see one another any more?", book = "", author = "Epictetus" },
    { text = "Resistance is vain in any case; it only leads to useless struggle while inviting grief and sorrow.", book = "", author = "Epictetus" },
    { text = "Restrict yourself to choice and refusal; and exercise them carefully, with discipline and detachment.", book = "", author = "Epictetus" },
    { text = "Seeing that our birth involves the blending of these two things ”the body, on the one hand, that we share with animals, and, on the other hand, rationality and intelligence, that we share with the gods ”most of us incline to this former relationship, wretched and dead though it is, while only a few to the one that is divine and blessed.", book = "Enchiridion", author = "Epictetus" },
    { text = "Seek not for events to happen as you wish but rather wish for events to happen as they do and your life will go smoothly.", book = "Enchiridion", author = "Epictetus" },
    { text = "Seek not that the things which happen should happen as you wish; but wish the things which happen to be as they are, and you will have a tranquil flow of life.", book = "", author = "Epictetus" },
    { text = "Seek not the good in external things;seek it in yourselves.", book = "", author = "Epictetus" },
    { text = "Show me a man who though sick is happy, who though in danger is happy, who though in prison is happy, and I'll show you a Stoic.", book = "stoicism", author = "Epictetus" },
    { text = "Show me one who is sick and yet happy, in peril and yet happy, dying and yet happy, in exile and happy, in disgrace and happy. Show him me. By the gods I would fain see a Stoic. Nay you cannot show me a finished Stoic; then show me one in the moulding, one who has set his feet on the path", book = "The Discourses of Epictetus : Classic Edition", author = "Epictetus" },
    { text = "Show me someone sick and happy, in danger and happy, dying and happy, exiled and happy, disgraced and happy. Show me! By God, how much I’d like to see a Stoic. But since you can’t show me someone that perfectly formed, at least show me someone actively forming themselves so, inclined in this way.... Show me!", book = "Discourses", author = "Epictetus" },
    { text = "Sick and yet happy, in peril and yet happy, dying and yet happy, in exile and happy, in disgrace and happy.", book = "", author = "Epictetus" },
    { text = "Since habit is such a powerful influence, and we’re used to pursuing our impulses to gain and avoid outside our own choice, we should set a contrary habit against that, and where appearances are really slippery, use the counterforce of our training.", book = "Discourses", author = "Epictetus" },
    { text = "Small-minded people blame others. Average people blame themselves. The wise see all blame as foolishness.", book = "", author = "Epictetus" },
    { text = "So don't make a show of your philosophical learning to the uninitiated, show them by your actions what you have absorbed.", book = "", author = "Epictetus" },
    { text = "So what oppresses and scares us? It is our own thoughts, obviously, What overwhelms people when they are about to leaves friends, family, old haunts and their accustomed way of life? Thoughts.", book = "", author = "Epictetus" },
    { text = "Some things are in our control, while others are not. We control our opinion, choice, desire, aversion, and, in a word, everything of our own doing. We don’t control our body, property, reputation, position, and, in a word, everything not of our own doing. Even more, the things in our control are by nature free, unhindered, and unobstructed, while those not in our control are weak, slavish, can be hindered, and are not our own.", book = "Enchiridion", author = "Epictetus" },
    { text = "Some things are up to us, and some things are not up to us.", book = "", author = "Epictetus" },
    { text = "Stop honouring externals, quit turning yourself into the tool of mere matter, or of people who can supply you or deny you those material things.", book = "", author = "Epictetus" },
    { text = "Take care not to hurt the ruling faculty of your mind. If you were to guard against this in every action, you should enter upon those actions more safely.", book = "", author = "Epictetus" },
    { text = "Taking account of the value of externals, you see, comes at some cost to the value of one's own character.", book = "", author = "Epictetus" },
    { text = "Tell us your secrets.' [23] 'I refuse, as this is up to me.' 'I will put you in chains.' 'What's that you say, friend? It's only my leg you will chain, not even God can conquer my will.' [24] 'I will throw you into prison.' 'Correction  “ it is my body you will throw there.' 'I will behead you.' 'Well, when did I ever claim that mine was the only neck that couldn't be severed?", book = "Of Human Freedom", author = "Epictetus" },
    { text = "Tell yourself what you want to be, then act your part accordingly.", book = "", author = "Epictetus" },
    { text = "That is the way things are weighed and disagreements settled — when standards are established. Philosophy aims to test and set such standards. And the wise man is advised to make use of their findings right way.", book = "", author = "Epictetus" },
    { text = "That’s why the philosophers warn us not to be satisfied with mere learning, but to add practice and then training. For as time passes we forget what we learned and end up doing the opposite, and hold opinions the opposite of what we should.", book = "Discourses", author = "Epictetus" },
    { text = "The beautiful and good person neither fights with anyone nor, as much as they are able, permits others to fight... this is the meaning of getting an education—learning what is your own affair and what is not. If a person carries themselves so, where is there any room for fighting?", book = "Discourses", author = "Epictetus" },
    { text = "The chief task in life is simply this: to identify and separate matters so that I can say clearly to myself which are externals not under my control, and which have to do with the choices I actually control. Where then do I look for good and evil? Not to uncontrollable externals, but within myself to the choices that are my own...", book = "Discourses", author = "Epictetus" },
    { text = "The essence of good is a certain kind of reasoned choice; just as the essence of evil is another kind. What about externals, then? They are only the raw material for our reasoned choice, which finds its own good or evil in working with them. How will it find the good? Not by marveling at the material! For if judgments about the material are straight that makes our choices good, but if those judgments are twisted, our choices turn bad.", book = "Discourses", author = "Epictetus" },
    { text = "The essence of philosophy is that a man should so live that his happiness shall depend as little as possible on external things.", book = "", author = "Epictetus" },
    { text = "The first and most important field of philosophy is the application of principles such as Do not lie. Next come the proofs, such as why we should not lie. The third field supports and articulates the proofs, by asking, for example, How does this prove it? What exactly is a proof, what is logical inference, what is contradiction, what is truth, what is falsehood? Thus, the third field is necessary because of the second, and the second because of the first. The most important, though, the one that should occupy most of our time, is the first. But we do just the opposite. We are preoccupied with the third field and give that all our attention, passing the first by altogether. The result is that we lie  “ but have no difficulty proving why we shouldn't.", book = "The Art of Living: The Classical Manual on Virtue, Happiness and Effectiveness", author = "Epictetus" },
    { text = "The good of man, and likewise his ill, lies in how he exercises his choice, while everything else is nothing to us.", book = "", author = "Epictetus" },
    { text = "The greater the difficulty, the more glory in surmounting it. Skillful pilots gain their reputation from storms and tempests.", book = "", author = "Epictetus" },
    { text = "The husbandman deals with land; physicians and trainers with the body; the wise man with his own Mind.", book = "", author = "Epictetus" },
    { text = "The ignorant blame others for their own misfortune. To blame oneself is proof of progress. But the wise see all blame as foolishness.", book = "", author = "Epictetus" },
    { text = "The Iliad consists of nothing more than impressions and the use of impressions. An impression prompted Paris to carry off the wife of Menelaus, and an impression prompted Helen to go with him. If an impression, then, had prompted Menelaus to feel that it was a gain to be deprived of such a wife, what would have come about? Not only the Iliad would have been lost, but the Odyssey too!", book = "", author = "Epictetus" },
    { text = "The key is to keep company only with people who uplift you, whose presence calls forth your best.", book = "", author = "Epictetus" },
    { text = "The knowledge of what is mine and what is not mine, what I can and cannot do. I must die. But must I die bawling? I must be exiled; but is there anything to keep me from going with a smile, calm and self-composed?", book = "", author = "Epictetus" },
    { text = "The person is free who lives as they wish, neither compelled, nor hindered, nor limited—whose choices aren’t hampered, whose desires succeed, and who don’t fall into what repels them. Who wishes to live in deception—tripped up, mistaken, undisciplined, complaining, in a rut? No one. These are base people who don’t live as they wish; and so, no base person is free.", book = "Discourses", author = "Epictetus" },
    { text = "The philosopher's lecture room is a 'hospital': you ought not to walk out of it in a state of pleasure, but in pain; for you are not in good condition when you arrive.", book = "", author = "Epictetus" },
    { text = "The proper work of the mind is the exercise of choice, refusal, yearning, repulsion, preparation, purpose, and assent. What then can pollute and clog the mind’s proper functioning? Nothing but its own corrupt decisions.", book = "Discourses", author = "Epictetus" },
    { text = "The raw material for the work of a good and excellent person is their own guiding reason, the body is that of the doctor and the physical trainer, and the farm the farmer’s.", book = "Discourses", author = "Epictetus" },
    { text = "The soul is like a bowl of water, and our impressions are like the ray of light falling upon the water. When the water is troubled, it appears that the light itself is moved too, but it isn’t. So, when a person loses their composure it isn’t their skills and virtues that are troubled, but the spirit in which they exist, and when that spirit calms down so do those things.", book = "Discourses", author = "Epictetus" },
    { text = "The task of a philosopher: we should bring our will into harmony with whatever happens, so that nothing happens against our will and nothing that we wish for fails to happen.", book = "Discourses", author = "Epictetus" },
    { text = "The unrestricted person, who has in hand what they will in all events, is free. But anyone who can be restricted, coerced, or pushed into something against what they will is a slave.", book = "Discourses", author = "Epictetus" },
    { text = "The wise person knows it is fruitless to project hopes and fears on the future. This only leads to forming melodramatic representations in your mind and wasting time.", book = "", author = "Epictetus" },
    { text = "Then what makes a beautiful human being? Isn’t it the presence of human excellence? Young friend, if you wish to be beautiful, then work diligently at human excellence. And what is that? Observe those whom you praise without prejudice. The just or the unjust? The just. The even-tempered or the undisciplined? The even-tempered. The self-controlled or the uncontrolled? The self-controlled. In making yourself that kind of person, you will become beautiful—but to the extent you ignore these qualities, you’ll be ugly, even if you use every trick in the book to appear beautiful.", book = "Discourses", author = "Epictetus" },
    { text = "There are three areas in which the person who would be wise and good must be trained. The first has to do with desires and aversions—that a person may never miss the mark in desires nor fall into what repels them. The second has to do with impulses to act and not to act—and more broadly, with duty—that a person may act deliberately for good reasons and not carelessly. The third has to do with freedom from deception and composure and the whole area of judgment, the assent our mind gives to its perceptions. Of these areas, the chief and most urgent is the first which has to do with the passions, for strong emotions arise only when we fail in our desires and aversions.", book = "Discourses", author = "Epictetus" },
    { text = "There are two things that must be rooted out in human beings - arrogant opinion and mistrust. Arrogant opinion expects that there is nothing further needed, and mistrust assumes that under the torrent of circumstance there can be no happiness.", book = "The Discourses", author = "Epictetus" },
    { text = "There is a time and place for diversion and amusements, but you should never allow them to override your true purposes.", book = "", author = "Epictetus" },
    { text = "There is but one way to tranquility of mind and happiness, and that is to account no external things thine own, but to commit all to God.", book = "", author = "Epictetus" },
    { text = "There is no shame in making an honest effort.", book = "", author = "Epictetus" },
    { text = "There is only one way to happiness and that is to cease worrying about things which are beyond the power or our will.", book = "", author = "Epictetus" },
    { text = "Therefore we ought to exercise ourselves in small things, and beginning with them to proceed to the greater.", book = "stoicism", author = "Epictetus" },
    { text = "These things don’t go together. You must be a unified human being, either good or bad. You must diligently work either on your own reasoning or on things out of your control—take great care with the inside and not what’s outside, which is to say, stand with the philosopher, or else with the mob!", book = "Discourses", author = "Epictetus" },
    { text = "This is the true athlete—the person in rigorous training against false impressions. Remain firm, you who suffer, don’t be kidnapped by your impressions! The struggle is great, the task divine—to gain mastery, freedom, happiness, and tranquility.", book = "Discourses", author = "Epictetus" },
    { text = "This is your business—to act well the given part, but to choose it belongs to another.", book = "", author = "Epictetus" },
    { text = "Those proficient praise no one, blame no one, and accuse no one. They say nothing concerning their self as being anybody or knowing anything.", book = "", author = "Epictetus" },
    { text = "Those who are well constituted in the body endure both heat and cold: and so those who are well constituted in the soul endure both anger and grief and excessive joy and the other affects.", book = "", author = "Epictetus" },
    { text = "Those who receive the bare theories immediately want to spew them, as an upset stomach does its food. First digest your theories and you won’t throw them up. Otherwise they will be raw, spoiled, and not nourishing. After you’ve digested them, show us the changes in your reasoned choices, just like the shoulders of gymnasts display their diet and training, and as the craft of artisans show in what they’ve learned.", book = "Discourses", author = "Epictetus" },
    { text = "Throw out your conceited opinions, for it is impossible for a person to begin to learn what he thinks he already knows.", book = "Discourses", author = "Epictetus" },
    { text = "Thus Socrates became perfect, improving himself by everything. attending to nothing but reason. And though you are not yet a Socrates, you ought, however, to live as one desirous of becoming a Socrates.", book = "", author = "Epictetus" },
    { text = "Times relieves the foolish from sorrow, but reason relieves the wise.", book = "", author = "Epictetus" },
    { text = "Tis true I know what evil I shall do but passion overpowers the better council.", book = "", author = "Epictetus" },
    { text = "To accuse others for one’s own misfortune is a sign of want of education. To accuse oneself shows that one’s education has begun. To accuse neither oneself nor others shows that one’s education is complete.", book = "", author = "Epictetus" },
    { text = "To admonish is better than to reproach for admonition is mild and friendly, but reproach is harsh and insulting; and admonition corrects those who are doing wrong, but reproach only convicts them.", book = "", author = "Epictetus" },
    { text = "True instruction is this:--to learn to wish that each thing should come to pass as it does. And how does it come to pass? As the Disposer has disposed it. Now He has disposed that there should be summer and winter, and plenty and dearth, and vice and virtue, and all such opposites, for the harmony of the whole.", book = "", author = "Epictetus" },
    { text = "Try to enjoy the great festival of life with other men.", book = "", author = "Epictetus" },
    { text = "Understand that every event is indifferent and nothing to you, of whatever sort it may be; for it will be in your power to make a right use of it, and this no one can hinder.", book = "", author = "Epictetus" },
    { text = "Understand what words you use first, then use them.", book = "", author = "Epictetus" },
    { text = "Very little is needed for everything to be upset and ruined, only a slight lapse in reason.", book = "", author = "Epictetus" },
    { text = "We are at the mercy of whoever wields authority over the things we either desire or detest. If you would be free, then, do not wish to have, or avoid, things that other people control, because then you must serve as their slave.", book = "", author = "Epictetus" },
    { text = "We are not disturbed by what happens to us, but by our thoughts about what happens to us.", book = "", author = "Epictetus" },
    { text = "We aren't filled with fear except by things that are bad; and not by them, either, as long as it is in our power to avoid them.", book = "", author = "Epictetus" },
    { text = "We cannot choose our external circumstances, but we can always choose how we respond to them.", book = "", author = "Epictetus" },
    { text = "We control our reasoned choice and all acts that depend on that moral will. What’s not under our control are the body and any of its parts, our possessions, parents, siblings, children, or country—anything with which we might associate.", book = "Discourses", author = "Epictetus" },
    { text = "We cry to God Almighty, how can we escape this agony? Fool, don’t you have hands? Or could it be God forgot to give you a pair? Sit and pray your nose doesn’t run! Or, rather just wipe your nose and stop seeking a scapegoat.", book = "Discourses", author = "Epictetus" },
    { text = "We don’t abandon our pursuits because we despair of ever perfecting them.", book = "Discourses", author = "Epictetus" },
    { text = "We have two ears and one mouth so that we can listen twice as much as we speak.", book = "", author = "Epictetus" },
    { text = "We must not believe the many, who say that only free people ought to be educated, but we should rather believe the philosophers who say that only the educated are free.", book = "", author = "Epictetus" },
    { text = "We must undergo a hard winter training and not rush into things for which we haven’t prepared.", book = "Discourses", author = "Epictetus" },
    { text = "We should put our trust not in the crowd, who say that only free men can be educated, but rather in the philosophers, who say that none but the educated can be free.", book = "", author = "Epictetus" },
    { text = "We should realize that an opinion is not easily formed unless a person says and hears the same things every day and practises them in real life.", book = "", author = "Epictetus" },
    { text = "We suffer not from the events in our lives but from our judgement about them.", book = "", author = "Epictetus" },
    { text = "Wealth consists not in having great possessions, but in having few wants.", book = "", author = "Epictetus" },
    { text = "Well, when do we act like sheep: when we act for the sake of the belly, or of our sex-organs, or at random, or in a filthy fashion, or without due consideration, to what level have we degenerated? To the level of sheep.", book = "Epictetus. The Discourses as Reported By Arrian. Vol. I. Books 1 and 2. With an English Translation By W. A. Oldfather", author = "Epictetus" },
    { text = "What are we to do, then? To make the best of what lies within our power, and deal with everything else as it comes. ‘How does it come, then?’ As God wills.", book = "", author = "Epictetus" },
    { text = "What assistance can we find in the fight against habit? Try the opposite!", book = "Discourses", author = "Epictetus" },
    { text = "What concerns me is not the way things are, but the way people think things are.", book = "", author = "Epictetus" },
    { text = "What does it mean to be getting an education? It means learning to apply natural preconceptions to particular cases as nature prescribes, and distinguishing what is in our power from what is not.", book = "Discourses and Selected Writings", author = "Epictetus" },
    { text = "What is bad luck? Opinion. What are conflict, dispute, blame, accusation, irreverence, and frivolity? They are all opinions, and more than that, they are opinions that lie outside of our own reasoned choice, presented as if they were good or evil. Let a person shift their opinions only to what belongs in the field of their own choice, and I guarantee that person will have peace of mind, whatever is happening around them.", book = "Discourses", author = "Epictetus" },
    { text = "What is it then to be properly educated? It is learning to apply our natural preconceptions to the right things according to Nature, and beyond that to separate the things that lie within our power from those that don’t.", book = "Discourses", author = "Epictetus" },
    { text = "What is the fruit of these teachings? Only the most beautiful and proper harvest of the truly educated—tranquility, fearlessness, and freedom. We should not trust the masses who say only the free can be educated, but rather the lovers of wisdom who say that only the educated are free.", book = "Discourses", author = "Epictetus" },
    { text = "What makes for freedom and fluency in the practice of writing? Knowledge of how to write. The same goes for the practice of playing an instrument. It follows that, in the conduct of life, there must be a science to living well.", book = "", author = "Epictetus" },
    { text = "What really frightens and dismays us is not external events themselves, but the way in which we think about them. It is not things that disturb us, but our interpretation of their significance.", book = "", author = "Epictetus" },
    { text = "What saith Antisthenes? Hast thou never heard?— It is a kingly thing, O Cyrus, to do well and to be evil spoken of.", book = "", author = "Epictetus" },
    { text = "What upsets people is not things themselves but their judgements about these things.", book = "", author = "Epictetus" },
    { text = "What would Heracles have been if he had said, How am I to prevent a big lion from appearing, or a big boar, or brutal men? What care you, I say? If a big boar appears, you will have a greater struggle to engage in; if evil men appear, you will free the world from evil men.", book = "", author = "Epictetus" },
    { text = "What, then, makes a person free from hindrance and self-determining? For wealth doesn’t, neither does high-office, state or kingdom—rather, something else must be found... in the case of living, it is the knowledge of how to live.", book = "Discourses", author = "Epictetus" },
    { text = "Whatever moral rules you have deliberately proposed to yourself. abide by them as they were laws, and as if you would be guilty of impiety by violating any of them. Don’t regard what anyone says of you, for this, after all, is no concern of yours.", book = "", author = "Epictetus" },
    { text = "Whatever your mission, stick by it as if it were a law and you would be committing sacrilege to betray it. Pay no attention to whatever people might say; this no longer should influence you.", book = "", author = "Epictetus" },
    { text = "When a man is proud because he can understand and explain the writings of Chrysippus, say to yourself, if Chrysippus had not written obscurely, this man would have had nothing to be proud of.", book = "", author = "Epictetus" },
    { text = "When a youth was giving himself airs in the Theatre and saying, 'I am wise, for I have conversed with many wise men,' Epictetus replied, 'I too have conversed with many rich men, yet I am not rich!’.", book = "", author = "Epictetus" },
    { text = "When children stick their hand down a narrow goody jar they can’t get their full fist out and start crying. Drop a few treats and you will get it out! Curb your desire—don’t set your heart on so many things and you will get what you need.", book = "Discourses", author = "Epictetus" },
    { text = "When I see an anxious person, I ask myself, what do they want? For if a person wasn’t wanting something outside of their own control, why would they be stricken by anxiety?", book = "Discourses", author = "Epictetus" },
    { text = "When it comes to money, where we feel our clear interest, we have an entire art where the tester uses many means to discover the worth... just as we give great attention to judging things that might steer us badly. But when it comes to our own ruling principle, we yawn and doze off, accepting any appearance that flashes by without counting the cost.", book = "Discourses", author = "Epictetus" },
    { text = "When someone is properly grounded in life, they shouldn't have to look outside themselves for approval.", book = "", author = "Epictetus" },
    { text = "When something happens, the only thing in your power is your attitude toward it; you can either accept it or resent it.", book = "", author = "Epictetus" },
    { text = "When the standards have been set, things are tested and weighed. And the work of philosophy is just this, to examine and uphold the standards, but the work of a truly good person is in using those standards when they know them.", book = "Discourses", author = "Epictetus" },
    { text = "When then any man assents to that which is false, be assured that he did not intend to assent to it as false, for every soul is unwillingly deprived of the truth, as Plato says; but the falsity seemed to him to be true.", book = "", author = "Epictetus" },
    { text = "When things seem to have reached that stage, merely say “I won’t play any longer”, and take your departure; but if you stay, stop lamenting.", book = "", author = "Epictetus" },
    { text = "When you are alone, you should call this tranquility and freedom and when you are with many you shouldn't call this a crowd, or trouble or uneasiness but festival and company and contentedly accept it.", book = "Discources and Selected Writings", author = "Epictetus" },
    { text = "When you are feeling upset, angry, or sad, don’t blame another for your state of mind. Your condition is the result of your own opinions and interpretations.", book = "", author = "Epictetus" },
    { text = "When you find your direction, check to make sure that it is the right one.", book = "", author = "Epictetus" },
    { text = "When you let your attention slide for a bit, don’t think you will get back a grip on it whenever you wish—instead, bear in mind that because of today’s mistake everything that follows will be necessarily worse.... Is it possible to be free from error? Not by any means, but it is possible to be a person always stretching to avoid error. For we must be content to at least escape a few mistakes by never letting our attention slide.", book = "Discourses", author = "Epictetus" },
    { text = "Whenever disturbing news is delivered to you, bear in mind that no news can ever be relevant to your reasoned choice. Can anyone break news to you that your assumptions or desires are wrong? No way! But they can tell you someone died—even so, what is that to you?", book = "Discourses", author = "Epictetus" },
    { text = "Whenever you experience the pangs of losing something, don’t treat it like a part of yourself but as a breakable glass, so when it falls you will remember that and won’t be troubled. So too, whenever you kiss your child, sibling, or friend, don’t layer on top of the experience all the things you might wish, but hold them back and stop them, just as those who ride behind triumphant generals remind them they are mortal. In the same way, remind yourself that your precious one isn’t one of your possessions, but something given for now, not forever...", book = "Discourses", author = "Epictetus" },
    { text = "Whenever you find yourself blaming providence, turn it around in your mind and you will see that what has happened is in keeping with reason.", book = "Discourses", author = "Epictetus" },
    { text = "Whenever you get an impression of some pleasure, as with any impression, guard yourself from being carried away by it, let it await your action, give yourself a pause. After that, bring to mind both times, first when you have enjoyed the pleasure and later when you will regret it and hate yourself. Then compare to those the joy and satisfaction you’d feel for abstaining altogether. However, if a seemingly appropriate time arises to act on it, don’t be overcome by its comfort, pleasantness, and allure—but against all of this, how much better the consciousness of conquering it.", book = "Enchiridion", author = "Epictetus" },
    { text = "Where is Good? In our reasoned choices. Where is Evil? In our reasoned choices. Where is that which is neither Good nor Evil? In the things outside of our own reasoned choice.", book = "Discourses", author = "Epictetus" },
    { text = "Which of us does not admire what Lycurgus the Spartan did? A young citizen had put out his eye, and been handed over to him by the people to be punished at his own discretion. Lycurgus abstained from all vengeance, but on the contrary instructed and made a good man of him. Producing him in public in the theatre, he said to the astonished Spartans: I received this young man at your hands full of violence and wanton insolence; I restore him to you in his right mind and fit to serve his country.", book = "", author = "Epictetus" },
    { text = "Who are those people by whom you wish to be admired? Are they not these whom you are in the habit of saying that they are mad? What then? Do you wish to be admired by the mad?", book = "", author = "Epictetus" },
    { text = "Who is a friend?  his answer was,  A second self (alter ego). ", book = "", author = "Epictetus" },
    { text = "Who is your master? Whoever has authority over anything that you’re anxious to gain or avoid.", book = "", author = "Epictetus" },
    { text = "Who then is invincible? The one who cannot be upset by anything outside their reasoned choice.", book = "Discourses", author = "Epictetus" },
    { text = "Who, then, is the invincible human being? One who can be disconcerted by nothing that lies outside the sphere of choice.", book = "", author = "Epictetus" },
    { text = "Whoever chafes at the conditions dealt by fate is unskilled in the art of life; whoever bears with them nobly and makes wise use of the results is a man who deserves to be considered good.", book = "", author = "Epictetus" },
    { text = "Whoever is going to listen to the philosophers needs a considerable practice in listening.", book = "", author = "Epictetus" },
    { text = "Whoever then has knowledge of good things, would know how to love them; but how could one who cannot distinguish good things from evil and things indifferent from both have power to love?", book = "Discourses of Epictetus, Vol 2", author = "Epictetus" },
    { text = "Whoever then would be free, let him wish for nothing, let him decline nothing, which depends on others; else he must necessarily be a slave.", book = "", author = "Epictetus" },
    { text = "Why are you pestering me, pal? My own evils are enough for me.", book = "", author = "Epictetus" },
    { text = "Why do you want to read anyway – for the sake of amusement or mere erudition? Those are poor, fatuous pretexts.  Reading should serve the goal of attaining peace; if it doesn’t make you peaceful, what good is it?", book = "", author = "Epictetus" },
    { text = "Will you never come to a realisation of who you are, what you have been born for and the purpose for which the gift of vision was made in our case?", book = "Discources and Selected Writings", author = "Epictetus" },
    { text = "Working within our sphere of control, we are naturally free, independent, and strong. Beyond that sphere, we are weak, limited, and dependent.", book = "", author = "Epictetus" },
    { text = "Yes, but my nose is running.’ Then what do you have hands for, you slave?", book = "", author = "Epictetus" },
    { text = "You are a little soul carrying around a corpse.", book = "", author = "Epictetus" },
    { text = "You are not your body and hair-style, but your capacity for choosing well. If your choices are beautiful, so too will you be.", book = "Discourses", author = "Epictetus" },
    { text = "You are the one who knows yourself - which is to say, you know how much you are worth in your own estimation, and therefore at what price you will sell yourself; because people sell themselves at different rates.", book = "", author = "Epictetus" },
    { text = "You become what you give your attention to.", book = "", author = "Epictetus" },
    { text = "You can be invincible, if you enter into no contest in which it is not in your power to conquer.", book = "Enchiridion", author = "Epictetus" },
    { text = "You can bind up my leg, but not even Zeus has the power to break my freedom of choice.", book = "Discourses, 1.1.23", author = "Epictetus" },
    { text = "You know yourself what you are worth in your own eyes; and at what price you will sell yourself. For men sell themselves at various prices. This is why, when Florus was deliberating whether he should appear at Nero's shows, taking part in the performance himself, Agrippinus replied,'Appear by all means.' And when Florus inquired,'But why do not you appear?' he answered,'Because I do not even consider the question.' For the man who has once stooped to consider such questions, and to reckon up the value of external things, is not far from forgetting what manner of man he is.", book = "The Golden Sayings of Epictetus", author = "Epictetus" },
    { text = "You may fetter my leg, but Zeus himself cannot get the better of my free will.", book = "", author = "Epictetus" },
    { text = "You must be one man, either good or bad. You must cultivate either your own ruling faculty or externals, and apply yourself either to things within or without you; that is, be either a philosopher, or one of the vulgar.", book = "", author = "Epictetus" },
    { text = "You must stop blaming God, and not blame any person. You must completely control your desire and shift your avoidance to what lies within your reasoned choice. You must no longer feel anger, resentment, envy, or regret.", book = "Discourses", author = "Epictetus" },
    { text = "You only have to doze a moment, and all is lost. For ruin and salvation both have their source inside you.", book = "", author = "Epictetus" },
    { text = "You see, then, that it is necessary for you to become a student, that creature which every one laughs at, if you really desire to make an examination of your judgements. But this, as you are quite aware, is not the work of a single hour or day.", book = "", author = "Epictetus" },
    { text = "You will do the greatest services to the state, if you shall raise not the roofs of the houses, but the souls of the citizens: for it is better that great souls should dwell in small houses than for mean slaves to lurk in great houses.", book = "", author = "Epictetus" },
    { text = "You will never have to experience defeat if you avoid contests whose outcome is outside your control.", book = "", author = "Epictetus" },
    { text = "You’re unable to make someone change his views, recognize that he is a child, and clap as he does. Or if you don’t care to act in such a way, you have only to keep quiet.", book = "", author = "Epictetus" },
    { text = "You'd have a better chance persuading someone to change their sexual orientation than reaching people who have rendered themselves so deaf and blind.", book = "", author = "Epictetus" },
    { text = "Your happiness depends on three things, all of which are within your power: your will, your ideas concerning the events in which you are involved, and the use you make of your ideas.", book = "", author = "Epictetus" },
    { text = "You're not yet Socrates, but you can still live as if you want to be him.", book = "", author = "Epictetus" },
    { text = "Death is nothing to us. When we exist, death is not; and when death exists, we are not.", book = "stoicism", author = "Epicurus" },
    { text = "If you haven't learned something  From periods of suffering, If you haven't wrung the juices  Of your own pain and drank them  For your own nourishment, You have wasted your experience  And missed the chance  To expand the capacity  For being stronger the next time  That these seasons arrive at your door.", book = "Legacy", author = "Eric Overby" },
    { text = "Warriors should suffer their pain silently.", book = "Into the Wild", author = "Erin Hunter" },
    { text = "Really, doesn't everything make sense? There are, of course, things from which we more or less recover, although some of them are too harsh even for saints. But that is no reason to accuse God. Even if there are reasons to doubt him, the fact that he did not arrange the world like a well-ordered parlor is not one of them. It rather speaks in his favor. This used to be much better understood.", book = "The Glass Bees", author = "Ernst Jünger" },
    { text = "Whoever embraces necessity count as wise, skilled in divine matters.", book = "", author = "Euripides" },
    { text = "I smile to catch the piranhas from swimming out of my mouth.", book = "", author = "Evan Mariah Pettit" },
    { text = "The most beautiful things come from the hardest conditions.", book = "", author = "Ezedi Souvenir" },
    { text = "Submission, when it is submission to the truth  and when the truth is known to be both beautiful and merciful  has nothing in common with fatalism or stoicism as these terms are understood in the Western tradition, because its motivation is different. According to Fakhr ad-Din ar-RazT, one of the great commentators upon the Quran: The worship of the eyes is weeping, the worship of the ears is listening, the worship of the tongue is praise, the worship of the hands is giving, the worship of the body is effort, the worship of the heart is fear and hope, and the worship of the spirit is surrender and satisfaction in Allah.", book = "", author = "Fakhr ad-Din ar-Razi, Gai Eaton" },
    { text = "Before concluding the discussion on Partridge's connection to the Stoic tradition, I present what is probably the greatest proof Partridge was a Stoic: he suffered the public doom of one. Ironically, Partridge may have missed a powerful warning about his own fate within one of the key texts he used in his academies. A footnote within William Duncan's translation of Cicero's orations recalls the ill fortune of Quintus Aelius Tubero in the eyes of the people of Rome caused by his Stoic behavior at the funeral of Scipio Africanus: [It was the same from the study of Tubero] Cicero here ridicules the doctrine of the Stoics, shows the absurdities into which it may betray a man and paints the ill consequences that often arise from it. [Quintus Aelius] Tubero, of whom he speaks here had professed himself a Stoic and resolved to regulate his conduct by the tenets of that sect. Accordingly, in an entertainment he gave the Roman people on occasion of the death of the great Scipio Africanus he made use of plain wooden beds, goat skin covers, and earthen dishes. But this ill-timed parsimony was so displeasing to the Roman people that when he afterwards stood for the prÃ¦torship they refused him their suffrages though a man of illustrious birth and the most distinguished virtue. Is there a passage more fitting for the legacy of Partridge and his Stoic behavior? Even when Partridge had built an ideal model for educating a complete virtue-driven citizen worthy of the Republic, few would find the lifestyle required appealing. Being a virtuous man with a sufficient plan for American education was not enough to guarantee his acceptance among the masses.", book = "Controversial History & Educational Theories of Captain Alden Partridge", author = "Franklin C. Annis" },
    { text = "For the military community, philosophy isn't something casually debated. But something that should be fully embodied in everyday thought and action, with the abandonment of all principles not shown practical in the most extreme of environments.", book = "Controversial History & Educational Theories of Captain Alden Partridge", author = "Franklin C. Annis" },
    { text = "These deep interactions with Greek and Roman culture, to include Stoic philosophy, certainly affected the zeitgeist of the era and most certainly impacted the educational theories in the early days of the Republic. With so much interest in reviving and adopting elements of Stoic philosophy within America, many intended references to Stoic ethics may be hidden within the works of the early generations of America, as they explicitly referenced American ideals that would have incorporated Stoic philosophy.", book = "Controversial History & Educational Theories of Captain Alden Partridge", author = "Franklin C. Annis" },
    { text = "I fail to remember ever having made an effort  no trace of struggle is detectable in my life, I am the opposite of a heroic nature. To want something, to strive for something, to have an end a desire in mind  I know none of this from my experience. Even at this moment I look out upon my future  a broad future!  as upon a smooth sea: no desire ripples upon it. Not in the least do I want anything to be different from what it is; I myself do not want to be any different ... But thus I have always lived.", book = "Ecce Homo", author = "Friedrich Nietzsche" },
    { text = "Above all, avoid falsehood, every kind of falsehood, especially falseness to yourself. Watch over your own deceitfulness and look into it every hour, every minute. Avoid being scornful, both to others and to yourself. What seems to you bad within you will grow purer from the very fact of your observing it in yourself. Avoid fear, too, though fear is only the consequence of every sort of falsehood. Never be frightened at your own faint-heartedness in attaining love.", book = "The Brothers Karamazov", author = "Fyodor Dostoevsky" },
    { text = "A related model to watch out for is the hydra effect, named after the Lernaean Hydra, a beast from Greek mythology that grows two heads for each one that is cut off.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Addressing negative externalities is often referred to as internalizing them.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "As a metaphor, postmortem refers to any examination of a prior situation to understand what happened and how it could go better next time. At DuckDuckGo, it is mandatory to conduct", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Asymmetric information, where one side of a transaction has different information than the other side", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Chilling effects are a type of observer effect where the threat of retaliation creates a change in behavior.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Coase theorem, essentially a description of how a natural marketplace can internalize a negative externality", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The cobra effect, describing when an attempted solution actually makes the problem worse", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Cognitive dissonance, the stress felt by holding two contradictory, dissonant, beliefs at once", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Confirmation bias is so hard to overcome that there is a related model called the backfire effect that describes the phenomenon of digging in further on a position when faced with clear evidence that disproves it.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Ending up in foster care. Sometimes collateral damage can impact the entity that inflicted the damage in the first place, which is called blowback", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Externalities, which are consequences, good or bad, that affect an entity without its consent, imposed from an external source.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Found that a greater number of choices increased the decision time logarithmically, in a formulation now known as Hick’s law", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Fundamental attribution error, where you frequently make errors by attributing others’ behaviors to their internal, or fundamental, motivations rather than external factors. You are guilty of the fundamental attribution", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Goodhart’s law summarizes the issue: When a measure becomes a target, it ceases to be a good measure.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Hanlon’s razor: never attribute to malice that which is adequately explained by carelessness", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "In any conflict between two people, there are two sides of the story. Then there is the third story, the story that a third, impartial observer would recount.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "intuition, with your subconscious automatically intuiting what to do from instinct or encoded knowledge", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The just world hypothesis, where people always get what they deserve, good or bad, because of their actions alone, with no accounting for luck or randomness. This view is summed up as you reap what you sow", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Moral hazard, is where you take on more risk, or hazard, once you have information that encourages you to believe you are more protected. It has been a concern of the insurance industry", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Moral hazards can also occur when a person or company serves as an agent for another person or company, making decisions on behalf of this entity, known as the principal.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Perfect is the enemy of good", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Science progresses one funeral at a time.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Shirky principle, named after economics writer Clay Shirky. The Shirky principle states, Institutions will try to preserve the problem to which they are the solution.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Someone learns that they are helpless to control their circumstances, so they give up trying to change them.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Spillover effects, which happen when an effect of an activity spills over outside the core interactions of the activity", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The cobra effect, describing when an attempted solution actually makes the problem worse", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The concept of inverse thinking can help you with the challenge of making good decisions. The inverse of being right more is being wrong less.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The human tendency to gather and interpret new information in a biased way to confirm preexisting beliefs is called confirmation bias.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "the most respectful interpretation, or MRI. In any situation, you can explain a person’s behavior in many ways. MRI asks you to you interpret the other parties’ actions in the most respectful way possible. It’s giving people the benefit of the doubt", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "the observer effect, where there is an effect on something depending on how you observe it, or even who observes", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The root cause, by contrast, is what you might call the real reason something happened.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "The Streisand effect applies to an even more specific situation: when you unintentionally draw more attention to something when you try to hide it.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "These are all examples of drawing incorrect conclusions using anecdotal evidence, informally collected evidence from personal", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Tyranny of small decisions, where a series of small, individually rational decisions ultimately leads to a system-wide negative consequence", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Victims of circumstance are actually blamed for their circumstances, with no accounting for factors of randomness like the birth lottery.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "When something happens, the proximate cause is the thing that immediately caused it to happen.", book = "Super Thinking: The Big Book of Mental Models", author = "Gabriel Weinberg,Lauren McCann" },
    { text = "Being good is the same as being a philosopher. If you obey your father, you will follow the will of a man; if you choose the philosopher’s life, the will of the universe. It is plain, therefore, that your duty lies in the pursuit of philosophy.", book = "", author = "Gaius Musonius Rufus" },
    { text = "Choose to die well while you can; wait too long, and it might become impossible to do so.", book = "", author = "Gaius Musonius Rufus" },
    { text = "For mankind, evil is injustice and cruelty and indifference to a neighbour’s trouble, while virtue is brotherly love and goodness and justice and beneficence and concern for the welfare of your neighbour—with.", book = "", author = "Gaius Musonius Rufus" },
    { text = "Husband and wife should come together to craft a shared life, procreating children, seeing all things as shared between them-with nothing withheld or private to one another-not even their bodies.", book = "", author = "Gaius Musonius Rufus" },
    { text = "If we were to measure what is good by how much pleasure it brings, nothing would be better than self-control- if we were to measure what is to be avoided by its pain, nothing would be more painful than lack of self-control.", book = "", author = "Gaius Musonius Rufus" },
    { text = "If you accomplish something good with hard work, the labor passes quickly, but the good endures; if you do something shameful in pursuit of pleasure, the pleasure passes quickly, but the shame endures.", book = "", author = "Gaius Musonius Rufus" },
    { text = "In our control is the most beautiful and important thing, the thing because of which even the god himself is happy— namely, the proper use of our impressions. We must concern ourselves absolutely  with the things that are under our control and entrust the things not in our control to the universe.", book = "", author = "Gaius Musonius Rufus" },
    { text = "Since every man dies, it is better to die with distinction than to live long.", book = "", author = "Gaius Musonius Rufus" },
    { text = "To accept injury without a spirit of savage resentment-to show ourselves merciful toward those who wrong us-being a source of good hope to them-is characteristic of a benevolent and civilized way of life.", book = "", author = "Gaius Musonius Rufus" },
    { text = "We will train both soul and body when we accustom ourselves to cold, heat, thirst, hunger, scarcity of food, hardness of bed, abstaining from pleasures, and enduring pains.", book = "", author = "Gaius Musonius Rufus" },
    { text = "Wealth is able to buy the pleasures of eating, drinking and other sensual pursuits-yet can never afford a cheerful spirit or freedom from sorrow.", book = "", author = "Gaius Musonius Rufus" },
    { text = "What good are gilded rooms or precious stones-fitted on the floor, inlaid in the walls, carried from great distances at the greatest expense? These things are pointless and unnecessary-without them isn’t it possible to live healthy? Aren’t they the source of constant trouble? Don’t they cost vast sums of money that, through public and private charity, may have benefited many?", book = "", author = "Gaius Musonius Rufus" },
    { text = "You will earn the respect of all if you begin by earning the respect of yourself. Don’t expect to encourage good deeds in people conscious of your own misdeeds.", book = "", author = "Gaius Musonius Rufus" },
    { text = "True affluence is not needing anything.", book = "", author = "Gary Snyder" },
    { text = "If I did compress what I know and think about the spanish civil war into 6 lines you wouldn't print it. You wouldn't have the guts.", book = "Essays", author = "George Orwell" },
    { text = "Forces beyond your control can take away everything you possess except one thing, your freedom to choose how you will respond to the situation. You cannot control what happens to you in life, but you can always control what you will feel and do about what happens to you.", book = "Man's Search for Meaning", author = "Harold S. Kushner" },
    { text = "I must fling myself down and writhe; I must strive with every piece of force I possess; I bruise and batter myself against the floor, the walls; I strain and sob and exhaust myself, and begin again, and exhaust myself again; but do I feel pain? Never. How can I feel pain? There is no place for it.", book = "", author = "Harry Houdini" },
    { text = "Rasa susah, khawtir, cemas karena peristiwa eksternal sebernarnya tidak datang dari peristiwa hidup itu sendiri, tetapi dari persepsi dan opini kita sendiri, dan sepenuhnya dibawah kendali kita.", book = "Filosofi Teras", author = "Henry Manampiring" },
    { text = "For to be wise is only one thing—to fix our attention on our intelligence, which guides all things everywhere.", book = "Lives Of The Eminent Philosophers", author = "Heraclitus" },
    { text = "he saw and recognised the visible and he sought his place in this world. He did not seek reality; his goal was not on any other side. The world was beautiful when looked at in this way - without any seeking, so simple, so childlike. The moon and stars were beautiful, the brook, the shore, the forest and rock, the goat and the golden beetle, the flower and butterfly were beautiful. It was beautiful and pleasant to go through the world like that, so childlike, so awakened, so concerned with the immediate, without any distrust.", book = "Siddhartha", author = "Hermann Hesse" },
    { text = "You are indeed a man of sorrows and have suffered much...pray be seated now, here on this chair, and let us leave our sorrows, bitter though they are, locked up in our own hearts, for weeping is cold comfort and does little good.", book = "The Iliad", author = "Homer" },
    { text = "A good story has no end, it continues being a part of reality well after its last point by forming a union with us.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "How does one go about persuading the rain to stop?", book = "Oculus", author = "Ioannis Loukopoulos" },
    { text = "It is only when you fall that you learn whether you can fly.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Me? I'm a Stoic. Every time my eyes are opened, I am eager to see the world anew.", book = "Oculus", author = "Ioannis Loukopoulos" },
    { text = "One will never be able to control all things that concern an endeavor, but the magic is in riding the wave.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Pursuing similar results for dissimilar people will make fools of kings and kings of fools.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Speak the truth and above all claim the things you want, at least to yourself.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Strive to articulate your wants loudly so they become interwoven with reality, more than thoughts.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Take pride in your courage for it leads to difficult situations which, once overcome, leave you more than what you were before. Only in the most extreme of pressures does carbon become diamond", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "The closest we can get to winning at life is to never give up.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "The crossing of a blue bridge which bystanders who cannot distinguish from the blue of the horizon deem invisible.", book = "Oculus", author = "Ioannis Loukopoulos" },
    { text = "The most terrifying ghosts that haunt us are the ones of our dead dreams, especially if we were the murderers.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "The reaction that art produces in you has more to do with you than it does with art.", book = "", author = "Ioannis Loukopoulos" },
    { text = "Verily, life is a series of championships and the joy is to be found in playing the game.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "We should refrain from attempting to change things to fit our narrative of explaining the world, and start changing this narrative to better host the things we experience.", book = "Kaleidoscope", author = "Ioannis Loukopoulos" },
    { text = "Remember you will die but do brave deeds and endure", book = "Gathering of the Crimson Cloaks", author = "J.R. Potts" },
    { text = "Luck plays such an overpowering role in some lives that the thoughtful person must ask: 'Why have I been cursed with bad luck while another is blessed with so much good luck?' Believe me, the fortunate person who receives the favorable breaks also wonders about his favored situation. In my case, I have no explanation. I was hardworking; I had a tough character; I was a good student; and I acknowledged the leadership of my superiors. But no amount of hard work or high standard of behavior could have brought the many good things that happened to me; pure chance dictated most of them. The only generalization I can offer is that in an irrational world if a prudent course has been followed, you make yourself eligible to capitalize on luck if it happens to strike. If you have not made yourself eligible, you may never be aware that luck is at hand. By all this I mean: learn typing, master math, learn to draft a convincing letter, broaden the mind, and do not evade challenges. Making oneself eligible to seize the breaks if and when they come is the only sensible strategy I know. Be prepared to make full use of any stroke of luck, and even if it never comes, the preparation in itself will be a worthy effort. Chapter VIII, Writing page 289", book = "The World Is My Home: A Memoir", author = "James A. Michener" },
    { text = "A properly educated leader, especially when harassed and under pressure, will know from his study of history and the classics that circumstances very much like those he is encountering have occurred from time to time on this earth since the beginning of history. He will avoid the self-indulgent error of seeing himself in a predicament so unprecedented, so unique, as to justify his making an exception to law, custom or morality in favor of himself. The making of such exceptions has been the theme of public life throughout much of our lifetimes. For twenty years, we've been surrounded by gamesmen unable to cope with the wisdom of the ages. They make exceptions to law and custom in favor of themselves because they choose to view ordinary dilemmas as unprecedented crises.", book = "", author = "James B. Stockdale" },
    { text = "Always resignation and acceptance. Always prudence and honour and duty. Elinor, where is your heart?", book = "Sense and Sensibility", author = "Jane Austen" },
    { text = "Perhaps I did not always love him so well as I do now. But in such cases as these, a good memory is unpardonable.", book = "Pride and Prejudice", author = "Jane Austen" },
    { text = "What do you know of my heart? What do you know of anything but your own suffering. For weeks, Marianne, I've had this pressing on me without being at liberty to speak of it to a single creature. It was forced on me by the very person whose prior claims ruined all my hope. I have endured her exultations again and again whilst knowing myself to be divided from Edward forever. Believe me, Marianne, had I not been bound to silence I could have provided proof enough of a broken heart, even for you.", book = "Sense and Sensibility", author = "Jane Austen" },
    { text = "Cecilia, the youngest, only thirteen, had gone first, slitting her wrists like a Stoic while taking a bath, and when they found her, afloat in her pink pool, with the yellow eyes of someone possessed and her small body giving off the odor of a mature woman, the paramedics had been so frightened by her tranquillity that they had stood mesmerized.", book = "", author = "Jeffrey Eugenides, The Virgin Suicides" },
    { text = "I am not like the Gods! That was a painful thrust; I'm like the worm that burrows in the dust, Who, as he makes of dust his meager meal, Is crushed and buried by a wanderers heel Is it not dust that stares from every rack And narrows down this vaulting den? This moth's world full of bric-a-brac In which I live as in a pen? Here I should find for what I care? Should I read in a thousand books, maybe, That men have always suffered everywhere, Though now and then some man lived happily?- Why, hollow skull, do you grin like a faun? Save that your brain, like mine, once in dismay Searched for light day, but foundered in the heavy dawn", book = "Faust, First Part", author = "Johann Wolfgang von Goethe" },
    { text = "really believe that. If you embrace that idea, I believe you will discover two things. First, you will learn a lot, because every time you meet someone, it is a learning opportunity. Second, people will warm up to you. Complete strangers often treat me like an old friend, simply because I am open to them.", book = "The Maxwell Daily Reader: 365 Days of Insight to Develop the Leader Within You and Influence Those Around You", author = "John C. Maxwell" },
    { text = "Requesting a person’s story says, “You could be special.” • Remembering a person’s story says, “You are special.” •Reminding a person of his or her story says, “You are special to me.” • Repeating a person’s story to others says, “You should be special to them.” The result? You become special to the person who shared a story with you.", book = "The Maxwell Daily Reader: 365 Days of Insight to Develop the Leader Within You and Influence Those Around You", author = "John C. Maxwell" },
    { text = "The greatest day in your life and mine is when we take total responsibility for our attitudes. That’s the day we truly grow up.", book = "The Maxwell Daily Reader: 365 Days of Insight to Develop the Leader Within You and Influence Those Around You", author = "John C. Maxwell" },
    { text = "A man's wealth must be determined by the relation of his desires and expenditures to his income. If he feels rich on ten dollars, and has everything else he desires, he really is rich.", book = "stoicism", author = "John Davison Rockefeller" },
    { text = "They did this to me but I have remained who I am. I am tempered. I am able. Inside myself there's an untouched man. If they came back now, and did everything to me again, they would never reach the untouched man. I've passed the exam I've been shirking all my life. I'm a graduate of pain.", book = "", author = "John le Carré" },
    { text = "There was an iron simplicty in the seer. He was like a monolith of logic standing against waves of angry nonsense.", book = "", author = "John Steinbeck" },
    { text = "It would be foolish to be stoical all the time, you'd wear yourself out for nothing", book = "", author = "John-Paul Sartre" },
    { text = "If you are pained by any external tiling, it is not this things that disturbs you, but your own judgment about it. And it is in your power to wipe out this judgment now.", book = "The Little Book of Stoicism: Timeless Wisdom to Gain Resilience, Confidence, and Calmness", author = "Jonas Salzgeber" },
    { text = "The same situation can either be perceived as a lead ball chained to your feet, or as wings growing out of your shoulder blades. How you interpret the challenge is crucial to your success of overcoming it. Ultimately, it's never the challenges that matter, but how you perceive them.", book = "The Little Book of Stoicism: Timeless Wisdom to Gain Resilience, Confidence, and Calmness", author = "Jonas Salzgeber " },
    { text = "Just as chickens wake up and scream, being reborn is the polar opposite. You are blinded by bliss and numb to such pain.", book = "", author = "Jordan Binless" },
    { text = "Just as roosters scream in the morning, being reborn is the polar opposite. You are blinded by bliss and numb to such pains.", book = "", author = "Jordan Binless" },
    { text = "In his numerous historical and Scriptural works  Bauer  rejects all supernatural religion, and represents Christianity as a natural product of the mingling of the Stoic and Alexandrian philosophies...", book = "A Biographical Dictionary of Modern Rationalists", author = "Joseph McCabe" },
    { text = "Precision of thought comes from a tranquil mindset. A presenter can have a competitive edge if they are unmoved by the jabs and provocations that are directed at them", book = "", author = "Josh King Madrid" },
    { text = "It was as if I'd lost some cosmic game of musical chairs; the song had stopped, I was left standing, and there was simply nothing to be dine about it.", book = "The City of Mirrors", author = "Justin Cronin" },
    { text = "I sacrificed much to be where I am today, yet I will sacrifice much more to get to where I need to be someday.", book = "", author = "Justus Wiezorek" },
    { text = "Once you make a decision and then act on it, you have actually fulfilled the object of the game. This will probably surprise you, but what happens next in the hand after you act is not important. It does not matter what your opponents do next and it's immaterial whether or not you win the hand. The most important thing is that you understand why you're making the play and what goal you're trying to accomplish.", book = "The Big Book of Poker : A big,easy, and fun guide to winning", author = "Ken Warren" },
    { text = "At its core, Stoicism, like the sturdy oak tree, stands firm amidst the torrential downpour of life's distractions. It teaches us that while we may not command the winds to change, we possess the power to adjust our sails, to guide our minds through the tumultuous sea of life's happenings.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Beware the folly of lending your focus to vain pursuits. Just as a river, when it is split into countless rivulets, loses its force and becomes but a whimper, a mind divided by trivial pursuits dissipates its strength. Focus, therefore, is not merely concentration, it is selection; not merely observation, it is dedication.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Distractions adorn themselves in the grandeur of the immediate, urgent, and superficial, dazzling our senses and demanding our attention. They leap into the spotlight, shouting loudly to drown the quiet callings of our deepest intentions.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Distractions are the relentless waves of the ocean, crashing against the shores of our consciousness. They erode our resolve, and little by little, wash away the sandcastles of our focus. They arrive in various guises: the allure of trivial pleasures, the lure of the inconsequential, the din of idle gossip, the chains of past regret and the ghostly shadows of future anxieties. Each wave seeks to pull us into the depths of irrelevance, away from the firm ground of meaningful pursuits.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Imagine, if you will, a bird in flight. When it must overcome the gusts that hinder its path, it beats its wings with unyielding force. Yet, when it soars high in the sky, it spreads its wings and rides the wind, at peace in its journey. This is the model of focus we must aspire to: resolute in the face of opposition, tranquil in the embrace of flow.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Just as the sun is forever pursued by shadows, so too is our purpose chased by an unending flurry of distractions. They are the specters of our existence, conjured by the ceaseless clatter of the world, whispering tales of urgency and importance that often bear no relevance to our true path.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Stoicism, like a seasoned sculptor, fashions the raw marble of our attention into a well-honed pillar of focus. The true currency of our existence is not time, but attention. The past and the future are but shadows and specters that have no claim over the vivacious vitality of the present moment. Stoicism implores us to dispense our attention wisely, not on the ephemeral apparitions of past regrets or future anxieties, but on the solid ground of the present.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "The act of focusing is not simply the mental equivalent of gazing intently at an object. It is a confluence, a harmonious marriage of mind, heart, and will, an alignment akin to a troupe of actors on a stage, each playing their part, but all moving in harmony towards the climax of the play. This is the essence of true focus.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "The Stoic approach is the lighthouse that guides us amidst the tempest, leading us to the land of dreams crafted in the forge of the unyielding present.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "The world might rage around, yet within the Stoic's mind, a tranquil sea prevails. The Stoic remains anchored, not carried away by the torrents of distraction, but rather cultivating a steadfast presence in each fleeting moment. In this ever-passing instant, the Stoic exercises his virtue, sharpens his wisdom, and wields his actions.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "True focus is the ability to summon our mental strength when it is required and to let it rest when it is not.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "True focus requires wisdom in choosing the worthy target, courage in maintaining a resolute mind, and prudence in knowing when to exert effort and when to seek rest. Master these elements, and you begin to understand the nature of focus.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "Yet the object of our focus is not to be chosen lightly. In the marketplace of ambitions, dreams are sold in all sizes and shapes. But true fulfillment and achievement do not lie in the mere attainment of goals, but rather in the pursuit of those that are truly worthy. A target, after all, gives direction to our arrow, but the archer's glory lies not in merely hitting the target, but in striking one that demands skill and character.", book = "The Power of the Present: A Stoic's Guide to Unyielding Focus", author = "Kevin L. Michel" },
    { text = "How does a person deal with all the heartache and tragedy that fills their life without becoming insane or committing suicide?", book = "", author = "Kilroy J Oldster" },
    { text = "Each of us is impermanent wave of energy folded into the infinite cosmic order. Acknowledgement of the fundamental impermanence of ourselves unchains us from the strictures of living a terrestrial life stuck like a needle vacillating between the magnetic pull of endless desire and the terror of death. Once we achieve freedom from any craving and all desires and we are relieved of all titanic fears, we release ourselves from living in perpetual distress. Once we rid ourselves from any impulse to exist, we discover our true place in the universal order. The composition of our life filament is exactly right when we accept the notion of living and dying with equal stoicism.", book = "Dead Toad Scrolls", author = "Kilroy J. Oldster" },
    { text = "Life is neither a glorious highlight reel nor a monstrous tragedy. Every day is a good day to live and a good day to die. Every day is also an apt time to learn and express joy and love for the entire natural world. Each day is an apt time to make contact with other people and express empathy for the entire world. Each day is perfect to accept with indifference all aspects of being.", book = "Dead Toad Scrolls", author = "Kilroy J. Oldster" },
    { text = "Rejection of desire is liberating. Renunciation is a form of power.", book = "Dead Toad Scrolls", author = "Kilroy J. Oldster" },
    { text = "Whereas a belief in an absurd world arises out of the fundamental disharmony of a person searching for meaning in an apparently meaninglessness universe, an existential nihilist displays impassive intellectual stoicism towards their eventual mortality while embracing a passionate artistic commitment to munity against the underlying syndrome of insignificance and confusion encasing life.", book = "Dead Toad Scrolls", author = "Kilroy J. Oldster" },
    { text = "My boyfriends have all been as stoical as queen's guards. They'd been patient, committed, and dispassionate, and I'd had to really debase myself to extract any emotion, either grin or grimace, from them.", book = "Fury: A Memoir", author = "Koren Zailckas" },
    { text = "Externals are nothing to a stoic. The falsehoods and artificial limitations of human society are nothing to proponents of the theater principle", book = "", author = "Lashon Byrd" },
    { text = "Zeno is our friend but truth is an even greater friend.", book = "stoicism", author = "Latin saying" },
    { text = "Eternal Spirit of the chainless Mind! Brightest in dungeons, Liberty! thou art, For there thy habitation is the heart ”", book = "", author = "Lord Byron" },
    { text = "There will never come a time when I will be able to resist my emotions.", book = "Tales of Burning Love", author = "Louise Erdrich" },
    { text = "There was no sign of Plato, and I was told later that he had gone to live in his  Republic , where he was cheerfully submitting to his own  Laws . [...] None of the Stoics were present. Rumour had it that they were still clambering up the steep hill of Virtue [...]. As for the Sceptics, it appeared that they were extremely anxious to get there, but still could not quite make up their minds whether or not the island really existed.", book = "Satirical Sketches", author = "Lucian of Samosata" },
    { text = "Sometimes we have no luxury of choice. We must do certain things for survival. That should not stop us from doing the things we love.", book = "", author = "Malebo Sephodi" },
    { text = "A better wrestler. But not a better citizen, a better person, a better resource in tight places, a better forgiver of faults.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A good man does not spy around for the black spots in others, but presses unswervingly on towards his mark.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A key point to bear in mind: The value of attentiveness varies in proportion to its object. You’re better off not giving the small things more time than they deserve.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A limit of time is fixed for thee, which if thou dost not use for clearing away the clouds from thy mind, it will go and thou wilt go, and it will never return.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A little flesh, a little breath, and a Reason to rule all – that is myself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A little wisp of soul carrying a corpse.”—Epictetus.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A man cannot lose a thing if he has it not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A man must stand erect, not be kept erect by others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A man when he has done a good act, does not call out for others to come and see, but he goes on to another act, as a vine goes on to produce again the grapes in season.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A man’s worth is no greater than the worth of his ambitions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A Man's life is dyed the color of his imagination.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A noble man compares and estimates himself by an idea which is higher than himself; and a mean man, by one lower than himself. The one produces aspiration; the other ambition, which is the way in which a vulgar man aspires.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A person who doesn’t know what the universe is, doesn’t know where they are. A person who doesn’t know their purpose in life doesn’t know who they are or what the universe is. A person who doesn’t know any one of these things doesn’t know why they are here. So what to make of people who seek or avoid the praise of those who have no knowledge of where or who they are?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A person’s worth is measured by the worth of what he values.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A philosopher without clothes and one without books. “I have nothing to eat,” says he, as he stands there half-naked, “but I subsist on the logos.” And with nothing to read, I subsist on it too.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A poor soul burdened with a corpse,' Epictetus calls you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A prudent governor will not roughly oppose even the superstitions of his people; and though he may wish that they were wiser, he will know that he cannot make them so by offending their prejudices.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A ripe mature man, a perfect sound man; one that could not endure to be flattered; able to govern both himself and others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A society of equal laws, governed by equality of status and of speech, and of rulers who respect the liberty of their subjects above all else.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A very ridiculous thing it is, that any man should dispense with vice and wickedness in himself, which is in his power to restrain; and should go about to suppress it in others, which is altogether impossible.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "A wrongdoer is often a man who has left something undone, not always one who has done something.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Accept the things to which life binds you, and love the people with whom life brings you together, but do so with all your heart.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Accept whatever comes to you woven in the pattern of your destiny, for what could more aptly fit your needs?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Accustom yourself not to be disregarding of what someone else has to say: as far as possible enter into the mind of the speaker.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Adapt yourself to the life you have been given; and truly love the people with whom destiny has surrounded you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Adapt yourself to the things among which your lot has been cast and love sincerely the fellow creatures with whom destiny has ordained that you shall live.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Add nothing of your own from within, and that's an end of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Alexander the Great and his mule driver both died and the same thing happened to both.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Alexander the Macedonian and his groom by death were brought to the same state; for either they were received among the same seminal principles of the universe, or they were alike dispersed among the atoms.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All is ephemeral, both what remembers and what is remembered.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All men are made one for another: either then teach them better or bear with them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All of us are creatures of a day; the rememberer and the remembered alike.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All that comes to pass is as familiar and well known as the rose in spring, and the grape in summer. Of like fashion are sickness, death, calumny, intrigue, and all that gladdens or saddens the foolish.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All that exists is the seed of what will emerge from it.", book = "Meditations by Marcus Aurelius", author = "Marcus Aurelius" },
    { text = "The other is that all these things, which thou seest, change immediately and will no longer be; and constantly bear in mind how many of these changes thou hast already witnessed. The universe is transformation: life is opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All things fade and quickly turn to myth.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All things fade into the storied past, and in a little while are shrouded in oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All things from eternity are of like forms and come round in a circle.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All things of the body stream away like a river, all things of the mind are dreams and delusion; life is warfare, and a visit to a strange land; the only lasting fame is oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All things soon pass away and become a mere tale, and complete oblivion soon buries them. And I say this of those who have shone in a wondrous way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "All you need are these: certainty of judgment in the present moment; action for the common good in the present moment; and an attitude of gratitude in the present moment for anything that comes your way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Ambition means tying your well-being to what other people say or do. Self-indulgence means tying it to the things that happen to you. Sanity means tying it to your own actions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And as upon thy face and looks, thy mind hath easily power over them to keep them to that which is grave and decent; so let it challenge the same power over the whole body also.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And give up your thirst for books, so that you do not die a grouch, but in true grace and heartfelt gratitude to the god.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And he cares nothing for their praise—men who can’t even meet their own standards.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And he who pursues pleasure will not abstain from injustice, and this is plainly impiety.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And here are two of the most immediately useful thoughts you will dip into. First that things cannot touch the mind: they are external and inert; anxieties can only come from your internal judgement. Second, hat all these things you see will change almost as you look at them, and then will be no more. Constantly bring to mind all that you yourself have already seen changed. The universe is change: life is judgement.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And I observed that he had overcome all passion for boys.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And in the case of superior things like stars, we discover a kind of unity in separation. The higher we rise on the scale of being, the easier it is to discern a connection even among things separated by vast distances.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And indeed he who pursues pleasure as good, and avoids pain as evil, is guilty of impiety.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And not to think of philosophy as your instructor, but as the sponge and egg white that relieve ophthalmia—as a soothing ointment, a warm lotion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And so accept everything that happens, even if it is disagreeable, because it leads to this, to the health of the universe and to the prosperity and felicity of Zeus.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And that might be applied to him which is recorded of Socrates, that he was able both to abstain from, and to enjoy, those things which many are too weak to abstain from, and cannot enjoy without excess.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And those who complain and try to obstruct and thwart things—they help as much as anyone. The world needs them as well.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And thou wilt give thyself relief, if thou doest every act of thy life as if it were the last.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And to be easy and ready to be reconciled, and well pleased again with them that had offended me, as soon as any of them would be content to seek unto me again.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And to behave in a conciliatory way when people who have angered or annoyed us want to make up.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And to have learned how to accept favors from friends without losing your self-respect or appearing ungrateful.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And why is it so hard when things go against you? If it’s imposed by nature, accept it gladly and stop fighting it. And if not, work out what your own nature requires, and aim at that, even if it brings you no glory.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "And why should we feel anger at the world? As if the world would notice.", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Anger and the sorrow it produces are far more harmful than the things which make us angry.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Another does wrong. What is that to me? Let him look to it; he has his own disposition, his own activity. I have now what Universal Nature wills me to have, and I do what my own nature wills me to do.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Another has done me wrong? Let him see to it. He has his own tendencies, and his own affairs. What I have now is what the common nature has willed, and what I endeavor to accomplish now is what my nature wills.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Another useful point to bear in mind: What qualities has nature given us to counter that defect? As an antidote to unkindness it gave us kindness. And other qualities to balance other flaws.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Anything in any way beautiful derives its beauty from itself and asks nothing beyond itself. Praise is no part of it, for nothing is made worse or better by praise.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Anywhere you can lead your life, you can lead a good one.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Are you angry when someone’s armpits stink or when their breath is bad? What would be the point? Having such a mouth and such armpits, there’s going to be a smell emanating. You say, they must have sense, can’t they tell how they are offending others? Well, you have sense too, congratulations! So, use your natural reason to awaken theirs, show them, call it out. If the person will listen, you will have cured them without useless anger. No drama nor unseemly show required.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Art thou angry with him whose armpits stink? Art thou angry with him whose mouth smells foul?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "As far as you can, get into the habit of asking yourself in relation to any action taken by another:  What is his point of reference here?  But begin with yourself: examine yourself first.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "As for thy thirst after books, away with it with all speed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "As Plato said, every soul is deprived of truth against its will. The same holds true for justice, self-control, goodwill to others, and every similar virtue. It’s essential to constantly keep this in your mind, for it will make you more gentle to all.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "As they that long after figs in winter when they cannot be had; so are they that long after children, before they be granted them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "As you move forward along the path of reason, people will stand in your way. They will never be able to keep you from doing what’s sound, so don’t let them knock out your goodwill for them. Keep a steady watch on both fronts, not only for well-based judgments and actions, but also for gentleness with those who would obstruct our path or create other difficulties. For getting angry is also a weakness, just as much as abandoning the task or surrendering under panic. For doing either is an equal desertion—the one by shrinking back and the other by estrangement from family and friend.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Asia and Europe are corners in the Universe; every sea, a drop in the Universe; Mount Athos, a clod of earth in the Universe; every instant of time, a pin-prick of eternity. All things are petty, easily changed, vanishing away. All things come from that other world, starting from that common governing principle, or else are secondary consequences of it.", book = "MEDITATIONS", author = "Marcus Aurelius" },
    { text = "Ask yourself at every moment, 'Is this necessary?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "At best suffer patiently, if thou canst not suffer joyously.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "At dawn, when you have trouble getting out of bed, tell yourself, I have to go to work - as a human being. What do I have to complain of, if I'm going to do what I was born for - the things I was brought into the world to do? Or is this what I was created for? To huddle under the blankets and stay warm?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "At every moment keep a sturdy mind on the task at hand, as a Roman and human being, doing it with strict and simple dignity, affection, freedom, and justice—giving yourself a break from all other considerations. You can do this if you approach each task as if it is your last, giving up every distraction, emotional subversion of reason, and all drama, vanity, and complaint over your fair share. You can see how mastery over a few things makes it possible to live an abundant and devout life—for, if you keep watch over these things, the gods won’t ask for more.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Attend to the matter before you, whether it is an opinion or an act or a word. You suffer this justly: for you choose rather to become good tomorrow than to be good today.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "B.C.)—Stoicism stressed the search for inner peace and ethical certainty despite the apparent chaos of the external world by emulating in one’s personal conduct the underlying orderliness and lawfulness of nature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be cheerful also, and seek not external help nor the tranquility which others give. A man then must stand erect, not be kept erect by others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be content to seem what you really are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be like a headland: the Waves beat against it continuously, but it stands fast and around it the boiling water dies down.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be like the cliff against which the waves continually break; but it stands firm and tames the fury of the water around it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be not either a man of many words, or busy about too many things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be not querulous, be Content with little, be kind, be free; avoid all superfluity, all vain prattling; be magnanimous.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be tolerant with others and strict with yourself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Be your own master, and look at things as a man, as a human being, as a citizen, as a mortal creature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Bear in mind that everything that exists is already fraying at the edges, and in transition, subject to fragmentation and to rot. Or that everything was born to die.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Bear in mind that the measure of a man is the worth of the things he cares about.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Beautiful things of any kind are beautiful in themselves and sufficient to themselves. Praise is extraneous. The object of praise remains what it was—no better and no worse.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Because a thing seems difficult for you, do not think it impossible for anyone to accomplish.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Because most of what we say and do is not essential. If you can eliminate it, you’ll have more time, and more tranquillity. Ask yourself at every moment, “Is this necessary?”", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Because your own strength is unequal to the task, do not assume that it is beyond the powers of man; but if anything is within the powers and province of man, believe that it is within your own compass also.  Marcus Aurelius.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Begin each day by telling yourself: Today I shall be meeting with interference, ingratitude, insolence, disloyalty, ill-will, and selfishness – all of them due to the offenders’ ignorance of what is good or evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Begin the morning by saying to thyself, I shall meet with the busybody, the ungrateful, arrogant, deceitful, envious, unsocial. All these things happen to them by reason of their ignorance of what is good and evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Blame and praise have no true effects.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Both Alexander the Great and his mule-keeper were both brought to the same place by death—they were either received into the all-generative reason, or scattered among the atoms.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "But by all means bear this in mind, that within a very short time both thou and he will be dead; and soon not even your names will be left behind.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "But cast away the thirst after books, that thou mayest not die murmuring, but cheerfully, truly, and from thy heart thankful to the gods.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "But death and life, honor and dishonor, pain and pleasure—all these things equally happen to good men and bad, being things which make us neither better nor worse. Therefore they are neither good nor evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "But death and life, success and failure, pain and pleasure, wealth and poverty, all these happen to good and bad alike, and they are neither noble or shameful—and hence neither good nor bad.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "But death certainly, and life, honour and dishonour, pain and pleasure, all these things equally happen to good men and bad, being things which make us neither better nor worse. Therefore they are neither good nor evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Things?—I was once a fortunate man, but I lost it, I know not how.—But fortunate means that a man has assigned to himself a good fortune: and a good fortune is good disposition of the soul, good emotions, good actions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I was once a fortunate man but at some point fortune abandoned me.  But true good fortune is what you make for yourself. Good fortune: good character, good intentions, and good actions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Call to mind the whole of Substance of which you have a very small portion, and the whole of time whereof a small hair's breadth has been determined for you, and of the chain of causation whereof you are how small a link.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Casting aside other things, hold to the precious few; and besides bear in mind that every man lives only the present, which is an indivisible point, and that all the rest of his life is either past or is uncertain.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Casting therefore all other things aside, keep thyself to these few, and remember withal that no man properly can be said to live more than that which is now present, which is but a moment of time.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Change: nothing inherently bad in the process, nothing inherently good in the result.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Chasing what can’t be done is madness. But the base person is unable to do anything else.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Choose not to be harmed—and you won’t feel harmed. Don’t feel harmed—and you haven’t been.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Clear your mind and get a hold on yourself and, as when awakened from sleep and realizing it was only a bad dream upsetting you, wake up and see that what’s there is just like those dreams.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Conceal a flaw, and the world will imagine the worst.", book = "Meditations: Marcus Aurelius", author = "Marcus Aurelius" },
    { text = "Confine yourself to the present.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Consider how much more pain is brought on us by the anger and vexation caused by such acts than by the acts themselves, at which we are angry and vexed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Consider how quickly all things are dissolved and resolved.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Consider that everything is opinion, and opinion is in thy power. Take away then, when thou choosest, thy opinion, and like a mariner, who has doubled the promontory, thou wilt find calm, everything stable, and a waveless bay.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Consider yourself to be dead, and to have completed your life up to the present time; and now live according to nature the remainder which is allowed you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Continually, and, if possible, in the case of every mental image, consider its nature, realize its emotional content, and judge it rationally.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not act as if thou wert going to live ten thousand years. Death hangs over thee. While thou livest, while it is in thy power, be good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Death is a cessation of the impressions through the senses, and of the pulling of the strings that move the appetites, and of the discursive movements of the thoughts, and of the service to the flesh.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Death is a release from the impressions of the senses, and from desires that make us their puppets, and from the vagaries of the mind, and from the hard service of the flesh.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Death is such as generation is, a mystery of nature; a composition out of the same elements, and a decomposition into the same.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Death smiles at us all, all a man can do is smile back.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Death. The end of sense-perception, of being controlled by our emotions, of mental activity, of enslavement to our bodies.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Dig deep within yourself, for there is a fountain of goodness ever ready to flow if you will keep digging.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Dig deep; the water- goodness- is down there. And as long as you keep digging, it will keep bubbling up.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Dig within. Within is the wellspring of Good; and it is always ready to bubble up, if you just dig.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Disgraceful if, in this life where your body does not fail, your soul should fail you first.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Disgraceful: for the soul to give up when the body is still going strong.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Disturbance comes only from within- from our own perceptions. Everything you see will soon alter and cease to exist", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do away with the opinion I am harmed, and the harm is cast away too. Do away with being harmed, and harm disappears.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do every act of your life as if it were your last.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do every act of your life as though it were the very last act of your life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do external things distract you? Then make time for yourself to learn something worthwhile; stop letting yourself be pulled in all directions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not act as if you had ten thousand years to live ... while you have life in you, while you still can, make yourself good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not be ashamed of help.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not indulge in dreams of having what you have not, but reckon up the chief of the blessings you do possess, and then thankfully remember how you would crave for them if they were not yours.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not let the future disturb you, for you will arrive there, if you arrive, with the same reason you now apply to the present.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not look around to discover other people's ruling principles, but look straight to this, to what nature leads you, both the universal nature through which things happen to you, and your own nature through the acts which must be done by you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not suppose you are hurt, and your complaint ceases; cease your complaint, and you are not hurt.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not think that what is hard for you to master is humanly impossible; and if it is humanly possible, consider it to be within your reach.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do not waste the remainder of thy life in thoughts about others, when thou dost not refer thy thoughts to some object of common utility.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do nothing against thy will, nor contrary to the community, nor without due examination, nor with reluctancy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do now what nature demands of you. Get right to it if that’s in your power. Don’t look around to see if people will know about it. Don’t await the perfection of Plato’s <em>Republic</em>, but be satisfied with even the smallest step forward and regard the outcome as a small thing.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do the things external which fall upon thee distract thee? Give thyself time to learn something new and good, and cease to be whirled around.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do what you will. Even if you tear yourself apart, most people will continue doing the same things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do you have reason? I have. Why then do you not use it? For if reason does its own work, what else could you wish for?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Do, soul, do; abuse and contemn thyself; yet a while and the time for thee to respect thyself, will be at an end.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Does a man offend your pride? Remember he will be dead soon, as will you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Does another do me wrong? Let him look to it. He has his own disposition, his own activity. I now have what the universal nature wills me to have; and I do what my nature now wills me to do.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Does anything genuinely beautiful need supplementing? No more than justice does- or truth, or kindness, or humility. Are any of those improved by being praised? Or damaged by contempt? Is an emerald suddenly flawed if no one admires it?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Does the emerald lose its beauty for lack of admiration? Does gold, or ivory, or purple? A lyre or a dagger, a rosebud or a sapling?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Does the light of a lamp shine and keep its glow until its fuel is spent? Why shouldn’t your truth, justice, and self-control shine until you are extinguished?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t act grudgingly, selfishly, without due diligence, or to be a contrarian. Don’t overdress your thought in fine language. Don’t be a person of too many words and too many deeds.... Be cheerful, not wanting outside help or the relief others might bring. A person needs to stand on their own, not be propped up.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t allow yourself to be heard any longer griping about public life, not even with your own ears!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t be ashamed of needing help. You have a duty to fulfill just like a soldier on the wall of battle. So what if you are injured and can’t climb up without another soldier’s help?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t be bounced around, but submit every impulse to the claims of justice, and protect your clear conviction in every appearance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t behave as if you are destined to live forever. What’s fated hangs over you. As long as you live and while you can, become good now.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t imagine that something is good for you if, in pursuing it, you must break a promise, harm anyone else, lose self-respect, act hypocritically, or hide in shame.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t lament this and don’t get agitated.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t let your reflection on the whole sweep of life crush you. Don’t fill your mind with all the bad things that might still happen. Stay focused on the present situation and ask yourself why it’s so unbearable and can’t be survived.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t look at things the way wrong-doers do. Don’t look at things as wrong-doers want you too, either. Instead, strive to see things in truth, as they really are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t return to philosophy as a task-master, but as patients seek out relief in a treatment of sore eyes, or a dressing for a burn, or from an ointment. Regarding it this way, you’ll obey reason without putting it on display and rest easy in its care.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t set your mind on things you don’t possess as if they were yours, but count the blessings you actually possess and think how much you would desire them if they weren’t already yours. But watch yourself, that you don’t value these things to the point of being troubled if you should lose them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don’t tell yourself anything more than what the initial impressions report. It’s been reported to you that someone is speaking badly about you. This is the report—the report wasn’t that you’ve been harmed. I see that my son is sick—but not that his life is at risk. So always stay within your first impressions, and don’t add to them in your head—this way nothing can happen to you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don't be overheard complaining ... not even to yourself.", book = "Meditations by Marcus Aurelius", author = "Marcus Aurelius" },
    { text = "Don't live as though you were going to live a myriad years. Fate is hanging over your head; while you have life, while you may, become good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Don't waste the rest of your time here worrying about other people- unless it affects the common good. It will keep you from doing anything useful.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Drama, combat, terror, numbness, and subservience—every day these things wipe out your sacred principles, whenever your mind entertains them uncritically or lets them slip in.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Dwell on the beauty of life. Watch the stars, and see yourself running with them. Think constantly on the changes of the elements into each other, for such thoughts wash away the dust of earthly life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Each of us lives only now, in this brief instant. The rest of our life has been lived already, or is impossible to see because it lies in the unknowable future.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Forget everything else. Keep hold of this alone and remember it: Each of us lives only now, this brief instant. The rest has been lived already, or is impossible to see. The span we live is small—small.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Either teach them better if it be in thy power; or if it be not, remember that for this use, to bear with them patiently, was mildness and goodness granted unto thee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Enough of this miserable, whining life. Stop monkeying around! Why are you troubled? What’s new here? What’s so confounding? The one responsible? Take a good look. Or just the matter itself? Then look at that. There’s nothing else to look at. And as far as the gods go, by now you could try being more straightforward and kind. It’s the same, whether you’ve examined these things for a hundred years, or only three.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Enter their minds, and you'll find the judges you're so afraid of—and how judiciously they judge themselves.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Epictetus says we must discover the missing art of assent and pay special attention to the sphere of our impulses—that they are subject to reservation, to the common good, and that they are in proportion to actual worth.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Erase the false impressions from your mind by constantly saying to yourself, I have it in my soul to keep out any evil, desire or any kind of disturbance—instead, seeing the true nature of things, I will give them only their due. Always remember this power that nature gave you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Even chance is not divorced from nature, from the inweaving and and enfolding of things governed by Providence.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Even the least of our activities ought to have some end in view.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Even when the gods stood on the side of righteousness, they were concerned with the act more than with the intent.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Every living organism is fulfilled when it follows the right path for its own nature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Every man is worth   just so much as the things are worth about which he busies himself. .", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Every man's happiness depends from himself, but behold thy life is almost at an end, whiles affording thyself no respect, thou dost make thy happiness to consist in the souls, and conceits of other men.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Every portion of me will be reassigned as another portion of the world, and that in turn transformed into another. Ad infinitum.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything - a horse, a vine - is created for some duty... For what task, then, were you yourself created?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything is banal in experience, fleeting in duration, sordid in content; in all respects the same today as generations now dead and buried have found it to be.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything is interwoven, and the web is holy; none of its parts are unconnected. They are composed harmoniously, and together they compose the world. One world, made up of all things. One divinity, present in them all.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything is only for a day, both that which remembers and that which is remembered.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything lasts for a day, the one who remembers and the remembered.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything of the body is a river. Everything of the soul is dream and vapour. Life is war and the abode of a stranger. The only fame after death is oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything that exists is in a manner the seed of that which will be.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything that happens is either endurable or not. If it’s endurable, then endure it. Stop complaining. If it’s unendurable … then stop complaining. Your destruction will mean its end as well.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything that happens, happens as it should, and if you observe carefully, you will find this to be so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything turns on your assumptions about it, and that’s on you. You can pluck out the hasty judgment at will, and like steering a ship around the point, you will find calm seas, fair weather and a safe port.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything we hear is an opinion, not a fact. Everything we see is a perspective, not the truth.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everything which belongs to the body is a stream, and what belongs to the soul is a dream.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Everywhere, at each moment, you have the option: to accept this event with humility, to treat this person as he should be treated, or to approach this thought with care, so that nothing irrational creeps in.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "External things are not the problem. It’s your assessment of them. Which you can erase right now. If the problem is something in your own character, who’s stopping you from setting your mind straight?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Failure to observe what is in the mind of another has seldom made a man unhappy; but those who do not observe the movements of their own minds must of necessity be unhappy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Failure to read what is happening in another's soul is not easily seen as a cause of unhappiness: but those who fail to attend the motions of their own soul are necessarily unhappy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Fame in a world like this is worthless.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Finally, in every event which leads you to sorrow, remember to use this principle: that this is not a misfortune, but that to bear it like a brave man is good fortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Finally, therefore, remember your retreat into this little domain which is yourself, and above all be not disturbed nor on the rack, but be free and look at things as a man, a human being, a citizen, a creature that must die.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Finally, waiting for death with a cheerful mind, as being nothing else than a dissolution of the elements of which every living being is compounded.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Fire feeds on obstacles.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For a man cannot lose either the past or the future: for what a man has not, how can any one take this from him?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For a man to be proud and high conceited, that he is not proud and high conceited, is of all kind of pride and presumption, the most intolerable.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For all things fade and turn to fable, and quickly too, utter oblivion covers them like sand.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For in those things that properly belong unto the mind, she cannot be hindered by any man.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For it is according to nature, and nothing is evil which is according to nature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For it is in your power to retire into yourself whenever you choose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For outward show is a wonderful perverter of the reason.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For the entire earth is but a point, and the place of your own habitation but a minute corner in it. Remember then to withdraw into the little field of self. Above all, never struggle or strain; but be master of yourself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For the present is the only thing of which a man can be deprived, if it is true that this is the only thing which he has, and that a man cannot lose a thing if he has it not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For the sole thing of which any man can be deprived is the present; since this is all he owns, and nobody can lose what is not his.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For then thou wilt neither blame those who offend involuntarily, nor wilt thou want their approbation, if thou lookest to the sources of their opinions and appetites.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "For we are made for co-operation, like feet, like hands, like eyelids, like the rows of the upper and lower teeth. To act against one another then is contrary to nature; and it is acting against one another to be vexed and to turn away.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Frame your thoughts like this—you are an old person, you won’t let yourself be enslaved by this any longer, no longer pulled like a puppet by every impulse, and you’ll stop complaining about your present fortune or dreading the future.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "From my grandfather Verus I learned good morals and the government of my temper.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "From my Great-grandfather, not to have frequented public schools, and to have had good teachers at home, and to know that on such things a man should spend liberally.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "From my great-grandfather: not to have attended schools for the public; to have had good teachers at home, and to realize that this is the sort of thing on which one should spend lavishly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "From Rusticus... I learned to read carefully and not be satisfied with a rough understanding of the whole, and not to agree too quickly with those who have a lot to say about something.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "From the philosopher Catulus, never to be dismissive of a friend's accusation, even if it seems unreasonable, but to make every effort to restore the relationship to its normal condition.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Give what thou wilt, and take away what thou wilt, saith he that is well taught and truly modest, to Him that gives, and takes away. And it is not out of a stout and peremptory resolution, that he saith it, but in mere love, and humble submission.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Give your heart to the trade you have learnt, and draw refreshment from it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "God give me patience, to reconcile with what I am not able to change Give me strength to change what I can And give me wisdom to distinguish one from another.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He blind, who cannot see with the eyes of his understanding.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He claimed that a man's life should be valued according to the value of the things to which he gave his attention.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He is an abscess on the universe who withdraws and separates himself from the reason of our common nature through being displeased with the things that happen; for the same nature that produces these things has produced you, too.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He is so rich, he has no room to shit.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He may not be profound, he is always sincere.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He never exhibited rudeness, lost control of himself, or turned violent. No one ever saw him sweat. Everything was to be approached logically and with due consideration, in a calm and orderly fashion but decisively, and with no loose ends.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He that knoweth not what the world is, knoweth not where he himself is. And he that knoweth not what the world was made for, cannot possibly know either what are the qualities, or what is the nature of the world.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He that sinneth, sinneth unto himself. He that is unjust, hurts himself, in that he makes himself worse than he was before. Not he only that committeth, but he also that omitteth something, is oftentimes unjust.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He was taught to dress plainly and to live simply, to avoid all softness and luxury.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He who acts unjustly, acts impiously.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He who eats my bread does my will.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He who follows reason in all things is both tranquil and active at the same time, and also cheerful and collected.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He who has seen the present has seen everything, that which happened in the most distant past and that which will happen in the future.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "He who loves fame considers another man’s activity to be his own good; and he who loves pleasure, his own sensations; but he who has understanding, considers his own acts to be his own good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "So here is a rule to remember in future, when anything tempts you to feel bitter: not, ‘This is a misfortune,’ but ‘To bear this worthily is good fortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Here’s a way to think about what the masses regard as being ‘good’ things. If you would first start by setting your mind upon things that are unquestionably good—wisdom, self-control, justice, courage—with this preconception you’ll no longer be able to listen to the popular refrain that there are too many good things to experience in a lifetime.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Hold sacred your capacity for understanding. For in it is all, that our ruling principle won’t allow anything to enter that is either inconsistent with nature or with the constitution of a logical creature. It’s what demands due diligence, care for others, and obedience to God.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Honor and revere the gods, treat human beings as they deserve, be tolerant with others and strict with yourself. Remember, nothing belongs to you but your flesh and blood—and nothing else is under your control.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Hour by hour resolve firmly to do what comes to hand with dignity, and with humanity, independence, and justice. Allow your mind freedom from all other considerations. This you can do, if you will approach each action as though it were your last, dismissing the desire to create an impression, the admiration of self, the discontent with your lot. See how little man needs to master, for his days to flow on in quietness and piety: he has but to observe these few counsels, and the gods will ask nothing more.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How beautifully Plato put it. Whenever you want to talk about people, it’s best to take a bird’s-eye view and see everything all at once—of gatherings, armies, farms, weddings and divorces, births and deaths, noisy courtrooms or silent spaces, every foreign people, holidays, memorials, markets—all blended together and arranged in a pairing of opposites.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How does your ruling reason manage itself? For in that is the key to everything. Whatever else remains, be it in the power of your choice or not, is but a corpse and smoke.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How free from all vanity he carried himself in matter of honour and dignity, (as they are esteemed:) his laboriousness and assiduity, his readiness to hear any man, that had aught to say tending to any common good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How good it is, when you have roast meat or suchlike foods before you, to impress on your mind that this is the dead body of a fish, this the dead body of a bird or pig.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How many of them who came into the world at the same time when I did, are already gone out of it? LII.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How many together with whom I came into the world are already gone out of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How much more harmful are the consequences of anger and grief than the circumstances that aroused them in us!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How much time he gains who does not look to see what his neighbour says or does or thinks, but only at what he does himself, to make it just and holy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How plain does it appear that there is not another condition of life so well suited for philosophising as this in which thou now happenest to be.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How ridiculous and how strange to be surprised at anything which happens in life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How ridiculous not to flee from one's own wickedness, which is possible, yet endeavour to flee from another's, which is not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How rotten and fraudulent when people say they intend to ‘give it to you straight.’ What are you up to, dear friend? It shouldn’t need your announcement, but be readily seen, as if written on your forehead, heard in the ring of your voice, a flash in your eyes—just as the beloved sees it all in the lover’s glance. In short, the straightforward and good person should be like a smelly goat—you know when they are in the room with you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How satisfying it is to dismiss and block out any upsetting or foreign impression, and immediately to have peace in all things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How soon will time cover all things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "How unsound and insincere is he who says, I have determined to deal with thee in a fair way.—What art thou doing, man?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Humans have come into being for the sake of each other, so either teach them, or learn to bear them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Hurry to your own ruling reason, to the reason of the Whole, and to your neighbor’s. To your own mind to make it just; to the mind of the Whole to remember your place in it; and to your neighbor’s mind to learn whether it’s ignorant or of sound knowledge—while recognizing it’s like yours.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I am unhappy, because this has happened to me.” Not so: say, “I am happy, though this has happened to me, because I continue free from pain, neither crushed by the present nor fearing the future.”", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I can control my thoughts as necessary; then how can I be troubled? What is outside my mind means nothing to it. Absorb that lesson and your feet stand firm.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I do my duty: other things trouble me not; for they are either things without life, or things without reason, or things that have rambled and know not the way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I do not regard a man as poor, if the little which remains is enough for him.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I have no right to do myself an injury. Have I ever injured anyone else if I could avoid it?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I have often wondered how it is that every man loves himself more than all the rest of men, but yet sets less value on his own opinion of himself than on the opinion of others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I learned endurance of labour, and to want little, and to work with my own hands, and not to meddle with other people's affairs, and not to be ready to listen to slander.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "I’m constantly amazed by how easily we love ourselves above all others, yet we put more stock in the opinions of others than in our own estimation of self.... How much credence we give to the opinions our peers have of us and how little to our very own!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If all emotions are common coin, then what is unique to the good man? To welcome with affection what is sent by fate. Not to stain or disturb the spirit within him with a mess of false beliefs. Instead, to preserve it faithfully, by calmly obeying God  “ saying nothing untrue, doing nothing unjust. And if the others don't acknowledge it  “ this life lived in simplicity, humility, cheerfulness  “ he doesn't resent them for it, and isn't deterred from following the road where it leads: to the end of life. An end to be approached in purity, in serenity, in acceptance, in peaceful unity with what must be.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If any man is able to convince me and show me that I do not think or act right, I will gladly change; for I seek the truth by which no man was ever injured. But he is injured who abides in his error and ignorance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If any man despises me, that is his problem. My only concern is not doing or saying anything deserving of contempt.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If anyone can prove and show to me that I think and act in error, I will gladly change it—for I seek the truth, by which no one has ever been harmed. The one who is harmed is the one who abides in deceit and ignorance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If anyone can refute me—show me I’m making a mistake or looking at things from the wrong perspective—I’ll gladly change. It’s the truth I’m after, and the truth never harmed anyone. What harms us is to persist in self-deceit and ignorance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If anyone can show me, and prove to me, that I am wrong in thought or deed, I will gladly change. I think the truth , which never yet hurt anybody. It is only persistence and self-delusion and ignorance which does harm.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If it doesn't harm your character, how can it harm your life?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If it is not right do not do it; if it is not true do not say it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If our intellectual part is common, the reason also, in respect of which we are rational beings, is common: if this is so, common also is the reason which commands us what to do, and what not to do.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If some one tells you that so and so speaks ill of you, do not defend yourself against what he says, but answer, 'He did not know my other faults, or he would not have mentioned these alone.'", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If someone asks you how to write your name, would you bark out each letter? And if they get angry, would you then return the anger? Wouldn’t you rather gently spell out each letter for them? So then, remember in life that your duties are the sum of individual acts. Pay attention to each of these as you do your duty... just methodically complete your task.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If someone can prove me wrong and show me my mistake in any thought or action, I shall gladly change. I seek the truth, which never harmed anyone: the harm is to persist in one's own self-deception and ignorance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If someone is able to show me that what I think or do is not right, I will happily change, for I seek the truth, by which no one was ever truly harmed. It is the person who continues in his self-deception and ignorance who is harmed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If something is difficult for you to accomplish, do not then think it impossible for any human being; rather, if it is humanly possible and corresponds to human nature, know that it is attainable by you as well.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If then it’s not that the things you pursue or avoid are coming at you, but rather that you in a sense are seeking them out, at least try to keep your judgment of them steady, and they too will remain calm and you won’t be seen chasing after or fleeing from them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If there were anything harmful on the other side of death, they would have made sure that the ability to avoid it was within you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If therefore it be a thing external that causes thy grief, know, that it is not that properly that doth cause it, but thine own conceit and opinion concerning the thing: which thou mayest rid thyself of, when thou wilt.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If they’ve made a mistake, correct them gently and show them where they went wrong. If you can’t do that, then the blame lies with you. Or no one.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If unwilling to rise in the morning, say to thyself, ‘I awake to do the work of a man.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If we judge as good and evil only the things in the power of our own choice, then there is no room left for blaming gods or being hostile to others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If within the power of another, whom do you blame—atoms or gods? To do either is folly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you are distressed about anything, the pain is not due to the thing but to your own estimate of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you are distressed by anything external, the pain is not due to the thing itself, but to your estimate of it; and this you have the power to revoke at any moment.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you care about yourself at all, come to your own aid while there's still time.", book = "Meditations : A New Translation", author = "Marcus Aurelius" },
    { text = "If you find something very difficult to achieve yourself, don’t imagine it impossible—for anything possible and proper for another person can be achieved as easily by you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you suffer distress because of some external cause, it is not the thing itself that troubles you but your judgement about it, and it is within your power to cancel that judgement at any moment.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you work at that which is before you, following right reason seriously, vigorously, calmly, without allowing anything else to distract you, but keeping your divine part pure, as if you should be bound to give it back immediately; if you hold to this, expecting nothing, fearing nothing, but satisfied with your present activity according to nature, and with heroic truth in every word and sound which you utter, you will live happy. And there is no-one who is able to prevent this.", book = "The Meditations of Marcus Aurelius", author = "Marcus Aurelius" },
    { text = "If you’re honest and straightforward and mean well, it should show in your eyes. It should be unmistakable.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "If you’ve seen the present, you’ve seen all things, from time immemorial into all of eternity. For everything that happens is related and the same.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "III. Hippocrates having cured many sicknesses, fell sick himself and died.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In a little while you too will close your eyes, and soon there will be others mourning the man who buries you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In a little while you will have forgotten everything; in a little while everything will have forgotten you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In a sense, people are our proper occupation. Our job is to do them good and put up with them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In an expression of true gratitude, sadness is conspicuous only by its absence.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In everything that you do, pause and ask yourself if death is a dreadful thing because it deprives you of this.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In no great while you will be no one and nowhere, and nothing that you now behold will be in existence, nor will anyone now alive. For it is in the nature of all things to change and alter and perish, so that others may arise in their turn.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In the morning when thou risest unwillingly, let this thought be present - I am rising to the work of a human being. Why then am I dissatisfied if I am going to do the things for which I exist and for which I was brought into the world?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In the ways of Nature there is no evil to be found.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In this infinity then what is the difference between him who lives three days and him who lives three generations? Always.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "In your actions, don’t procrastinate. In your conversations, don’t confuse. In your thoughts, don’t wander. In your soul, don’t be passive or aggressive. In your life, don’t be all about business.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Indeed, if you find anything in human life better than justice, truth, self-control, courage—in short, anything better than the sufficiency of your own mind, which keeps you acting according to the demands of true reason and accepting what fate gives you outside of your own power of choice—I tell you, if you can see anything better than this, turn to it heart and soul and take full advantage of this greater good you’ve found.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Indeed, no one can thwart the purposes of your mind—for they can’t be touched by fire, steel, tyranny, slander, or anything.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Independence and unvarying reliability, and to pay attention to nothing, no matter how fleetingly, except the logos. And to be the same in all circumstances ”intense pain, the loss of a child, chronic illness. And to see clearly, from his example, that a man can show both strength and flexibility. His patience in teaching. And to have seen someone who clearly viewed his expertise and ability as a teacher as the humblest of virtues. And to have learned how to accept favors from friends without losing your self-respect or appearing ungrateful. On Apolonius", book = "Meditation", author = "Marcus Aurelius" },
    { text = "Is an emerald suddenly flawed if no one admires it?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Is any man so foolish as to fear change, to which all things that once were not owe their being? And what is it, that is more pleasing and more familiar to the nature of the universe?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Is this what I was created for? To huddle under the blankets and stay warm?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It can ruin your life only if it ruins your character. Otherwise it cannot harm you—inside or out.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is a ridiculous thing for a man not to fly from his own badness, which is indeed possible, but to fly from other men's badness, which is impossible.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is a shame when the soul is first to give way in this life, and the body does not give way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is crazy to want what is impossible. And impossible for the wicked not to do so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is essential for you to remember that the attention you give to any action should be in due proportion to its worth, for then you won’t tire and give up, if you aren’t busying yourself with lesser things beyond what should be allowed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is high time for thee, to understand that there is somewhat in thee, better and more divine than either thy passions, or thy sensual appetites and affections.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is in our power to have no opinion about a thing and not to be disturbed in our soul; for things themselves have no natural power to form our judgments.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is in your own power to maintain the beauty of your soul, or to be a decent human being.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is in your power to withdraw yourself whenever you desire. Perfect tranquility within consists in the good ordering of the mind, the realm of your own.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is man's peculiar duty to love even those who wrong him.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thou art a little soul bearing about a corpse, as Epictetus used to say. It is no evil for things to undergo change, and no good for things to subsist in consequence of change.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is not death that a man should fear, but rather he should fear never beginning to live.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is not fit that I should give myself pain, for I have never intentionally given pain even to another.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is only this present, a moment of time, that a man lives: all the rest either has been lived or may never be.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is possible to curb your arrogance, to overcome pleasure and pain, to rise above your ambition, and to not be angry with stupid and ungrateful people—yes, even to care for them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is quite possible to be a good man without anyone realizing it.", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "It is ridiculous not to escape from one’s own vices, which is possible, while trying to escape the vices of others, which is impossible.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is royal to do good and to be abused.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is said that if you would have peace of mind, busy yourself with little. But wouldn’t a better saying be do what you must and as required of a rational being created for public life? For this brings not only the peace of mind of doing few things, but the greater peace of doing them well. Since the vast majority of our words and actions are unnecessary, corralling them will create an abundance of leisure and tranquility. As a result, we shouldn’t forget at each moment to ask, is this one of the unnecessary things? But we must corral not only unnecessary actions but unnecessary thoughts, too, so needless acts don’t tag along after them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is within our power not to make a judgement about something, and so not disturb our minds; for nothing in itself possesses the power to form our judgements.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It is, in other words, not objects and events but the interpretations we place on them that are the problem. Our duty is therefore to exercise stringent control over the faculty of perception, with the aim of protecting our mind from error.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It isn't ceasing to live that I'm afraid of but never beginning to live properly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It isn't manly to be enraged. Rather gentleness and civility are more human, therefrom more manly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It loved to happen.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It never ceases to amaze me: we all love ourselves more than other people, but care more about their opinion than our own.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It should be a man's task, says the Imitation, 'to overcome himself, and every day to be stronger than himself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It stares you in the face. No role is so well suited to philosophy as the one you happen to be in right now.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It was for the best. So Nature had no choice but to do it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It was my tutor who dissuaded me from patronizing Green or Blue at the races, or Light or Heavy in the ring.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It’s a disgrace in this life when the soul surrenders first while the body refuses to.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It’s silly to try to escape other people’s faults. They are inescapable. Just try to escape your own.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "It’s the truth I’m after, and the truth never harmed anyone. What harms us is to persist in self-deceit and ignorance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Its a dream, a fearful dream, life is.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Joy for human beings lies in proper human work. And proper human work consists in: acts of kindness to other human beings, disdain for the stirrings of the senses, identifying trustworthy impressions, and contemplating the natural order and all that happens in keeping with it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Just as the nature of rational things has given to each person their rational powers, so it also gives us this power—just as nature turns to its own purpose any obstacle or any opposition, sets its place in the destined order, and co-opts it, so every rational person can convert any obstacle into the raw material for their own purpose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Just as we commonly hear people say the doctor prescribed someone particular riding exercises, or ice baths, or walking without shoes, we should in the same way say that nature prescribed someone to be diseased, or disabled, or to suffer any kind of impairment. In the case of the doctor, prescribed means something ordered to help aid someone’s healing. But in the case of nature, it means that what happens to each of us is ordered to help aid our destiny.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Just as when meat or other foods are set before us we think, this is a dead fish, a dead bird or pig; and also, this fine wine is only the juice of a bunch of grapes, this purple-edged robe just sheep’s wool dyed in a bit of blood from a shellfish; or of sex, that it is only rubbing private parts together followed by a spasmic discharge—in the same way our impressions grab actual events and permeate them, so we see them as they really are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Keep a list before your mind of those who burned with anger and resentment about something, of even the most renowned for success, misfortune, evil deeds, or any special distinction. Then ask yourself, how did that work out? Smoke and dust, the stuff of simple myth trying to be legend...", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Keep this thought handy when you feel a fit of rage coming on—it isn’t manly to be enraged. Rather, gentleness and civility are more human, and therefore manlier. A real man doesn’t give way to anger and discontent, and such a person has strength, courage, and endurance—unlike the angry and complaining. The nearer a man comes to a calm mind, the closer he is to strength.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Keep thyself therefore, truly simple, good, sincere, grave, free from all ostentation, a lover of that which is just, religious, kind, tender-hearted, strong and vigorous to undergo anything that becomes thee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Keeps in mind that all rational things are related, and that to care for all human beings is part of being human.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Kindness is invincible, but only when it’s sincere, with no hypocrisy or faking. For what can even the most malicious person do if you keep showing kindness and, if given the chance, you gently point out where they went wrong—right as they are trying to harm you?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Kingship: to earn a bad reputation by good deeds.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Leave the past behind, let the grand design take care of the future, and instead only rightly guide the present to reverence and justice. Reverence so that you’ll love what you’ve been allotted, for nature brought you both to each other. Justice so that you’ll speak the truth freely and without evasion, and so that you’ll act only as the law and value of things require.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let each thing you would do, say or intend be like that of a dying person.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let it happen, if it wants, to whatever it can happen to. And what’s affected can complain about it if it wants. It doesn’t hurt me unless I interpret its happening as harmful to me. I can choose not to.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let no act be done without a purpose, nor otherwise than according to the perfect principles of art.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let not the future trouble you; for you will come to it, if come you must, bearing with you the same reason which you are using now to meet the present.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let not the general representation unto thyself of the wretchedness of this our mortal life, trouble thee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let nothing be done rashly, and at random, but all things according to the most exact and perfect rules of art.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Let the god that is within you be the champion of the being you are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Life is a pilgrimage and a struggle. All we have of time is a moment the universe is in constant flux our bodies are fragile our senses grasp so little our souls are a mist the future is a fog and fame is fleeting.", book = "stoicism", author = "Marcus Aurelius" },
    { text = "Life is a warfare and a stranger's sojourn, and after-fame is oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Life is neither good or evil, but only a place for good and evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Life is opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Life is short. That’s all there is to say. Get what you can from the present—thoughtfully, justly. Unrestrained moderation.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Like an attachment to a sparrow: we glimpse it and it's gone.", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Live as though today is your last day.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Live every day as if they last.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Live out your life in truth and justice, tolerant of those who are neither true nor just.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look at the past—empire succeeding empire—and from that, extrapolate the future: the same thing. No escape from the rhythm of events. Which is why observing life for forty years is as good as a thousand. Would you really see anything new?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look back over the past, with its changing empires that rose and fell, and you can foresee the future too.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look beneath the surface; let not the several quality of a thing nor its worth escape thee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look in, let not either the proper quality, or the true worth of anything pass thee, before thou hast fully it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look to nothing, not even for a moment except to reason.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look well into thyself; there is a source of strength which will always spring up if thou wilt always look.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Look within. Within is the fountain of good, and it will ever bubble up, if thou wilt ever dig.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Loss is nothing else but change, and change is Nature's delight.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Love that only which happens to thee and is spun with the thread of thy destiny. For what is more suitable? In.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Love the discipline you know, and let it support you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Love the humble art you have learned, and take rest in it. Pass through the remainder of your days as one who whole-heartedly entrusts all possessions to the gods, making yourself neither a tyrant nor a slave to any person.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Make sure you’re not made ‘Emperor,’ avoid that imperial stain. It can happen to you, so keep yourself simple, good, pure, saintly, plain, a friend of justice, god-fearing, gracious, affectionate, and strong for your proper work. Fight to remain the person that philosophy wished to make you. Revere the gods, and look after each other. Life is short—the fruit of this life is a good character and acts for the common good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Manage all your actions, words, and thoughts accordingly, since you may at any moment quit life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Meditate often on the interconnectedness and mutual interdependence of all things in the universe. For in a sense, all things are mutually woven together and therefore have an affinity for each other—for one thing follows after another according to their tension of movement, their sympathetic stirrings, and the unity of all substance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Meditate often on the swiftness with which all that exists and is coming into being is swept by us and carried away. For substance is like a river’s unending flow, its activities continually changing and causes infinitely shifting so that almost nothing at all stands still.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Meditate upon what you ought to be in body and soul when death overtakes you; meditate on the brevity of life, and the measureless gulf of eternity behind it and before, and upon the frailty of everything material.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Men exist for the sake of one another. Teach them then or bear with them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Misfortune nobly born is good fortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Moreover, to endure labour; nor to need many things; when I have anything to do, to do it myself rather than by others; not to meddle with many businesses; and not easily to admit of any slander.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "My city and my country, as I am Antoninus, is Rome; as I am a man, it is the world.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "My mind. What is it? What am I making of it? What am I using it for? Is it empty of thought? Isolated and torn loose from those around it? Melted into flesh and blended with it, so that it shares its urges?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "My reasoned choice is as indifferent to the reasoned choice of my neighbor, as to his breath and body. However much we’ve been made for cooperation, the ruling reason in each of us is master of its own affairs. If this weren’t the case, the evil in someone else could become my harm, and God didn’t mean for someone else to control my misfortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Neither must he use himself to cut off actions only, but thoughts and imaginations also, that are unnecessary for so will unnecessary consequent actions the better be prevented and cut off.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Neither worse then nor better is a thing made by being praised.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never esteem anything as of advantage to you that will make you break your word or lose your self-respect.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never esteem of anything as profitable, which shall ever constrain thee either to break thy faith, or to lose thy modesty; to hate any man, to suspect, to curse, to dissemble, to lust after anything, that requireth the secret of walls or veils.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never let the future disturb you - you will meet it with the same weapons of reason and mind that, today, guard you against the present...", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never let the future disturb you. You will meet it, if you have to, with the same weapons of reason which today arm you against the present.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never shirk the proper dispatch of your duty, no matter if you are freezing or hot, groggy or well-rested, vilified or praised, not even if dying or pressed by other demands. Even dying is one of the important assignments of life and, in this as in all else, make the most of your resources to do well the duty at hand.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never value anything as profitable that compels you to break your promise, to lose your self-respect, to hate any man, to suspect, to curse, to act the hypocrite, to desire anything that needs walls and curtains.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never value the advantages derived from anything involving breach of faith, loss of self-respect, hatred, suspicion, or execration of others, insincerity, or the desire for something which has to be veiled and curtained.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Never wilt your soul, never be just good, simple or unpolished. Manifest more then the body that surrounds yourself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No action in the human context will succeed without reference to the divine, nor vice versa.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No difference between here and there: the city that you live in is the world.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No man is happy who does not think himself so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No matter what anyone says or does, my task is to be good. like gold or emerald or purple repeating to itself,  no matter what anyone says or does, my task is to be emerald, my color undiminished. ", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No more roundabout discussions of what makes a good man. Be one!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No one can lose either the past or the future - how could anyone be deprived of what he does not possess? ... It is only the present moment of which either stands to be deprived: and if this is all he has, he cannot lose what he does not have.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No one loses any other life than the one he now lives, nor does one live any other life than that which he will lose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "No random actions, none not based on underlying principles.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "None of us have much time. And yet you act as if things were eternal—the way you fear and long for them.… Before long, darkness. And whoever buries you mourned in their turn.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nor does he deviate from the way which leads to the end of life, to which a man ought to come pure, tranquil, ready to depart, and without any compulsion perfectly reconciled to his lot.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not just that every day more of our life is used up and less and less of it is left, but this too: if we live longer, can we be sure our mind will still be up to understanding the world ”to the contemplation that aims at divine and human knowledge? If our mind starts to wander, we'll still go on breathing, go on eating, imagining things, feeling urges and so on. But getting the most of ourselves, calculating where our duty lies, analyzing what we hear and see, deciding whether it's time to call it quits ”all the things you need a healthy mind for... all those are gone.", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Not the “not” but the “not yet.”", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to assume it’s impossible because you find it hard. But to recognize that if it’s humanly possible, you can do it too.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to be offended with other men's liberty of speech, and to apply myself unto philosophy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to be overwhelmed by what you imagine, but just do what you can and should.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to know what the world is is to be ignorant of where you are. Not to know why it’s here is to be ignorant of who you are. And what it is. Not to know any of this is to be ignorant of why you’re here.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to live as if you had endless years ahead of you. Death overshadows you. While you’re alive and able—be good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Not to waste time on nonsense. Not to be taken in by conjurors and hoodoo artists with their talk about incantations and exorcism and all the rest of it. Not to be obsessed with quail-fighting or other crazes like that.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing earthly succeeds by ignoring heaven, nothing heavenly by ignoring the earth.", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Nothing happens to any creature beyond it's own natural endurance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing happens to any man which he is not formed by nature to bear.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing has such power to broaden the mind as the ability to investigate systematically and truly all that comes under thy observation in life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing is as encouraging as when virtues are visibly embodied in the people around us, when we’re practically showered with them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing is more scandalous than a man that is proud of his humility.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nothing that goes on in anyone else’s mind can harm you. Nor can the shifts and changes in the world around you. —Then where is harm to be found? In your capacity to see it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Now a man should take away not only unnecessary acts, but also, unnecessary thoughts, for thus superfluous acts will not follow after.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nowhere can man find a quieter or more untroubled retreat than in his own soul.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Nowhere you can go is more peaceful—more free of interruptions—than your own soul.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Objective judgment … Unselfish action … Willing acceptance … of all external events.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Objective judgment, now, at this very moment. Unselfish action, now, at this very moment. Willing acceptance—now, at this very moment—of all external events. That’s all you need.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Obsequious courting of the mob.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Observe always that everything is the result of change, and get used to thinking that there is nothing Nature loves so well as to change existing forms and make new ones like them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Observe the movements of the stars as if you were running their courses with them, and let your mind constantly dwell on the changes of the elements into each other. Such imaginings wash away the filth of life on the ground.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Occupy thyself with few things, says the philosopher, if thou wouldst be tranquil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Of all existing things some are in our power, and others are not in our power.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Of my grandfather Verus I have learned to be gentle and meek, and to refrain from all anger and passion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Often injustice lies in what you aren’t doing, not only in what you are doing.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "On every occasion a man should ask himself, Is this one of the unnecessary things?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "On those mornings you struggle with getting up, keep this thought in mind—I am awakening to the work of a human being. Why then am I annoyed that I am going to do what I’m made for, the very things for which I was put into this world? Or was I made for this, to snuggle under the covers and keep warm? It’s so pleasurable. Were you then made for pleasure? In short, to be coddled or to exert yourself?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "One person, on doing well by others, immediately accounts the expected favor in return. Another is not so quick, but still considers the person a debtor and knows the favor. A third kind of person acts as if not conscious of the deed, rather like a vine producing a cluster of grapes without making further demands, like a horse after its race, or a dog after its walk, or a bee after making its honey. Such a person, having done a good deed, won’t go shouting from rooftops but simply moves on to the next deed just like the vine produces another bunch of grapes in the right season.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Or is it your reputation that’s bothering you? But look at how soon we’re all forgotten. The abyss of endless time that swallows it all. The emptiness of those applauding hands. The people who praise us; how capricious they are, how arbitrary. And the tiny region it takes place. The whole earth a point in space – and most of it uninhabited.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Our actions may be impeded by them, but there can be no impeding our intentions or our dispositions. Because we can accommodate and adapt. The mind adapts and converts to its own purposes the obstacle to our acting.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Our life is a warfare, and a mere pilgrimage.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe is change; our life is what our thoughts make it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Our own worth is measured by what we devote our energy to.  4.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Our rational nature moves freely forward in its impressions when it: 1) accepts nothing false or uncertain; 2) directs its impulses only to acts for the common good; 3) limits its desires and aversions only to what’s in its own power; 4) embraces everything nature assigns it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Our thoughts is what our life make it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Part of the Stoic mindset then was a sort of a cultivated ignorance. Publilius Syrus’s epigram expresses it well: “Always shun that which makes you angry.” Meaning: turn your mind away from the things that provoke it. If you find that discussing politics at the dinner table leads to fighting, why do you keep bringing it up? If your sibling’s life choices bother you, why don’t you stop picking at them and making them your concern? The same goes for so many other sources of aggravation. If someone is slipping up, kindly correct them and point out what they missed. But if you can’t, blame yourself—or no one.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Pass then through this little space of time conformably to nature, and end thy journey in content, just as an olive falls off when it is ripe, blessing nature who produced it, and thanking the tree on which it grew.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Pass through this brief patch of time in harmony with nature, and come to your final resting place gracefully, just as a ripened olive might drop, praising the earth that nourished it and grateful to the tree that gave it growth.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Pay attention to what’s in front of you—the principle, the task, or what’s being portrayed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Pay close attention in conversation to what is being said, and to what follows from any action. In the action, immediately look for the target, in words, listen closely to what’s being signaled.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "People aren’t in awe of your sharp mind? So be it. But you have many other qualities you can’t claim to have been deprived of at birth. Display then those qualities in your own power: honesty, dignity, endurance, chastity, contentment, frugality, kindness, freedom, persistence, avoiding gossip, and magnanimity.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "People out for posthumous fame forget that the Generations To Come will be the same annoying people they know now.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "People seek retreats for themselves in the country, by the sea, or in the mountains. You are very much in the habit of yearning for those same things. But this is entirely the trait of a base person, when you can, at any moment, find such a retreat in yourself. For nowhere can you find a more peaceful and less busy retreat than in your own soul—especially if on close inspection it is filled with ease, which I say is nothing more than being well-ordered. Treat yourself often to this retreat and be renewed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "People who are excited by posthumous fame forget that the people who remember them will soon die too. And those after them in turn. Until their memory, passed from one to another like a candle flame, gutters and goes out.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "People who labor all their lives but have no purpose to direct every thought and impulse toward are wasting their time—even when hard at work.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Perfection of character is this: to live each day as if it were your last, without frenzy, without apathy, without pretence.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Perfection of character: to live your last day, every day, without frenzy, or sloth, or pretense.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Practice even what seems impossible. The left hand is useless at almost everything, for lack of practice. But it guides the reins better than the right. From practice.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Practice even what seems impossible.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Pride is a master of deception: when you think you’re occupied in the weightiest business, that’s when he has you in his spell.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Publilius Syrus reminds us with an epigram, “are easiest to cross at their source.” That’s what Seneca means too. The raging waters and deadly currents of bad habits, ill discipline, chaos, and dysfunction—somewhere they began as no more than just a slight trickle. Somewhere they are a placid lake or pond, even a bubbling underground spring.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Put from you the belief that 'I have been wronged', and with it will go the feeling. Reject your sense of injury, and the injury itself disappears.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Receive without conceit, release without struggle.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Receive without pride, let go without attachment.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Recognize the malice, cunning, and hypocrisy that power produces, and the peculiar ruthlessness often shown by people from “good families.”", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Refrain from all anger and passion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Regain your senses, call yourself back, and once again wake up. Now that you realize that only dreams were troubling you, view this 'reality' as you view your dreams.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Reject your sense of injury, and the injury itself disappears.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember how long thou hast already put off these things, and how often a certain day and hour as it were, having been set unto thee by the gods, thou hast neglected it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember how long you have been putting off these things, and how often you have received an opportunity from the gods, and yet do not use it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember that our efforts are subject to circumstances; you weren’t aiming to do the impossible. —Aiming to do what, then? To try. And you succeeded. What you set out to do is accomplished.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember that to change your mind and to follow someone’s correction are consistent with a free will. For the action is yours alone—to fulfill its purpose in keeping with your impulse and judgment, and yes, with your intelligence.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember this, that very little is needed to make a happy life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember that your ruling reason becomes unconquerable when it rallies and relies on itself, so that it won’t do anything contrary to its own will, even if its position is irrational. How much more unconquerable if its judgments are careful and made rationally? Therefore, the mind freed from passions is an impenetrable fortress—a person has no more secure place of refuge for all time.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember two things: i. that everything has always been the same, and keeps recurring, and it makes no difference whether you see the same things recur in a hundred years or two hundred, or in an infinite period; ii. that the longest-lived and those who will die soonest lose the same thing. The present is all that they can give up, since that is all you have, and what you do not have you cannot lose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember, however, that thou art formed by nature to bear everything, with respect to which it depends on thy own opinion to make it endurable and tolerable, by thinking that it is either thy interest or thy duty to do this.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember, however, that you are formed by nature to bear everything whose tolerability depends on your own opinion to make it so, by thinking that it is in your interest or duty to do so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember, nothing belongs to you but your flesh and blood—and nothing else is under your control.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember: Matter. How tiny your share of it. Time. How brief and fleeting your allotment of it. Fate. How small a role you play in it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Remember: philosophy requires only what your nature already demands. What you’ve been after is something else again—something unnatural.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Retire into thyself. The rational principle which rules has this nature, that it is content with itself when it does what is just, and so secures tranquility.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Robbers, perverts, killers, and tyrants—gather for your inspection their so-called pleasures!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Self reliance, always. And cheerfulness.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Set aside a certain number of days, during which you shall be content with the scantiest and cheapest fare, with coarse and rough dress, saying to yourself the while:  Is this the condition that I feared? ", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Sexual ecstasy is like death. It is one of the secrets of nature’s wisdom.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Show by a cheerful look that you don't need the help or comfort of others. Standing up - not propped up.", book = "The Emperor's Handbook: A New Translation of The Meditations", author = "Marcus Aurelius" },
    { text = "Similarly, man is born for deeds of kindness; and when he has done a kindly action, or otherwise served the common welfare, he has done what he was made for, and has received his quittance.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Since it is possible that thou mayest depart from life this very moment, regulate every act and thought accordingly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Sixth, consider when thou art much vexed or grieved, that man's life is only a moment, and after a short time we are all laid out dead.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "So other people hurt me? That’s their problem. Their character and actions are not mine. What is done to me is ordained by nature, what I do by my own.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "So remember this principle when something threatens to cause you pain: the thing itself was no misfortune at all; to endure it and prevail is great good fortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "So someone’s good at taking down an opponent, but that doesn’t make them more community-minded, or modest, or well-prepared for any circumstance, or more tolerant of the faults of others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "So there are two reasons to embrace what happens. One is that it's happening to you. It was prescribed for you, and it pertains to you. The thread was spun long ago, by the oldest cause of all.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Some things are hurrying into existence, and others are hurrying out of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Soon earth will cover us all. Then in time earth, too, will change; later, what issues from this change will itself in turn incessantly change, and so again will all that then takes its place, even unto the world's end. to let the mind dwell on these swiftly rolling billows of change and transformation is to know a contempt for all things mortal.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Soon you will be dead and none of it will matter", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Soon you will die, and still you aren’t sincere, undisturbed, or free from suspicion that external things can harm you, nor are you gracious to all, knowing that wisdom and acting justly are one and the same.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Soon you'll be ashes or bones. A mere name at most - and even that is just a sound, an echo. The things we want in life are empty, stale, trivial.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Soon, you will have forgotten everything.  Soon, everybody will have forgotten you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Spend not the remnant of thy days in thoughts and fancies concerning other men, when it is not in relation to some common good, when by it thou art hindered from some other better work.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stand up straight, not straightened The Gods give us everything, but not all at once.", book = "Meditations: Marcus Aurelius", author = "Marcus Aurelius" },
    { text = "Though thou shouldst be going to live three thousand years, and as many times ten thousand years, still remember that no man loses any other life than this which he now lives, nor lives any other than this which he now loses.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stoics held that material objects alone existed; but immanent in the material universe was a spiritual force which acted through them, manifesting itself under many forms, as fire, aether, spirit, soul, reason, the ruling principle.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stop allowing your mind to be a slave, to be jerked about by selfish impulses, to kick against fate and the present, and to mistrust the future.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stop wandering about! You aren’t likely to read your own notebooks, or ancient histories, or the anthologies you’ve collected to enjoy in your old age. Get busy with life’s purpose, toss aside empty hopes, get active in your own rescue—if you care for yourself at all—and do it while you can.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stop whatever you’re doing for a moment and ask yourself: Am I afraid of death because I won’t be able to do this anymore?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Strength and honor.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Studying philosophy instills modesty and straightforwardness in your character.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Stupidity is expecting figs in winter, or children in old age.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Such as you are your habitual thoughts, such also will be the character of your mind; for your soul is dyed through the thoughts.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Such behavior! People don’t want to praise their contemporaries whose lives they actually share, but hold great expectations for the praise of future generations—people they haven’t met or ever will! This is akin to being upset that past generations didn’t praise you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Swiftly the remembrance of all things is buried in the gulf of eternity.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Take a good hard look at people’s ruling principle, especially of the wise, what they run away from and what they seek out.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Take away thy opinion, and then there is taken away the complaint, “I have been harmed.” Take away the complaint, “I have been harmed,” and the harm is taken away.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Take full account of what Excellencies you possess, and in gratitude remember how you would hanker after them, if you had them not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Take pleasure in one thing and rest in it, in passing from one social act to another social act, thinking of God.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Take the shortest route, the one that nature planned—to speak and act in the healthiest way. Do that, and be free of pain and stress, free of all calculation and pretension.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That all is as thinking makes it so – and you control your thinking. So remove your judgements whenever you wish and then there is calm - as the sailor rounding the cape finds smooth water and the welcome of a waveless bay.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That cucumber is bitter, so toss it out! There are thorns on the path, then keep away! Enough said. Why ponder the existence of nuisance? Such thinking would make you a laughing-stock to the true student of Nature, just as a carpenter or cobbler would laugh if you pointed out the sawdust and chips on the floors of their shops. Yet while those shopkeepers have dustbins for disposal, Nature has no need of them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That I have such a wife, so obedient.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That kindness is invincible, provided it's sincere- not ironic or an act. What can even the most vicious person do if you keep treating him with kindness and gently set him straight", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That there is but a certain limit of time appointed unto thee, which if thou shalt not make use of to calm and allay the many distempers of thy soul, it will pass away and thou with it, and never after return.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That to expect bad people not to injure others is crazy. It's to ask the impossible. And to let them behave like that to other people but expect them to exempt you is arrogant--the act of a tyrant.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That way you'll see human life for what it is. Smoke. Nothing. Especially when you recall that once things alter they cease to exist through all the endless years to come. Then why such turmoil?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That whenever I felt like helping someone who was short of money, or otherwise in need, I never had to be told that I had no resources to do it with. And that I was never put in that position myself—of having to take something from someone else.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That which has died falls not out of the universe. If it stays here, it also changes here, and is dissolved into its proper parts, which are elements of the universe and of thyself. And these too change, and they murmur not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That which is not good for the bee-hive, cannot be good for the bee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That which is not good for the swarm, neither is it good for the bee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That which is really beautiful has no need of anything; not more than law, not more than truth, not more than benevolence or modesty.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That which isn’t good for the hive, isn’t good for the bee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "That you don’t know for sure it is a mistake. A lot of things are means to some other end. You have to know an awful lot before you can judge other people’s actions with real understanding.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The ambitious supposeth another man's act, praise and applause, to be his own happiness; the voluptuous his own sense and feeling; but he that is wise, his own action.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The art of living is more like wrestling than dancing, because an artful life requires being prepared to meet and withstand sudden and unexpected attacks.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The best kind of revenge is not to become like them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The best revenge is not to be like that.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The best revenge is not to do as they do.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The best revenge is to be unlike him who performed the injury.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The best way to avenge yourself is to not be like that.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The blazing fire makes flames and brightness out of everything thrown into it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The body and its parts are a river, the soul a dream and mist, life is warfare and a journey far from home, lasting reputation is oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The earth, saith the poet, doth often long after the rain. So is the glorious sky often as desirous to fall upon the earth, which argues a mutual kind of love between them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The existence of evil does not harm the world. And an individual act of evil does not harm the victim. Only one person is harmed by it—and he can stop being harmed as soon as he decides to.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The student as boxer, not fencer. The fencer’s weapon is picked up and put down again. The boxer’s is part of him. All he has to do is clench his fist.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The first rule is to keep an untroubled spirit. The second is to look things in the face and know them for what they are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The first thing to do—don’t get worked up. For everything happens according to the nature of all things, and in a short time you’ll be nobody and nowhere, even as the great emperors Hadrian and Augustus are now. The next thing to do—consider carefully the task at hand for what it is, while remembering that your purpose is to be a good human being. Get straight to doing what nature requires of you, and speak as you see most just and fitting—with kindness, modesty, and sincerity.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The freedom to do only what God wants, and accept whatever God sends us.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The gods either have power or they have not. If they have not, why pray to them? If they have, then instead of praying to be granted or spared such-and-such a thing, why not rather pray to be delivered from dreading it, or lusting for it, or grieving over it? Clearly, if they can help a man at all, they can help him in this way. You will say, perhaps, 'But all that is something they have put in my own power.' Then surely it were better to use your power and be a free man, than to hanker like a slave and a beggar for something that is not in your power. Besides, who told you the gods never lend their aid even towards things that do lie in our own power? Begin praying in this way, and you will see. Where another man prays 'Grant that I may possess this woman,' let your own prayer be, 'Grant that I may not lust to possess her.' Where he prays, 'Grant me to be rid of such-and-such a one,' you pray, 'Take from me my desire to be rid of him.' Where he begs, 'Spare me the loss of my precious child,' beg rather to be delivered from the terror of losing him. In short, give your petitions a turn in this direction, and see what comes.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The happiness and unhappiness of the rational, social animal depends not on what he feels but on what he does; just as his virtue and vice consist not in feeling but in doing.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The happiness of those who want to be popular depends on others; the happiness of those who seek pleasure fluctuates with moods outside their control; but the happiness of the wise grows out of their own free acts.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The happiness of your life depends upon the quality of your thoughts.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The highest good of man is consciously to work with God for the common good, and this is the sense in which the Stoic tried to live in accord with nature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The honest and good man ought to be exactly like a man who smells strong, so that the bystander as soon as he comes near him must smell whether he choose or not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The mind adapts and converts to its own purposes the obstacle to our acting. The impediment to action advances action. What stands in the way becomes the way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The man of ambition thinks to find his good in the operations of others; the man of pleasure in his own sensations; but the man of understanding in his own actions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The memory of everything is very soon overwhelmed in time.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The mind is that which is roused and directed by itself. It makes of itself what it chooses. It makes what it chooses of its own experience.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The mind, unconquered by violent passions, is a citadel, for a man has no fortress more impregnable in which to find refuge and remain safe forever.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The nearer a man comes to a calm mind, the closer he is to strength.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The object of life is not to be on the side of the majority, but to escape finding oneself in the ranks of the insane.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The offender needs pity, not wrath; those who must needs be corrected, should be treated with tact and gentleness; and one must be always ready to learn better. 'The best kind of revenge is, not to become like unto them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The perfection of moral character consists in this, in passing every day as the last, and in being neither violently excited nor torpid nor playing the hypocrite.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The person who does wrong, does wrong to themselves. The unjust person is unjust to themselves—making themselves evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The person who follows reason in all things will have both leisure and a readiness to act—they are at once both cheerful and self-composed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The pomps and glories which he despised were all his; what to most men is an ambition or a dream, to him was a round of weary tasks which nothing but the stern sense of duty could carry him through. And he did his work well.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The present is all that they can give up, since that is all you have, and what you do not have, you cannot lose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The present is the same for everyone its loss is the same for everyone and it should be clear that a brief instant is all that is lost. For you can't lose either the past or the future how could you lose what you don't have?", book = "stoicism", author = "Marcus Aurelius" },
    { text = "The present moment is the only thing of which anyone can be deprived, at least if this is the only thing he has and he cannot lose what he has not got.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The pride which is proud of want of pride is the most intolerable of all.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The Roman religion was in fact of the nature of a bargain: men paid certain sacrifices and rites, and the gods granted their favour, irrespective of right or wrong.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The ruler must be a philosopher as well as a king; and he must govern unwillingly, because he loves philosophy better than dominion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The sexual embrace can only be compared with music and with prayer.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The soul becomes dyed with the colours of its thoughts.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The Stoic makes no differentiation between a small act of kindness by a simple person and a great act of virtue from a learned sage. Virtue is virtue, and in both cases the result is happiness for the one who is virtuous.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The Stoics had always approved of participation in public life, and this stand struck a chord with the Roman aristocracy, whose code of values placed a premium on political and military activity.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The sun appears to pour itself down, and indeed its light pours in all direction, but the stream does not run out. This pouring is linear extension: that is why its beams are called rays, because they radiate in extended lines. You can see what a ray is if you observe the sun's light entering a dark room through a narrow opening. It extends in a straight line and impacts, so to speak, on any solid body in its path which blocks passage through the air on the other side: it settles there and does not slip off or fall.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The things ordained for you—teach yourself to be at one with those. And the people who share them with you—treat them with love. With real love.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The things you think about determine the quality of your mind.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The time is at hand when you will have forgotten everything; and the time is at hand when all will have forgotten you. Always reflect that soon you will be no one, and nowhere.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The tranquillity that comes when you stop caring what they say. Or think, or do. Only what you do. (Is this fair? Is this the right thing to do?)  . . .  not to be distracted by their darkness. To run straight for the finish line, unswerving.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe is change. Life is opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe is change; life is your perception of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe is flux, life is opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe is transformation; life is opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The universe, then, is God, of whom the popular gods are manifestations; while legends and myths are allegorical. The soul of man is thus an emanation from the godhead, into whom it will eventually be re-absorbed.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The unjust person acts against the gods. For insofar as the nature of the universe made rational creatures for the sake of each other, with an eye toward mutual benefit based on true value and never for harm, anyone breaking nature’s will obviously acts against the oldest of gods.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The way to peace is to be content with yourself, honor the light of reason within, live in harmony with others, and be grateful to the gods for the universe and your role in it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The whole Universe is change, and life itself is but what you deem it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The world is maintained by change- in the elements and in the things they compose. That should be enough for you treat it as an axiom.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The world is maintained by change—in the elements and in the things they compose.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "This world is mere change, and this life, opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "The world is nothing but change. Our life is only perception.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Then consider the Middle (and later the New) Comedy and what it aimed at—gradually degenerating into mere realism and empty technique.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There is a kind of river of things passing into being and Time is a violent torrent. For no sooner is each seen, than it has been carried away, and another is being carried by, and that, too, will be carried away.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There is a limit to the time assigned to you, and if you don't use it to free yourself it will be gone and will never return.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There is no evil in things changing, just as there is no good in persisting in a new state.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There is no man so blessed that some who stand by his deathbed won't hail the occasion with delight.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There is nothing more shameful than perfidious friendship.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There’s nothing more insufferable than people who boast about their own humility.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "There’s nothing worse than a wolf befriending sheep. Avoid false friendship at all costs. If you are good, straightforward, and well meaning it should show in your eyes and not escape notice.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thereby gain much leisure, and save much trouble, and therefore at every action a man must privately by way of admonition suggest unto himself, What? may not this that now I go about.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "These are the characteristics of the rational soul: self-awareness, self-examination, and self-determination. It reaps its own harvest.... It succeeds in its own purpose...", book = "Meditations", author = "Marcus Aurelius" },
    { text = "They contemn one another, and yet they seek to please one another: and whilest they seek to surpass one another in worldly pomp and greatness, they most debase and prostitute themselves in their better part one to another.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "They despise one another, yet they flatter one another;they sant to get above another and get they bow down to one another.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Things of themselves cannot touch the soul at all. They have no entry to the soul, and cannot turn or move it. The soul alone turns and moves itself, making all externals presented to it cohere with the judgements it thinks worthy of itself.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Things: and the vanity of praise, and the inconstancy.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think by way of example on the times of Vespasian, and you’ll see all these things: marrying, raising children, falling ill, dying, wars, holiday feasts, commerce, farming, flattering, pretending, suspecting, scheming, praying that others die, grumbling over one’s lot, falling in love, amassing fortunes, lusting after office and power. Now that life of theirs is dead and gone... the times of Trajan, again the same...", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think not so much of what you lack as of what you have: but of the things that you have, select the best, and then reflect on how eagerly you would have sought them if you did not have them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of the countless changes in which you yourself have bad a part. The whole universe is change, and life is but what you deem it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of the life you have lived until now as over and, as a dead man, see what’s left as a bonus and live it according to Nature. Love the hand that fate deals you and play it as your own, for what could be more fitting?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of the universal substance, of which thou has a very small portion; and of universal time, of which a short and indivisible interval has been assigned to thee; and of that which is fixed by destiny, and how small a part of it thou art.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of the whole universe of matter and how small your share. Think about the expanse of time and how brief—almost momentary—the part marked for you. Think of the workings of fate and how infinitesimal your role.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of your many years of procrastination; how the gods have repeatedly granted you further periods of grace, of which you have taken no advantage. It is time now to realise the nature of the universe to which you belong, and of that controlling Power whose offspring you are; and to understand that your time has a limit set to it. Use it, then, to advance your enlightenment; or it will be gone, and never in your power again.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think of yourself as dead. You have lived your life. Now take what’s left and live it properly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Think often the connection of all things in the world and their mutual relations, they are arguably intertwined with each other and thus have for each other a mutual friendship, and that under the connection that leads him and the unity of matter.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "This is the mark of perfection of character—to spend each day as if it were your last, without frenzy, laziness, or any pretending.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "This that I am, whatever it be, is mere flesh and a little breath and the ruling Reason.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "This then remains: Remember to retire into this little territory of thy own, and, above all, do not distract or strain thyself, but be free, at look and things as a man, as a human being, as a citizen, as a mortal.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "This thing, what is it in itself, in its own constitution? What is its substance and material?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Those obsessed with glory attach their well-being to the regard of others, those who love pleasure tie it to feelings, but the one with true understanding seeks it only in their own actions.... Think on the character of the people one wishes to please, the possessions one means to gain, and the tactics one employs to such ends. How quickly time erases such things, and how many will yet be wiped away.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thou art an old man; no longer let this be a slave, no longer be pulled by the strings like a puppet to unsocial movements, no longer either be dissatisfied with thy present lot, or shrink from the future.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thou must be like a promontory of the sea, against which though the waves beat continually, yet it both itself stands, and about it are those swelling waves stilled and quieted.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thou wilt cease to be held by pains and pleasures, and to be a slave to the vessel, which is as much inferior as that which serves it is superior: for the one is intelligence and deity; the other is earth and corruption.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Though you break your heart, men will go on as before.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Though you should be going to live three thousand years, and as many times ten thousand years, still remember that no man loses any other life than this which he now lives, nor lives any other than this which he now loses. The longest and shortest are thus brought to the same. For the present is the same to all, though that which perishes is not the same; and so that which is lost appears to be a mere moment. For a man cannot lose either the past or the future, for what a man has not, how can any one take this from him?", book = "Meditations: A New Translation", author = "Marcus Aurelius" },
    { text = "Thus the Stoics arrive at their main thesis. Virtue alone is admirable, virtue is absolutely self-sufficient; the good man needs no help from circumstances, neither sickness nor adversity can harm him; he is a king, a god among men.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Thus thou must use to keep thyself to the first motions and apprehensions of things, as they present themselves outwardly; and add not unto them from within thyself through mere conceit and opinion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Time is a river, a violent current of events, glimpsed once and already carried past us, and another one follows and is gone.", book = "stoicism", author = "Marcus Aurelius" },
    { text = "Time is like a river made up of the events which happen, and a violent stream; for as soon as a thing has been seen, it is carried away, and another comes in its place, and this will be carried away too.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To be like the rock that the waves keep crashing over. It stands unmoved and the raging of the sea falls still around it. It's unfortunate that this has happened. No. It's fortunate that this has happened and I've remained unharmed by it - not shattered by the present or frightened of the future. It could have happened to anyone. But not everyone could have remained unharmed by it. Why treat the one as a misfortune rather than the other as fortunate? Can you really call something a misfortune that doesn't violate human nature? Or do you think something that's not against nature's will can violate it? But you know what its will is. Does what's happened keep you from acting with justice, generosity, self-control, sanity, prudence, honesty, humility, straightforwardness, and all the other qualities that allow a person's nature to fulfil itself? So remember this principle when something threatens to cause you pain: the thing itself was no misfortune at all; to endure it and prevail is great good fortune.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To conclude, always observe how ephemeral and worthless human things are, and what was yesterday a little mucus tomorrow will be a mummy or ashes.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To enter others’ minds and let them enter yours.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To grieve or be angry about or fear what happens to you is to be a fugitive from the law of nature.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To grumble at anything that happens is a rebellion against Nature, in some part of which are bound up the natures of all other things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To how much envy and fraud and hypocrisy the state of a tyrannous king is subject unto, and how they who are commonly called, i.e. nobly born, are in some sort incapable, or void of natural affection.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To live happily is an inward power of the soul.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To love only what happens, what was destined. No greater harmony.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To pass through this brief life as nature demands. To give it up without complaint. Like an olive that ripens and falls. Praising its mother, thanking the tree it grew on.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To pursue the impossible is madness: but it is impossible for evil men not to do things of this sort.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To pursue the unattainable is insanity, yet the thoughtless can never refrain from doing so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To read with diligence; not to rest satisfied with a light and superficial knowledge, nor quickly to assent to things commonly spoken of.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To recover your life is within your power; simply view things again as once you viewed them, for your revival rests in that.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To refrain from imitation is the best revenge.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To say all in a word, everything which belongs to the body is a stream, and what belongs to the soul is a dream and vapour, and life is a warfare and a stranger’s sojourn, and after-fame is oblivion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To stand up straight — not straightened.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To the best of my judgment, when I look at the human character I see no virtue placed there to counter justice. But I see one to counter pleasure: self-control.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To the gods I am indebted for having good grandfathers, good parents, a good sister, good teachers, good associates, good kinsmen and friends, nearly everything good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To the world: Your harmony is mine. Whatever time you choose is the right time. Not late, not early.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To undertake nothing: i. at random or without a purpose; ii. for any reason but the common good.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "To what service is my soul committed? Constantly ask yourself this and thoroughly examine yourself by seeing how you relate to that part called the ruling principle. Whose soul do I have now? Do I have that of a child, a youth... a tyrant, a pet, or a wild animal?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Today I escaped all circumstance, or rather I cast out all circumstance, for it was not outside me, but within my judgements.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Today I escaped from anxiety. Or no, I discarded it, because it was within me, in my own perceptions- not outside.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Today I escaped from the crush of circumstances, or better put, I threw them out, for the crush wasn’t from outside me but in my own assumptions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Today I have got out of all trouble, or rather I have cast out all trouble, for it was not outside, but within and in my opinions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Tranquillity is nothing else than the good ordering of the mind.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Try how the life of the good man suits thee, the life of him who is satisfied with his portion out of the whole, and satisfied with his own just acts and benevolent disposition.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Try praying differently, and see what happens: Instead of asking for ‘a way to sleep with her,’ try asking for ‘a way to stop desiring to sleep with her.’ Instead of ‘a way to get rid of him,’ try asking for ‘a way to not crave his demise.’ Instead of ‘a way to not lose my child,’ try asking for ‘a way to lose my fear of it.’", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Turn it inside out and see what it is like—what it becomes like when old, sick, or prostituting itself. How short-lived the praiser and praised, the one who remembers and the remembered. Remembered in some corner of these parts, and even there not in the same way by all, or even by one. And the whole earth is but a mere speck.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Understand at last that you have something in you more powerful and divine than what causes the bodily passions and pulls you like a mere puppet. What thoughts now occupy my mind? Is it not fear, suspicion, desire, or something like that?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Use thyself even unto those things that thou doest at first despair of. For the left hand we see, which for the most part hieth idle because not used; yet doth it hold the bridle with more strength than the right, because it hath been used unto it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Very little is needed to make a happy life; it is all within yourself in your way of thinking.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Vex not thy spirit at the course of things,they not heed thy vexations.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Wait for it patiently—annihilation or metamorphosis.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Walk the long gallery of the past, of empires and kingdoms succeeding each other without number. And you can also see the future, for surely it will be exactly the same, unable to deviate from the present rhythm. It’s all one whether we’ve experienced forty years or an aeon. What more is there to see?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Waste no more time arguing about what a good man should be. Be one.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Watch the stars in their courses and imagine yourself running alongside them. Think constantly on the changes of the elements into each other, for such thoughts wash away the dust of earthly life.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We are all mere nuggets of incense on the one altar. Some burn down now , some later - there is no difference .", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We are like many pellets of incense falling on the same altar. Some collapse sooner, others later, but it makes no difference.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We are the other of the other.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We have the power to hold no opinion about a thing and to not let it upset our state of mind—for things have no natural power to shape our judgments.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We must make haste, then, not only because we are daily nearer to death, but also because the conception of things and the understanding of them cease first.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We ought to do good to others as simply as a horse runs, or a bee makes honey, or a vine bears grapes season after season without thinking of the grapes it has borne.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We should remember that even Nature's inadvertence has its own charm, its own attractiveness. Take the baking of bread. The loaf splits open here and there, and those very cracks, in one way a failure of the baker's profession, somehow catch the eye and give particular stimulus to our appetite.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We shrink from change; yet is there anything that can come into being without it?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "We were made, Marcus tells us over and over, not for ourselves but for others, and our nature is fundamentally unselfish. In our relationships with others we must work for their collective good, while treating them justly and fairly as individuals.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Were you to live three thousand years, or even a countless multiple of that, keep in mind that no one ever loses a life other than the one they are living, and no one ever lives a life other than the one they are losing. The longest and the shortest life, then, amount to the same, for the present moment lasts the same for all and is all anyone possesses. No one can lose either the past or the future, for how can someone be deprived of what’s not theirs?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What am I but a little flesh, a little breath, and the thinking part that rules the whole?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What am I doing with my soul? Interrogate yourself, to find out what inhabits your so-called mind and what kind of soul you have now. A child’s soul, an adolescent’s, a woman’s? A tyrant’s soul? The soul of a predator—or its prey?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What else did you expect from helping someone out? Isn’t it enough that you’ve done what your nature demands? You want a salary for it too? As if your eyes expected a reward for seeing, or your feet for walking. That’s what they were made for.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What if someone despises me? Let them see to it. But I will see to it that I won’t be found doing or saying anything contemptible. What if someone hates me? Let them see to that. But I will see to it that I’m kind and good-natured to all, and prepared to show even the hater where they went wrong. Not in a critical way, or to show off my patience, but genuinely and usefully.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What is divine deserves our respect because it is good; what is human deserves our affection because it is like us. And our pity too, sometimes, for its inability to tell good from bad- as terrible a blindness as the kind that can't tell white from black.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What is not good for the hive is no good for the bee.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What is this, fundamentally? What is its nature and substance, its reason for being? What is it doing in the world? How long is it here for?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What is your vocation? To be a good person.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What progress, you ask, have I made? I have begun to be a friend to myself.  That was indeed a great benefit; such a person can never be alone. You may be sure that such a man is a friend to all mankind.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What we cannot bear removes us from life; what remains can be borne.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What we do now echoes in eternity.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "What’s left to be prized? This, I think—to limit our action or inaction to only what’s in keeping with the needs of our own preparation... it’s what the exertions of education and teaching are all about—here is the thing to be prized! If you hold this firmly, you’ll stop trying to get yourself all the other things.... If you don’t, you won’t be free, self-sufficient, or liberated from passion, but necessarily full of envy, jealousy, and suspicion for any who have the power to take them, and you’ll plot against those who do have what you prize.... But by having some self-respect for your own mind and prizing it, you will please yourself and be in better harmony with your fellow human beings, and more in tune with the gods—praising everything they have set in order and allotted you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever anyone does or says, for my part I’m bound to the good. In the same way an emerald or gold or purple might always proclaim: ‘whatever anyone does or says, I must be what I am and show my true colors.’", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever anyone does or says, I must be emerald and keep my colour.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever anyone does or says, I must be good; just as if the emerald were always saying this:  Whatever anyone does or says, I must still be emerald, and keep my color. ", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever happens at all happens as it should; you will find this true, if you watch narrowly.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever happens to every man, this is for the interest of the universal.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever happens to you has been waiting to happen since the beginning of time. The twining strands of fate wove both of them together: your own existence and the things that happen to you.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever happens, happens rightly. Watch closely, and you will find this true. In the succession of events there is not mere sequence alone, but an order that is just right, as from the hand of one who dispense to their due.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever happens, happens such as you are either formed by nature able to bear it, or not able to bear it. If such as you are by nature form'd able to bear, bear it and fret not: But if such as you are not naturally able to bear, don't fret; for when it has consum'd you, itself will perish. Remember, however, you are by nature form'd able to bear whatever it is in the power of your own opinion to make supportable or tolerable, according as you conceive it advantageous, or your duty, to do so.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever is in any way beautiful hath its source of beauty in itself, and is complete in itself; praise forms no part of it. So it is none the worse nor the better for being praised.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whatever may happen to you, it was prepared for you from all eternity; and the implication of causes was from eternity spinning the thread of your being, and of that which is incident to it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When faced with people's bad behavior, turn around and ask when you have acted like that. When you saw money as a good, or pleasure, or social position. Your anger will subside as soon as you recognize that they acted under compulsion (what else could they do?)", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When force of circumstance upsets your equanimity, lose no time in recovering your self-control, and do not remain out of tune longer than you can help. Habitual recurrence to the harmony will increase your mastery of it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When forced, as it seems, by circumstances into utter confusion, get a hold of yourself quickly. Don’t be locked out of the rhythm any longer than necessary. You’ll be able to keep the beat if you are constantly returning to it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When it allows its action and impulse to be without a purpose, to be random and disconnected: even the smallest things ought to be directed toward a goal.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When jarred, unavoidably, by circumstance, revert at once to yourself, and don’t lose the rhythm more than you can help. You’ll have a better group of harmony if you keep on going back to it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When men are inhuman, take care not to feel towards them as they do towards other humans.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When someone wrongs you, ask yourself: What made him do it? Once you understand his concept of good and evil, you'll feel sorry for him and cease to either be amazed or angry. If his concept is similar to yours, then you will be bound to forgive him since you would have acted as he did in similar circumstances. But if you do not share his ideas of good and evil, then you should find it even easier to overlook the wrongs of someone who is confused and in a moral muddle.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When the longest- and shortest-lived of us dies their loss is precisely equal. For the sole thing of which any of us can be deprived is the present, since this is all we own, and nobody can lose what is not theirs.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When the object perishes, the pneuma that animated it is reabsorbed into the logos as a whole. This process of destruction and reintegration happens to individual objects at every moment.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you are distressed by an external thing, it’s not the thing itself that troubles you, but only your judgment of it. And you can wipe this out at a moment’s notice.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you are disturbed by events and lose your serenity, quickly return to yourself and don't stay upset longer than the experience lasts; for you'll have more mastery over your inner harmony by continually returning to it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you are offended at any man’s fault, immediately turn to yourself and reflect in what manner you yourself have erred.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you arise in the moring, think of what a precious privelege it is to be alive-- to breathe, to think, to enjoy, to love.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you deal with irrational animals, with things and circumstances, be generous and straightforward. You are rational; they are not.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you first rise in the morning tell yourself: I will encounter busybodies, ingrates, egomaniacs, liars, the jealous and cranks. They are all stricken with these afflictions because they don’t know the difference between good and evil. Because I have understood the beauty of good and the ugliness of evil, I know that these wrong-doers are still akin to me... and that none can do me harm, or implicate me in ugliness—nor can I be angry at my relatives or hate them. For we are made for cooperation.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you have done a good act and another has received it, why do you look for a third thing besides these, as fools do, either to have the reputation of having done a good act or to obtain a return?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you run up against someone else's shamelessness, ask yourself this: Is a world without shamelessness possible? No. Then don't ask the impossible. There have to be shameless people in the world. This is one of them. The same for someone vicious or untrustworthy, or with any other defect. Remembering that the whole world class has to exist will make you more tolerant of its members.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you start to lose your temper, remember: There's nothing manly about rage. It's courtesy and kindness that define a human being- and a man. That's who possesses strength and nerves and guts, not the angry whiners.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you wake up in the morning, tell yourself: The people I deal with today will be meddling, ungrateful, arrogant, dishonest, jealous, and surly. They are like this because they can’t tell good from evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When you’ve done well and another has benefited by it, why like a fool do you look for a third thing on top—credit for the good deed or a favor in return?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "When your sparring partner scratches or head-butts you, you don’t then make a show of it, or protest, or view him with suspicion or as plotting against you. And yet you keep an eye on him, not as an enemy or with suspicion, but with a healthy avoidance. You should act this way with all things in life. We should give a pass to many things with our fellow trainees. For, as I’ve said, it’s possible to avoid without suspicion or hate.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whenever someone has done wrong by you, immediately consider what notion of good or evil they had in doing it. For when you see that, you’ll feel compassion, instead of astonishment or rage. For you may yourself have the same notions of good and evil, or similar ones, in which case you’ll make an allowance for what they’ve done. But if you no longer hold the same notions, you’ll be more readily gracious for their error.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whenever you are about to find fault with someone, ask yourself the following question: What fault of mine most nearly resembles the one I am about to criticize?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whenever you have trouble getting up in the morning, remind yourself that you’ve been made by nature for the purpose of working with others, whereas even unthinking animals share sleeping. And it’s our own natural purpose that is more fitting and more satisfying.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whenever you suffer pain, keep in mind that it’s nothing to be ashamed of and that it can’t degrade your guiding intelligence, nor keep it from acting rationally and for the common good. And in most cases you should be helped by the saying of Epicurus, that pain is never unbearable or unending, so you can remember these limits and not add to them in your imagination. Remember too that many common annoyances are pain in disguise, such as sleepiness, fever and loss of appetite. When they start to get you down, tell yourself you are giving in to pain.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whenever you take offense at someone’s wrongdoing, immediately turn to your own similar failings, such as seeing money as good, or pleasure, or a little fame—whatever form it takes. By thinking on this, you’ll quickly forget your anger, considering also what compels them—for what else could they do? Or, if you are able, remove their compulsion.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Where a man can live, there he can also live well. But he must live in a palace;- well then, he can also live well in a palace.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Where is harm to be found? In your capacity to see it. Stop doing that and everything will be fine.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Where is the harm or surprise in the ignorant behaving as the ignorant do?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Wherein Antoninus recordeth, What and of whom, whether Parents, Friends, or Masters; by their good examples, or good advice and counsel, he had learned.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Wherever a person can live, there one can also live well; life is also in the demands of court, there too one can live well.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Wherever you go, there you are—the same person, with the same patterns of thought.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "While it’s true that someone can impede our actions, they can’t impede our intentions and our attitudes, which have the power of being conditional and adaptable. For the mind adapts and converts any obstacle to its action into a means of achieving it. That which is an impediment to action is turned to advance action. The obstacle on the path becomes the way.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Whoever does wrong, wrongs himself; whoever does injustice, does it to himself, making himself evil.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Why all this guesswork? You can see what needs to be done. If you can see the road, follow it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Why doth a little thing said or done against thee make thee sorry? It is no new thing; it is not the first, nor shall it be the last, if thou live long. At best suffer patiently, if thou canst not suffer joyously.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Will any man despise me? Let him see to it. But I will see to it that I may not be found doing or saying anything that deserves to be despised.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Wilt thou, then, my soul, never be good and simple and one and naked, more manifest than the body which surrounds thee?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "With how little he was satisfied, such as lodging, bed, dress, food, servants.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "With respect to pain, then, and pleasure, or death and life, or honour and dishonour, which the universal nature employs equally, whoever is not equally affected is manifestly acting impiously.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Within ten days you will seem a god to those to whom you are now a beast and an ape, if you will return to your principles and the worship of reason.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Work done with anxiety about results is far inferior to work done without such anxiety, in the calm of self surrender.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Yes, getting your wish would have been so nice. But isn’t that exactly why pleasure trips us up? Instead, see if these things might be even nicer—a great soul, freedom, honesty, kindness, saintliness. For there is nothing so pleasing as wisdom itself, when you consider how sure-footed and effortless the works of understanding and knowledge are.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Yes, keep on degrading yourself, soul. But soon your chance at dignity will be gone. Everyone gets one life. Yours is almost used up, and instead of treating yourself with respect, you have entrusted your own happiness to the souls of others.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Yes, you can—if you do everything as if it were the last thing you were doing in your life, and stop being aimless, stop letting your emotions override what your mind tells you, stop being hypocritical, self-centered, irritable.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You always own the option of having no opinion. There is never any need to get worked up or to trouble your soul about things you can't control. These things are not asking to be judged by you. Leave them alone.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You are a little soul carrying about a corpse, as Epictetus used to say.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You are a spirit, bearing the weight of a dead body, as Epictetus used to say.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You are but an impression, and not at all what you seem to be'.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You aren’t bothered, are you, because you weigh a certain amount and not twice as much? So why get worked up that you’ve been given a certain lifespan and not more? Just as you are satisfied with your normal weight, so you should be with the time you’ve been given.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You can also commit injustice by doing nothing.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You can live here as you expect to live there.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You could enjoy this very moment all the things you are praying to reach by taking the long way around—if you’d stop depriving yourself of them.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You could leave life right now. Let that determine what you do and say and think.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You get what you deserve. Instead of being a good person today, you choose instead to become one tomorrow.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have a mind? —Yes. Well, why not use it? Isn’t that all you want—for it to do its job?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have been formed of three parts—body, breath, and mind. Of these, the first two are yours insofar as they are only in your care. The third alone is truly yours.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have grown beyond supposing such actions to be either good or bad, and therefore it will be so much the easier to be tolerant of another's blindness.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have no assurance that they are doing wrong at all, for the motives of man's actions are not always what they seem. There is generally much to learn before any judgement can be pronounced with certainty on another's doings.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have power over your mind - not outside events. Realize this, and you will find strength. When you arise in the morning, think of what a precious privilege it is to be alive - to breathe, to think, to enjoy, to love.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have power over your mind — not outside events. Realize this, and you will find strength.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have proof in the extent of your wanderings that you never found the art of living anywhere—not in logic, nor in wealth, fame, or in any indulgence. Nowhere. Where is it then? In doing what human nature demands. How is a person to do this? By having principles be the source of desire and action. What principles? Those to do with good and evil, indeed in the belief that there is no good for a human being except what creates justice, self-control, courage and freedom, and nothing evil except what destroys these things.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You have the power to strip away many superfluous troubles located wholly in your judgement, and to possess a large room for yourself embracing in thought the whole cosmos, to consider everlasting time, to think of the rapid change in the parts of each thing, of how short it is from birth until dissolution, and how the void before birth and that after dissolution are equally infinite.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You must build up your life action by action, and be content if each one achieves its goal as far as possible—and no one can keep you from this. But there will be some external obstacle! Perhaps, but no obstacle to acting with justice, self-control, and wisdom. But what if some other area of my action is thwarted? Well, gladly accept the obstacle for what it is and shift your attention to what is given, and another action will immediately take its place, one that better fits the life you are building.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You need to avoid certain things in your train of thought: everything random, everything irrelevant. And certainly everything self-important or malicious. You need to get used to winnowing your thoughts, so that if someone says, What are your thinking about? you can respond at once (and truthfully) that you are thinking this or thinking that.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You say, good fortune used to meet you at every corner. But the fortunate person is the one who gives themselves a good fortune. And good fortunes are a well-tuned soul, good impulses and good actions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You should always look on human life as short and cheap. Yesterday sperm: tomorrow a mummy or ashes.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You shouldn’t give circumstances the power to rouse anger, for they don’t care at all.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You’ll more quickly find an earthly thing kept from the earth than you will a person cut off from other human beings.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You’ve endured countless troubles—all from not letting your ruling reason do the work it was made for—enough already!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "You’ve given aid and they’ve received it. And yet, like an idiot, you keep holding out for more: to be credited with a Good Deed, to be repaid in kind. Why?", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your character is simply the sum of your thoughts over time.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your days are numbered. Use them to throw open the windows of your soul to the sun. If you do not, the sun will soon set, and you with it.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your mind will be like its habitual thoughts; for the soul becomes dyed with the color of its thoughts.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your mind will take the shape of what you frequently hold in thought, for the human spirit is colored by such impressions.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your principles can’t be extinguished unless you snuff out the thoughts that feed them, for it’s continually in your power to reignite new ones.... It’s possible to start living again! See things anew as you once did—that is how to restart life!", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Your principles have life in them. For how can they perish, unless the ideas that correspond to them are extinguished? And it is up to you to be constantly fanning them into new flame.", book = "Meditations", author = "Marcus Aurelius" },
    { text = "Fourteen years without a mother had me believe I could be stoic when I finally met her.", book = "Magic Study", author = "Maria V. Snyder" },
    { text = "Love me for my affection, love me even for my weakness; I am satisfied myself. I prefer my feelings to all the fine sentiments of Seneca or Epictetus.", book = "The Letters of Madame De Sevigne to Her Daughter and Friends", author = "Marie Rabutin-Chantal De Sevigne" },
    { text = "There was a lot of pretense floating around; not just with aunties and all that but with emotions and how people saw you. They had a point. There's a lot to learn from that generation -- the stoic approach. I think it's disgusting how they've been forgotten about in this way. It's the American hippies' fault, they saw an in there, a way of making money out of bad moods. That's all it is most of the time. You can't expect to feel cock-a-hoop every minute of every day. My mam and dad's generation understood this. They were just thankful the bombs had stopped threatening their lives. They just wanted to get on with living.", book = "Renegade: The Lives and Tales of Mark E. Smith", author = "Mark E. Smith" },
    { text = "Imagine smiling after a slap in the face. Then think of doing it twenty-four hours a day.", book = "The Book Thief", author = "Markus Zusak" },
    { text = "A man who won't die for something is not fit to live.", book = "The Autobiography of Martin Luther King, Jr.", author = "Martin Luther King Jr." },
    { text = "As my sufferings mounted I soon realized that there were two ways in which I could respond to my situation -- either to react with bitterness or seek to transform the suffering into a creative force. I decided to follow the latter course.", book = "", author = "Martin Luther King Jr." },
    { text = "But I know, somehow, that only when it is dark enough can you see the stars.", book = "", author = "Martin Luther King Jr." },
    { text = "Darkness cannot drive out darkness: only light can do that. Hate cannot drive out hate: only love can do that.", book = "A Testament of Hope", author = "Martin Luther King Jr." },
    { text = "Everybody can be great...because anybody can serve. You don't have to have a college degree to serve. You don't have to make your subject and verb agree to serve. You only need a heart full of grace. A soul generated by love.", book = "", author = "Martin Luther King Jr." },
    { text = "Faith is taking the first step even when you can't see the whole staircase.", book = "", author = "Martin Luther King Jr." },
    { text = "Forgiveness is not an occasional act, it is a constant attitude.", book = "", author = "Martin Luther King Jr." },
    { text = "I have a dream that my four little children will one day live in a nation where they will not be judged by the color of their skin but by the content of their character.", book = "", author = "Martin Luther King Jr." },
    { text = "I have a dream that one day little black boys and girls will be holding hands with little white boys and girls.", book = "I Have a Dream", author = "Martin Luther King Jr." },
    { text = "I have decided to stick to love...Hate is too great a burden to bear.", book = "A Testament of Hope", author = "Martin Luther King Jr." },
    { text = "If a man is called to be a street sweeper, he should sweep streets even as a Michaelangelo painted, or Beethoven composed music or Shakespeare wrote poetry. He should sweep streets so well that all the hosts of heaven and earth will pause to say, 'Here lived a great street sweeper who did his job well.'", book = "", author = "Martin Luther King Jr." },
    { text = "If you can't fly then run, if you can't run then walk, if you can't walk then crawl, but whatever you do you have to keep moving forward.", book = "", author = "Martin Luther King Jr." },
    { text = "In the end, we will remember not the words of our enemies, but the silence of our friends.", book = "", author = "Martin Luther King Jr." },
    { text = "Injustice anywhere is a threat to justice everywhere.", book = "", author = "Martin Luther King Jr." },
    { text = "Intelligence plus character-that is the goal of true education.", book = "", author = "Martin Luther King Jr." },
    { text = "Let no man pull you so low as to hate him.", book = "A Knock at Midnight", author = "Martin Luther King Jr." },
    { text = "No one really knows why they are alive until they know what they'd die for.", book = "", author = "Martin Luther King Jr." },
    { text = "Nothing in the world is more dangerous than sincere ignorance and conscientious stupidity.", book = "", author = "Martin Luther King Jr." },
    { text = "Now there is a final reason I think that Jesus says, \"Love your enemies.\" It is this: that love has within it a redemptive power. And there is a power there that eventually transforms individuals. Just keep being friendly to that person. Just keep loving them, and they can't stand it too long. Oh, they react in many ways in the beginning. They react with guilt feelings, and sometimes they'll hate you a little more at that transition period, but just keep loving them. And by the power of your love they will break down under the load. That's love, you see. It is redemptive, and this is why Jesus says love. There's something about love that builds up and is creative. There is something about hate that tears down and is destructive. So love your enemies.", book = "A Knock at Midnight", author = "Martin Luther King Jr." },
    { text = "Our lives begin to end the day we become silent about things that matter.", book = "I Have a Dream", author = "Martin Luther King Jr." },
    { text = "Science investigates; religion interprets. Science gives man knowledge, which is power; religion gives man wisdom, which is control. Science deals mainly with facts; religion deals mainly with values. The two are not rivals.", book = "", author = "Martin Luther King Jr." },
    { text = "The ultimate measure of a man is not where he stands in moments of comfort and convenience, but where he stands at times of challenge and controversy.", book = "", author = "Martin Luther King Jr." },
    { text = "There comes a time when one must take a position that is neither safe, nor politic, nor popular, but he must take it because conscience tells him it is right.", book = "A Testament of Hope", author = "Martin Luther King Jr." },
    { text = "There comes a time when silence is betrayal.", book = "", author = "Martin Luther King Jr." },
    { text = "There is some good in the worst of us and some evil in the best of us. When we discover this, we are less prone to hate our enemies.", book = "", author = "Martin Luther King Jr." },
    { text = "Those who are not looking for happiness are the most likely to find it, because those who are searching forget that the surest way to be happy is to seek happiness for others.", book = "", author = "Martin Luther King Jr." },
    { text = "We must accept finite disappointment, but never lose infinite hope.", book = "", author = "Martin Luther King Jr." },
    { text = "We must come to see that the end we seek is a society at peace with itself, a society that can live with its conscience.", book = "", author = "Martin Luther King Jr." },
    { text = "We must live together as brothers or perish together as fools.", book = "", author = "Martin Luther King Jr." },    { text = "Emilio was certainly within his rights not to reveal the sordid details of his childhood even to his friends. Or perhaps especially to his friends, whose good opinion of him, he might feel, would not survive the revelations.", book = "The Sparrow", author = "Mary Doria Russell" },
    { text = "In your conversation, don't dwell at excessive length on your own deeds or adventures. Just because you enjoy recounting your exploits doesn't mean that others derive the same pleasure from hearing about them.", book = "How to Be a Stoic: Using Ancient Philosophy to Live a Modern Life", author = "Massimo Pigliucci" },
    { text = "Running is a form of practiced stoicism. It means teaching your brain and body to be biochemically comfortable in a state of disrepair.", book = "The Terrible and Wonderful Reasons Why I Run Long Distances (Volume 5)", author = "Matthew Inman" },
    { text = "During the Great Depression, the philosophy of grin-and-bear-it became a national coping mechanism.", book = "Leave Me Alone, I'm Reading: Finding and Losing Myself in Books", author = "Maureen Corrigan" },
    { text = "Just as I prepared to stand and bow, a woman appeared with a miniature coffee cup in her hand.  She offered it to me.  As I took it, I noticed two things:  Bugs crawling on the ground and the men approving of me by snapping their fingers. I bowed and took a sip of the coffee and almost fainted. I had a cockroach on my tongue. I looked at the peoples' faces and I could not spit it out. My grandmother would have pushed away the grave's dirt and traveled by willpower to show me her face of abject disappointment. I could not bear that. I opened my throat and drank the cup dry. I counted four cockroaches.", book = "Letter to My Daughter", author = "Maya Angelou" },
    { text = "Don't let the force of an impression when it first hits you knock you off your feet; just say to it, Hold on a moment; let me see who you are and what you represent. Let me put you to the test. - Epictetus", book = "STOICISM: The Simplistic Timeless Stoic Art of Better Living with Ancient Wisdom", author = "Maya Bennett" },
    { text = "People look for retreats for themselves, in the country, by the coast, or in the hills. There is nowhere that a person can find a more peaceful and trouble-free retreat than in his mind. So constantly give yourself this retreat, and renew yourself.", book = "STOICISM: The Simplistic Timeless Stoic Art of Better Living with Ancient Wisdom", author = "Maya Bennett " },
    { text = "That on which you so pride yourself will be your ruin, you who think yourself to be somebody.", book = "stoicism", author = "Menander" },
    { text = "He who fears he shall suffer, already suffers what he fears.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "How many things served us yesterday for articles of faith, which today are fables for us?", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I am afraid that our eyes are bigger than our stomachs, and that we have more curiosity than understanding. We grasp at everything, but catch nothing except wind.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I do not care so much what I am to others as I care what I am to myself.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I find I am much prouder of the victory I obtain over myself, when, in the very ardor of dispute, I make myself submit to my adversary’s force of reason, than I am pleased with the victory I obtain over him through his weakness.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I prefer the company of peasants because they have not been educated sufficiently to reason incorrectly.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I quote others only in order the better to express myself.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "I speak the truth, not so much as I would, but as much as I dare; and I dare a little more as I grow older.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "If I speak of myself in different ways, that is because I look at myself in different ways.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "If there is such a thing as a good marriage, it is because it resembles friendship rather than love.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "If you press me to say why I loved him, I can say no more than because he was he, and I was I.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Learned we may be with another man's learning: we can only be wise with wisdom of our own.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Lend yourself to others, but give yourself to yourself.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Let us give Nature a chance; she knows her business better than we do.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Man is certainly stark mad; he cannot make a worm, and yet he will be making gods by dozens.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "My art and profession is to live.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Nothing fixes a thing so intensely in the memory as the wish to forget it.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Nothing is so firmly believed as that which we least know.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Obsession is the wellspring of genius and madness.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Off I go, rummaging about in books for sayings which please me.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "On the highest throne in the world, we still sit only on our own bottom.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "The greater part of the world's troubles are due to questions of grammar.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "The greatest thing in the world is to know how to belong to oneself.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "There is nothing more notable in Socrates than that he found time, when he was an old man, to learn music and dancing, and thought it time well spent.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "There were many terrible things in my life and most of them never happened.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "To begin depriving death of its greatest advantage over us, let us adopt a way clean contrary to that common one; let us deprive death of its strangeness, let us frequent it, let us get used to it; let us have nothing more often in mind than death... We do not know where death awaits us: so let us wait for it everywhere.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "To compose our character is our duty, not to compose books, and to win, not battles and provinces, but order and tranquility in our conduct. Our great and glorious masterpiece is to live appropriately. All other things, ruling, hoarding, building, are only little appendages and props, at most.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "To forbid us anything is to make us have a mind for it.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "To practice death is to practice freedom. A man who has learned how to die has unlearned how to be a slave.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "When I am attacked by gloomy thoughts, nothing helps me so much as running to my books. They quickly absorb me and banish the clouds from my mind.", book = "The Complete Essays", author = "Michel de Montaigne" },
    { text = "Halleck came from people who regarded a slight change of facial expression as adequate to convey the pain of a severed limb.", book = "Sinner's Cross", author = "Miles Watson" },
    { text = "99.99% of fools deny their foolishness. The rest underestimate it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A better attitude towards life is better than a better life, and leads to a better life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A blind man's thoughts almost never have anything to do with the things he is facing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A book can be read to you, not for you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A child is one of the most common results of the lack or loss of self-control.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A cup with a broken handle can still handle its task.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A desired thing often comes with seeds of at least one desire.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A family member is initially loved out of expectation 'and is eventually loved out of habit.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A fool's plans are entertainment for the wise.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A long life is a curse if you have a short temper.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "A man whose mind has completely left childhood behind would not be surprised if he were to walk in on his wife having sex with her father 'or with his mother.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A millionaire who is a minimalist feels and is a trillion times richer than billionaires who are not minimalists.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A suicide attempt is an act of fighting for one's death.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A thing named, misnamed, unnamed, or renamed is still itself.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A true believer in God prays only to thank, never to ask; and welcomes, with open arms, every single thing that is happening.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A truth is not any less truthful, when it is said by someone who did not discover, or does not understand, it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A truth whispered is not less truthful. And an untruth shouted is not less untruthful.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "A wise answer is even more pleasing when it is a response to a foolish question.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Admitting that their child is, or can be, more educated than them is the closest most parents are willing to get to admitting that their child is, or can be, smarter or wiser than them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Alcohol is the worst thing to mix with anger.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "All too often, a wise or free person is ridiculed, because of ignorance, by fools or slaves.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "An accident is often caused by an attempt to prevent one.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "An action is at least a billion times less difficult to choose than a reaction.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "An apology is usually a disguised request for a key to the cage of guilt or regret.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "An emotion is a mild mental illness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Anxiety is the shadow of what we do not want to lose.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Appreciating what you have is the best cure for wanting what you have not or have lost.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Arrogance gives confidence 'a bad name.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "At any given moment, it is a beautiful day in many parts of the world.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Because of things such as arrogance, alcohol, and promiscuity, some people are each a legend in the unmaking.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Being grateful for the shade of a tree is not nearly as honourable as planting a tree.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Being in a hurry does not slow down time.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Being in a hurry gives us the illusion of doubling the length of every second.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Being patient with a fool requires one not to be one.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Being spiritually asleep has deceived the vast majority of people into thinking that poverty is a poor person's main problem in life. To those who are spiritually awake, poverty is not even a problem.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Capitalism is disgusted by those whose happiness is not a result of buying 'or selling.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Change is not always a bad thing: it sometimes takes the form of progress. And is not always a good thing: it sometimes takes the form of regress.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Complaining about a person is way less annoying when we complain to that person.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Conformity eats away individuality.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Death devours not only those who have been cooked by old age it also feasts on those who are half-cooked and even those who are raw.", book = "The Use and Misuse of Children", author = "Mokokoma Mokhonoana" },
    { text = "Death is freedom from life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Death is the release of an organism from the prison of life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Death would not surprise us as often as it does, if we let go of the misbelief that newborns are less mortal than the elderly.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Destroying the seeds of disappointment requires you to unexpect the expected.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Destroying your mirrors hides your ugliness or facial blemishes from only you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Destroying your mirrors leaves your facial blemishes intact.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Developing the extremely rare attitude of not minding how life is happening is a billion times better than prolonging your life, even if by a trillion years.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Difficulty is the foundation of growth, which is the foundation of greatness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Disappointment is an unwanted ”but invited ”guest.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Education almost always leaves stupidity intact.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Education teaches us how to make a living, not how to live.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Employers pay with their money for what employees have paid for with portions of their lives.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Enlightenment does not mean making the most of bad situations. It means knowing that every situation is neither good nor bad.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Equanimity is often mistaken for depression.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Escaping death is a temporary victory.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Even most of those whose wealth was not inherited or won often lose sleep over losing their wealth.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Even the busiest bee does not move from one flower to another as often as an untamed mind moves from one thought to another.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Even the worst that has ever happened to you could have been worse.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Every goal or desire is a seed of an excuse to be unhappy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Every life is a different path to death.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Every second is a step away from our mothers' wombs towards our own tombs.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Expectation is the only seed of disappointment.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Failing can ultimately be way more rewarding than succeeding.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Feeling sorry for our bodies ought to be the closest we get to feeling sorry for ourselves.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Finding peace of mind usually demands that we lose some things and some people.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Fools act wise, not wisely.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Fools are often unable to do what needs to be done, because they were doing, or are doing, what need not be done at that time 'or at all.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Fools refuse to truly believe that a thing can be both delicious or pleasurable 'and harmful.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "For our happiness or unhappiness, we have only what we think about something or someone to thank or blame.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Freedom of speech does not come with opinions worth listening to.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Funerals greatly exaggerate the pleasantness of being alive, while they prevent us from thinking about the advantages of being dead.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Getting something or someone we want is often a guaranteed way to eventually stop us from wanting it, him, or her.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Giving in to sleep is a great opportunity to practice letting go of life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Growth is often the cause or the result of pain.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Growth is often the parent or the child of pain.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Happiness is an inevitable result of embracing, and unhappiness that of rejecting, what is.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Happiness is sweet; its pursuit, bitter.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Happiness prefers to live inside those who do not have preferences, because it never gets evicted there.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Hating our opponent benefits us. Underestimating them benefits them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Hatred and love are equally enslaving.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Hatred is as powerful an intoxicant as love.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Having problems is not nearly as tormenting as being had by problems.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Having to make a difficult or important decision is sometimes more agonizing than not having a choice.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "He who has more money or possessions than you is not necessarily happier than you, happy more often than you, or happy like you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Heartless' is a label that is all too often wrongly given to someone who is rational by someone who is emotional.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "How was your day?' ought to be 'How did you look at your day?", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Human beings are makers, usually of a mountain out of a molehill.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Hunger is by far the best spice.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "I value my time so much that undressing is the only thing I am willing to do for sex.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "If an adult has just moved as fast as a child, from crying to laughing, then it is either the laughter is fake, or they are being tickled.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Increasing the strength of our minds is the only way to reduce the difficulty of life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Intelligent people question everything. Stupid people answer every question.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is a curse to be childish, but a blessing to be childlike.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is a humbling practice to make a mental note whenever your assumption turns out to be wrong.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is a rare blessing to see things, and to accept people, as they are.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is childish to be surprised by something that you knew exists or is possible.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is doubly foolish to underuse what you have overpaid for.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is foolish to expect a fool to act wisely.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is foolish to give up on yourself. And doubly so to do that before everyone has given up on you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is foolish to waste time in order to save money.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is human to be angry, but childish to be controlled by anger.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is humanly impossible to be unhappy while you are dancing or laughing willingly.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is humbling to realize that what you hate (the most) about someone is actually what they love (the most) about themselves.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is impossible to lose everything and still be alive.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is impossible to separate the art of living from the art of dying, because to be living is to be dying.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is impossible to trip and fall while walking slowly.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is joyful to see someone who is hopeful in a situation that is hopeless.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is our natural and moral duty as consumers of other living things to someday die.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is sometimes foolish to assume that someone is wise, or vice versa.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is the human race, not the world, that desperately needs to be changed.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It is way more pleasurable to master yourself than it is to masturbate.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It takes a great degree of tolerance, and that of humility, to strongly disagree with someone, and not express your disagreement.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It takes courage to speak or react way slower than you think.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It takes patience to nurture patience.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It takes selfishness to stop someone from killing themself.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "It takes, not cowardice, but courage to kill yourself.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "It usually takes maturity in a child, and immaturity in an adult, not to be on speaking terms with someone.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Judgments are the only possible cause of unhappiness and happiness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Killing a person does not lead to nearly as much pain as creating a human being.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Learning how to live would take most people at least three lifetimes.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life cannot, not even for a millisecond, remain exactly how it is.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is a game we are all bound to lose.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is happening neither to nor for but through us.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is how you look at it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is not more kind, or less cruel, towards those who take it seriously.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is the struggle of delaying death.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life is yet to produce someone who is loved by or important to everyone.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life sometimes delays giving us the thing we are forever praying or working hard for, until it has managed to show us that that thing is not that important, or important at all.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life sometimes shows kindheartedness by not handing us the success or fame we want, until we have matured enough to be able to handle it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Life takes from us only lives we were given by it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Like a problem, time is nothing but a shadow of thought.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Like great ecologists, great pessimists make us see the beauty of death.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Like happiness, unhappiness usually springs from a comparison.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Living is the outside of dying.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Love, unless it is for life as a whole, is contaminated by things such as our preferences and memories.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Many millions of people secretly feel caged by employment, marriage, and/or parenthood.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Meditation betters not only the mind but also the brain.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Meditation can make an hour feel slightly longer 'than a sneeze.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Mental suffering is an inferno started, and kept burning, by thinking; and its smoke sometimes leaves one crying.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Mindfulness is the only doorway to the unhurried life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most adult geniuses are more playful than most children.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most adults make adulthood seem like a disease that is caused by a deficiency of playfulness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most of us would eventually lose count if we were to literally count our blessings.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people are like all stomachs: they cannot remain satisfied for a long time.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people celebrate the continuity of their existence so passionately that you would swear they chose to exist.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people frequently waste their life, mostly in front of a screen.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people have given back to life the power to make themselves happy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people usually talk faster than they think.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people want more than they have without having made the most of what they have.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people will leave you with the impression that the main function of our emotions is to cloud our judgement.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people would rather believe something that is not true about something than accept the fact that they do not understand a thing about that thing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Most people would rather have their remarks be misunderstood than be disagreed with.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "No one is too old to live another day, or too young to die today.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Nobody is stopping you from using things such as your ability to read or hear as your definition of 'success' or 'wealth'.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Not complaining is sometimes a show off of tolerance or patience.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Not even once has life or the weather complained about a human being.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Not everything that could have been done should have been done.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Not having expected an event makes it seem way better or worse than it really is.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Once you start learning from your problems, you stop wishing for a life without problems.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "One man's bad day is another man's good night.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "One of the main goals and effects of stoicism is to stop an adult from being a crybaby.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Only those who are stupid mind coming across as stupid.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Optimism is an effort.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our caring about what others think about us is one of the pillars of the economy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our deaths are not obliged to happen in the same order as our births.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our education system would be betraying its master, capitalism, if it taught us to be content with what we have. Or if it told us about the fruits of practicing minimalism.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our efforts do not owe us our desired outcomes.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our inability to imagine the length of the rest of existence magnifies our problems.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our mind can be in heaven while our body is in hell. And vice versa.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Our rationality is a visitor.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Paying someone to do something on our behalf is the closest we can get to buying time.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "People often give us a piece of their mind with the intention to take away our peace of mind.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Pitying a living man for being poor is like envying a dead man for being rich.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Pleasure and pain are often each other's seed.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Pleasure is often felt through the tongue or genitals as an attempt to distract oneself from the pain one is feeling through the heart.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Poverty is greatly exaggerated by sanity.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Praying deceives us into thinking that we are doing something about what we are praying for.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Pretty much all wealthy people who were willing to lose and have lost their health while chasing wealth are now willing to lose their wealth while chasing health.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Saving money, when buying an unnecessary thing, leads to wasting time, when using the thing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Seeing your loved one asleep is a great opportunity to practice seeing them dead.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sex for pleasure is chewing gum for genitals.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Silence is often the wisest reply.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Slavery often masquerades as freedom.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Sleep is often a form of escapism.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Small talk is one of the most common symptoms of small-mindedness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some children's lives begin before the end of their parents' childhood.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some fools have children. Some have children who have children. And some have children who have children who have children.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some of our problems came to us; some, we went to them.", book = "F for Philosopher: A Collection of Funny Yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Some of the best things that have ever happened to us wouldn't have happened to us, if it weren't for some of the worst things that have ever happened to us.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some of the people who we think care that we hate them do not even care that there are people who love them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some of the things we are trying to pray away were caused by some of our answered prayers.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Some of the things we fear exist nowhere but where fear happens.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some of those whose existence you wish could end now do not even know about your existence.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people are a degree of impatience away from wishing a year were only a few weeks long.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people are lucky to no longer be, and some are unlucky to still be, alive.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people avoid thinking deeply in public, only because they are afraid of coming across as suicidal.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people deny the existence of God in order to give themselves credit for their successes. Some accept His existence in order to deny responsibility for their failures.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people get killed by water. Some die from dehydration.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people who have been sentenced for life for crimes they did not commit are usually blissful, whereas many people who can go to any part of planet earth are usually miserable.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some people would be ashamed of driving the cars, or living in the houses, some people are showing off.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some real kings are drama queens.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some sentences take seconds to read, but take minutes, hours, days, weeks, months, or even years to understand.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some solutions are seeds of some problems.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some things are made way more appealing than they are by our lack of them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Some things do not make sense, not in themselves, but to some people.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sometimes silence is a sign, not of not knowing what to say, but of knowing when to say what you know.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sometimes the only thing you can do is accept the fact that there is nothing you can do.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sometimes we are lucky to lose something or someone.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sometimes we want not freedom of choice, but freedom from choice.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sometimes you find yourself so grateful that a prayer of yours was not answered that you pray that it be ignored. Just in case it is on the waiting list of prayers to be answered.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Stoicism is a mild form of pessimism 'sprinkled with optimism.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Suffering adds spice to life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Suffering and happiness are not mutually exclusive.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Sunglasses are all too often used to hide shyness 'or unhappiness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Telling some people not to waste time is a waste of time.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "That we can change the shadow of an object without changing the object (by changing the position of the source of light) reminds us that we can change how we feel about a situation or person by changing only how we look at it or them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "That you are about to bury or have just buried your loved one does not make you and your loved ones immortal for a while.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "That you have just caught success after chasing it for many years does not mean that death will stop chasing you for at least a few seconds.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The ability to utter wise words is not exclusive to the wise.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "The best kind of pleasure comes from the indifference to pain 'and pleasure.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The bigger the family, the bigger the number of corpses it owes life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The curse of mortality is the other side of the coin of the blessing of life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The degree of our happiness is not determined by (what we regard as) the source of our happiness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The fact that our minds are problem-solving machines says a lot about the nature of life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The fact that we are all going to die prevents the vast majority of people from being driven insane by the fact that they are going to die.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The fear of being poor or broke is a blessing, if you are a successful entrepreneur; but is a curse, if you want to be an entrepreneur.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The happiest people are not those who have the most, but those who are the most grateful for what they have.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The mind is inclined to zoom in on your problem, or few problems, to an extend that you cannot see your many blessings.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The most fruitful breaks are often those we are or were forced to take by life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The older you are, and the faster you walk, the crazier you look.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The passage of time is as real as the movement of an animated object.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The person you are mad at for being late could be dead.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The present isn't more capable of causing mental pain than the past or the future.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The present moment is the entirety of reality.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The probability of something not happening does not decrease as we increase the number of times we worry about the possibility of it happening.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The problem with pleasure is that it needs to be intermittent in order to retain its pleasantness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The pursuit of happiness is one of the most common symptoms of intellectual immaturity.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The second best thing to not chasing success is chasing success that was defined by you, not for you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The size of your problem is in your mind.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The thing whose acquisition 'made' you happy need not be stolen, lost, or broken for 'it' to make you unhappy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The triviality of a question does not make a profound answer an impossibility.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The vast majority of people are each a puppet that is forever pulled in this or that direction, or pushed into this or that action, by things such as public opinion and an emotion.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The vast majority of people make complaining seem to be a basic human need.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The weaker the desire to change, the further away from now is the moment from which we plan on changing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The wise remind themselves that 'This too shall pass' even when things are good; the foolish, only when things are bad.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The wise willingly accept the unwillingness of the foolish to accept what is as part of what is.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "The worst that can happen to anyone will happen to everyone.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is a correlation between how foolish a man is and how tolerant he is of people who waste his time.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is a correlation between how hard life seems to us and how easy we expected it to be.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is a correlation between how seriously we take life and how many problems it gives us.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is no correlation between how many people or things, how much money, or how many problems you have 'and how grateful, happy, or peaceful you can be.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is no correlation between the degree to which you are confident that you are right and the chances of you not being wrong.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "There is usually at least one person praying for a situation, or an outcome, that is the exact opposite of the one someone or some people are praying for.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "They who always expect the worst are almost always pleasantly surprised.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Those who died quietly asleep are not less dead than those who were killed awake by bombs.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Time and money are almost always saved to be wasted.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To act wise isn't to act wisely.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To chase pleasure is to be chased by pain.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "To complain about life is to complain about being alive.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To give something or someone your attention is to give it or them a portion of your life.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To live is to owe life to die.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "To make life very pleasurable, expect nothing. To make it even more pleasurable than that, expect nothing 'but the worst.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To plan is to hope 'without feeling passive.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "To some of us, these are the good old days in the making.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "To the wise, peace of mind is the result of being fine with how things are; to the foolish, the result of things being fine.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Unhappiness and the like often inspire us to perform random acts of unkindness.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Unlearning makes learning at least three times longer than necessary.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Unless you are spiritually awakened, being happy requires you to ignore or forget other people's suffering.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Unlike existing, living requires effort.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Usually, that which could have been better could have been worse.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We all die having lived a full life, even those who die while they are being born.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We all have problems. Or rather, everyone has at least one thing that they regard as a problem.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We all too often invite a lie by asking someone how he or she is doing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We almost never teach or learn when arguing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We always have a choice as to, not what we hear, but what we listen to.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We always put ourselves first: the fulfilment of our desire sometimes comes last.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are all capable of laughing at what is meant or expected to make us unhappy or angry.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are all talented at coming up with plausible excuses.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are born old enough to die.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are food even before we are dead.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are forever getting closer to the dreaded moment that will finally confirm that we will not live forever.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are generally pleased the most by compliments that are insincere.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are good to others only because we think that that is, or will be, good for us.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are hurried, not by what is happening, but by what we are desiring.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are more in control of how much we know than we are of how much we have.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We are often blind to the fact that our situation is not as bad as we think, until it gets worse.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We can always choose not what we see but how we look at what we see.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We cannot be too young to die.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We cannot have, but can lose, everything.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We cannot really save time. We can merely avoid wasting it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We do not need to lose people or things to appreciate them.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We do things for others for ourselves.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We each unwittingly contribute, each and every day, to the preventions and to the causes of millions of accidents.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We gain the highest degree of freedom when we lose the desire to live, and gain the second highest degree when we lose the desire to live as long as we possibly can.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We get a taste of death, not when we're asleep, but when we awake.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We get addicted, not to the substance, but to the effect.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We have control over when, how, and where to plant a seed, not over what it will become.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We have never tried to do most of the things we are dead sure we cannot do.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We have, not problems, but negative attitudes towards some situations (towards which some people have or would have positive attitudes).", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We live life passively whenever we are not practicing mindfulness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We lose a significant portion of our lives attending ceremonies for people who have lost theirs.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We love being mentally strong, but we hate situations that allow us to put our mental strength to good use.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We make life even more painful by having expectations and preferences.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We must say nothing, when we have nothing to say.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We need not reply or even listen to people who are talking about ”not to ”us.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We often do not, not because we cannot, but because we think so.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We often mistake assuming or hoping for knowing.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We ought to be thankful not only for what we have but also for what we do not have.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We played the main role in the doing of some things we didn't do, by saying they couldn't or wouldn't be done.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We prefer our way into things such as regret, unhappiness, and anxiety.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We prefer ourselves into unhappiness.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We sometimes learn, not from something, but from not having learned from it.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We subconsciously wish that all of the things we hate but our enemies love were harmful.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "We would rarely waste time if our existence were earned.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "What is happening is life's way of telling us what should be happening.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "What is heard is pushed, but what is read is pulled, into the mind.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "What some people regard as an expression of freedom is actually that of slavery.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "When conversing, some people regularly stop talking, not to listen, but to rest their tongues.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "When you are unhappy, happy people are disgusting.", book = "F for Philosopher: A Collection of Funny Yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "Whenever an animal is overworking, a human is to blame.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Wishing is usually an indirect way of feeling sorry for yourself.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "Within, the only place where it is created, is the very last place most pursuers of happiness are likely to go.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You can be hurt, not by what others think of you, but by what you think of what they think or you think they think of you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You can be too old to live, but not too young to die.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You can look unhappy but feel the opposite. Or vice versa.", book = "P for Pessimism: A Collection of Funny yet Profound Aphorisms", author = "Mokokoma Mokhonoana" },
    { text = "You can wear an expensive watch and still be late.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You cannot attain everlasting peace of mind unless you stop seeing your mind as yourself and start seeing yourself as your mind's guardian.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You cannot be blessed with the ability to be happy without being cursed with the ability to be unhappy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You cannot continue to hate someone without repeatedly wasting, on them, some of your precious time and mental energy.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You cannot love what you have become, yet hate what you have overcome.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You cannot really not care about what others think about you, yet care about whether or not they know that you do not care about what they think about you.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "You have not yet reaped the sweetest fruits of meditation, if you still do not meditate only to meditate.", book = "", author = "Mokokoma Mokhonoana" },
    { text = "As for me, I would choose being sick over living in luxury, for being sick only harms the body, whereas luxury destroys both the body and the soul, causing weakness and incapacity in the body, and lack of control and cowardice in the soul. What’s more, luxury breeds injustice because it also breeds greediness.", book = "Lectures", author = "Musonius Rufus" },
    { text = "Consider what intemperate lovers undergo for the sake of evil desires, and how much exertion others expend for the sake of making profit, and how much suffering those who are pursuing fame endure, and bear in mind that all of these people submit to all kinds of toil and hardship voluntarily. Is it then not monstrous that they for no honorable reward endure such things, while we for the sake of the ideal good - that is not only the avoidance of evil such as wrecks our lives, but also the acquisition of virtue, which we may call the provider of all goods -- are not ready to bear every hardship? And yet would not anyone admit how much better it is, in place of exerting oneself to win someone else's wife, to exert oneself the discipline of one's desires; in place of enduring hardships for the sake of money, the train oneself to want little; instead of giving oneself trouble about getting notoriety; instead of trying to find a way to injure an envied person, to enquire how not to envy anyone; and instead of slaving, as sycophants do, to win false friends, to undergo suffering in order to possess true friends? Since toil and hardship are a necessity for all, both for those who seek better and worse, it is preposterous that those pursuing the better are not much more eager in their efforts than those for whom there is small hope of reward for all their pains. ... It remains for me to say that who is unwilling to exert himself almost always convicts himself as unworthy of good, since all good is gained by toil.", book = "Lectures and Fragments", author = "Musonius Rufus" },
    { text = "For I believe a good king is from the outset and by necessity a philosopher, and the philosopher is from the outset a kingly person.", book = "Lectures", author = "Musonius Rufus" },
    { text = "For philosophy doesn’t consist in outward display, but in taking heed to what is needed and being mindful of it.", book = "Lectures", author = "Musonius Rufus" },
    { text = "From good people you’ll learn good, but if you mingle with the bad you’ll destroy such soul as you had.", book = "Lectures", author = "Musonius Rufus" },
    { text = "Gluttony is nothing other than lack of self-control with respect to food, and human beings prefer food that is pleasant to food that is nutritious.", book = "Musonius Rufus: Lectures and Sayings", author = "Musonius Rufus" },
    { text = "How much better is it to be known for doing well by many than for living extravagantly? How much more worthy than spending on sticks and stones is it to spend on people?", book = "Lectures", author = "Musonius Rufus" },
    { text = "If one accomplishes some good though with toil, the toil passes, but the good remains; if one does something dishonourable with pleasure, the pleasure passes, but the dishonour remains.", book = "That One Should Disdain Hardships: The Teachings of a Roman Stoic", author = "Musonius Rufus" },
    { text = "In order to protect ourselves we must live like doctors and be continually treating ourselves with reason.", book = "stoicism", author = "Musonius Rufus" },
    { text = "Indeed, how could exile be an obstacle to a person’s own cultivation, or to attaining virtue when no one has ever been cut off from learning or practicing what is needed by exile?", book = "Lectures", author = "Musonius Rufus" },
    { text = "So in the majority of other things, we address circumstances not in accordance with the right assumptions, but mostly by following wretched habit. Since all that I’ve said is the case, the person in training must seek to rise above, so as to stop seeking out pleasure and steering away from pain; to stop clinging to living and abhorring death; and in the case of property and money, to stop valuing receiving over giving.", book = "Lectures", author = "Musonius Rufus" },
    { text = "Some people are sharp and others dull; some are raised in a better environment, others in worse, the latter, having inferior habits and nurture, will require more by way of proof and careful instruction to master these teachings and to be formed by them—in the same way that bodies in a bad state must be given a great deal of care when perfect health is sought.", book = "Lectures", author = "Musonius Rufus" },
    { text = "The human being is born with an inclination toward virtue.", book = "Lectures", author = "Musonius Rufus" },
    { text = "We should not use philosophy like a herbal remedy, to be discarded when we're through. Rather, we must allow philosophy to remain with us, continually guarding our judgements throughout life, forming part of our daily regimen, like eating a nutritious diet or taking phisical exercise.", book = "stoicism", author = "Musonius Rufus" },
    { text = "When the problem arose for us whether habit or theory was better for getting virtue—if by theory is meant what teaches us correct conduct, and by habit we mean being accustomed to act according to this theory—Musonius thought habit to be more effective.", book = "Lectures", author = "Musonius Rufus" },
    { text = "And, just as it is harder to have good qualities when one is rich than when one is poor, it is harder to be a Stoic when one is wealthy, powerful, and respected than when one is destitute, miserable, and lonely.", book = "The Black Swan: The Impact of the Highly Improbable", author = "Nassim Nicholas Taleb" },
    { text = "He liked the English and their peculiarities. He liked their stoicism under pressure on the wall in his factory he kept a copy of a war poster emblazoned with the Crown of King George and underneath the words Keep Calm and Carry On.", book = "Mr. Rosenblum Dreams in English", author = "Natasha Solomons" },
    { text = "Do you consider yourself a nobody? What weight does that label even have? It's a silly label. As silly as the label'somebody'. Silly and non-adhesive.  First off, to be thought of as a nobody someone has to be thinking of you in the first place.  Second, being a so-called'nobody' doesn't make you irrelevant. We are all relevant to somebody else but unfortunately, we can lose sight of our most germane and important relationships when we chase the approval of people we don't even know.", book = "Terra Dark", author = "Nate Hamon" },
    { text = "Don't take things too personally. Critique, failures, unwarranted advice - take it to mind, not to heart.  What you hear out of the mouths of others are opinions and perspectives. It's often worth listening to opinions and perspectives, but it's not a requisite that you take them on board.", book = "", author = "Nate Hamon" },
    { text = "Success is not a stamp of approval given by others.", book = "Terra Dark", author = "Nate Hamon" },
    { text = "Take it to mind, not to heart.", book = "Terra Dark", author = "Nate Hamon" },
    { text = "The best way to have people laugh with you and not at you, is to get ahead of them and laugh at yourself first.", book = "", author = "Nate Hamon" },
    { text = "At the crisis of my fever, I besought Hollingsworth to let nobody else enter the room, but continually to make me sensible of his own presence'then he should be the witness how courageously I would encounter the worst. It still impresses me almost a matter of regret, that I did not die then, when I had tolerably made up my mind to do it", book = "The Blithedale Romance", author = "Nathaniel Hawthorne" },
    { text = "If being better is the surest way of feeling better, it must be better than feeling better.", book = "Stoic Stories: A Heroic Account of Stoicism", author = "Neel Burton" },
    { text = "Man is mostly a collection of emotions, most of which he would do better not to be feeling.", book = "", author = "Neel Burton" },
    { text = "We cannot believe in the fundamental goodness of the world until and unless we ourself become that goodness.", book = "", author = "Neel Burton" },
    { text = "When that which we are enjoying is a true good, we feel joy; when it is not, we feel, at best, pleasure.", book = "Stoic Stories: A Heroic Account of Stoicism", author = "Neel Burton" },
    { text = "As we let our own light shine, we unconsciously give other people permission to do the same.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "A good head and good heart are always a formidable combination. But when you add to that a literate tongue or pen, then you have something very special.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "A leader. . .is like a shepherd. He stays behind the flock, letting the most nimble go out ahead, whereupon the others follow, not realizing that all along they are being directed from behind.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "A Nation should not be judged by how it treats its highest citizens, but it's lowest ones", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "A winner is a dreamer who never gives up", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "After climbing a great hill, one only finds that there are many more hills to climb.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Appearances matter — and remember to smile.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "As I have said, the first thing is to be honest with yourself. You can never have an impact on society if you have not changed yourself... Great peacemakers are all people of integrity, of honesty, but humility.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "As I walked out the door toward the gate that would lead to my freedom, I knew if I didn't leave my bitterness and hatred behind, I'd still be in prison.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Do not judge me by my successes, judge me by how many times I fell down and got back up again.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "For to be free is not merely to cast off one's chains, but to live in a way that respects and enhances the freedom of others.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "I am fundamentally an optimist. Whether that comes from nature or nurture, I cannot say. Part of being optimistic is keeping one's head pointed toward the sun, one's feet moving forward. There were many dark moments when my faith in humanity was sorely tested, but I would not and could not give myself up to despair. That way lays defeat and death.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "I am not a saint, unless you think of a saint as a sinner who keeps on trying.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "I am the captain of my soul.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "I have walked that long road to freedom. I have tried not to falter; I have made missteps along the way. But I have discovered the secret that after climbing a great hill, one only finds that there are many more hills to climb. I have taken a moment here to rest, to steal a view of the glorious vista that surrounds me, to look back on the distance I have come. But I can only rest for a moment, for with freedom come responsibilities, and I dare not linger, for my long walk is not ended.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "I learned that courage was not the absence of fear, but the triumph over it. The brave man is not he who does not feel afraid, but he who conquers that fear.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "If you talk to a man in a language he understands, that goes to his head. If you talk to him in his language, that goes to his heart.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "It always seems impossible until it's done.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "It is said that no one truly knows a nation until one has been inside its jails. A nation should not be judged by how it treats its highest citizens, but its lowest ones.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Lead from the back — and let others believe they are in front.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "May your choices reflect your hopes, not your fears.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "No one is born hating another person because of the color of his skin, or his background, or his religion. People must learn to hate, and if they can learn to hate, they can be taught to love, for love comes more naturally to the human heart than its opposite.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "One of the things I learned when I was negotiating was that until I changed myself, I could not change others.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Overcoming poverty is not a task of charity, it is an act of justice. Like Slavery and Apartheid, poverty is not natural. It is man-made and it can be overcome and eradicated by the actions of human beings. Sometimes it falls on a generation to be great. YOU can be that great generation. Let your greatness blossom.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Resentment is like drinking poison and then hoping it will kill your enemies.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "There is no passion to be found playing small - in settling for a life that is less than the one you are capable of living.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "There is nothing like returning to a place that remains unchanged to find the ways in which you yourself have altered.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "When a man is denied the right to live the life he believes in, he has no choice but to become an outlaw.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Where you stand depends on where you sit.", book = "Long Walk to Freedom", author = "Nelson Mandela" },
    { text = "Feeling too much is a hell of a lot better than feeling nothing.", book = "Midnight Bayou", author = "Nora Roberts" },
    { text = "And here lies the essential difference between Stoicism and the modern-day'cult of optimism.' For the Stoics, the ideal state of mind was tranquility, not the excitable cheer that positive thinkers usually seem to mean when they use the word,'happiness.' And tranquility was to be achieved not by strenuously chasing after enjoyable experiences, but by cultivating a kind of calm indifference towards one's circumstances.", book = "The Antidote: Happiness for People Who Can't Stand Positive Thinking", author = "Oliver Burkeman" },
    { text = "Confronting the worst-case scenario saps it of much of its anxiety-inducing power. Happiness reached via positive thinking can be fleeting and brittle, negative visualization generates a vastly more dependable calm.", book = "The Antidote: Happiness for People Who Can't Stand Positive Thinking", author = "Oliver Burkeman" },
    { text = "You will feel pain. You need to accept this truth. ... When it comes, accept it; embrace it. Realize it's a sensation like any other...the same as being hot or cold. Put it to one side and do what must be done. Don't let it overwhelm or control you. Ever.", book = "", author = "Orlando A Sanchez" },
    { text = "Ordinary riches can be stolen from a man. Real riches cannot. In the treasure-house of your soul, there are infinitely precious things that may not be taken from you.", book = "The Soul of Man Under Socialism", author = "Oscar Wilde" },
    { text = "I encouraged them to bear up against all evils, and if we must perish, to die in our own cause, and not weakly distrust the providence of the Almighty, by giving ourselves up to despair. I reasoned with them, and told them that we would not die sooner by keeping up our hopes; that the dreadful sacrifices and privations we endured were to preserve us from death, and were not to be put in competition with the price which we set upon our lives, and their value to our families: it was, besides, unmanly to repine at what neither admitted of alleviation nor cure; and withal, that it was our solemn duty to recognise in our calamities an overruling divinity, by whose mercy we might be suddenly snatched from peril, and to rely upon him alone, 'Who tempers the wind to the shorn lamb?", book = "Wreck of the Whale Ship Essex: The Complete Illustrated Edition: The Extraordinary and Distressing Memoir That Inspired Herman Melville's Moby-Dick", author = "Owen Chase" },
    { text = "Life is a series of problems we must navigate with grace - one problem solved, another arises, again and again until we die.", book = "", author = "Pamela Anderson, Love, Pamela" },
    { text = "Well, and it is not my fault if I have not loved as one loves a concubine, since men do not.", book = "", author = "Pearl S. Buck" },
    { text = "A resistance that dispenses with consolations is always stronger than one which relies on them.", book = "Spectrum: From Right to Left in the World of Ideas", author = "Perry Anderson" },
    { text = "Birds weren't given wings just to walk everywhere . . . and you weren't born with resilience and a beautiful mind just to have an easy life.", book = "The Little Book of Stoic Quotes: Philosophy for a Meaningful and Courageous Life", author = "Phil Van Treuren" },
    { text = "The world is asking us the questions, and it couldn't care less what we expect from it. But here's the good news: real meaning doesn't come from what the world gives you, but how you respond to it.", book = "The Little Book of Stoic Quotes: Philosophy for a Meaningful and Courageous Life", author = "Phil Van Treuren" },
    { text = "All Hellenistic schools seem to define [wisdom] in approximately the same terms: first and foremost, as a state of perfect peace of mind. From this viewpoint, philosophy appears as a remedy for human worries, anguish, and misery brought about, for the Cynics, by social constraints and conventions; for the Epicureans, by the quest for false pleasures; for the Stoics, by the pursuit of pleasure and egoistic self-interest; and for the Skeptics, by false opinions. Whether or not they laid claim to the Socratic heritage, all Hellenistic philosophers agreed with Socrates that human beings are plunged in misery, anguish, and evil because they exist in ignorance. Evil is to be found not within things, but in the value judgments with people bring to bear  upon  things. People can therefore be cured of their ills only if they are persuaded to change their value judgments, and in this sense all these philosophies wanted to be therapeutic.", book = "What Is Ancient Philosophy?", author = "Pierre Hadot" },
    { text = "In the first place, sensation (aisthesis) is a corporeal process which we have in common with animals, and in which the impression of an exterior object is transmitted to the soul. By means of this process, an image (phantasia) of the object is produced in the soul, or more precisely in the guiding part (hegemonikon) of the soul", book = "The Inner Citadel: The Meditations of Marcus Aurelius", author = "Pierre Hadot" },
    { text = "With respect to Stoicism, Hadot has described four features that constitute the universal Stoic attitude. They are, first, the Stoic consciousness of the fact that no being is alone, but that we make up part of a Whole, constituted by the totality of human beings as well as by the totality of the cosmos; second, the Stoic feels absolutely serene, free, and invulnerable to the extent that he has become aware that there is no other evil but moral evil and that the only thing that counts is the purity of moral consciousness; third, the Stoic believes in the absolute value of the human person a belief that is at the origin of the modern notion of the'rights of man'; finally, the Stoic exercises his concentration on the present instant, which consists, on the one hand, in living as if we were seeing the world for the first and for the last time, and, on the other hand, in being conscious that, in this lived presence of the instant, we have access to the totality of time and of the world.  17 Thus, for Hadot, cosmic consciousness, the purity of moral consciousness, the recognition of the equality and absolute value of human beings, and the concentration on the present instant represent the universal Stoic attitude. The universal Epicurean attitude essentially consists, by way of a certain discipline and reduction of desires, in returning from pleasures mixed with pain and suffering to the simple and pure pleasure of existing.", book = "Philosophy as a Way of Life: Spiritual Exercises from Socrates to Foucault", author = "Pierre Hadot" },
    { text = "How could I admit that the All-American Girl's force field of stoicism and self-reliance and do-unto-others-and-keep-smiling wasn't working, wasn't keeping pain and shame and powerlessness away?  From a young age I had learned to get over - to cover my tracks emotionally, to hide or ignore my problems in the belief that they were mine alone to solve. So when exhilarating transgressions required getting over on authority figures, I knew how to do it. I was a great bluffer. And when common, everyday survival in prison required getting over, I could do that too. This is what was approvingly described by my fellow prisoners as'street-smarts,' as in'You wouldn't think it to look at her, but Piper's got street-smarts.", book = "Orange Is the New Black", author = "Piper Kerman" },
    { text = "There will come a day when i will be able to resist and control my emotions... And when that day comes, i will know that i truly made it.", book = "stoicism", author = "Plandertaker" },
    { text = "Cato practiced the kind of public speech capable of moving the masses, believing proper political philosophy takes care like any great city to maintain the warlike element. But he was never seen practicing in front of others, and no one ever heard him rehearse a speech. When he was told that people blamed him for his silence, he replied, ‘Better they not blame my life. I begin to speak only when I’m certain what I’ll say isn’t better left unsaid.’", book = "Cato The Younger", author = "Plutarch" },
    { text = "Concern should drive us into action and not into a depression. No man is free who cannot control himself.", book = "The Big Book of Ancient Classics: Contains the works of Aristotle, Plato, Homer, Aeschylus...", author = "Pythagoras" },
    { text = "Complaining does not work as a strategy. We all have finite time and energy. Any time we spend whining is unlikely to help us achieve our goals. And it won't make us happier.", book = "The Last Lecture", author = "Randy Pausch" },
    { text = "In Tsurani culture, forgiveness was simply a less shameful form of weakness than capitulation.", book = "", author = "Raymond E. Feist" },
    { text = "What", book = "", author = "Richard Nixon" },
    { text = "Christianity is not a therapy for those who wish never to be upset (177).", book = "Spiritual Emotions: A Psychology of Christian Virtues", author = "Robert Campbell Roberts" },
    { text = "We must become friends of despair if we are to be drawn above it to genuine and heartfelt hope. Far from being  an exercise in morbidity or arrogance, a deepening acquaintance with our  death and with the vanity of human wishes is our worldly hearts a  needed path to perfect health (61).", book = "Spiritual Emotions: A Psychology of Christian Virtues", author = "Robert Campbell Roberts" },
    { text = "Why should we place Christ at the top and summit of the human race? Was he kinder, more forgiving, more self-sacrificing than  Buddha? Was he wiser, did he meet death with more perfect calmness, than  Socrates? Was he more patient, more charitable, than  Epictetus? Was he a greater philosopher, a deeper thinker, than  Epicurus? In what respect was he the superior of  Zoroaster? Was he gentler than  Lao-tsze , more universal than  Confucius? Were his ideas of human rights and duties superior to those of  Zeno? Did he express grander truths than  Cicero? Was his mind subtler than  Spinoza's? Was his brain equal to  Kepler's or  Newton's? Was he grander in death  “ a sublimer martyr than  Bruno? Was he in intelligence, in the force and beauty of expression, in breadth and scope of thought, in wealth of illustration, in aptness of comparison, in knowledge of the human brain and heart, of all passions, hopes and fears, the equal of  Shakespeare , the greatest of the human race?", book = "About The Holy Bible", author = "Robert G. Ingersoll" },
    { text = "The causes that work best use a noble veneer to cover a blatant appeal to self-interest; the cause seduces but the self-interest secures the deal. Daily Law: Show people what’s in it for them.", book = "The Daily Laws", author = "Robert Greene" },
    { text = "At the bar on the Favoritenstrasse, Julius the policeman talked to us about dignity, evolution, the great Darwin and the great Nietzsche. I translated so that my good friend Ulises could understand what he was saying, although I didn't understand any of it. The prayer of the bones, said Julius. The yearning for health. The virtue of danger. The tenacity of the forgotten. Bravo, said my good friend Ulises. Bravo, said everyone else. The limits of memory. The wisdom of plants. The eye of parasites. The agility of the earth. The merit of the soldier. The cunning of the giant. The hole of the will. Magnificent, said my good friend Ulises in German. Extraordinary.", book = "The Savage Detectives", author = "Roberto Bolaño" },
    { text = "Do not underestimate the quiet and laid-back individuals because displaying stoicism, at certain times, is a superpower.", book = "", author = "Robin S. Baker" },
    { text = "The stoics divided philosophy into three branches: logic, physics, and ethics. Logic covered not only the rules of correct argumentation, but also grammar, linguistics, rhetorical theory, epistemology, and all the tools that might be needed to discover the truth of any matter. Physics was concerned with the nature of the world and the laws that govern it, and so included ontology and theology as well as what we would recognize as physics, astronomy, and cosmology. Ethics was concerned with how to achieve happiness, or how to live a fulfilled and flourishing life as a human being. A stoic sage was supposed to be fully expert in all three aspects.", book = "Meditations", author = "Robin Waterfield" },
    { text = "However one may interpret this culturally, the upshot is the same: people carry within them a great number of wishes to which they react passively and which they hide. Stoicism, in our day, is not strength to overcome wishes, but to hide them. To a patient who, let us say, is interminably rationalizing and justifying this and that, balancing one thing against another as though life were a tremendous market place where all the business is done on paper and tickertape and there are never any  goods , I sometimes have the inclination in psychotherapy to shout out, Don't you ever  want  anything? But I don't cry out, for it is not difficult to see that on some level the patient does want a good deal; the trouble is he has formulated and reformulated it, until it is the rattling of dry bones as Eliot puts it. Tendencies have become endemic in our culture for our denial of wishes to be rationalized and accepted with the belief that this denial of the wish will result in its being fulfilled. And whether the reader would disagree with me on this or that detail, our psychological problem is the same: it is necessary for us to help the patient achieve some emotional viability and honesty by bringing out his wishes and his capacity to wish. This is not the end of therapy but it is an essential starting point.", book = "Love and Will", author = "Rollo May" },
    { text = "Stoicism is a logical philosophy.", book = "stoicism", author = "Ron Hall" },
    { text = "As for us, we face things that are not nearly as intimidating, and then we promptly decide we're screwed.  This is how obstacles become obstacles.  In other words, through our perception of events, we are complicit in the creation-as well as the destruction-of every one of our obstacles. There is no good or bad without us, there is only perception. There is the event itself and the story we tell ourselves about what it means.", book = "51 Most Powerful Prayers", author = "Ryan Holiday" },
    { text = "At any moment we may be toppled from our perch and made to do with less ”less money, less recognition, less access, less resources. Even the less-es that come with age: less mobility, less energy, less freedom. But we can prepare for that, in some way, by familiarizing ourselves with what that might feel like.", book = "The Daily Stoic: 366 Meditations on Wisdom, Perseverance, and the Art of Living", author = "Ryan Holiday" },
    { text = "Stoicism is designed to be medicine for the soul.", book = "The Daily Stoic, [Hardcover] The Daily Stoic Journal, Perennial Seller By Ryan Holiday Collection 3 Books Set", author = "Ryan Holiday" },
    { text = "The goodness inside you is like a small flame, and you are its keeper. It's your job, today and every day, to make sure that it has enough fuel, that it doesn't get obstructed or snuffed out. Every person has their own version of the flame and is responsible for it, just as you are. If they all fail, the world will be much darker ”that is something you don't control. But so long as your flame flickers, there will be some light in the world.", book = "The Daily Stoic: 366 Meditations on Wisdom, Perseverance, and the Art of Living", author = "Ryan Holiday" },
    { text = "Whatever you're going through, there is wisdom from the stoics that can help. In fact, in many cases, they have addressed it explicitly in terms that feel shockingly modern.", book = "The Daily Stoic: 366 Meditations on Wisdom, Perseverance, and the Art of Living", author = "Ryan Holiday" },
    { text = "You have two essential tasks in life: to be a good person and to pursue the occupation that you love. Everything else is a waste of energy and a squandering of your potential.", book = "The Daily Stoic", author = "Ryan Holiday" },
    { text = "You owe it to yourself and to the world to actively engage with the brief moment you have with this planet. You cannot retreat exclusively into ideas. You must contribute.", book = "Lives of the Stoics: The Art of Living from Zeno to Marcus Aurelius", author = "Ryan Holiday" },
    { text = "You will only get one shot at today. You have only twenty-four hours with which to take it. And then it is gone and lost forever. Will you fully inhbit all of today? Will you call out, I've got this and do your very best to be your very best? What will you manage to make of today before it slips from you fingers and becomes the past? When someone asks you what you did yesterday, do you really want the answer to be nothing?", book = "The Daily Stoic: 366 Meditations on Wisdom, Perseverance, and the Art of Living", author = "Ryan Holiday" },
    { text = "How do you defeat terrorism? Don't be terrorized.", book = "Step Across This Line: Collected Nonfiction 1992-2002", author = "Salman Rushdie" },
    { text = "A benefit should be kept like a buried treasure, only to be dug up in necessity.... Nature bids us to do well by all.... Wherever there is a human being, we have an opportunity for kindness.", book = "On The Happy Life", author = "Seneca" },
    { text = "A charming enemy comes to me as a friend faults creep in calling themselves virtues temerity cloaks itself with the name of courage cowardice gets called moderation and timidity passes itself off as caution.", book = "stoicism", author = "Seneca" },
    { text = "A family formed by crime must be broken by more crime.", book = "", author = "Seneca" },
    { text = "A gift consists not in what is done or given, but in the intention of the giver or doer.", book = "", author = "Seneca" },
    { text = "A good man will not waste himself upon mean and discreditable work or be busy merely for the sake of being busy.", book = "", author = "Seneca" },
    { text = "A great mind becomes a great fortune.", book = "", author = "Seneca" },
    { text = "A grey-haired wrinkled man has not necessarily lived long. More accurately, he has existed long.", book = "", author = "Seneca" },
    { text = "A guilty person sometimes has the luck to escape detection, but never to feel sure of it.", book = "", author = "Seneca" },
    { text = "A hungry people neither listens to reason nor is mollified by fair treatment or swayed by any appeals.", book = "", author = "Seneca" },
    { text = "A man is as much a fool for shedding tears because he isn't going to be alive a thousand years from now.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "A man is as unhappy as he has convinced himself he is.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "A man is wealthy if he has attuned himself to his restricted means and has made himself rich on little.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "A man should therefore grow accustomed to his state and complain about it as little as possible, seizing upon whatever good it may have.", book = "", author = "Seneca" },
    { text = "A man who makes a decision without listening to both sides is unjust, even if his ruling is a fair one.", book = "", author = "Seneca" },
    { text = "A man’s past is forever set in stone.", book = "", author = "Seneca" },
    { text = "A man's peace of mind does not depend upon Fortune; for, even when angry she grants enough for our needs.", book = "", author = "Seneca" },
    { text = "A multitude of books only gets in one's way. So if you are unable to read all the books in your possession, you have enough when you have all the books you are able to read.", book = "", author = "Seneca" },
    { text = "A person teaching and a person learning,' he said, 'should have the same end in view: the improvement of the latter.", book = "", author = "Seneca" },
    { text = "A person's fears are lighter when the danger is at hand.", book = "", author = "Seneca" },
    { text = "A pleasure that is ephemeral brings no true satisfaction to any man. How miserable must be the lives of those folk who labor so hard for something that once gained they must work even harder to keep.", book = "", author = "Seneca" },
    { text = "A sword never kills anybody; it is a tool in the killer's hand.", book = "", author = "Seneca" },
    { text = "A wise man never asks what another man serves, for only his actions will speak the truth.", book = "", author = "Seneca" },
    { text = "A woman is not beautiful when her ankle or arm wins compliments, but when her total appearance diverts admiration from the individual parts of her body.", book = "", author = "Seneca" },
    { text = "Ab honesto virum bonum nihil deterret. (Nothing deters a good man from doing what is honorable.)-A Wrinkle in Time.", book = "", author = "Seneca" },
    { text = "Above all, it is necessary for a person to have a true self-estimate, for we commonly think we can do more than we really can.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Above all, my dear Lucilius, make this your business: learn how to feel joy.", book = "", author = "Seneca" },
    { text = "After friendship is formed you must trust, but before that you must judge. Those people who, contrary to Theophrastus’ advice, judge a man after they have made him their friend instead of the other way round, certainly put the cart before the horse.", book = "", author = "Seneca" },
    { text = "Again, when my mind is lifted up by the greatness of its thoughts, it becomes ambitious for words and longs to match its higher inspiration with its language, and so produces a style that conforms to the impressiveness of the subject matter.", book = "", author = "Seneca" },
    { text = "All cruelty springs from weakness.", book = "", author = "Seneca" },
    { text = "All fools suffer the burden of dissatisfaction with themselves.", book = "", author = "Seneca" },
    { text = "All life is a servitude. So you have to get used to your circumstances, complain about them as little as possible, and grasp whatever advantage they have to offer: no condition is so bitter that a stable mind cannot find some consolation in it.", book = "", author = "Seneca" },
    { text = "All outdoors may be bedlam, provided there is no disturbance within.", book = "", author = "Seneca" },
    { text = "All that remains of our existence is not actually life but merely time.", book = "", author = "Seneca" },
    { text = "All the greatest blessings are a source of anxiety, and at no time is fortune less wisely trusted than when it is best.", book = "", author = "Seneca" },
    { text = "All the greatest blessings create anxiety, and Fortune is never less to be trusted than when it is fairest.", book = "", author = "Seneca" },
    { text = "All the works of mortal man have been doomed to mortality, and in the midst of things which have been destined to die, we live!", book = "", author = "Seneca" },
    { text = "All things that are still to come lie in uncertainty; live straightway!", book = "", author = "Seneca" },
    { text = "All things were ready for us at our birth; it is we that have made everything difficult for ourselves, through our disdain for what is easy.", book = "", author = "Seneca" },
    { text = "All this hurrying from place to place won’t bring you any relief, for you’re traveling in the company of your own emotions, followed by your troubles all the way.", book = "", author = "Seneca" },
    { text = "All those who call you to themselves draw you away from yourself.", book = "", author = "Seneca" },
    { text = "All vices are at odds with nature.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Although the sum and substance of the happy life is unalloyed freedom from care, and though the secret of such freedom is unshaken confidence... men gather together that which causes worry.", book = "", author = "Seneca" },
    { text = "Am I not to inquire into the identity of the artist of this universe?", book = "", author = "Seneca" },
    { text = "An unpopular rule is never long maintained.", book = "", author = "Seneca" },
    { text = "And I hold that no man has treated mankind worse than he who has studied philosophy as if it were some marketable trade, who lives in a different manner from that which he advises.", book = "", author = "Seneca" },
    { text = "And if you want to know why all this running away cannot help you, the answer is simply this: you are running away in your own company.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "And there’s no state of slavery more disgraceful than one which is self-imposed.", book = "", author = "Seneca" },
    { text = "And what is more wretched than a man who forgets his benefits and clings to his injuries?", book = "", author = "Seneca" },
    { text = "And what’s so bad about your being deprived of that? All things seem unbearable to people who have become spoilt, who have become soft through a life of luxury, ailing more in the mind than they ever are in the body.", book = "", author = "Seneca" },
    { text = "And when the soul has yielded to pleasure, its functions and actions grow weak, and any undertaking comes from a nerveless and unsteady source.", book = "", author = "Seneca" },
    { text = "Anger will abate and become more controlled when it knows it must come before a judge each day.", book = "", author = "Seneca" },
    { text = "Anger, if not restrained, is frequently more hurtful to us than the injury that provokes it.", book = "", author = "Seneca" },
    { text = "Any man,’ he says, ‘who does not think that what he has is more than ample, is an unhappy man, even if he is the master of the whole world.", book = "", author = "Seneca" },
    { text = "Anyone who likes may make things easier for himself by viewing them with equanimity.", book = "", author = "Seneca" },
    { text = "Anything that must yet be done, virtue can do with courage and promptness. For anyone would call it a sign of foolishness for one to undertake a task with a lazy and begrudging spirit, or to push the body in one direction and the mind in another, to be torn apart by wildly divergent impulses.", book = "Moral Letters", author = "Seneca" },
    { text = "Apparently, when the arrogant King of Persia beheld the vastness of his troops spread out across boundless plains, he shed copious tears when he realized that not one man amongst his prodigious army would be alive in a hundred years’ time.", book = "", author = "Seneca" },
    { text = "Apply yourself to thinking through difficulties—hard times can be softened, tight squeezes widened, and heavy loads made lighter for those who can apply the right pressure.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Aren’t you ashamed to reserve for yourself only the remnants of your life and to dedicate to wisdom only that time can’t be directed to business?", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "As Cicero says, we hate gladiators if they are quick to save their lives by any means; we favor them if they show contempt for their lives.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "As is a tale, so is life: not how long it is, but how good it is, is what matters.", book = "", author = "Seneca" },
    { text = "As it is with a play, so it is with life - what matters is not how long the acting lasts, but how good it is.", book = "", author = "Seneca" },
    { text = "As long as you live, keep learning how to live.", book = "", author = "Seneca" },
    { text = "As often as I have been amongst men, I have returned less a man.", book = "", author = "Seneca" },
    { text = "As things are, there is about wisdom a nobility and magnificence in the fact that she didn't just fall to a person's lot, that each man owes her to his own efforts, that one doesn't go to anyone other than oneself to find her.", book = "Letters from a Stoic: Complete (Letters 1 - 124) Adapted for the Contemporary Reader", author = "Seneca" },
    { text = "As to what the future's uncertain lot has in store, why should I demand of Fortune that she give rather than demand of myself that I should not crave?", book = "", author = "Seneca" },
    { text = "Ask about those whose names are learned by heart, and you will see that they have these distinguishing marks: X cultivates Y and Y cultivates Z – no one bothers about himself.", book = "", author = "Seneca" },
    { text = "Ask nature: she will tell you that she made both day and night.", book = "", author = "Seneca" },
    { text = "Associate with people who are likely to improve you.", book = "", author = "Seneca" },
    { text = "Withdraw into yourself, as far as you can. Associate with those who will make a better man of you. Welcome those whom you yourself can improve. The process is mutual; for men learn while they teach.", book = "", author = "Seneca" },
    { text = "Associate with those who will make a better of man. Welcome those whom yourself can improve. Men learn while they teach.", book = "", author = "Seneca" },
    { text = "At this moment you aren’t on a journey, but wandering about, being driven from place to place, even though what you seek—to live well—is found in all places. Is there any place more full of confusion than the Forum? Yet even there you can live at peace, if needed.", book = "Moral Letters", author = "Seneca" },
    { text = "Atreus: Who would reject the flood of fortune’s gifts? Thyestes: Anyone who has experienced how easily they flow back.", book = "Thyestes", author = "Seneca" },
    { text = "Awake, my heart, And do such deeds as in the time to come No tongue shall praise, but none refuse to tell.", book = "", author = "Seneca" },
    { text = "Be aware, then, that every human condition is subject to change, and that whatever mishap can befall any man can also happen to you.", book = "", author = "Seneca" },
    { text = "Be deaf to those who love you most of all; they pray for bad things with good intentions. .", book = "", author = "Seneca" },
    { text = "because it is natural to touch more often the parts that hurt.", book = "", author = "Seneca" },
    { text = "Because thou writest me often, I thank thee. Never do I receive a letter from thee, but immediately we are together.", book = "", author = "Seneca" },
    { text = "Begin at once to live, and count each separate day as a separate life.", book = "", author = "Seneca" },
    { text = "Being unexpected adds to the weight of a disaster, and being a surprise has never failed to increase a person’s pain. For that reason, nothing should ever be unexpected by us. Our minds should be sent out in advance to all things and we shouldn’t just consider the normal course of things, but what could actually happen. For is there anything in life that Fortune won’t knock off its high horse if it pleases her?", book = "Moral Letters", author = "Seneca" },
    { text = "Being without your country is not misery: you have thoroughly taught yourself by your studies to know that to a wise man every place is his country.", book = "", author = "Seneca" },
    { text = "Believe me if you consult philosophy she will persuade you not to lit so long at your counting desk.", book = "", author = "Seneca" },
    { text = "Believe me, it is the sign of a great man, and one who is above human error, not to allow his time to be frittered away: he has the longest possible life simply because whatever time was available he devoted entirely to himself.", book = "", author = "Seneca" },
    { text = "Believe me, it takes a great man and one who has risen far above human weaknesses not to allow any of his time to be filched from him.", book = "", author = "Seneca" },
    { text = "Believe me, it’s better to produce the balance-sheet of your own life than that of the grain market.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "Besides, he who is feared, fears also; no one has been able to arouse terror and live in peace of mind.", book = "", author = "Seneca" },
    { text = "Beyond all things is the sea.", book = "", author = "Seneca" },
    { text = "Brave men rejoice in adversity, just as brave soldiers triumph in war.", book = "", author = "Seneca" },
    { text = "But consider whether you may not get more help from the customary method than from that which is now commonly called a  breviary,  though in the good old days, when real Latin was spoken, it was called a  summary .", book = "", author = "Seneca" },
    { text = "But every great and overpowering grief must take away the capacity to choose words, since it often stifles the voice itself.", book = "", author = "Seneca" },
    { text = "But he must have richly dyed purple clothes, woven with gold thread and decorated with multicoloured patterns: it is his fault, not nature’s, if he feels poor.", book = "", author = "Seneca" },
    { text = "Everyone hurries his life on and suffers from a yearning for the future and a weariness of the present. But he who bestows all of his time on his own needs, who plans out every day as if it were his last, neither longs for nor fears the morrow.", book = "", author = "Seneca" },
    { text = "But is life really worth so much? Let us examine this; it's a different inquiry. We will offer no solace for so desolate a prison house; we will encourage no one to endure the overlordship of butchers. We shall rather show that in every kind of slavery, the road of freedom lies open. I will say to the man to whom it befell to have a king shoot arrows at his dear ones [Prexaspes], and to him whose master makes fathers banquet on their sons' guts [Harpagus]:'What are you groaning for, fool?... Everywhere you look you find an end to your sufferings. You see that steep drop-off? It leads down to freedom. You see that ocean, that river, that well? Freedom lies at its bottom. You see that short, shriveled, bare tree? Freedom hangs from it.... You ask, what is the path to freedom? Any vein in your body.", book = "Dying Every Day: Seneca at the Court of Nero", author = "Seneca" },
    { text = "But learning how to live takes a whole life, and, which may surprise you more, it takes a whole life to learn how to die. So many of the finest men have put aside all.", book = "", author = "Seneca" },
    { text = "But let him consider that those disorders which are so dangerous that they have gained ground in spite of treatment can generally be treated by opposite methods.", book = "", author = "Seneca" },
    { text = "But life is very short and anxious for those who forget the past, neglect the present, and fear the future.", book = "", author = "Seneca" },
    { text = "But only philosophy will wake us; only philosophy will shake us out of that heavy sleep. Devote yourself entirely to her. You're worthy of her, she's worthy of you-fall into each other's arms. Say a firm, plain no to every other occupation.", book = "", author = "Seneca" },
    { text = "But our friend Bassus stays sharp minded. Philosophy furnishes him with this: to be cheerful when death comes in view, to stay strong and happy no matter what one’s bodily condition.", book = "", author = "Seneca" },
    { text = "But the man who is not puffed up in good times does not collapse either when they change.", book = "", author = "Seneca" },
    { text = "But the wise person can lose nothing. Such a person has everything stored up for themselves, leaving nothing to Fortune, their own goods are held firm, bound in virtue, which requires nothing from chance, and therefore can’t be either increased or diminished.", book = "On The Firmness Of The Wise", author = "Seneca" },
    { text = "But there can be no such good except as the soul discovers it for itself within itself.", book = "Letters From A Stoic: A Comprehensive Guide to Seneca's Philosophical Insights including Practical Exercises and Insights for Modern Readers", author = "Seneca" },
    { text = "But there is no reason to live and no limit to our miseries if we let our fears predominate.", book = "Moral Letters", author = "Seneca" },
    { text = "But when you are looking on anyone as a friend when you do not trust him as you trust yourself, you are making a grave mistake, and have failed to grasp sufficiently the full force of true friendship.", book = "", author = "Seneca" },
    { text = "But you never deign to look at yourself or listen to yourself. So you have no reason to claim credit from anyone for those attentions, since you showed them not because you wanted someone else’s company but because you could not bearyour own.", book = "", author = "Seneca" },
    { text = "By overloading the body with food you strangle the soul and render it less active.", book = "", author = "Seneca" },
    { text = "By the toil of others we are brought into the presence of things which have been brought from darkness into light.", book = "", author = "Seneca" },
    { text = "By the toil of others we are led into the presence of things which have been brought from darkness into light. We are excluded from no age, but we have access to them all.", book = "", author = "Seneca" },
    { text = "Can you no longer see a road to freedom? It's right in front of you. You need only turn over your wrists.", book = "", author = "Seneca" },
    { text = "Certain people have good, ordinary blood and others have an animated, lively sort of blood that comes to the face quickly.", book = "", author = "Seneca" },
    { text = "Circumstances are what deceive us—you must be discerning in them. We embrace evil before good. We desire the opposite of what we once desired. Our prayers are at war with our prayers, our plans with our plans.", book = "Moral Letters", author = "Seneca" },
    { text = "Cling tooth and nail to the following rule: not to give in to adversity, never to trust prosperity, and always take full not of fortune's habit of behaving just as she pleases, treating her as if she were actually going to do everything it is in her power to do.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Consider above all else whether you've advanced in philosophy or just in actual years.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Consider, too, that a man lifting his head from the very funeral pyre must need some novel vocabulary not drawn from ordinary everyday condolence to comfort his own dear ones.", book = "", author = "Seneca" },
    { text = "Conversation has a kind of charm about it, an insinuating and insidious something that elicits secrets just like love or liquor.", book = "", author = "Seneca" },
    { text = "Could anything be more stupid than to praise a person for something that is not his? Or more crazy than admiring things which in a single moment can be transferred to another?", book = "", author = "Seneca" },
    { text = "Count your years, and you will be ashamed to desire and pursue the same things you desired in your boyhood days. .", book = "", author = "Seneca" },
    { text = "Count yourself fortunate when you are able to live in a manner open to the public ”when walls are there for shelter, not for concealment. For as a rule we think we have walls around us not to protect us but to afford greater privacy to our misdeeds.", book = "stoicism", author = "Seneca" },
    { text = "Crimes often return to their teacher.", book = "Thyestes", author = "Seneca" },
    { text = "Death lies heavy upon one who, known exceedingly well by all, dies unknown to himself.", book = "Thyestes", author = "Seneca" },
    { text = "Democritus says:  One man means as much to me as a multitude, and a multitude only as much as one man. ", book = "", author = "Seneca" },
    { text = "Despise everything that useless toil creates as an ornament and an object of beauty. And reflect that nothing except the soul is worthy of wonder; for to the soul, if it be great, naught is great.", book = "", author = "Seneca" },
    { text = "Desultory reading is delightful, but to be beneficial, our reading must be carefully directed.", book = "", author = "Seneca" },
    { text = "Det ille veniam facile, cui venia est opus - the one who needs pardon should readily grant it.", book = "", author = "Seneca" },
    { text = "Different reasons roused different peoples to leave their homes; but this at least is clear, nothing has stayed where it was born. The human race is always on the move.", book = "", author = "Seneca" },
    { text = "Difficulties strengthen the mind, as labor does the body.", book = "", author = "Seneca" },
    { text = "Disasters, therefore, and losses, and wrongs, have only the same power over virtue that a cloud has over the sun.", book = "", author = "Seneca" },
    { text = "Distringit librorum multitudo  (the abundance of books is distraction).", book = "", author = "Seneca" },
    { text = "Do not run hither and thither and distract yourself by changing your abode; for such restlessness is the sign of a disordered spirit.", book = "", author = "Seneca" },
    { text = "Do not trust her seeming calm in a moment the sea is moved to its depths.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Do the one thing that can render you really happy: cast aside and trample under foot all the things that glitter outwardly and are held out to you a by another or as obtainable from another.", book = "", author = "Seneca" },
    { text = "Do you ask me what you should regard as especially to be avoided? I say, crowds; for as yet you cannot trust yourself to them with safety.", book = "", author = "Seneca" },
    { text = "Do you ask what is the foundation of a sound mind? It is, not to find joy in useless things. .", book = "", author = "Seneca" },
    { text = "Do you ask what is the proper limit to wealth? It is, first, to have what is necessary, and, second, to have what is enough.", book = "", author = "Seneca" },
    { text = "Does it serve any useful purpose to know that Pompey was the first to exhibit the slaughter of eighteen elephants in the Circus, pitting criminals against them in a mimic battle?", book = "", author = "Seneca" },
    { text = "Drunkenness is nothing but voluntary madness.", book = "", author = "Seneca" },
    { text = "Each day acquire something that will fortify you against poverty, against death, indeed against other misfortunes as well; and after you have run over many thoughts, select one to be thoroughly digested that day.", book = "", author = "Seneca" },
    { text = "Each day... acquire something which will help you to face poverty, or death, and other ills as well. After running over a lot of different thoughts, pick out one to be digested thoroughly that day.", book = "", author = "Seneca" },
    { text = "Each man has a character of his own choosing it is chance or fate that decides his choice of job.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Each person acquires their own character, but their official roles are designated by chance. You should invite some to your table because they are deserving, others because they may come to deserve it.", book = "Moral Letters", author = "Seneca" },
    { text = "Enjoy present pleasures in such a way as not to injure future ones.", book = "", author = "Seneca" },
    { text = "Envy of other people shows how they are unhappy. Their continual attention to others behavior shows how they are boring.", book = "", author = "Seneca" },
    { text = "Errare humanum est, sed perseverare diabolicum: 'to err is human, but to persist (in the mistake) is diabolical.", book = "", author = "Seneca" },
    { text = "Even a poisonous snake is safe to handle in cold weather, when it is sluggish. Its venom is still there, but inactive. In the same way, there are many people whose cruelty, ambition, or self-indulgence fails to match the most outrageous cases only by the grace of fortune.", book = "stoicism", author = "Seneca" },
    { text = "Even if you had a lot of life left to live, you would need to parcel out your time sparingly so as to have enough for necessities. As it is, with time in such short supply, what madness it is to learn things that are superfluous.", book = "stoicism", author = "Seneca" },
    { text = "Even in the longest life real living is the least portion thereof.", book = "Ad Lucilium Epistulae Morales Volume 3", author = "Seneca" },
    { text = "Everlasting misfortune does have one blessing, that it ends up by toughening those whom it constantly afflicts.", book = "", author = "Seneca" },
    { text = "Every day as it comes should be welcomed and reduced forthwith into our own possession as if it were the finest day imaginable. What flies past has to be seized at.", book = "", author = "Seneca" },
    { text = "Every hour of the day, countless situations arise that call for advice, and for that advice we have to look to philosophy.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Every individual can make himself happy. External goods are of trivial importance and without much influence in either direction: prosperity does not elevate the sage and adversity does not depress him.", book = "", author = "Seneca" },
    { text = "Every life without exception is a short one.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Every man, when he first sees light, is commanded to be content with milk and rags. Such is our beginning, and yet kingdoms are all too small for us!", book = "", author = "Seneca" },
    { text = "Every new beginning comes from some other beginning's end.", book = "", author = "Seneca" },
    { text = "Every pleasure is most valued when it is coming to an end.", book = "", author = "Seneca" },
    { text = "Everyone goes out of life just as if he had but lately entered.", book = "", author = "Seneca" },
    { text = "Everyone hustles his life along, and is troubled by a longing for the future and weariness of the present.", book = "", author = "Seneca" },
    { text = "Everyone prefers belief to the exercise of judgement.", book = "", author = "Seneca" },
    { text = "Everything which went beyond our actual needs was just so much unnecessary weight, a burden to the man who had to carry it.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Everywhere means nowhere. When a person spends all his time in foreign travel, he ends by having many acquaintances, but no friends.", book = "", author = "Seneca" },
    { text = "Everywhere means nowhere.", book = "Letters From A Stoic | Moral Letters To Lucilius", author = "Seneca" },
    { text = "Everywhere the people are of mixed and imported stock. One group has followed another: one longed for what another scorned; one was driven out from where he had expelled others. So fate has decreed that nothing maintains the same condition forever.", book = "", author = "Seneca" },
    { text = "Expecting is the greatest impediment to living. In anticipation of tomorrow, it loses today.", book = "", author = "Seneca" },
    { text = "Fate leads the willing and drags along the reluctant.", book = "", author = "Seneca" },
    { text = "Fidelity purchased with money, money can destroy.", book = "", author = "Seneca" },
    { text = "Finally, it is generally agreed that no activity can be successfully pursued by an individual who is preoccupied.", book = "", author = "Seneca" },
    { text = "Ignis aurum probat, miseria fortes viros. Fire is the test of gold; adversity, of strong men.", book = "", author = "Seneca" },
    { text = "Fire tests gold and adversity tests the brave.", book = "", author = "Seneca" },
    { text = "Fire tests gold, suffering tests brave men.", book = "", author = "Seneca" },
    { text = "Flattery looks very much like friendship, indeed not only resembles it but actually wins out against it. A person drinks it in with eager ears and takes it deeply to heart, delighted by the very qualities that make it dangerous.", book = "stoicism", author = "Seneca" },
    { text = "For a delight in bustling about is not industry - it is only the restless energy of a hunted mind. And the state of mind that looks on all activity as tiresome is not true repose, but a spineless inertia.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "For a life spent viewing all the variety, the majesty, the sublimity in things around us can never succumb to ennui: the feeling that one is tired of being, of existing, is usually the result of an idle and inactive leisure.", book = "stoicism", author = "Seneca" },
    { text = "For a person who is not aware that he is doing anything wrong has no desire to be put right. You have to catch yourself doing it before you can reform.", book = "", author = "Seneca" },
    { text = "For even peace itself will supply more reason for worry. Not even safe circumstances will bring you confidence once your mind has been shocked—once it gets in the habit of blind panic, it can’t provide for its own safety. For it doesn’t really avoid danger, it just runs away. Yet we are exposed to greater danger with our backs turned.", book = "Moral Letters", author = "Seneca" },
    { text = "For Fate/ The willing leads, the unwilling drags along.", book = "", author = "Seneca" },
    { text = "For how little have we lost, when the two finest things of all will accompany us wherever we go, universal nature and our individual virtue.", book = "", author = "Seneca" },
    { text = "For if we could be satisfied with anything, we should have been satisfied long ago.", book = "", author = "Seneca" },
    { text = "For it is disheartening to inspire in a man the desire, and to take away from him the hope, of emulation.", book = "", author = "Seneca" },
    { text = "For it’s disgraceful for an old person, or one in sight of old age, to have only the knowledge carried in their notebooks. Zeno said this... what do you say? Cleanthes said that... what do you say? How long will you be compelled by the claims of another? Take charge and stake your own claim—something posterity will carry in its notebook.", book = "Moral Letters", author = "Seneca" },
    { text = "For love of bustle is not industry, —it is only the restlessness of a hunted mind.", book = "", author = "Seneca" },
    { text = "For manliness gains much strength by being challenged.", book = "", author = "Seneca" },
    { text = "For many men, the acquisition of wealth does not end their troubles, it only changes them.", book = "", author = "Seneca" },
    { text = "For men cease to possess all things the moment they desire all things for their own.", book = "", author = "Seneca" },
    { text = "For only philosophy or honourable occupation can divert from its anguish a heart whose grief springs from love.", book = "", author = "Seneca" },
    { text = "For some persons the remedy should be merely prescribed; in the case of others, it should be forced down their throats. .", book = "", author = "Seneca" },
    { text = "For that is the people’s verdict, but wise men on the whole reject the people’s decrees.", book = "", author = "Seneca" },
    { text = "For that love is greater which wins less through equal danger.", book = "", author = "Seneca" },
    { text = "For the only safe harbour in this life's tossing, troubled sea is to refuse to be bothered about what the future will bring and to stand ready and confident, squaring the breast to take without skulking or flinching whatever fortune hurls at us.", book = "", author = "Seneca" },
    { text = "For the wise man regards wealth as a slave, the fool as a master.", book = "", author = "Seneca" },
    { text = "For this is what makes us wicked: that no one of us looks back over his own life. Our thoughts are devoted only to what we are about to do. And yet our plans for the future always depend on the past.", book = "", author = "Seneca" },
    { text = "For those who follow nature everything is easy and straightforward, whereas for those who fight against her life is just like rowing against the stream.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "For to be afflicted with endless sorrow at the loss of someone very dear is foolish self-indulgence, and to feel none is inhuman callousness.", book = "", author = "Seneca" },
    { text = "For we are mistaken when we look forward to death; the major portion of death has already passed. Whatever years be behind us are in death's hands.", book = "", author = "Seneca" },
    { text = "For we are not summoned according to the paristi register And besides there is no man so old as to make it sinful to expect another day. Now every day is another step in life.", book = "", author = "Seneca" },
    { text = "For we must indeed have someone according to whom we may regulate our characters; you can never straighten that which is crooked unless you use a ruler.", book = "", author = "Seneca" },
    { text = "For what can be above the man who is above fortune?", book = "", author = "Seneca" },
    { text = "For what prevents us from saying that the happy life is to have a mind that is free, lofty, fearless and steadfast - a mind that is placed beyond the reach of fear, beyond the reach of desire, that counts virtue the only good, baseness the only evil, and all else but a worthless mass of things, which come and go without increasing or diminishing the highest good, and neither subtract any part from the happy life nor add any part to it? A man thus grounded must, whether he wills or not, necessarily be attended by constant cheerfulness and a joy that is deep and issues from deep within, since he finds delight in his own resources, and desires no joys greater than his inner joys.", book = "The Stoic Philosophy of Seneca: Essays and Letters", author = "Seneca" },
    { text = "For what purpose, then, do I make a man my friend? In order to have someone for whom I may die, whom I may follow into exile, against whose death I may stake my own life, and pay the pledge, too.", book = "", author = "Seneca" },
    { text = "For you have no reason to suppose that we come to grief more through the flattery of others than through our own.", book = "", author = "Seneca" },
    { text = "Fortune attacks us as often as we attack Fortune.  It.", book = "", author = "Seneca" },
    { text = "Fortune doesn’t have the long reach we suppose, she can only lay siege to those who hold her tight. So, let’s step back from her as much as possible.", book = "Moral Letters", author = "Seneca" },
    { text = "Fortune falls heavily on those for whom she’s unexpected. The one always on the lookout easily endures.", book = "On Consolation To Helvia", author = "Seneca" },
    { text = "Fortune recently took away her mother, but your love will mean that she will only grieve over her mother’s loss but not suffer for it.", book = "", author = "Seneca" },
    { text = "From this state also will he flee. If I should attempt to enumerate them one by one, I should not find a single one which could tolerate the wise man or which the wise man could tolerate.", book = "", author = "Seneca" },
    { text = "Furthermore, if you will pay close heed to the problem, you will find that the largest portion of our life passes while we are doing ill, a goodly share while we are doing nothing, and the whole while we are doing that which is not to the purpose.", book = "", author = "Seneca" },
    { text = "Gold tests with fire, woman with gold, man with woman.", book = "", author = "Seneca" },
    { text = "Good people will do what they find honorable to do, even if it requires hard work; they’ll do it even if it causes them injury; they’ll do it even if it will bring danger. Again, they won’t do what they find base, even if it brings wealth, pleasure, or power. Nothing will deter them from what is honorable, and nothing will lure them into what is base.", book = "Moral Letters", author = "Seneca" },
    { text = "Greed is satisfied by nothing, but nature finds satisfaction even in scant measure.", book = "", author = "Seneca" },
    { text = "Hang on to your youthful enthusiasms -- you’ll be able to use them better when you’re older.", book = "", author = "Seneca" },
    { text = "Happy is the man who can make others better, not merely when he is in their company, but even when he is in their thoughts!", book = "", author = "Seneca" },
    { text = "Harmony makes small things grow; lack of harmony makes great things decay.", book = "", author = "Seneca" },
    { text = "Having in mind not how bravely I was capable of dying but how far from bravely he was capable of bearing the loss, I commanded myself to live.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "He can’t serve in the military? Let him seek public office. Must he live in the private sector? Let him be a spokesperson. Is he condemned to silence? Let him aid his fellow citizens by silent public witness. Is it dangerous to enter the Forum? Let him display himself, in private homes, at public events and gatherings, as a good associate, faithful friend, and moderate tablemate. Has he lost the duties of a citizen? Let him exercise those of a human being.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "He is a slave.'' But shall that stand in his way? Show me a man who is not a slave; one is a slave to lust, another to greed, another to ambition, and all men are slaves to fear.", book = "Letters from a Stoic (Collins Classics) Paperback  “ 17 September 2020", author = "Seneca" },
    { text = "He is ungrateful who denies that he has received a kindness which has been bestowed upon him; he is ungrateful who conceals it; he is ungrateful who makes no return for it; most ungrateful of all is he who forgets it.", book = "", author = "Seneca" },
    { text = "He praised his own achievements, not without cause but without end.", book = "", author = "Seneca" },
    { text = "He suffers more than necessary, who suffers before it is necessary.", book = "", author = "Seneca" },
    { text = "He who boasts of his descent, praises the deeds of another.", book = "", author = "Seneca" },
    { text = "He who has injured thee was either stronger or weaker than thee. If weaker, spare him; if stronger, spare thyself.", book = "", author = "Seneca" },
    { text = "He who has made a fair compact with poverty is rich.", book = "", author = "Seneca" },
    { text = "He who is brave is free.", book = "", author = "Seneca" },
    { text = "He who needs riches least, enjoys riches most.", book = "", author = "Seneca" },
    { text = "He who restrains himself within the limits prescribed by nature, will not feel poverty; he who exceeds them will always be poor, however great his wealth may be.", book = "", author = "Seneca" },
    { text = "He who saw that everything depended on himself alone, who decided the fortune of individuals and nations, was happiest when thinking of that day on which he would lay aside his own greatness.", book = "", author = "Seneca" },
    { text = "He who spares the wicked injures the good.", book = "", author = "Seneca" },
    { text = "He will live ill who does not know how to die well.", book = "", author = "Seneca" },
    { text = "Hecato says, ‘cease to hope and you will cease to fear.’... The primary cause of both these ills is that instead of adapting ourselves to present circumstances we send out thoughts too far ahead.", book = "Moral Letters", author = "Seneca" },
    { text = "Hecato says, ‘I can teach you a love potion made without any drugs, herbs, or special spell—if you would be loved, love.’", book = "Moral Letters", author = "Seneca" },
    { text = "Hence the dictum of the greatest of doctors:† ‘Life is short, art is long.", book = "", author = "Seneca" },
    { text = "Heraclitus would shed tears whenever he went out in public—Democritus laughed. One saw the whole as a parade of miseries, the other of follies. And so, we should take a lighter view of things and bear them with an easy spirit, for it is more human to laugh at life than to lament it.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Here is your great soul ”the man who has given himself over to Fate; on the other hand, that man is a weakling and a degenerate who struggles and maligns the order of the universe and would rather reform the gods than reform himself.", book = "Letters From A Stoic: Epistulae Morales AD Lucilium (Illustrated. Newly revised text. Includes Image Gallery + Audio): All Three Volumes", author = "Seneca" },
    { text = "Here’s a lesson to test your mind’s mettle: take part of a week in which you have only the most meager and cheap food, dress scantly in shabby clothes, and ask yourself if this is really the worst that you feared. It is when times are good that you should gird yourself for tougher times ahead, for when Fortune is kind the soul can build defenses against her ravages. So it is that soldiers practice maneuvers in peacetime, erecting bunkers with no enemies in sight and exhausting themselves under no attack so that when it comes they won’t grow tired.", book = "Moral Letters", author = "Seneca" },
    { text = "His last words heard on earth came after he'd let off a louder noise from his easiest channel of communication: 'Oh my! I think I've shit myself.' For all I know, he did. He certainly shat on everything else.", book = "", author = "Seneca" },
    { text = "Hold fast, then, to this sound and wholesome rule of life - that you indulge the body only so far as is needful for good health. The body should be treated more rigorously, that it may not be disobedient to the mind.", book = "", author = "Seneca" },
    { text = "Honours, monuments, whatever the ambitious have ordered by decrees or raised in public buildings are soon destroyed: there is nothing that the passage of time does not demolish and remove.", book = "", author = "Seneca" },
    { text = "How can you wonder your travels do you no good, when you carry yourself around with you? You are saddled with the very thing that drove you away.", book = "", author = "Seneca" },
    { text = "How closely flattery resembles friendship! It not only apes friendship, but outdoes it, passing it in the race; with wide-open and indulgent ears it is welcomed and sinks to the depths of the heart, and it is pleasing precisely wherein it does harm.", book = "", author = "Seneca" },
    { text = "How disgraceful is the lawyer whose dying breath passes while at court, at an advanced age, pleading for unknown litigants and still seeking the approval of ignorant spectators.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "How does it help, my husband, to make misfortune heavier by complaining about it? This is more fit for a king—to seize your adversities head on. The more precarious his situation, the more imminent his fall from power, the more firmly he should be resolved to stand and fight. It isn’t manly to retreat from fortune.", book = "Oedipus", author = "Seneca" },
    { text = "How late it is to begin living only when one must stop!", book = "", author = "Seneca" },
    { text = "How late it is to begin really to live just when life must end! How stupid to forget our mortality, and put off sensible plans to our fiftieth and sixtieth years, aiming to begin life from a point at which few have arrived!", book = "", author = "Seneca" },
    { text = "How long will this last?’ This feeling has caused kings to bewail their power, and they were not so much delighted by the greatness of their fortune as terrified by the thought of its inevitable end.", book = "", author = "Seneca" },
    { text = "How many have laid waste to your life when you weren’t aware of what you were losing, how much was wasted in pointless grief, foolish joy, greedy desire, and social amusements—how little of your own was left to you. You will realize you are dying before your time!", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "How much better it is that you defeat anger than that it defeats itself!", book = "", author = "Seneca" },
    { text = "How much better to follow a straight course and attain a goal where the words  pleasant  and  honourable  have the same meaning!", book = "", author = "Seneca" },
    { text = "How much better to heal than seek revenge from injury. Vengeance wastes a lot of time and exposes you to many more injuries than the first that sparked it. Anger always outlasts hurt. Best to take the opposite course. Would anyone think it normal to return a kick to a mule or a bite to a dog?", book = "On Anger", author = "Seneca" },
    { text = "How much happier is the man who owes nothing to anybody except the one he can most easily refuse, himself!", book = "", author = "Seneca" },
    { text = "How silly then to imagine that the human mind, which is formed of the same elements as divine beings, objects to movement and change of abode, while the divine nature finds delight and even self-preservation in continual and very rapid change.", book = "", author = "Seneca" },
    { text = "However much you possess there's someone else who has more, and you'll be fancying yourself to be short of things you need to exact extent to which you lag behind him.", book = "", author = "Seneca" },
    { text = "Humanity is the quality which stops one being arrogant towards one's fellows, or being acrimonious.", book = "", author = "Seneca" },
    { text = "Hurry up and live.", book = "", author = "Seneca" },
    { text = "I am acting on behalf of later generations. I am writing down a few things that may be of use to them.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "I am loath to call clemency what was, rather, the exhaustion of cruelty.", book = "", author = "Seneca" },
    { text = "I am not a ‘wise man,’ nor . . . shall I ever be. And so require not from me that I should be equal to the best, but that I should be better than the wicked. It is enough for me if every day I reduce the number of my vices, and blame my mistakes.", book = "", author = "Seneca" },
    { text = "I am, however, discussing with you troubles which concern us both, and sharing the remedy with you, just as if we were lying ill in the same hospital. Listen to me, therefore, as you would if I were talking to myself. .", book = "", author = "Seneca" },
    { text = "I can show you a philtre, compounded without drugs, herbs, or any witch's incantation: 'If you want to be loved, love.", book = "", author = "Seneca" },
    { text = "I don’t agree with those who plunge headlong into the middle of the flood and who, accepting a turbulent life, struggle daily in great spirit with difficult circumstances. The wise person will endure that, but won’t choose it—choosing to be at peace, rather than at war.", book = "Moral Letters", author = "Seneca" },
    { text = "I don’t complain about the lack of time... what little I have will go far enough. Today—this day—will achieve what no tomorrow will fail to speak about. I will lay siege to the gods and shake up the world.", book = "Medea", author = "Seneca" },
    { text = "I examine my entire day and go back over what I have done and said, hiding nothing from myself, passing nothing by. For why should I fear any consequence from my mistakes, when I am able to say, See that you do not do it again ”but now I forgive you.", book = "How to Do the Right Thing: An Ancient Guide to Treating People Fairly", author = "Seneca" },
    { text = "I have learned to be a friend to myself Great improvement this indeed Such a one can never be said to be alone for know that he who is a friend to himself is a friend to all mankind.", book = "", author = "Seneca" },
    { text = "I have never wished to cater to the crowd; for what I know, they do not approve, and what they approve, I do not know.", book = "", author = "Seneca" },
    { text = "I have, I hold whatever of mine I have ever had. There is no reason for you to suppose me conquered and yourself my conqueror. It is your fortune which has overcome mine. As for those fleeting possessions which change their owners, I know not where they are; what belongs to myself is with me, and ever will be.", book = "", author = "Seneca" },
    { text = "I imagine many people could have achieved wisdom if they had not imagined they had already achieved it, if they had not dissembled about some of their own characteristics and turned a blind eye to others.", book = "", author = "Seneca" },
    { text = "I judge you unfortunate because you have never lived through misfortune. You have passed through life without an opponent—no one can ever know what you are capable of, not even you.", book = "On Providence", author = "Seneca" },
    { text = "I know that these mental disturbances of mine are not dangerous and give no promise of a storm; to express what I complain of in apt metaphor, I am distressed, not by a tempest, but by sea-sickness.", book = "", author = "Seneca" },
    { text = "I may wish to be free from torture, but if the time comes for me to endure it, I’ll wish to bear it courageously with bravery and honor. Wouldn’t I prefer not to fall into war? But if war does befall me, I’ll wish to carry nobly the wounds, starvation, and other necessities of war. Neither am I so crazy as to desire illness, but if I must suffer illness, I’ll wish to do nothing rash or dishonorable. The point is not to wish for these adversities, but for the virtue that makes adversities bearable.", book = "Moral Letters", author = "Seneca" },
    { text = "I never spend a day in idleness; I appropriate even a part of the night for study. I do not allow time for sleep but yield to it when I must, and when my eyes are wearied with waking and ready to fall shut, I keep them at their task.", book = "", author = "Seneca" },
    { text = "I realize that these mental agitations of mine are not dangerous and won’t produce a storm. To express my complaint for you in a realistic metaphor, I am harried not by a tempest but by sea-sickness.", book = "", author = "Seneca" },
    { text = "I say, let no one rob me of a single day who isn’t going to make a full return on the loss.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "I shall expose and reopen all the wounds which have already healed.", book = "", author = "Seneca" },
    { text = "I shall never be ashamed of citing a bad author if the line is good.", book = "", author = "Seneca" },
    { text = "I shall never be ashamed to go to a bad author for a good quotation.", book = "", author = "Seneca" },
    { text = "I shall use the old road, but if I find a shorter and easier one I shall open it up. [...] Truth lies open to everyone.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "I think the pinnacle of misfortune is to be forced by chance to want things one should loathe.", book = "", author = "Seneca" },
    { text = "I was shipwrecked before I even boarded... the journey showed me this—how much of what we have is unnecessary, and how easily we can decide to rid ourselves of these things whenever it’s necessary, never suffering the loss.", book = "Moral Letters", author = "Seneca" },
    { text = "I will keep a watch on myself straightway and ”the most useful step ”review my day. The fact that we do not look back over our lives makes us worse. We ponder ”though rarely ”what we are to do, but we do not ponder at all what we have done ”and yet planning for the future depends on the past.", book = "Epistles 66-92", author = "Seneca" },
    { text = "I will keep constant watch over myself and—most usefully—will put each day up for review. For this is what makes us evil—that none of us looks back upon our own lives. We reflect upon only that which we are about to do. And yet our plans for the future descend from the past.", book = "Moral Letters", author = "Seneca" },
    { text = "I will storm the gods, and shake the universe.", book = "", author = "Seneca" },
    { text = "I wish Lucilius you had been so happy as to have taken this resolution long ago I wish we had not deferred to think of an happy life till now we are come within light of death But let us delay no longer.", book = "", author = "Seneca" },
    { text = "I’ll never be ashamed to quote a bad writer with a good saying.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "If a great man falls and remains great as he lies, people no more despise him than they stamp on a fallen temple, which the devout still worship as much as when it was standing.", book = "", author = "Seneca" },
    { text = "If a man knows not to which port he sails, no wind is favorable.", book = "", author = "Seneca" },
    { text = "If an evil has been pondered beforehand, the blow is gentle when it comes.", book = "", author = "Seneca" },
    { text = "If ever you want to find out whether anything has been achieved, observe whether your intentions are the same today as they were yesterday. A change of intention shows that the mind is at sea, drifting here and there as carried by the wind.", book = "stoicism", author = "Seneca" },
    { text = "If i had not been admitted to these studies it would not have been worth while to have been born.", book = "", author = "Seneca" },
    { text = "If the breaking day sees someone proud, The ending day sees them brought low. No one should put too much trust in triumph, No one should give up hope of trials improving. Clotho mixes one with the other and stops Fortune from resting, spinning every fate around. No one has had so much divine favor that they could guarantee themselves tomorrow. God keeps our lives hurtling on, Spinning in a whirlwind.", book = "Thyestes", author = "Seneca" },
    { text = "If we do not want to be overwhelmed and struck numb by rare events as if they were unprecedented ones; fortune needs envisaging in a thoroughly comprehensive way.", book = "", author = "Seneca" },
    { text = "If what you have seems insufficient to you, then though you possess the world, you will yet be miserable.", book = "stoicism", author = "Seneca" },
    { text = "If wisdom were offered me on the one condition that I should keep it shut away and not divulge it to anyone, I should reject it. There is no enjoying the possession of anything valuable unless one has someone to share it with.", book = "", author = "Seneca" },
    { text = "If you admit to having derived great pleasures, your duty is not to complain about what has been taken away but to be thankful for what you have been given.", book = "stoicism", author = "Seneca" },
    { text = "If you apply yourself to study you will avoid all boredom with life, you will not long for night because you are sick of daylight, you will be neither a burden to yourself nor useless to others, you will attract many to become your friends and the finest people will flock about you.", book = "", author = "Seneca" },
    { text = "If you gain from a crime, you did it.", book = "", author = "Seneca" },
    { text = "If you have nothing to stir you up and rouse you to action, nothing which will test your resolution by its threats and hostilities; if you recline in unshaken comfort, it is not tranquillity; it is merely a flat calm.", book = "", author = "Seneca" },
    { text = "If you live according to nature, you will never be poor; if you live according to opinion, you will never be rich.", book = "", author = "Seneca" },
    { text = "If you live in harmony with nature you will never be poor; if you live according what others think, you will never be rich.", book = "", author = "Seneca" },
    { text = "If you look on wealth as a thing to be valued you’ll always fancy yourself to be short of the things you need to the extent to which you lag behind what others have.", book = "", author = "Seneca" },
    { text = "What good does it do you to go overseas, to move from city to city? If you really want to escape the things that harass you, what you're needing is not to be in a different place but to be a different person.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "If you regard your last day not as a punishment but as a law of nature, the breast from which you have banished the dread of death no fear will dare to enter.", book = "", author = "Seneca" },
    { text = "If you want to keep a secret, never share it.", book = "", author = "Seneca" },
    { text = "If you wish Pythocles to have pleasure for ever, do not add to his pleasures, but subtract from his desires.", book = "", author = "Seneca" },
    { text = "If you wish to be loved, love.", book = "", author = "Seneca" },
    { text = "If you wish to fear nothing, consider that all things are to be feared.", book = "", author = "Seneca" },
    { text = "If you wish to have leisure for your mind, either be a poor man, or resemble a poor man.", book = "", author = "Seneca" },
    { text = "If you wish to make Pythocles an old man, filling his life to the full, do not add to his years, but subtract from his desires.", book = "", author = "Seneca" },
    { text = "If you wish to put off all worry, assume that what you fear may happen is certainly going to happen.", book = "", author = "Seneca" },
    { text = "If you would escape your troubles, you need not another place but another personality.", book = "", author = "Seneca" },
    { text = "If you would not have a man flinch when the crisis comes, train him before it comes.", book = "", author = "Seneca" },
    { text = "Ignorance is no cure for suffering.", book = "", author = "Seneca" },
    { text = "Timendi causa est nescire -  Ignorance is the cause of fear.", book = "", author = "Seneca" },
    { text = "In a man praise is due only to what is his very own. Suppose he has a beautiful home and a handsome collection of servants, a lot of land under cultivation and a lot of money out at interest; not one of these things can be said to be in him  “ they are just things around him. Praise in him what can neither be given nor snatched away, what is peculiarly a man's. You ask what that is? It is his spirit, and the perfection of his reason in that spirit.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "In all things we should try to make ourselves be as grateful as possible. For gratitude is a good thing for ourselves, in a manner in which justice, commonly held to belong to others, is not. Gratitude pays itself back in large measure.", book = "Moral Letters", author = "Seneca" },
    { text = "In every good person, there lives a god. Which god? We cannot be sure - but it is a god.", book = "", author = "Seneca" },
    { text = "In guarding their fortune men are often closefisted, yet, when it comes to the matter of wasting time, in the case of the one thing in which it is right to be miserly, they show themselves most prodigal.", book = "", author = "Seneca" },
    { text = "In protecting their wealth men are tight-fisted, but when it comes to the matter of time, in the case of the one thing in which it is wise to be parsimonious, they are actually generous to a fault.", book = "", author = "Seneca" },
    { text = "In the ashes all men are levelled. We're born unequal, we die equal.", book = "", author = "Seneca" },
    { text = "In the meantime, cling tooth and nail to the following rule: not to give in to adversity, not to trust prosperity, and always take full note of fortune’s habit of behaving just as she pleases.", book = "", author = "Seneca" },
    { text = "In times of happiness, no point in shaking things up. But in a time of crisis, the safest thing is change.", book = "", author = "Seneca" },
    { text = "Indulge the body just so far as suffices for good health. It needs to be treated somewhat strictly to prevent it from being disobedient to the spirit. Your food should appease your hunger, your drink quench your thirst, your clothing keep out the cold, your house be a protection against inclement weather.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Inflicted.", book = "", author = "Seneca" },
    { text = "Injustice never rules forever.", book = "", author = "Seneca" },
    { text = "Inwardly, we ought to be different in every respect, but our outward dress should blend in with the crowd.", book = "Moral Letters", author = "Seneca" },
    { text = "Istam terra de fossam premat, gravisque terrus impio capiti incubet! (As for her, let her be buried deep in earth, and heavy may the soil lie on her unholy head.).", book = "", author = "Seneca" },
    { text = "It does good also to take walks out of doors, that our spirits may be raised and refreshed by the open air and fresh breeze: sometimes we gain strength by driving in a carriage, by travel, by change of air, or by social meals and a more generous allowance of wine.", book = "", author = "Seneca" },
    { text = "It does not make any difference what a man say; what matters is how he feels, and not how he feels on one particular day but how he feels at all times.", book = "", author = "Seneca" },
    { text = "It does not matter how many books you have, but how good the books are which you have.", book = "", author = "Seneca" },
    { text = "It is a denial of justice not to stretch out a helping hand to the fallen; that is the common right of humanity.", book = "", author = "Seneca" },
    { text = "It is a great man that can treat his earthenware as if it was silver, and a man who treats his silver as if it was earthenware is no less great.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "It is a great thing to know the season for speech and the season for silence.", book = "", author = "Seneca" },
    { text = "It is a question whether he died by his own hand; for he fell from a sudden wound received in his groin, some doubting whether his death was voluntary, no one, whether it was timely.", book = "", author = "Seneca" },
    { text = "It is a rough road that leads to the heights of greatness.", book = "", author = "Seneca" },
    { text = "It is a small part of life we really live.’ Indeed, all the rest is not life but merely time.", book = "", author = "Seneca" },
    { text = "It is better to be despised for simplicity than to suffer agonies from everlasting pretense.", book = "Dialogues and Letters", author = "Seneca" },
    { text = "It is better to conquer our grief than to deceive it.", book = "", author = "Seneca" },
    { text = "It is better to understand the balance-sheet of one’s own life than of the corn trade.", book = "", author = "Seneca" },
    { text = "It is in no man's power to have whatever he wants, but he has it in his power not to wish for what he hasn't got, and cheerfully make the most of the things that do come his way.", book = "", author = "Seneca" },
    { text = "It is in times of security that the spirit should be preparing itself for difficult times; while fortune is bestowing favors on it is then is the time for it to be strengthened against her rebuffs.", book = "", author = "Seneca" },
    { text = "It is inevitable that life will be not just very short but very miserable for those who acquire by great toil what they must keep by greater toil. They achieve what they want laboriously; they possess what they have achieved anxiously; and meanwhile they take no account of time that will never more return. New preoccupations take the place of the old, hope excites more hope and ambition more ambition. They do not look for an end to their misery, but simply change the reason for it.", book = "On the Shortness of Life: Life Is Long if You Know How to Use It", author = "Seneca" },
    { text = "It is more civilized to make fun of life than to bewail it.", book = "", author = "Seneca" },
    { text = "It's not because things are difficult that we dare not venture. It's because we dare not venture that they are difficult.", book = "", author = "Seneca" },
    { text = "It is not that we have a short time to live, but that we waste a lot of it. Life is long enough, and a sufficiently generous amount has been given to us for the highest achievements if it were all well invested.", book = "", author = "Seneca" },
    { text = "It is not that we have so little time but that we lose so much. The life we receive is not short but we make it so; we are not ill provided but use what we have wastefully.", book = "", author = "Seneca" },
    { text = "It is not the man who has too little who is poor, but the one who hankers after more.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "It is not what you endure that matters, but how you endure it.", book = "", author = "Seneca" },
    { text = "It is of course better to know useless things than to know nothing.", book = "", author = "Seneca" },
    { text = "It is only in the ideal or perfect state that the virtues of the good citizen and the good man are identical.", book = "", author = "Seneca" },
    { text = "It is our conscience, not our pride, that has put doorkeepers at our doors.", book = "", author = "Seneca" },
    { text = "It is precisely in times of immunity from care that the soul should toughen itself beforehand for occasions of greater stress, and it is while Fortune is kind that it should fortify itself against her violence.", book = "", author = "Seneca" },
    { text = "It is quality rather than quantity that matters.", book = "", author = "Seneca" },
    { text = "It is shameful to hate a person who deserves your praises; but how much more shameful it is to hate someone for the very cause that makes him deserve your pity.", book = "", author = "Seneca" },
    { text = "It is so, my dear Lucilius; there are a few men whom slavery holds fast, but there are many more who hold fast to slavery.", book = "", author = "Seneca" },
    { text = "It is sweet to draw the world down with you when you are perishing.", book = "", author = "Seneca" },
    { text = "It is the evil mind that gets first hold on all of us.  Learning virtue means unlearning vice.  We.", book = "", author = "Seneca" },
    { text = "It is the mind that creates our wealth, and this goes with us into exile, and in the harshest desert places it finds sufficient to nourish the body and revels in the enjoyment of its own goods.", book = "", author = "Seneca" },
    { text = "It is the power of the mind to be unconquerable.", book = "The Stoic Philosophy of Seneca: Essays and Letters", author = "Seneca" },
    { text = "It is the quality of a great soul to scorn great things and to prefer that which is ordinary rather than that which is too great.", book = "", author = "Seneca" },
    { text = "It is the sign of a weak mind to be unable to bear wealth.", book = "", author = "Seneca" },
    { text = "It is the superfluous things for which men sweat, – the superfluous things that wear our togas threadbare, that force us to grow old in camp, that dash us upon foreign shores. That which is enough is ready to our hands.", book = "", author = "Seneca" },
    { text = "'It is unbearable to be deprived of your country.' Come now, look at this mass of people whom the buildings of huge Rome can scarcely hold: most of that crowd are deprived of their country.", book = "", author = "Seneca" },
    { text = "It is uncertain where Death will await you; there expect it everywhere.", book = "", author = "Seneca" },
    { text = "It is while Fortune is kind that it should fortify itself against her violence.", book = "", author = "Seneca" },
    { text = "It is wrong not to stretch out your hand to the fallen: that is a common law of the human race.", book = "", author = "Seneca" },
    { text = "It is wrong to live under constraint; but no man is constrained to live under constraint.", book = "", author = "Seneca" },
    { text = "It makes no difference how important the provocation may be, but into what kind of soul it penetrates. Similarly with fire; it does not matter how great is the flame, but what it falls upon.", book = "", author = "Seneca" },
    { text = "It matters not how long the action is spun out, but how good the acting is", book = "", author = "Seneca" },
    { text = "It should be our care not so much to live a long life as a satisfactory one.", book = "", author = "Seneca" },
    { text = "It takes all of our life to learn how to live, and – something that may surprise you more – it takes just as long to learn how to die.", book = "", author = "Seneca" },
    { text = "It takes the whole of life to learn how to live... it takes the whole of life to learn how to die.", book = "On the Shortness of Life: Adapted for the Contemporary Reader", author = "Seneca" },
    { text = "It takes you more time to solve a problem than to set it.", book = "", author = "Seneca" },
    { text = "We are born under circumstances that would be favorable if we did not abandon them. It was nature's intention that there should be no need of great equipment for a good life: every individual can make himself happy.", book = "", author = "Seneca" },
    { text = "It’s in keeping with Nature to show our friends affection and to celebrate their advancement, as if it were our very own. For if we don’t do this, virtue, which is strengthened only by exercising our perceptions, will no longer endure in us.", book = "Moral Letters", author = "Seneca" },
    { text = "It’s not at all that we have too short a time to live, but that we squander a great deal of it. Life is long enough, and it’s given in sufficient measure to do many great things if we spend it well. But when it’s poured down the drain of luxury and neglect, when it’s employed to no good end, we’re finally driven to see that it has passed by before we even recognized it passing. And so it is—we don’t receive a short life, we make it so.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "It’s not that we have a short time to live, but that we waste a lot of it.” -Lucius Annaeus Seneca.", book = "", author = "Seneca" },
    { text = "It’s ruinous for the soul to be anxious about the future and miserable in advance of misery, engulfed by anxiety that the things it desires might remain its own until the very end. For such a soul will never be at rest—by longing for things to come it will lose the ability to enjoy present things.", book = "Moral Letters", author = "Seneca" },
    { text = "It's easier to get philosophers to agree than clocks.", book = "", author = "Seneca" },
    { text = "It's not that we have a short time to live, but that we waste much of it. Life is long enough, and it's been given to us in generous measure for accomplishing the greatest things, if the whole of it is well invested.", book = "", author = "Seneca" },
    { text = "It's not that we have little time, but more that we waste a good deal of it.", book = "", author = "Seneca" },
    { text = "It's only when you're breathing your last that the way you've spent your time will become apparent, I accept the terms, and feel no dread of the coming judgment.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Just as great and princely wealth is scattered in a moment when it comes into the hands of a bad owner, while wealth however limited, if it is entrusted to a good guardian, increases by use, so our life is amply long for him who orders it properly.", book = "", author = "Seneca" },
    { text = "Kingdoms which act unjustly never last.", book = "", author = "Seneca" },
    { text = "Kings hate to hear the things they order spoken.", book = "", author = "Seneca" },
    { text = "Lay hold of today's task, and you will not need to depend so much upon to-morrow's. While we are postponing, life speeds by.", book = "", author = "Seneca" },
    { text = "Leisure without books is death, and burial of a man alive.", book = "", author = "Seneca" },
    { text = "Leisure without study is death; it is a tomb for the living man.", book = "", author = "Seneca" },
    { text = "Let all your efforts be directed to something, let it keep that end in view. It’s not activity that disturbs people, but false conceptions of things that drive them mad.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Let Fate find us prepared and active. Here is the great soul—the one who surrenders to Fate. The opposite is the weak and degenerate one, who struggles with and has a poor regard for the order of the world, and seeks to correct the faults of the gods rather than their own.", book = "Moral Letters", author = "Seneca" },
    { text = "Let me indicate here how men can prove that their words are their own: let them put their preaching into practice", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Let my mind be fixed on itself, cultivate itself, have no external interest – nothing that seeks the approval of another; let it cherish the tranquillity that has no part in public or private concerns.", book = "", author = "Seneca" },
    { text = "Let Nature make whatever use she pleases of matter, which is her own: lets us be cheerful and brave in the face of all, and consider that nothing of our own perishes. What is the duty of a good man? To offer himself to fate.", book = "Dialogues and Essays", author = "Seneca" },
    { text = "Let tears flow of their own accord: their flowing is not inconsistent with inward peace and harmony.", book = "", author = "Seneca" },
    { text = "Let us also produce some bold act of our own—and join the ranks of the most emulated.", book = "Moral Letters", author = "Seneca" },
    { text = "Let us be brave in the face of hazards. Let us not fear wrongs, or wounds, or bonds, or poverty. And what is death? It is either the end, or a process of change.", book = "", author = "Seneca" },
    { text = "Let us get used to dining out without the crowds, to being a slave to fewer slaves, to getting clothes only for their real purpose, and to living in more modest quarters.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Let us keep to the way which Nature has mapped out for us, and let us not swerve therefrom. If we follow Nature, all is easy and unobstructed; but if we combat Nature, our life differs not a whit from that of men who row against the current.", book = "", author = "Seneca" },
    { text = "Let us prepare our minds as if we’d come to the very end of life. Let us postpone nothing. Let us balance life’s books each day.... The one who puts the finishing touches on their life each day is never short of time.", book = "Moral Letters", author = "Seneca" },
    { text = "Let us say what we feel, and feel what we say; let speech harmonize with life.", book = "", author = "Seneca" },
    { text = "Let us take pleasure in what we have received and make no comparison; no man will ever be happy if tortured by the greater happiness of another.", book = "", author = "Seneca" },
    { text = "Let us therefore set out whole-heartedly, leaving aside our many distractions and exert ourselves in this single purpose, before we realize too late the swift and unstoppable flight of time and are left behind. As each day arises, welcome it as the very best day of all, and make it your own possession. We must seize what flees.", book = "Moral Letters", author = "Seneca" },
    { text = "Let us too overcome all things, with our reward consisting not in any wreath or garland, not in trumpet-calls for silence for the ceremonial proclamation of our name, but in moral worth, in strength of spirit, in a peace that is won for ever once in any contest fortune has been utterly defeated.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Let’s pass over to the really rich—how often the occasions they look just like the poor! When they travel abroad they must restrict their baggage, and when haste is necessary, they dismiss their entourage. And those who are in the army, how few of their possessions they get to keep...", book = "On Consolation To Helvia", author = "Seneca" },
    { text = "Life is divided into three periods, past, present and future. Of these, the present is short, the future is doubtful, the past is certain. For this last is the one over which Fortune has lost her power, which cannot be brought back to anyone's control. But this is what preoccupied people lose: for they have no time to look back at their past, and even if they did, it is not pleasant to recall activities they are ashamed of.", book = "On the Shortness of Life: Life Is Long if You Know How to Use It", author = "Seneca" },
    { text = "Life is like a play: it's not the length, but the excellence of the acting that matters.", book = "", author = "Seneca" },
    { text = "Life is long and there is enough of it for satisfying personal accomplishments if we use our hours well.", book = "", author = "Seneca" },
    { text = "Life is long enough, and it has been given in sufficiently generous measure to allow the accomplishment of the very greatest things if the whole of it is well invested.", book = "", author = "Seneca" },
    { text = "Life is long, if only you knew how to use it.", book = "", author = "Seneca" },
    { text = "Life is not worth living, and there is no limit to our sorrows, if we indulge our fears to the greatest possible extent.", book = "", author = "Seneca" },
    { text = "Life is short but life is long", book = "stoicism", author = "Seneca" },
    { text = "Life is slavery if the courage to die is absent.", book = "", author = "Seneca" },
    { text = "Life without a design is erratic. As soon as one is in place, principles become necessary. I think you’ll concede that nothing is more shameful than uncertain and wavering conduct, and beating a cowardly retreat. This will happen in all our affairs unless we remove the faults that seize and detain our spirits, preventing them from pushing forward and making an all-out effort.", book = "Moral Letters", author = "Seneca" },
    { text = "Life, if you know how to use it, is long; but…many, following no fixed aim, shifting and… dissatisfied, are plunged by their fickleness into plans that are ever new; some have no fixed principle by which to direct their course.", book = "", author = "Seneca" },
    { text = "Life’s finest day for wretched mortals here Is always first to flee.", book = "", author = "Seneca" },
    { text = "Light griefs are loquacious, but the great are dumb.", book = "", author = "Seneca" },
    { text = "Limiting one's desires actually helps to cure one of fear. 'Cease to hope 'and you will cease to fear.' 'Widely different [as fear and hope] are, the two of them march in unison like a prisoner and the escort he is handcuffed to. Fear keeps pace with hope 'both belong to a mind in suspense, to a mind in a state of anxiety through looking into the future. Both are mainly due to projecting our thoughts far ahead of us instead of adapting ourselves to the present.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Linger among a limited number of master thinkers, and digest their works.", book = "", author = "Seneca" },
    { text = "Lives such as yours ”how true it is! ”though they should exceed a thousand years, will contract into the smallest span: but those vices of yours will swallow up any amount of time. This length of time you have, that reason prolongs, however swift nature makes its sojourn, is bound to pass quickly through your fingers; for you do not grasp it, or seek to hold on to it, or try to delay the passing of the swiftest thing of all, but allow it to depart, as if it were something surplus to requirement and easily replaced.", book = "On the Shortness of Life", author = "Seneca" },
    { text = "Living is the least important activity of the preoccupied man.", book = "", author = "Seneca" },
    { text = "Long association brings love of evil as well as good.", book = "", author = "Seneca" },
    { text = "Longing for the future and weariness of the present.", book = "", author = "Seneca" },
    { text = "Love of bustle is not industry.", book = "", author = "Seneca" },
    { text = "Love sometimes injures. Friendship always benefits, After friendship is formed you must trust, but before that you must judge.", book = "", author = "Seneca" },
    { text = "Luck is what happens when preparation meets opportunity.", book = "", author = "Seneca" },
    { text = "Making noble resolutions is not as important as keeping the resolutions you have made already. (Letter XVI)", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Mankind is perpetually the victim of a pointless and futile martydom, fretting life away in fruitless worries though failure to realise what limit is set to acquisition and to the growth of genuine pleasure.", book = "", author = "Seneca" },
    { text = "Many are harmed by fear itself, and many may have come to their fate while dreading fate.", book = "Oedipus", author = "Seneca" },
    { text = "Many are the things that have caused terror during the night and been turned into matters of laughter with the coming of daylight.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Many pursue no fixed goal, but are tossed about in ever-changing designs by a fickleness which is shifting, inconstant and never satisfied with itself.", book = "", author = "Seneca" },
    { text = "Many times an old man has no other evidence besides his age to prove he has lived a long time.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Many words have been spoken by Plato, Zeno, Chrysippus, Posidonius, and by a whole host of equally excellent Stoics. I’ll tell you how people can prove their words to be their own—by putting into practice what they’ve been preaching.", book = "Moral Letters", author = "Seneca" },
    { text = "Maximum remedium est irae mora.", book = "", author = "Seneca" },
    { text = "me dulcis saturet quies; obscuro positus loco leni perfruar otio, nullis nota Quiritibus aetas per tacitum fluat. sic cum transierint mei nullo cum strepitu dies. plebeius moriar senex. illi mors gravis incubat qui, notus nimis omnibus, ignotus moritur sibi.", book = "Thyestes", author = "Seneca" },
    { text = "Meanwhile, as they rob and are robbed, as they disturb each other’s peace, as they make each other miserable, their lives pass without satisfaction, without pleasure, without mental improvement.", book = "", author = "Seneca" },
    { text = "Men are not made restless by activity but driven to madness by false impressions of reality.", book = "", author = "Seneca" },
    { text = "Men are so thoughtless, nay, so mad, that some, through fear of death, force themselves to die.", book = "", author = "Seneca" },
    { text = "Men are tight-fisted in keeping control of their fortunes, but when it comes to the matter of wasting time, they are positively extravagant in the one area where there is honour in being miserly.", book = "", author = "Seneca" },
    { text = "Men do not care how nobly they live, but only for how long, although it is within the reach of every man to live nobly, but within no man’s power to live long.", book = "", author = "Seneca" },
    { text = "Men learn as they teach.", book = "", author = "Seneca" },
    { text = "Men love their country, not because it is great, but because it is their own.", book = "", author = "Seneca" },
    { text = "Men whose spirit has grown arrogant from the great favor of fortune have this most serious fault—those whom they have injured they also hate.", book = "", author = "Seneca" },
    { text = "More active and commendable still is the person who is waiting for the daylight and intercepts the first rays of the sun; shame on him who lies in bed dozing when the sun is high in the sky, whose waking hours commence in the middle of the day.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Most men ebb and flow in wretchedness between the fear of death and the hardships of life; they are unwilling to live, and yet they do not know how to die. .", book = "", author = "Seneca" },
    { text = "Most powerful is he who has himself in his own power.", book = "", author = "Seneca" },
    { text = "My advice is really this: what we hear the philosophers saying and what we find in their writings should be applied in our pursuit of the happy life. We should hunt out the helpful pieces of teaching, and the spirited and noble-minded sayings which are capable of immediate practical application ”not far-fetched or archaic expressions or extravagant metaphors and figures of speech ”and learn them so well that words become works. No one to my mind lets humanity down quite so much as those who study philosophy as if it were a sort of commercial skill and then proceed to live in a quite different manner from the way they tell other people to live.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Natural abilities do not respond well to compulsion; when Nature is in opposition, labour is fruitless.", book = "", author = "Seneca" },
    { text = "Nature does not reveal her mysteries once and for all.", book = "", author = "Seneca" },
    { text = "Nero:  Am I forbidden to do what all may do?  Seneca:  From high rank high example is expected. ", book = "", author = "Seneca" },
    { text = "Never will there be a shortage of reasons for anxiety, whether born of happiness or misery; life will press on its way from one pursuit to another; leisure will never be enjoyed, though the prayer is constantly on our lips.", book = "", author = "Seneca" },
    { text = "New preoccupations take the place of the old, hope excites more hope and ambition more ambition. They do not look for an end to their misery, but simply change the reason for it.", book = "", author = "Seneca" },
    { text = "Night brings our troubles to the light rather than banishes them.", book = "", author = "Seneca" },
    { text = "No condition is so distressing that a balanced mind cannot find some comfort in it.", book = "", author = "Seneca" },
    { text = "No delicate breeze brings comfort with icy breath of wind to the hearts which pant on the flames.", book = "", author = "Seneca" },
    { text = "No genius that ever won acclaim did so without a measure of indulgence. Name me any man you like who had a celebrated reputation, and I’ll tell you what the age he lived in forgave him, what it turned a blind eye to in his work.", book = "", author = "Seneca" },
    { text = "No good thing renders its possessor happy, unless his mind is reconciled to the possibility of loss.", book = "", author = "Seneca" },
    { text = "No man can be sane who searches for what will injure him in place of what is best.", book = "", author = "Seneca" },
    { text = "No man can have a peaceful life who thinks too much about lengthening it.", book = "", author = "Seneca" },
    { text = "No man can live a happy life, or even a supportable life, without the study of wisdom.", book = "", author = "Seneca" },
    { text = "No man finds it difficult to return to nature, except the man who has deserted nature.  We.", book = "", author = "Seneca" },
    { text = "No man has been shattered by the blows of Fortune unless he was first deceived by her favours.", book = "", author = "Seneca" },
    { text = "No man has escaped paying the penalty for being born.", book = "", author = "Seneca" },
    { text = "No man is crushed by misfortune unless he has first been deceived by prosperity.", book = "", author = "Seneca" },
    { text = "No man is despised by another unless he is first despised by himself.", book = "", author = "Seneca" },
    { text = "No man is good by chance. Virtue is something which must be learned.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "No man is more unhappy than he who never faces adversity. For he is not permitted to prove himself.", book = "", author = "Seneca" },
    { text = "No man is so faint-hearted that he would rather hang in suspense for ever than drop once for all.", book = "", author = "Seneca" },
    { text = "No man was ever wise by chance.", book = "", author = "Seneca" },
    { text = "No man, if he be ungrateful, will be unhappy in the future. I allow him no day of grace; he is unhappy forthwith.", book = "", author = "Seneca" },
    { text = "No man’s good by accident. Virtue has to be learnt.", book = "", author = "Seneca" },
    { text = "No one becomes a laughingstock who laughs at himself.", book = "", author = "Seneca" },
    { text = "No one can live happily who has regard for himself alone and transforms everything into a question of his own utility.", book = "", author = "Seneca" },
    { text = "No one can merely go wrong by himself, but he must become both the cause and adviser of another's wrong doing.", book = "", author = "Seneca" },
    { text = "No one dies except on his own day. You are throwing away none of your own time; for what you leave behind does not belong to you.", book = "", author = "Seneca" },
    { text = "No one is crushed by Fortune, unless they are first deceived by her... those who aren’t pompous in good times, don’t have their bubbles burst with change. Against either circumstance, the stable person keeps their rational soul invincible, for it’s precisely in the good times they prove their strength against adversity.", book = "On Consolation To Helvia", author = "Seneca" },
    { text = "No one is the object of another man's contempt, unless he is first the object of his own.", book = "", author = "Seneca" },
    { text = "No one keeps himself waiting; and yet the greatest cure for anger is to wait, so that the initial passion it engenders may die down, and the fog that shrouds the mind may subside, or become less thick.", book = "", author = "Seneca" },
    { text = "No one willingly reverts to the past unless all his actions have passed his own censorship, which is never deceived.", book = "", author = "Seneca" },
    { text = "No one,  he says,  leaves this world in a different manner from one who has just been born. That is not true; for we are worse when we die than when we were born; but it is our fault, and not that of Nature.", book = "", author = "Seneca" },
    { text = "No past life has been lived to lend us glory, and that which has existed before us is not ours.", book = "", author = "Seneca" },
    { text = "No person has the power to have everything they want, but it is in their power not to want what they don’t have, and to cheerfully put to good use what they do have.", book = "Moral Letters", author = "Seneca" },
    { text = "Non est ad astra mollis e terris via  - There is no easy way from the earth to the stars. ", book = "", author = "Seneca" },
    { text = "None of these will force you to die, but all will teach you how to die. None of them will exhaust your years, but each will contribute his years to yours.", book = "", author = "Seneca" },
    { text = "Not all men are wounded in the same place; and so you ought to know what part of you is weak, so you can give it the most protection.", book = "", author = "Seneca" },
    { text = "Not single is the death which comes; the death Which takes us off is but the last of all.", book = "", author = "Seneca" },
    { text = "Nothing can satisfy greed, but even a small measure satisfies nature. So it is that the poverty of an exile brings no misfortune, for no place of exile is so barren as not to produce ample support for a person.", book = "On Consolation To Helvia", author = "Seneca" },
    { text = "Nothing happens to the wise man against his expectation.", book = "", author = "Seneca" },
    { text = "Nothing hinders a cure so much as frequent changes of treatment.", book = "", author = "Seneca" },
    { text = "Nothing is burdensome if taken lightly, and nothing need arouse one's irritation so long as one doesn't make it bigger than it is by getting irritated.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Nothing is more dishonourable than an old man, heavy with years, who has no other evidence of his having lived long except his age.", book = "", author = "Seneca" },
    { text = "Nothing is more honorable than a grateful heart.", book = "", author = "Seneca" },
    { text = "Nothing is noble if it’s done unwillingly or under compulsion. Every noble deed is voluntary.", book = "Moral Letters", author = "Seneca" },
    { text = "Nothing is ours, except time.", book = "", author = "Seneca" },
    { text = "Nothing satisfies greed, but even a little satisfies nature.", book = "", author = "Seneca" },
    { text = "Nothing will ever befall me that I will receive with gloom or a bad disposition. I will pay my taxes gladly. Now, all the things which cause complaint or dread are like the taxes of life—things from which, my dear Lucilius, you should never hope for exemption or seek escape.", book = "Moral Letters", author = "Seneca" },
    { text = "Nothing, Lucilius, is ours, except time. We were entrusted by nature with the ownership of this single thing, so fleeting and slippery that anyone who will can oust us from possession.", book = "", author = "Seneca" },
    { text = "Nothing, to my way of thinking, is a better proof of a well ordered mind than a man's ability to stop just where he is and pass some time in his own company.", book = "", author = "Seneca" },
    { text = "Nūllum magnum ingenium sine mixtūrā dēmentiae fuit. No great talent without an element of madness.", book = "", author = "Seneca" },
    { text = "O how many noble deeds of women are lost in obscurity!", book = "", author = "Seneca" },
    { text = "Of all men, only those who find time for philosophy are at leisure; only they are truly alive; for it is not only their own lifetime they guard well: they add every age to their own.", book = "", author = "Seneca" },
    { text = "Of this one thing make sure against your dying day - that your faults die before you do.", book = "", author = "Seneca" },
    { text = "Offer new prayers; pray for a sound mind and for good health, first of soul and then of body.", book = "", author = "Seneca" },
    { text = "Often a very old man has no other proof of his long life than his age.", book = "", author = "Seneca" },
    { text = "Often it is better to hide an illness from the patient, because just the mere awareness of a disease can bring about death.", book = "", author = "Seneca" },
    { text = "On Epicurus; He says:  Contended poverty is an honourable estate.  Indeed, if it is contented, it is not poverty at all. It is not the man who has little, but the man who craves more, that is poor.", book = "", author = "Seneca" },
    { text = "Once we have driven away all that excites or affrights us, there ensues unbroken tranquility and enduring freedom.", book = "", author = "Seneca" },
    { text = "One can expect an agreement between philosophers sooner than between clocks.", book = "", author = "Seneca" },
    { text = "One cannot sincerely weep over getting what one wanted.", book = "", author = "Seneca" },
    { text = "One hand washes the other. (Manus Manum Lavat).", book = "", author = "Seneca" },
    { text = "One of the causes of the troubles that beset us is the way our lives are guided by the example of others; instead of being set to rights by reason we’re seduced by convention.", book = "", author = "Seneca" },
    { text = "Only a mind that is deeply stirred can utter something noble and beyond the power of others.", book = "", author = "Seneca" },
    { text = "Only an absolute fool values a man according to his clothes, or according to his social position, which after all is only something that we wear like clothing.", book = "", author = "Seneca" },
    { text = "Only the wise man is content with what is his. All foolishness suffers the burden of dissatisfaction with itself.", book = "", author = "Seneca" },
    { text = "Only time can heal what reason cannot.", book = "", author = "Seneca" },
    { text = "Our soul is sometimes a king, and sometimes a tyrant. A king, by attending to what is honorable, protects the good health of the body in its care, and gives it no base or sordid command. But an uncontrolled, desire-fueled, over-indulged soul is turned from a king into that most feared and detested thing—a tyrant.", book = "Moral Letters", author = "Seneca" },
    { text = "Our universe is a sorry little affair unless it has in it something for every age to investigate.", book = "", author = "Seneca" },
    { text = "Pain is slight if opinion has added nothing to it; ... in thinking it slight, you will make it slight. Everything depends on opinion. It is according to opinion that we suffer. A man is as wretched as he has convinced himself that he is.", book = "", author = "Seneca" },
    { text = "Part of my joy in learning is that it puts me in a position to teach; nothing, however outstanding and however helpful, will ever give me any pleasure if the knowledge is for my benefit alone.", book = "", author = "Seneca" },
    { text = "Peace you can claim for yourself without being disliked by anyone, without any sense of loss, and without any pangs of spirit.", book = "", author = "Seneca" },
    { text = "People are frugal in guarding their personal property; but as soon as it comes to squandering time they are most wasteful of the one thing in which it is right to be stingy.", book = "", author = "Seneca" },
    { text = "People prone to every fault they denounce are walking advertisements of the uselessness of their training. That kind of man can be of no more help to me as an instructor than a steersman who is seasick in a storm[...]. What good to me is a vomiting and stupefied helmsman? [...] What is needed is a steering hand, not talking.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "People who know no self-restraint lead stormy and disordered lives, passing their time in a state of fear commensurate with the injuries they do to others, never able to relax.", book = "", author = "Seneca" },
    { text = "Perchance some day the memory of this sorrow Will even bring delight", book = "", author = "Seneca" },
    { text = "Philosophers have come to envy the philologist and the mathematician, and they have taken over all the inessential elements in those studies ”with the result that they know more about devoting care and attention to their speech than about devoting such attention to their lives.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Philosophy calls for simple living, but not for penance—it’s quite possible to be simple without being crude.", book = "Moral Letters", author = "Seneca" },
    { text = "Philosophy calls for simple living, not for doing penance, and the simple way of life need not be a crude one.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Philosophy is good advice; and no one can give advice at the top of his lungs.", book = "", author = "Seneca" },
    { text = "Philosophy is not an occupation of a popular nature, nor is it pursued for the sake of self-advertisement. Its concern is not with words, but with facts. It is not carried on with the object of passing the day in an entertaining sort of way and taking the boredom out of leisure. It moulds and builds the personality, orders one's life, regulates one's conduct, shows one what one should do and what one should leave undone, sits at the helm and keeps one on the correct course as one is tossed about in perilous seas. Without it no one can lead a life free of fear or worry. Every hour of the day countless situations arise that call for advice, and for that advice we have to look to philosophy.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Philosophy isn’t a parlor trick or made for show. It’s not concerned with words, but with facts. It’s not employed for some pleasure before the day is spent, or to relieve the uneasiness of our leisure. It shapes and builds up the soul, it gives order to life, guides action, shows what should and shouldn’t be done—it sits at the rudder steering our course as we vacillate in uncertainties. Without it, no one can live without fear or free from care. Countless things happen every hour that require advice, and such advice is to be sought out in philosophy.", book = "Moral Letters", author = "Seneca" },
    { text = "Philosophy neither rejects anyone nor chooses anyone it shines for all.", book = "stoicism", author = "Seneca" },
    { text = "Philosophy teaches us to act, not to speak.", book = "", author = "Seneca" },
    { text = "Plague on it! what madness this is, to punish one's self because one is unfortunate, and not to lessen, but to increase one's ills!", book = "", author = "Seneca" },
    { text = "Plato says:  Every king springs from a race of slaves, and every slave has had kings among his ancestors.  The flight of time, with its vicissitudes, has jumbled all such things together, and Fortune has turned them upside down.", book = "", author = "Seneca" },
    { text = "Pleasure, unless it has been kept within bounds, tends to rush headlong into the abyss of sorrow.", book = "", author = "Seneca" },
    { text = "Prove - and an easy task it is - that so-called pleasures, when they go beyond a certain limit, are but punishments...", book = "", author = "Seneca" },
    { text = "Poor woman, do you want to know where hatred ends? Look to love.", book = "", author = "Seneca" },
    { text = "Possession of a friend should be with the spirit: the spirit's never absent: it sees daily whoever it likes.", book = "", author = "Seneca" },
    { text = "Poverty will keep for you your true and tried friends; you will be rid of the men who were not seeking you for yourself, but for something which you have.", book = "", author = "Seneca" },
    { text = "Preserve a sense of proportion in your attitude to everything that pleases you, and make the most of them while they are at their best.", book = "", author = "Seneca" },
    { text = "Press on and make all your actions and words cohere and fit with one another, all struck from the same mold.", book = "stoicism", author = "Seneca" },
    { text = "Prosperity does not elevate the sage and adversity does not depress him. For he has always made the effort to rely as much as possible on himself and to derive all delight from himself.", book = "", author = "Seneca" },
    { text = "Prosperity is a restless thing; it drives itself to distraction. It addles the brain, and not always in the same way, for it goads people in different directions ”some toward power, others toward self-indulgence. Some are puffed up by it, others unmanned and made entirely feeble.", book = "stoicism", author = "Seneca" },
    { text = "Providence which could be spoken of, almost according to choice or context, under a variety of names or descriptions including the divine reason, creative reason, nature.", book = "", author = "Seneca" },
    { text = "Read good books many times, rather than many books.", book = "", author = "Seneca" },
    { text = "Reading of many books is distraction.", book = "", author = "Seneca" },
    { text = "Reason shows us there is nothing either good or bad but thinking makes it so.", book = "", author = "Seneca" },
    { text = "Reasons for anxiety will never be lacking, whether born of prosperity or of wretchedness; life pushes on in a succession of engrossments. We shall always pray for leisure, but never enjoy it.", book = "", author = "Seneca" },
    { text = "Reflect how pleasant it is to demand nothing, how noble it is to be contented and not to be dependent upon Fortune.", book = "", author = "Seneca" },
    { text = "Reflect that nothing merits admiration except the spirit, the impressiveness of which prevents it from being impressed by anything.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Regard [a friend] as loyal, and you will make him loyal.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Religion is regarded by the common people as true, by the wise as false, and by rulers as useful.", book = "", author = "Seneca" },
    { text = "Remember that all we have is on loan from Fortune, which can reclaim it without our permission ”indeed, without even advance notice. Thus, we should love all our dear ones, but always with the thought that we have no promise that we may keep them forever ”nay, no promise even that we may keep them for long.", book = "", author = "Seneca" },
    { text = "Resent a thing by all means if it represents an injustice decreed against yourself personally; but if this same constraint is binding on the lowest and the highest alike, then make your peace again with destiny, the destiny that unravels all ties.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Restless people often pretend to be calm.", book = "", author = "Seneca" },
    { text = "Revenge is an admission that we have been hurt. That cannot be a great mind which is disturbed by injury. He who has hurt you must be either stronger or weaker than yourself. If he be weaker, spare him: if he be stronger, spare yourself.", book = "", author = "Seneca" },
    { text = "Say good-bye at last to those deceptive prizes more precious to those who hope for them than to those who have won them.", book = "", author = "Seneca" },
    { text = "Shall I tell you what philosophy holds out to humanity? Counsel.", book = "", author = "Seneca" },
    { text = "Show me someone who isn’t a slave! One is a slave to lust, another to greed, another to power, and all are slaves to fear. I could name a former Consul who is a slave to a little old woman, a millionaire who is the slave of the cleaning woman.... No servitude is more abject than the self-imposed.", book = "Moral Letters", author = "Seneca" },
    { text = "Show me that the good life doesn’t consist in its length, but in its use, and that it is possible—no, entirely too common—for a person who has had a long life to have lived too little.", book = "Moral Letters", author = "Seneca" },
    { text = "Silence is a lesson learned from the many sufferings of life.", book = "Thyestes", author = "Seneca" },
    { text = "Silently time sneaks up on you, each hour  gone is followed by a worse one.", book = "", author = "Seneca" },
    { text = "Similarly, too rich a soil makes the grain fall flat, branches break down under too heavy a load, excessive productiveness does not bring fruit to ripeness.", book = "", author = "Seneca" },
    { text = "Since nature allows us to enter into a partnership with every age, why not turn from this brief and transient spell of time and give ourselves wholeheartedly to the past, which is limitless and eternal and can be shared with better men than we?", book = "", author = "Seneca" },
    { text = "Since the mind when distracted absorbs nothing deeply, but rejects everything which is, so to speak, crammed into it.", book = "", author = "Seneca" },
    { text = "Sine philosophia nemo intrepide potest vivere, nemo secure.", book = "The Stoic Philosophy of Seneca: Essays and Letters", author = "Seneca" },
    { text = "So - to the best of your ability - demonstrate your own guilt, conduct inquiries of your own into all the evidence against yourself. Play the part first of prosecutor, then of judge, and finally of pleader in mitigation. Be harsh with yourself at times.", book = "", author = "Seneca" },
    { text = "So I have never believed that there was any genuine good in the things which everyone prays for; what is more, I have found them empty and daubed with showy and deceptive colours, with nothing inside to match their appearance.", book = "", author = "Seneca" },
    { text = "So it is inevitable that life will be not just very short but very miserable for those who acquire by great toil what they must keep by greater toil.", book = "", author = "Seneca" },
    { text = "So it is: we are not given a short life but we make it short, and we are not Ill-supplied but wasteful of it.", book = "", author = "Seneca" },
    { text = "So the life of a philosopher extends widely: he is not confined by the same boundary as are others. He alone is free from the laws that limit the human race, and all ages serve him as though he were a god.", book = "", author = "Seneca" },
    { text = "So the man who restrains himself within the bounds set by nature will not notice poverty; the man who exceeds these bounds will be pursued by poverty however rich he.", book = "", author = "Seneca" },
    { text = "So the spirit must be trained to a realization and an acceptance of its lot. It must come to see that there is nothing fortune will shrink from[.]  There's no ground for resentment in all this. We've entered into a world in which these are the terms life is lived on  “ if you're satisfied with that, submit to them, if you're not, get out, whatever way you please.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "So you must match time’s swiftness with your speed in using it, and you must drink quickly as though from a rapid stream that will not always flow.", book = "", author = "Seneca" },
    { text = "So, concerning the things we pursue, and for which we vigorously exert ourselves, we owe this consideration—either there is nothing useful in them, or most aren’t useful. Some of them are superfluous, while others aren’t worth that much. But we don’t discern this and see them as free, when they cost us dearly.", book = "Moral Letters", author = "Seneca" },
    { text = "Socrates made the same remark to one who complained; he said:  Why do you wonder that globe-trotting does not help you, seeing that you always take yourself with you? The reason which set you wandering is ever at your heels. ", book = "", author = "Seneca" },
    { text = "Soft living imposes on us the penalty of debility; we cease to be able to do the things we've long been grudging about doing.", book = "", author = "Seneca" },
    { text = "Some men have shrunk so far into dark corners that objects in bright daylight seem quite blurred to them.’ A.", book = "", author = "Seneca" },
    { text = "Some people with exceptional minds quickly grasp virtue, or produce it within themselves. But other dim and lazy types, hindered by bad habits, must have their rusty souls constantly scrubbed down.... The weaker sorts will be helped and lifted from their bad opinions if we put them in the care of philosophy’s principles.", book = "Moral Letters", author = "Seneca" },
    { text = "Some vices delight them as being proofs of their prosperity; it seems the part of a man who is very lowly and despicable to know what he is doing.", book = "", author = "Seneca" },
    { text = "Sometimes even to live is an act of courage.”   Anger.", book = "", author = "Seneca" },
    { text = "Sorrowers tend to avoid what they are most fond of and try to give vent to their grief.", book = "", author = "Seneca" },
    { text = "Speak ill of yourself when by yourself; then you will become accustomed both to speak and to hear the truth.", book = "", author = "Seneca" },
    { text = "Spurn everything that is added by way of decoration and display by unneccesary labour. Relect that nothing merits admiration except the spirit, the impressiveness of which prevents it from being impressed by anything.", book = "", author = "Seneca" },
    { text = "Stolid pack-animals are much more fit for carrying loads than thoroughbred horses: who ever subdued their noble speed with a heavy burden?", book = "", author = "Seneca" },
    { text = "Stop preventing philosophers from possessing money; no one has condemned wisdom to poverty. I will despise whatever lies in the domain of Fortune, but if a choice is offered, I will choose the better half.", book = "", author = "Seneca" },
    { text = "Success comes to the lowly and to the poorly talented, but the special characteristic of a great person is to triumph over the disasters and panics of human life.", book = "On Providence", author = "Seneca" },
    { text = "Tantalus: The highest power is—Thyestes: No power, if you desire nothing.", book = "Thyestes", author = "Seneca" },
    { text = "That advocate is lionized throughout the whole forum, and fills all the place with a great crowd that stretches farther than he can be heard, yet he says: “When will vacation time come?”", book = "", author = "Seneca" },
    { text = "That day, which you fear as being the end of all things, is the birthday of your eternity.", book = "", author = "Seneca" },
    { text = "That deed and word should be in accord, that a man should be equal to himself under all conditions, and always the same.", book = "", author = "Seneca" },
    { text = "That man who had prayed for the fasces, when he attains them, desires to lay them aside and says over and over: “When will this year be over!”", book = "", author = "Seneca" },
    { text = "That which Fortune has not given, she cannot take away.", book = "stoicism", author = "Seneca" },
    { text = "That which takes effect by chance is not an art.", book = "", author = "Seneca" },
    { text = "The ability to do without a kingdom is a kingdom.", book = "Six Tragedies", author = "Seneca" },
    { text = "The acquisition of riches has been for many men, not an end, but a change, of troubles.", book = "", author = "Seneca" },
    { text = "The amount of life we truly live is small. For our existence on Earth is not Life, but merely Time.", book = "", author = "Seneca" },
    { text = "The belly will not listen to advice; it makes demands, it importunes. And yet it is not a troublesome creditor; you can send it away at small cost, provided only that you give it what you owe, not merely all you are able to.", book = "", author = "Seneca" },
    { text = "The best and the greatest number of authors have asserted that philosophy consists of three parts: the moral, the natural, and the rational. The first puts the soul in order. The second thoroughly examines the natural order of things. The third inquires into the proper meaning of words, and their arrangements and proofs which keep falsehoods from creeping in to displace truth.", book = "Moral Letters", author = "Seneca" },
    { text = "The best compromise between love and good sense is both to feel longing and to conquer it.", book = "", author = "Seneca" },
    { text = "The best ideas are common property.", book = "", author = "Seneca" },
    { text = "The body’s needs are few: it wants to be free from cold, to banish hunger and thirst with nourishment; if we long for anything more we are exerting ourselves to serve our vices, not our needs.", book = "", author = "Seneca" },
    { text = "The boon that could be given can be withdrawn.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The bravest sight in the world is to see a great man struggling against adversity.", book = "", author = "Seneca" },
    { text = "The busy man is busy with everything except living; there is nothing that is more difficult to learn how to do right.", book = "", author = "Seneca" },
    { text = "The busy man remains rooted to the ground, ever stuck in the present, a time so brief that it cannot be grasped, and thus it is stolen from him, busy as he is with so many things.", book = "", author = "Seneca" },
    { text = "The day which we fear as our last is but the birthday of eternity.", book = "", author = "Seneca" },
    { text = "The difficulty comes from our lack of confidence.", book = "", author = "Seneca" },
    { text = "The diseases of the rational soul are long-standing and hardened vices, such as greed and ambition—they have put the soul in a straitjacket and have begun to be permanent evils inside it. To put it briefly, this sickness is an unrelenting distortion of judgment, so things that are only mildly desirable are vigorously sought after.", book = "Moral Letters", author = "Seneca" },
    { text = "The fates lead those who will those who won't they drag.", book = "", author = "Seneca" },
    { text = "The final hour when we cease to exist does not itself bring death; it merely of itself completes the death-process. We reach death at that moment, but  we have been a long time on the way.", book = "", author = "Seneca" },
    { text = "The first sign of a settled mind is that it can stay in one place and spend time with itself.", book = "", author = "Seneca" },
    { text = "The first thing which philosophy undertakes to give is fellow-feeling with all men; in other words, sympathy and sociability.", book = "", author = "Seneca" },
    { text = "The fool, with all his other faults, has this also, he is always getting ready to live.", book = "", author = "Seneca" },
    { text = "The fool's life is empty of gratitude and full of fears; its course lies wholly toward the future.", book = "", author = "Seneca" },
    { text = "The founder of the universe, who assigned to us the laws of life, provided that we should live well, but not in luxury. Everything needed for our well-being is right before us, whereas what luxury requires is gathered by many miseries and anxieties. Let us use this gift of nature and count it among the greatest things.", book = "Moral Letters", author = "Seneca" },
    { text = "The geat blessing of mankind are within us and within our reach; but we shut our eyes, and like people in the dark, we fall foul upon the very thing we search for, without finding it.", book = "", author = "Seneca" },
    { text = "The geometrician teaches me how I may avoid losing any fraction of my estates, but what I really want to learn is how to lose the lot and still keep smiling.", book = "", author = "Seneca" },
    { text = "The greatest hindrance to living is expectancy, which depends upon the morrow and wastes to-day.", book = "", author = "Seneca" },
    { text = "The greatest loss of time is delay and expectation, which depend upon the future. We let go the present, which we have in our power, and look forward to that which depends upon chance, and so relinquish a certainty for an uncertainty.", book = "", author = "Seneca" },
    { text = "The greatest obstacle to living is expectancy, which hangs upon tomorrow and loses today. You are arranging what lies in Fortune’s control, and abandoning what lies in yours. What are you looking at? To what goal are you straining? The whole future lies in uncertainty: live immediately.", book = "On the Shortness of Life: Life Is Long if You Know How to Use It", author = "Seneca" },
    { text = "The greatest portion of peace of mind is doing nothing wrong. Those who lack self-control live disoriented and disturbed lives.", book = "Moral Letters", author = "Seneca" },
    { text = "The grief that has been conquered by reason is calmed for ever.", book = "", author = "Seneca" },
    { text = "The happy life is a life that is in harmony with its own nature.", book = "", author = "Seneca" },
    { text = "The happy man is satisfied with his present situation, no matter what it is, and eyes his fortune with contentment; the happy man is the one who permits reason to evaluate every condition of his existence.", book = "", author = "Seneca" },
    { text = "The highest good is a mind that scorns the happenings of chance, and rejoices only in virtue.", book = "", author = "Seneca" },
    { text = "The liberal arts do not conduct the soul all the way to virtue, but merely set it going in that direction.", book = "", author = "Seneca" },
    { text = "The man who fears death will never do anything worthy of a man who is alive.", book = "", author = "Seneca" },
    { text = "The man who has anticipated the coming of troubles takes away their power when they arrive.", book = "", author = "Seneca" },
    { text = "The man who lives extravagantly wants his manner of living to be on everybody's lips as long as he is alive. He thinks he is wasting his time if he is not being talked about.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The man who looks for the morrow without worrying over it knows a peaceful independence and a happiness beyond all others. Whoever has said, I have lived' receives a windfall every day he gets up in the morning.", book = "", author = "Seneca" },
    { text = "The man who spends all his time on his own needs, who organizes every day as though it were his last, neither longs for nor fears the next day.", book = "", author = "Seneca" },
    { text = "The man who spends his time choosing one resort after another in a hunt for peace and quiet, will in every place he visits find something to prevent him from relaxing. The story is told that someone complained to Socrates that travelling abroad had never done him any good and received the reply: 'What else can you expect, seeing that you always take yourself along with you when you go abroad?'", book = "", author = "Seneca" },
    { text = "The man who tries to find out what has been said against him, who seeks to unearth spiteful gossip, even when engaged in privately, is destroying his own peace of mind.", book = "", author = "Seneca" },
    { text = "The man, though, whom you should admire and imitate is the one who finds it a joy to live and in spite of that is not reluctant to die.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The mind is never right but when it is at peace with itself.", book = "", author = "Seneca" },
    { text = "The mind must be given relaxation—it will rise improved and sharper after a good break. Just as rich fields must not be forced—for they will quickly lose their fertility if never given a break—so constant work on the anvil will fracture the force of the mind. But it regains its powers if it is set free and relaxed for a while. Constant work gives rise to a certain kind of dullness and feebleness in the rational soul.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "The mind that is anxious about future events is miserable.", book = "", author = "Seneca" },
    { text = "The mind when distracted absorbs nothing deeply.", book = "", author = "Seneca" },
    { text = "The more a mind takes in the more it expands.", book = "", author = "Seneca" },
    { text = "The more we value things outside our control, the less control we have.", book = "", author = "Seneca" },
    { text = "The one to whom nothing was refused, whose tears were always wiped away by an anxious mother, will not abide being offended.", book = "", author = "Seneca" },
    { text = "The only really leisured people are those who devote time to acquiring true knowledge rather than trivia. .", book = "", author = "Seneca" },
    { text = "The other side shall be heard as well.", book = "", author = "Seneca" },
    { text = "The part of life we really live is small.  For all the rest of existence is not life, but merely time.", book = "On the Shortness of Life", author = "Seneca" },
    { text = "The past is ours, and there is nothing more secure for us than that which has been. We are ungrateful for past gains, because we hope for the future, as if the future – if so be that any future is ours – will not be quickly blended with the past.", book = "", author = "Seneca" },
    { text = "The person who has practiced philosophy as a cure for the self becomes great of soul, filled with confidence, invincible—and greater as you draw near.", book = "Moral Letters", author = "Seneca" },
    { text = "The place one's in, though, doesn't make any contribution to peace of mind: it's the spirit that makes everything agreeable to oneself.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The preoccupied become aware of it only when it is over.", book = "", author = "Seneca" },
    { text = "The present alone can make no man wretched.", book = "", author = "Seneca" },
    { text = "The primary indication, to my thinking, of a well-ordered mind is a man's ability to remain in one place and linger in his own company.", book = "", author = "Seneca" },
    { text = "The problem, Paulinus, is not that we have a short life, but that we waste time.", book = "", author = "Seneca" },
    { text = "The rational soul is stronger than any kind of fortune—from its own share it guides its affairs here or there, and is itself the cause of a happy or miserable life.", book = "Moral Letters", author = "Seneca" },
    { text = "The road is long if one proceeds by way of precepts but short and effectual if by way of personal example.", book = "", author = "Seneca" },
    { text = "The shortest route to wealth is the contempt of wealth.", book = "", author = "Seneca" },
    { text = "The sun also shines on the wicked.", book = "", author = "Seneca" },
    { text = "The supreme ideal does not call for any external aids. It is homegrown, wholly self-developed. Once it starts looking outside itself for any part of itself it is on the way to being dominated by fortune.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The surest way for those who want to rule  is praising moderation, talking of peace and quiet.", book = "", author = "Seneca" },
    { text = "The things that are essential are acquired with little bother it is the luxuries that call for toil and effort.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "The things that are indispensable require no elaborate pains for their acquisition; it is only the luxuries that call for labour. Follow nature, and you will need no skilled craftsmen.", book = "", author = "Seneca" },
    { text = "The time of the actual enjoyment is short and swift, and made much shorter through their own fault. For they dash from one pleasure to another and cannot stay steady in one desire.", book = "", author = "Seneca" },
    { text = "The whole future lies in uncertainty: live immediately.", book = "", author = "Seneca" },
    { text = "The willing, Destiny guides them. The unwilling, Destiny drags them.", book = "", author = "Seneca" },
    { text = "The wise man is self-sufficient, that he can do without friends, not that he desires to do without them. When I say  can,  I mean this: he endures the loss of a friend with equanimity.", book = "", author = "Seneca" },
    { text = "The wise man regards the reason for all his actions, but not the results.", book = "", author = "Seneca" },
    { text = "The wise man, he said, lacked nothing but needed a great number of things, whereas 'the fool, on the other hand, needs nothing (for he does not know how to use anything) but lack everything.", book = "", author = "Seneca" },
    { text = "The young character, which cannot hold fast to righteousness, must be rescued from the mob.", book = "", author = "Seneca" },
    { text = "Then they reflect how pointlessly they acquired things they never would enjoy, and how all their toil has been in vain.", book = "", author = "Seneca" },
    { text = "There are more things, Lucilius, likely to frighten us than there are to crush us; we suffer more often in imagination than in reality.", book = "", author = "Seneca" },
    { text = "There are more things to alarm us than to harm us, and we suffer more often in apprehension than reality.", book = "", author = "Seneca" },
    { text = "There can be no place of exile within the world since nothing within the world is alien to men.", book = "", author = "Seneca" },
    { text = "There has never been a great mind without some degree of madness.", book = "", author = "Seneca" },
    { text = "There is a sequence about the creative process, and a work of genius is a synthesis of its individual features from which nothing can be subtracted without disaster.", book = "", author = "Seneca" },
    { text = "There is an old adage about gladiators, - that they plan their fight in the ring.", book = "", author = "Seneca" },
    { text = "There is but one chain holding us in fetters, and that is our love of life.", book = "", author = "Seneca" },
    { text = "There is never a time when new distraction will not show up; we sow them, so several will grow from the same seed.", book = "", author = "Seneca" },
    { text = "There is no enjoying the possession of anything valuable unless one has someone to share it with.", book = "", author = "Seneca" },
    { text = "There is no favorable wind for the sailor who doesn’t know where to go.", book = "", author = "Seneca" },
    { text = "There is no great genius without some touch of madness.", book = "", author = "Seneca" },
    { text = "There is no more stupefying thing than anger, nothing more bent on its own strength. If successful, none more arrogant, if foiled, none more insane—since it’s not driven back by weariness even in defeat, when fortune removes its adversary it turns its teeth on itself.", book = "On Anger", author = "Seneca" },
    { text = "There is no need to complain of particular grievances, for life in its entirety is lamentable.", book = "", author = "Seneca" },
    { text = "There is no need to raise our hands to heaven; there is no need to implore the temple warden to allow us close to the ear of some graven image, as though this increased the chances of our being heard. God is near you, is with you, is inside you.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "There is no such thing as good or bad fortune for the individual; we live in common.", book = "", author = "Seneca" },
    { text = "There is no vice which lacks a defense, none that at the outset isn’t modest and easily intervened—but after this the trouble spreads widely. If you allow it to get started you won’t be able to control when it stops. Every emotion is at first weak. Later it rouses itself and gathers strength as it moves along—it’s easier to slow it down than to supplant it.", book = "Moral Letters", author = "Seneca" },
    { text = "There is no worse penalty for vice than the fact that it is dissatisfied with itself and all its fellows.", book = "", author = "Seneca" },
    { text = "There is nothing in the world so much admired as a man who knows how to bear unhappiness with courage.", book = "", author = "Seneca" },
    { text = "There is nothing the busy man is less busied with than living:  there is nothing that is harder to learn.", book = "", author = "Seneca" },
    { text = "There is nothing the wise man does reluctantly. He escapes necessity because he wills what necessity is going to force on him.", book = "", author = "Seneca" },
    { text = "There is only one relief for great sufferings, and that is to endure and surrender to their compulsion.", book = "", author = "Seneca" },
    { text = "There is the mind of a monarch within each of us, wanting to be granted complete freedom of action but not wanting it to be turned against us.", book = "Of Anger", author = "Seneca" },
    { text = "There will always be causes for anxiety, whether due to prosperity or to wretchedness. Life will be driven on through a succession of preoccupations: we shall always long for leisure, but never enjoy it.", book = "", author = "Seneca" },
    { text = "Therefore it is better to conquer our grief than to deceive it. For if it has withdrawn, being merely beguiled by pleasures and preoccupations, it starts up again and from its very respite gains force to savage us.", book = "", author = "Seneca" },
    { text = "Therefore whenever his last day comes, the wise man will not hesitate to meet death with a firm step.", book = "", author = "Seneca" },
    { text = "Therefore, explain why a wise person shouldn’t get drunk—not with words, but by the facts of its ugliness and offensiveness. It’s most easy to prove that so-called pleasures, when they go beyond proper measure, are but punishments.", book = "Moral Letters", author = "Seneca" },
    { text = "Therefore, my dear Lucilius, begin at once to live, and count each separate day as a separate life. He who has thus prepared himself, he whose daily life has been a rounded whole, is easy in his mind.", book = "", author = "Seneca" },
    { text = "Therefore, nothing ought to be unexpected by us. Our minds should be sent forward in advance to meet all problems, and we should consider, not what is wont to happen, but what can happen.", book = "", author = "Seneca" },
    { text = "Theseus: What is the crime for which you must pay by death? Phaedra: My life.", book = "", author = "Seneca" },
    { text = "They are like prowling enemies who pounce on you when occasion offers, and allow you neither to be at the ready as in war nor at ease as in peace.", book = "", author = "Seneca" },
    { text = "They lose the day in expectation of the night, and the night in fear of the dawn.", book = "", author = "Seneca" },
    { text = "They lose the day in waiting for the night, and the night in fearing the dawn.", book = "", author = "Seneca" },
    { text = "Things we wouldn't be willing to pay for if it meant giving up our house for them, or some pleasant or productive estate, we are quite ready to obtain at the cost of anxiety, of danger, of losing our freedom, our decency, our time.", book = "stoicism", author = "Seneca" },
    { text = "Think for a long time whether or not you should admit a given person to your friendship. But when you have decided to do so, welcome him heart and soul, and speak as unreservedly with him as you would with yourself.", book = "", author = "Seneca" },
    { text = "Think of those who, not by fault of inconsistency but by lack of effort, are too unstable to live as they wish, but only live as they have begun.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Think your way through difficulties: harsh conditions can be softened, restricted ones can be widened, and heavy ones can weigh less on those who know how to bear them.", book = "", author = "Seneca" },
    { text = "Thinking of departed friends is to me something sweet and mellow. For when I had them with me it was with the feeling that I was going to lose them, and now that I have lost them I keep the feeling that I have them with me still.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "This can be swiftly taught in very few words: virtue is the only good; there is no certain good without virtue; and virtue resides in our nobler part, which is the rational one. And what can this virtue be? True and steadfast judgment. For from this will arise every mental impulse, and by it every appearance that spurs our impulses will be rendered clear.", book = "Moral Letters", author = "Seneca" },
    { text = "This evil of taking our cue from others has become so deeply ingrained that even that most basic feeling, grief, degenerates into imitation.", book = "", author = "Seneca" },
    { text = "This is what you should teach me, how to be like Odysseus—how to love my country, wife and father, and how, even after suffering shipwreck, I might keep sailing on course to those honorable ends.", book = "Moral Letters", author = "Seneca" },
    { text = "This is why we say that nothing happens to the wise person contrary to their expectations.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "This will not be a gentle prescription for healing, but cautery and the knife. What shall I achieve? That a soul which has conquered so many miseries will be ashamed to worry about one more wound in a body which already has so many scars.", book = "", author = "Seneca" },
    { text = "This wretched body, the chain and prison of the soul, is tossed hither and thither; upon it punishment and pillage and disease wreak havoc: but the soul itself is holy and eternal, and it cannot be assailed with violence.", book = "", author = "Seneca" },
    { text = "This, I say, is the highest duty and the highest proof of wisdom, – that deed and word should be in accord, that.", book = "", author = "Seneca" },
    { text = "Those who are busy with other things do not notice it until the end comes.", book = "", author = "Seneca" },
    { text = "Those who choose to have no real purpose in life are ever rootless and dissatisfied, tossed by their aimlessness into ever-changing situations.", book = "", author = "Seneca" },
    { text = "Those who forget the past, ignore the present, and fear for the future have a life that is very brief and filled with anxiety.", book = "", author = "Seneca" },
    { text = "Those who forget the past, neglect the present, and fear for the future have a life that is very brief and troubled. They lose the day in expectation of the night, and the night in fear of the dawn.", book = "", author = "Seneca" },
    { text = "Those who lack self-control lead disturbed and tumultuous lives; their crimes are balanced by their fears, and they are never at ease.", book = "", author = "Seneca" },
    { text = "Throw aside all hindrances and give up your time to attaining a sound mind.", book = "", author = "Seneca" },
    { text = "Thus far, you have indeed not been sluggish, but you must quicken your pace. Much toil remains; to confront it, you must yourself lavish all your waking hours, and all your efforts, if you wish the result to be accomplished.", book = "", author = "Seneca" },
    { text = "Thus the time we are given is not brief, but we make it so. We do not lack time; on the contrary, there is so much of it that we waste an awful lot.", book = "", author = "Seneca" },
    { text = "Time flies on fickle wings.", book = "", author = "Seneca" },
    { text = "Time heals what reason cannot.", book = "", author = "Seneca" },
    { text = "To be always fortunate, and to pass through life with a soul that has never known sorrow, is to be ignorant of one half of nature.", book = "", author = "Seneca" },
    { text = "To be everywhere, is to be no where at all.", book = "", author = "Seneca" },
    { text = "To consort with the crowd is harmful; there is no person who does not make some vice attractive to us, or stamp it upon us, or taint us unconsciously therewith.", book = "", author = "Seneca" },
    { text = "To expect punishment is to suffer it; and to earn it is to expect it.", book = "", author = "Seneca" },
    { text = "To have may be taken from us, to have had, never. A man is thankless in the highest degree if, after losing something, he feels no obligation for having received it.", book = "", author = "Seneca" },
    { text = "To know how many are jealous of you, count your admirers.", book = "", author = "Seneca" },
    { text = "To live under constraint is a misfortune, but there is no constraint to live under constraint.", book = "", author = "Seneca" },
    { text = "To lose someone you love is something you'll regard as the hardest of all blows to bear, while all the time this will be as silly as crying because the leaves fall from the beautiful trees that add to the charm of your home. [...] At one moment chance will carry off one of them, at another moment another; but the falling of the leaves is not difficult  to bear, since they grow again, and it is no more hard to bear the loss of those whom you love and regard as brightening your existence; for even if they do not grow again they are replaced. But their successors will never be quite the same. No, and neither will you.", book = "", author = "Seneca" },
    { text = "To make Pythocles rich, do not add to his store of money, but subtract from his desires.", book = "", author = "Seneca" },
    { text = "To reduce your worry, you must assume that what you fear may happen is certainly going to happen.", book = "", author = "Seneca" },
    { text = "To want to know more than is sufficient is a form of intemperance. Apart from which this kind of obsession with the liberal arts turns people into pedantic, irritating, tactless, self-satisfied bores, not learning what they need simply because they spend their time learning things they will never need. The scholar Didymus wrote four thousand works: I should feel sorry him if he had merely read so many useless works.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "To what lengths would so precocious an ambition not go?", book = "", author = "Seneca" },
    { text = "To win true freeedom you must be a slave to philosophy.", book = "", author = "Seneca" },
    { text = "To wish to be well is a part of becoming well.", book = "", author = "Seneca" },
    { text = "Tranquility can’t be grasped except by those who have reached an unwavering and firm power of judgment—the rest constantly fall and rise in their decisions, wavering in a state of alternately rejecting and accepting things. What is the cause of this back and forth? It’s because nothing is clear and they rely on the most uncertain guide—common opinion.", book = "Moral Letters", author = "Seneca" },
    { text = "Treat your inferiors in the way in which you would like to be treated by your own superiors.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "True happiness is to enjoy the present, without anxious dependence upon the future, not to amuse ourselves with either hopes or fears but to rest satisfied with what we have, which is sufficient, for he that is so wants nothing. The greatest blessings of mankind are within us and within our reach. A wise man is content with his lot, whatever it may be, without wishing for what he has not.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "True happiness is... to enjoy the present, without anxious dependence upon the future.", book = "", author = "Seneca" },
    { text = "Trust me, real joy is a serious thing. Do you think someone can, in the charming expression, blithely dismiss death with an easy disposition? Or swing open the door to poverty, keep pleasures in check, or meditate on the endurance of suffering? The one who is comfortable with turning these thoughts over is truly full of joy, but hardly cheerful. It’s exactly such a joy that I would wish for you to possess, for it will never run dry once you’ve laid claim to its source.", book = "Moral Letters", author = "Seneca" },
    { text = "Truth often harms the one who digs it up.", book = "", author = "Seneca" },
    { text = "Ubicumque ex aequo ad caelum erigitur acies, paribus intervallis omnia divina ab omnibus humanis distant - From whatever point on the earth's surface you look up to heaven the same distance lies between the realms of gods and men.", book = "", author = "Seneca" },
    { text = "Unblest is he who thinks himself unblest.", book = "", author = "Seneca" },
    { text = "Unbroken prosperity cannot bear a single blow; but he who has waged an unceasing strife with his misfortunes has gained a thicker skin by his sufferings, yields to no disaster, and even though he fall yet fights on his knee.", book = "", author = "Seneca" },
    { text = "Undisturbed by fears and unspoiled by pleasures, we shall be afraid neither of death nor the gods.", book = "", author = "Seneca" },
    { text = "Unless we are complete ingrates, the lives of all those men that preceded us should be seen as sacred. Their collective existence paved the way for our own time on Earth.", book = "", author = "Seneca" },
    { text = "Until we have begun to go without them, we fail to realize how unnecessary many things are. We've been using them not because we needed them but because we had them.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Vices have to be crushed rather than picked at.", book = "", author = "Seneca" },
    { text = "Virtue alone affords everlasting and peace-giving joy; even if some obstacle arise, it is but like an intervening cloud, which floats beneath the sun but never prevails against it.", book = "Letters from a Stoic: Modern English Edition", author = "Seneca" },
    { text = "Virtue is according to nature; vice is opposed to it and hostile.", book = "", author = "Seneca" },
    { text = "Virtue is not vouchsafed to a soul unless that soul has been trained and taught, and by unremitting practice brought to perfection.", book = "", author = "Seneca" },
    { text = "We abandon nature and surrender to the mob – who are never good advisers in anything, and in this respect as in all others are most inconsistent.", book = "", author = "Seneca" },
    { text = "We all rush through life torn between a desire for the future and a weariness of the present. But he who devotes his time to his own needs, who plans out every day as if it were his last, neither longs for nor fears for tomorrow.", book = "", author = "Seneca" },
    { text = "We always feel anger longer than we feel hurt.", book = "", author = "Seneca" },
    { text = "We are all bound by this oath:  To bear the ills of mortal life, and to submit with a good grace to what we cannot avoid. ", book = "", author = "Seneca" },
    { text = "We are frightened at uncertainties, just as if they were certain. We observe no moderation. The slightest thing turns the scales and throws us forthwith into a panic.", book = "", author = "Seneca" },
    { text = "We are in the habit of saying that it was not in our power to choose the parents who were allotted to us, that they were given to us by chance. But we can choose whose children we would like to be.", book = "", author = "Seneca" },
    { text = "We are indeed apt to ascribe certain faults to the place or to the time; but those faults will follow us, no matter how we change our place.  You.", book = "", author = "Seneca" },
    { text = "We are mad, not only individually but nationally. We check manslaughter and isolated murders, but what of war and the much-vaunted crime of slaughtering whole peoples?", book = "", author = "Seneca" },
    { text = "We are members of one great body, planted by nature…. We must consider that we were born for the good of the whole.", book = "", author = "Seneca" },
    { text = "We are more often frightened than hurt; and we suffer more from imagination than from reality.", book = "", author = "Seneca" },
    { text = "We are weak, watery beings standing in the midst of unrealities; therefore let us turn our minds to the things that are everlasting.", book = "", author = "Seneca" },
    { text = "We are wont to say that it was not in our power to choose the parents who fell to our lot, that they have been given to men by chance; yet we may be the sons of whomsoever we will.", book = "", author = "Seneca" },
    { text = "We can have the things we need for our ordinary purposes if we will only be content with what the earth has made available on its surface.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "We can remove most sins if we have a witness standing by as we are about to go wrong. The soul should have someone it can respect, by whose example it can make its inner sanctum more inviolable. Happy is the person who can improve others, not only when present, but even when in their thoughts!", book = "Moral Letters", author = "Seneca" },
    { text = "We cease to be so angry once we cease to be so hopeful.", book = "", author = "Seneca" },
    { text = "We deceive ourselves in thinking that death only follows life whereas it both goes before and will follow after it for where is the difference in not beginning or ceasing to exist the effect of both is not to be.", book = "", author = "Seneca" },
    { text = "We do not need many words, but, rather, effective words.", book = "", author = "Seneca" },
    { text = "We do not receive a life that is short, but rather we make it so.", book = "", author = "Seneca" },
    { text = "We learn not in the school, but in life.", book = "", author = "Seneca" },
    { text = "We like to say that we don’t get to choose our parents, that they were given by chance—yet we can truly choose whose children we’d like to be.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "We live among wicked man through our own wickedness. One thing alone can bring us peace, an agreement to treat one another with kindness.", book = "", author = "Seneca" },
    { text = "We must give up many things to which we are addicted, considering them to be good. Otherwise, courage will vanish, which should continually test itself. Greatness of soul will be lost, which can’t stand out unless it disdains as petty what the mob regards as most desirable.", book = "Moral Letters", author = "Seneca" },
    { text = "We must indulge the mind and from time to time allow it the leisure which is its food and strength.", book = "", author = "Seneca" },
    { text = "We must, therefore, take a less serious view of all things, tolerating them in a spirit of acceptance: It is more human to laugh at life than to weep tears over it.", book = "", author = "Seneca" },
    { text = "We need to set our affections on some good man and keep him constantly before our eyes, so that we may live as if he were watching us and do everything as if he saw what we were doing.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "We ought frequently to remind ourselves that we must love the things of this life as we would what is shortly to leave us, or indeed in the very act of leaving us.", book = "", author = "Seneca" },
    { text = "We ought not, therefore, to give over our hearts for good to any one part of the world. We should live with the conviction:'I wasn't born for one particular corner: the whole world's my home country.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "We perish because we follow other men's examples: we should be cured of this if we were to disengage ourselves from the herd.", book = "", author = "Seneca" },
    { text = "We shall be rich with all the more comfort, if we once learn how far poverty is from being a burden.", book = "", author = "Seneca" },
    { text = "We shall consider later whether these evils derive their power from their own strength, or from our own weakness.", book = "", author = "Seneca" },
    { text = "We should conduct ourselves not as if we ought to live for the body, but as if we could not live without it. Our too great love for it makes us restless with fears, burdens us with cares, and exposes us to insults.", book = "", author = "Seneca" },
    { text = "We should every night call ourselves to an account;  What infirmity have I mastered today?  What passions opposed? What temptation resisted? What virtue acquired? Our vices will abort of themselves if they be brought every day to the shrift.", book = "", author = "Seneca" },
    { text = "We should often withdraw into ourselves; for mixing with persons of dissimilar natures throws into disorder our settled composure and wakens our passions anew, exacerbating whatever is weak in the mind and not properly healed.", book = "", author = "Seneca" },
    { text = "We should take wandering outdoor walks, so that the mind might be nourished and refreshed by the open air and deep breathing.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "We Stoics are not subjects of a despot: each of us lays claim to his own freedom.", book = "", author = "Seneca" },
    { text = "We suffer more often in imagination than in reality.", book = "", author = "Seneca" },
    { text = "Wealth however limited, if it is entrusted to a good guardian, increases by use.", book = "", author = "Seneca" },
    { text = "Wealth is the slave of a wise man. The master of a fool.", book = "", author = "Seneca" },
    { text = "Wealth is the slave of the wise man and master of the fool.", book = "", author = "Seneca" },
    { text = "Weigh carefully your hopes as well as your fears, and whenever all the elements are in doubt, decide in your own favour; believe what you prefer.", book = "", author = "Seneca" },
    { text = "Well begun is half done. This is something that depends on the mind; so when one is willing to become good, goodness is in large part achieved.", book = "stoicism", author = "Seneca" },
    { text = "Well then, shall we act like other men? Shall there be no distinction between ourselves and the world?  Yes, a very great one; let men find that we are unlike the common herd, if they look closely.", book = "", author = "Seneca" },
    { text = "Were all the geniuses of history to focus on this single theme, they could never fully express their bafflement at the darkness of the human mind. No person would give up even an inch of their estate, and the slightest dispute with a neighbor can mean hell to pay; yet we easily let others encroach on our lives—worse, we often pave the way for those who will take it over. No person hands out their money to passersby, but to how many do each of us hand out our lives! We’re tight-fisted with property and money, yet think too little of wasting time, the one thing about which we should all be the toughest misers.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "What cause can there be for complaint, after all, in anything that was always bound to come to an end fading gradually away? What is troubling about that? ... Moving to one's end through nature's own gentle process of dissolution - is there a better way of leaving life than that? Not because there is anything wrong with a sudden, violent departure, but because this gradual withdrawal is an easy route.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "What Chance has made yours is not really yours.", book = "", author = "Seneca" },
    { text = "What difference does it make, after all, what your position in life is if you dislike it yourself?", book = "", author = "Seneca" },
    { text = "What fortune has made yours is not your own.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "What is death? Either a transition or an end. I am not afraid of coming to an end, this being the same as never having begun, nor of transition, for I shall never be in confinement quite so cramped anywhere else as I am here.", book = "", author = "Seneca" },
    { text = "What is freedom, you ask?  It means not being a slave to any circumstance, to any constraint, to any chance; it.", book = "", author = "Seneca" },
    { text = "What is harder than rock? What is softer than water? Yet hard rocks are hollowed out by soft water?", book = "", author = "Seneca" },
    { text = "What is sweeter than to be so valued by one's wife that one becomes more valuable to oneself for this reason? Hence my dear Paulina is able to make me responsible, not only for her fears, but also for my own.", book = "", author = "Seneca" },
    { text = "What man can you show me who places any value on his time, who reckons the worth of each day, who understands that he is dying daily?", book = "", author = "Seneca" },
    { text = "What mental darkness, what ignorance of the truth blinds those who, though afflicted by the fear of poverty, yet take pleasure in imitating it!", book = "", author = "Seneca" },
    { text = "What need is there to weep over parts of life? The whole of it calls for tears.", book = "", author = "Seneca" },
    { text = "What progress, you ask, have I made? I have begun to be a friend to myself.", book = "Epistulae Morales Ad Lucilium: Latin Text", author = "Seneca" },
    { text = "What really ruins our character is the fact that none of us looks back over his life.", book = "", author = "Seneca" },
    { text = "What shall we not go in fear of if we fear that which cowardice itself has chosen for its refuge?", book = "", author = "Seneca" },
    { text = "What then is good? The knowledge of things. What is evil? The lack of knowledge of things.", book = "", author = "Seneca" },
    { text = "What’s the point of having countless books and libraries, whose titles could hardly be read through in a lifetime. The learner is not taught, but burdened by the sheer volume, and it’s better to plant the seeds of a few authors than to be scattered about by many.", book = "On Tranquility Of Mind", author = "Seneca" },
    { text = "Whatever can happen at any time can happen today.", book = "", author = "Seneca" },
    { text = "Whatever happens is never as serious as rumour makes it out to be.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Whatever years be behind us are in death's hands.", book = "", author = "Seneca" },
    { text = "What's the good of dragging up sufferings which are over, of being unhappy now just because you were then?", book = "", author = "Seneca" },
    { text = "What's the use of overcoming opponent after opponent in the wrestling or boxing rings if you can be overcome by your temper?", book = "", author = "Seneca" },
    { text = "When a man does not know what harbor he is making for, no wind is the right wind.", book = "", author = "Seneca" },
    { text = "When a mind is impressionable and has none too firm a hold on what is right, it must be rescued from the crowd: it is so easy for it to go over to the majority.", book = "", author = "Seneca" },
    { text = "When a soul rises superior to other souls, when it is under control, when it passes through every experience as if it were of small account, when it smiles at our fears and at our prayers, it is stirred by a force from heaven.", book = "", author = "Seneca" },
    { text = "When arrogant hands once seize power, the ruler thinks authority resides in stubbornness.", book = "", author = "Seneca" },
    { text = "When one is busy and absorbed in one's work, the very absorption affords great delight; but when one has withdrawn one's hand from the completed masterpiece, the pleasure is not so keen.", book = "", author = "Seneca" },
    { text = "When philosophy is wielded with arrogance and stubbornly, it is the cause for the ruin of many. Let philosophy scrape off your own faults, rather than be a way to rail against the faults of others.", book = "Moral Letters", author = "Seneca" },
    { text = "When things are at their worst,  there are no tears.", book = "", author = "Seneca" },
    { text = "When we have done everything within our power, we shall possess a great deal: but we once possessed the world.", book = "", author = "Seneca" },
    { text = "When you see someone often flashing their rank or position, or someone whose name is often bandied about in public, don’t be envious; such things are bought at the expense of life.... Some die on the first rungs of the ladder of success, others before they can reach the top, and the few that make it to the top of their ambition through a thousand indignities realize at the end it’s only for an inscription on their gravestone.", book = "On The Brevity Of Life", author = "Seneca" },
    { text = "When Zeno received news of a shipwreck and heard that all his luggage had been sunk he said,  Fortune bids me to be a less encumbered philosopher. ", book = "", author = "Seneca" },
    { text = "Whenever I wish to enjoy the quips of a clown, I am not compelled to hunt far; I can laugh at myself.", book = "", author = "Seneca" },
    { text = "Where you arrive does not matter as much as what sort of person you are when you arrive there.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Where, then, lies the mistake, since all men crave the happy life?  It is that they regard the means for producing happiness as happiness itself, and, while seeking happiness, they are really fleeing from it.", book = "", author = "Seneca" },
    { text = "Wherever there is a human being, there is an opportunity for a kindness.", book = "", author = "Seneca" },
    { text = "While the fates permit, live happily; life speeds on with hurried step, and with winged days the wheel of the headlong year is turned.", book = "", author = "Seneca" },
    { text = "While we are postponing, life speeds by.", book = "", author = "Seneca" },
    { text = "While we wait for life, life passes.", book = "", author = "Seneca" },
    { text = "Who as though inspired with divine utterance sings salutary verses: Life.", book = "", author = "Seneca" },
    { text = "Who can doubt, my dear Lucilius, that life is the gift of the immortal gods, but that living well is the gift of philosophy?", book = "", author = "Seneca" },
    { text = "Who scorns his own life is lord of yours.", book = "", author = "Seneca" },
    { text = "Why be concerned about others, come to that, when you've outdone your own self? Set yourself a limit which you couldn't even exceed if you wanted to, and say good-bye at last to those deceptive prizes more precious to those who hope for them than to those who have won them. If there were anything substantial in them they would sooner or later bring a sense of fullness; as it is they simply aggravate the thirst of those who swallow them.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Why do I not rather seek some real good - one which I could feel, not one which I could display? These things that draw the eyes of men, before which they halt, which they show to one another in wonder, outwardly glitter, but are worthless within.", book = "", author = "Seneca" },
    { text = "Why do you voluntarily deceive yourself and require to be told now for the first time what fate it is that you have long been labouring under? Take my word for it: since the day you were born you are being led thither.", book = "", author = "Seneca" },
    { text = "Why need we weep over parts of our life? the whole of it calls for tears: new miseries assail us before we have freed ourselves from the old ones.", book = "", author = "Seneca" },
    { text = "Why not stop trying to prevent posterity being silent about you? You were born to die, and a silent funeral is less bothersome.", book = "", author = "Seneca" },
    { text = "why should I demand from fortune that she should give me this and that rather than demand from myself that I should not ask for them? why should I ask for them, after all? am I to pile them up in total forgetfulness of the frailty of human existence?", book = "Letters from a Stoic", author = "Seneca" },
    { text = "Why then are we offended? Why do we complain? This is what we’re here for.", book = "On Providence", author = "Seneca" },
    { text = "Won’t you be walking in your predecessors’ footsteps? I surely will use the older path, but if I find a shorter and smoother way, I’ll blaze a trail there. The ones who pioneered these paths aren’t our masters, but our guides. Truth stands open to everyone, it hasn’t been monopolized.", book = "Moral Letters", author = "Seneca" },
    { text = "Words need to be sown like seeds. No matter how tiny a seed may be, when in lands in the right sort of ground it unfolds its strength and from being minute expands and grows to a massive size.", book = "", author = "Seneca" },
    { text = "Work nourishes noble minds.", book = "Moral Letters", author = "Seneca" },
    { text = "Would you rather be poor and sated, or rich and hungry? Prosperity is not only greedy, but it also lies exposed to the greed of others. And as long as nothing satisfies you, you yourself cannot satisfy others.", book = "", author = "Seneca" },
    { text = "Write something therefore in a simple style, merely to pass the time, for your own use, and not for publication. Less labour is needed when one does not look beyond the present.  Then.", book = "", author = "Seneca" },
    { text = "You act like mortals in all that you fear, and like immortals in all that you desire.", book = "", author = "Seneca" },
    { text = "You are afraid of dying. But, come now, how is this life of yours anything but death?", book = "Moral Letters", author = "Seneca" },
    { text = "You are retained as counsel for unhappy mankind. You have promised to help those in peril by sea, those in captivity, the sick and the needy, and those whose heads are under the poised axe. Whither are you straying? What are you doing?", book = "", author = "Seneca" },
    { text = "You are scared of dying - and, tell me, is the kind of life you lead really any different from being dead?", book = "Letters from a Stoic", author = "Seneca" },
    { text = "You are unfortunate in my judgment, for you have never been unfortunate. You have passed through life with no antagonist to face you; no one will know what you were capable of, not even you yourself.", book = "", author = "Seneca" },
    { text = "You ask what is the proper limit to a person's wealth? First, having what is essential, and second, having what is enough.", book = "", author = "Seneca" },
    { text = "You can put up with a change of place if only the place is changed.", book = "", author = "Seneca" },
    { text = "You can tell the character of every man when you see how he receives praise.”   Difficult.", book = "", author = "Seneca" },
    { text = "You cry, I’m suffering severe pain! Are you then relieved from feeling it, if you bear it in an unmanly way?", book = "Moral Letters", author = "Seneca" },
    { text = "You fear everything as mortals but desire to have everything as gods.", book = "", author = "Seneca" },
    { text = "You have all the fears of mortals and all the desires of immortals.", book = "", author = "Seneca" },
    { text = "You know what wine and liqueur tastes like. It makes no difference whether a hundred or a thousand bottles pass through your bladder—you are nothing more than a filter.", book = "Moral Letters", author = "Seneca" },
    { text = "You live as if you will live forever, no care for your mortality ever enters your head, you pay no mind to how much time has already gone by.", book = "", author = "Seneca" },
    { text = "You live as though you were going to live for ever, at no time taking thought for your weakness, and you fail to note how much time has already passed by.", book = "", author = "Seneca" },
    { text = "You must go to the scene of action, first, because men put more faith in their eyes than in their ears, and second, because the way is long if one follows precepts, but short and helpful, if one follows patterns.", book = "", author = "Seneca" },
    { text = "You must lay aside the burdens of the mind; until you do this, no place will satisfy you.", book = "", author = "Seneca" },
    { text = "You must linger among a limited number of master thinkers, and digest their works, if you would derive ideas which shall win firm hold in your mind. .", book = "", author = "Seneca" },
    { text = "You must set your hands to tasks which you can finish or at least hope to finish, and avoid those which get bigger as you proceed and do not cease where you had intended.", book = "", author = "Seneca" },
    { text = "You must vie with time's swiftness in the speed of using it, and, as from a torrent that rushes by and will not always flow, you must drink quickly.", book = "", author = "Seneca" },
    { text = "You should, I need hardly say, live in such a way that there is nothing which you could not as easily tell your enemy as keep to yourself.", book = "Letters from a Stoic", author = "Seneca" },
    { text = "You will notice that the most powerful and highly stationed men let drop remarks in which they pray for leisure, praise it, and rate it higher than all their blessings.", book = "", author = "Seneca" },
    { text = "Your greatest difficulty is with yourself; for you are your own stumbling-block.", book = "", author = "Seneca" },
    { text = "He is the kind of person I should expect to rescue one from a mad dog at any risk but then insist on a stoical indifference to the fright afterward. Jefferson Davis's future wife describing him at first meeting.", book = "The Civil War, Vol. 1: Fort Sumter to Perryville", author = "Shelby Foote" },
    { text = "Forever seeking, forever moving forward. To strive, to struggle.", book = "", author = "Shonjuk Chakma" },
    { text = "Kindness has become so rare that it provokes perplexity about what's sincere and what's deceitful.", book = "", author = "Shonjuk Chakma" },
    { text = "The only way to know what lies ahead is by continuing onward.", book = "", author = "Shonjuk Chakma" },
    { text = "Those who courageously choose to confront extreme hardships perceive their experience differently than others. They have the ability to envision something beyond the difficulties they encounter. Perhaps a glimmer of hope? Or perhaps another form of adversity? The truth is that the only way to know what lies ahead is by continuing onward.", book = "", author = "Shonjuk Chakma" },
    { text = "Your mind is your most powerful ally; master it, and no obstacle will ever stand in your way.", book = "", author = "Sira Masetti" },
    { text = "After failure, it is possible to keep going “ and to fail better.", book = "", author = "Slavoj Žižek" },
    { text = "Men are of little worth. Their brief lives last a single day. They cannot hold elusive pleasure fast; It melts away. All laurels wither; all illusions fade; Hopes have been phantoms, shade on air-built shade, since time began.", book = "The Oedipus Cycle: Oedipus Rex, Oedipus at Colonus, Antigone", author = "Sophocles" },
    { text = "The wife of a junior officer cooped up in a horrible canvas partition in steerage for five months wrote: I had enjoyed much peace there in the absence of every comfort, even of such as are now enjoyed in jail. I used to say that there were four privations in my situation - fire, water, earth and air. No fire to warm oneself on the coldest day, no water to drink but what was tainted, no earth to set the foot on, and scarcely any air to breathe. Yet, with all these miserable circumstances, we spent many a happy hour by candlelight in that wretched cabin whilst I sewed and he read the Bible to me.", book = "", author = "Stephen Taylor" },
    { text = "Draconus staggered up.'Pearl, my friend, I have come to say goodbye. And to tell you I am sorry.''What saddens you?' the demon asked.'I am sorry, Pearl, for all of this. For Dragnipur. For the horror forged by my own hands. It was fitting, was it not, that the weapon claimed its maker? I think, yes, it was. It was.' He paused, and then brought both hands up to his face. For a moment it seemed he would begin clawing his beard from the skin beneath it. Instead, the shackled hands fell away, down, dragged by the weight of the chains.'I too am sorry,' said Pearl.'To see the end of this.''What?''So many enemies, all here and not one by choice. Enemies, and yet working together for so long. It was a wonderous thing, was it not, Draconus? When necessity forced each hand to clasp, to work as one. A wonderous thing.' The warrior stared at the demon. He seemed unable to speak.", book = "Toll the Hounds", author = "Steven Erikson" },
    { text = "Life is such unutterable hell, solely because it is sometimes beautiful. If we could only be miserable all the time, if there could be no such things as love or beauty or faith or hope, if I could be absolutely certain that my love would never be returned: how much more simple life would be. One could plod through the Siberian salt mines of existence without being bothered about happiness. Unfortunately the happiness is there. There is always the chance (about eight hundred and fifty to one) that another heart will come to mine. I can't help hoping, and keeping faith, and loving beauty. Quite frequently I am not so miserable as it would be wise to be.", book = "Ghostly, Grim and Gruesome", author = "T.H. White" },
    { text = "Perhaps struggle is all we have because the god of history is an atheist, and nothing about his world is meant to be. So you must wake up every morning knowing that no promise is unbreakable, least of all the promises of waking up at all. This is not despair. These are the preferences of universe itself: verbs over nouns, actions over states, struggle over hope.", book = "", author = "Ta Nahesi Coates" },
    { text = "A Stoic is someone who transforms fear into prudence, pain into transformation, mistakes into initiation, and desire into undertaking.", book = "stoicism", author = "Taleb Nassim Nicholas" },
    { text = "Just as the earth that bears the man who tills and digs it, to bear those who speak ill of them, is a quality of the highest respect.", book = "Thirukkural", author = "Thiruvalluvar" },
    { text = "Thoroughly convinced of the impossibility of his own suit, a high resolve constrained him not to injure that of another. This is a lover's most stoical virtue, as the lack of it is a lover's most venial sin.", book = "Far From the Madding Crowd", author = "Thomas Hardy" },
    { text = "If you lose today every-day, you are lost every-day.", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "I've let people's opinions, my own self judgements and many negative things take this life away from me. No more!", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "The good and the bad occur at all times and will keep happening. We can become lost if we go with the hype of 'good and bad' every time.", book = "Introducing Ubuntu Stoicism: Gain Joy, Resilience, Productivity, and Defuse Anxiety", author = "Tiisetso Maloma" },
    { text = "Tomorrow will take care of itself, so take care of today, otherwise tomorrow will take ill-care of you today  “ thus losing today.", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "Tomorrow's worries contaminate the present.", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "What are virtues, if not practiced evenly in both times of joy and in hardships?", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "When pain comes, it must not derail you from your set virtues. If it does, you have failed to practice your virtues by going with the hype of pain.", book = "The Anxious Entrepreneur: Anxiety Defeats Creativity - Creativity Defeats Anxiety", author = "Tiisetso Maloma" },
    { text = "If a discrepancy exists between supply and demand, then for the Stoics the prescription for a happy life was to decrease demand, not to increase supply (or production), which the Hedonists saw as the prescription for a happy life.", book = "Economics of Good and Evil: The Quest for Economic Meaning from Gilgamesh to Wall Street", author = "Tomáš Sedláček" },
    { text = "But Moominmamma was quite unperturbed.  Well, well!  she said, it seems to me that our guests are having a very good time. I hope so replied Moominpappa. Pass me a banana, please dear.", book = "Finn Family Moomintroll", author = "Tove Jansson" },
    { text = "Oh, dear me!  he lamented. The raft has floated off and I suppose it's gone down that awful hole by now. Well, never mind. We're not on it said Snufkin gaily. What's a kettle here or there when you're out looking for a comet!", book = "Comet in Moominland", author = "Tove Jansson" },
    { text = "In the evening I came home and read about the Messina earthquake, and how the relief ships arrived, and the wretched survivors crowded down to the water's edge and tore each other like wild beasts in their rage of hunger. The paper set forth, in horrified language, that some of them had been seventy-two hours without food. I, as I read, had also been seventy-two hours without food; and the difference was simply that they thought they were starving.", book = "Fasting Cure", author = "Upton Sinclair" },
    { text = "A surprising number of people believe that other people can hurt their feelings.", book = "Acceptance", author = "Vincent P. Collins" },
    { text = "The first principle of practical Stoicism is this: we don't react to events; we react to our judgments about them, and the judgments are up to us.", book = "The Practicing Stoic", author = "Ward Farnsworth" },
    { text = "I have always swung back and forth between alienation and relatedness. As a child, I would run away from the beatings, from the obscene words, and always knew that if I could run far enough, then any leaf, any insect, any bird, any breeze could bring me to my true home. I knew I did not belong among people. Whatever they hated about me was a human thing; the nonhuman world has always loved me. I can't remember when it was otherwise. But I have been emotionally crippled by this. There is nothing romantic about being young and angry, or even about turning that anger into art. I go through the motions of living in society, but never feel a part of it. When my family threw me away, every human on earth did likewise.", book = "", author = "Wendy Rose" },
    { text = "...we can do some historical research to see how our ancestors lived. We will quickly discover that we are living in what to them would have been a dream world that we tend to take for granted things that our ancestors had to live without...", book = "A Guide to the Good Life: The Ancient Art of Stoic Joy", author = "William B. Irvine" },
    { text = "Ideally, a Stoic will be oblivious to the services he does for others, as oblivious as a grapevine is when it yields a cluster of grapes to a vintner. He will not pause to boast about the service he has performed but will move on to perform his next service, the way the grape vine moves on to bear more grapes.", book = "A Guide to the Good Life: The Ancient Art of Stoic Joy", author = "William B. Irvine" },
    { text = "Most of us are living the dream living, that is, the dream we once had for ourselves.", book = "A Guide to the Good Life: The Ancient Art of Stoic Joy", author = "William B. Irvine" },
    { text = "All the world's a stage, And all the men and women merely players; They have their exits and their entrances; And one man in his time plays many parts, His acts being seven ages.", book = "As You Like It", author = "William Shakespeare" },
    { text = "Be not afraid of greatness. Some are born great, some achieve greatness, and others have greatness thrust upon them.", book = "Twelfth Night", author = "William Shakespeare" },
    { text = "By the pricking of my thumbs, Something wicked this way comes.", book = "Macbeth", author = "William Shakespeare" },
    { text = "Cowards die many times before their deaths; The valiant never taste of death but once. Of all the wonders that I yet have heard, It seems to me most strange that men should fear; Seeing that death, a necessary end, Will come when it will come.", book = "Julius Caesar", author = "William Shakespeare" },
    { text = "Don't waste your love on somebody who doesn't value it.", book = "Romeo and Juliet", author = "William Shakespeare" },
    { text = "Doubt thou the stars are fire; Doubt that the sun doth move; Doubt truth to be a liar; But never doubt I love.", book = "Hamlet", author = "William Shakespeare" },
    { text = "For death remembered should be like a mirror, Who tells us life's but breath, to trust it error.", book = "Pericles", author = "William Shakespeare" },
    { text = "Hell is empty and all the devils are here.", book = "The Tempest", author = "William Shakespeare" },
    { text = "I like this place and could willingly waste my time in it.", book = "As You Like It", author = "William Shakespeare" },
    { text = "It is not in the stars to hold our destiny but in ourselves.", book = "Julius Caesar", author = "William Shakespeare" },
    { text = "Lord, what fools these mortals be!", book = "A Midsummer Night's Dream", author = "William Shakespeare" },
    { text = "Love all, trust a few, Do wrong to none: be able for thine enemy; Rather in power than use; and keep thy friend Under thy own life's key: be check'd for silence; But never tax'd for speech.", book = "All's Well That Ends Well", author = "William Shakespeare" },
    { text = "Love looks not with the eyes, but with the mind; And therefore is wing'd Cupid painted blind. Nor hath love's mind of any judgment taste; Wings and no eyes figure unheedy haste: And therefore is love said to be a child, Because in choice he is so oft beguil'd.", book = "A Midsummer Night's Dream", author = "William Shakespeare" },
    { text = "My bounty is as boundless as the sea, My love as deep; the more I give to thee, The more I have, for both are infinite.", book = "Romeo and Juliet", author = "William Shakespeare" },
    { text = "My only love sprung from my only hate! Too early seen unknown, and known too late! Prodigious birth of love it is to me, That I must love a loathed enemy.", book = "Romeo and Juliet", author = "William Shakespeare" },
    { text = "My tongue will tell the anger of my heart, or else my heart concealing it will break.", book = "The Taming of the Shrew", author = "William Shakespeare" },
    { text = "Stars, hide your fires; Let not light see my black and deep desires.", book = "Macbeth", author = "William Shakespeare" },
    { text = "The fault, dear Brutus, is not in our stars, but in ourselves.", book = "Julius Caesar", author = "William Shakespeare" },
    { text = "The fool doth think he is wise, but the wise man knows himself to be a fool.", book = "As You Like It", author = "William Shakespeare" },
    { text = "There is nothing either good or bad, but thinking makes it so.", book = "Hamlet", author = "William Shakespeare" },
    { text = "This above all: to thine own self be true, And it must follow, as the night the day, Thou canst not then be false to any man.", book = "Hamlet", author = "William Shakespeare" },
    { text = "Though she be but little, she is fierce!", book = "A Midsummer Night's Dream", author = "William Shakespeare" },
    { text = "We are not the first Who with best meaning have incurred the worst. For thee, oppressed king, I am cast down. Myself could else outfrown false Fortune's frown.", book = "", author = "William Shakespeare" },
    { text = "We cannot but obey the powers above us. Could I rage and roar as doth the sea She lies in, yet the end must be as 'tis.", book = "Pericles", author = "William Shakespeare" },
    { text = "We know what we are, but not what we may be.", book = "Hamlet", author = "William Shakespeare" },
    { text = "When he shall die, Take him and cut him out in little stars, And he will make the face of heaven so fine; That all the world will be in love with night; And pay no worship to the garish sun.", book = "Romeo and Juliet", author = "William Shakespeare" },
    { text = "Words are easy, like the wind; faithful friends are hard to find.", book = "The Passionate Pilgrim", author = "William Shakespeare" },
    { text = "You speak an infinite deal of nothing.", author = "William Shakespeare", book = "The Merchant of Venice" },
    { text = "Ambition: The willingness to continually question and assess one's acceptance and contentment with their place in life; conjunct with the willingness to take action should a resolvable discrepancy between one's values and one's current standing, present itself. By extension, an ambitious person is someone who has to the best of their abilities thoughtfully defined their values and continues on to do whatever is reasonably possible to fully embrace who they are in life.", book = "", author = "Yann Tanguay" },
    { text = "A bad feeling is a commotion of the mind repugnant to reason, and against nature.", book = "", author = "Zeno of Citium" },
    { text = "Better to trip with the feet than with the tongue.", book = "Lives Of The Eminent Philosophers", author = "Zeno of Citium" },
    { text = "Happiness is a good flow of life.", book = "", author = "Zeno of Citium" },
    { text = "If you lay violent hands on me, you’ll have my body, but my mind will remain with Stilpo.", book = "Lives Of The Eminent Philosophers", author = "Zeno of Citium" },
    { text = "Man conquers the world by conquering himself.", book = "", author = "Zeno of Citium" },
    { text = "man was given two ears and one mouth for a reason", book = "", author = "Zeno of Citium" },
    { text = "No loss should be more regrettable to us than losing our time, for it’s irretrievable.", book = "", author = "Zeno of Citium" },
    { text = "The goal of life is living in agreement with Nature.", book = "", author = "Zeno of Citium" },
    { text = "We have two ears and one mouth, so we should listen more than we say.", book = "", author = "Zeno of Citium" },
    { text = "Well-being is realized by small steps, but is truly no small thing.", book = "Lives Of The Eminent Philosophers", author = "Zeno of Citium" },
    { text = "When a dog is tied to a cart, if it wants to follow, it is pulled and follows, making its spontaneous act coincide with necessity. But if the dog does not follow, it will be compelled in any case. So it is with men too: even if they don't want to, they will be compelled to follow what is destined.", book = "", author = "Zeno of Citium" },
    { text = "It is only with the heart that one can see rightly; what is essential is invisible to the eye.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "What makes the desert beautiful is that somewhere it hides a well.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "All grown-ups were once children… but only few of them remember it.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "If you love a flower that lives on a star, it is sweet to look at the sky at night. All the stars are a-bloom with flowers…", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "You become responsible, forever, for what you have tamed.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "People have forgotten this truth. But you must not forget it. You become responsible, forever, for what you have tamed.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "Grown-ups never understand anything by themselves, and it is tiresome for children to be always and forever explaining things to them.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "It is much more difficult to judge oneself than to judge others.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "One sees clearly only with the heart. Anything essential is invisible to the eyes.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "The most beautiful things in the world cannot be seen or touched, they are felt with the heart.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "Well, I must endure the presence of a few caterpillars if I wish to become acquainted with the butterflies.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "I did not know how to reach him, how to catch him… I felt so awkward and so helpless.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "In those days, I did not understand anything. I should have judged her according to her actions, not her words.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "The stars are beautiful, because of a flower that cannot be seen.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "You - you alone will have the stars as no one else has them… In one of the stars I shall be living. In one of them I shall be laughing. And so it will be as if all the stars were laughing, when you look at the sky at night… You - only you - will have stars that can laugh!", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },    
    { text = "To tame is not to own. It is to promise: I will keep showing up, even when it is inconvenient.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "What is essential is invisible only until someone brave enough dares to look with the heart.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "Stars become personal when you know one of them is laughing because of you.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "The desert is beautiful because somewhere it hides a well. So too is every person beautiful because somewhere they hide a secret goodness.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "We do not own the ones we love. We are merely trusted with their light for a little while.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "A child asks why. An adult forgets to ask. The wisest among us never stop asking.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "It is not the rose's thorns that make it precious. It is the time you spent watering it.", book = "The Little Prince", author = "Antoine de Saint-Exupéry" },
    { text = "The smallest kindness, given without fanfare, can redraw the map of someone's entire day.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "We walk past people every day carrying portraits of themselves they have never truly seen. Sometimes all it takes is one gentle glance to hand it back.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "Love is not loud. It is the quiet decision to stay present when everything else is leaving.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "The heart remembers what the eyes only glance at. Look longer, and you begin to see miracles in ordinary faces.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "A single unnoticed act of care can become the cornerstone someone builds their courage upon for years.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "We are all waiting to be seen—not for what we do, but for who we are when no one is watching.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "The most beautiful gift is attention given freely, without scorekeeping or expectation.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "Kindness travels in secret. It arrives before we know we've sent it, and lingers long after we've forgotten.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "Sometimes the greatest courage is to remain soft in a world that keeps trying to harden you.", book = "", author = "Reflective" },
    { text = "Every person carries a story written in invisible ink. Kindness is the light that makes it readable.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "The world does not need more heroes. It needs more people who show up quietly and stay.", book = "Theo of Golden", author = "Allen Levi" },
    { text = "You do not have to fix anyone. Sometimes just sitting beside them while they break is the deepest medicine.", book = "", author = "Gentle reminder" },
    { text = "The heart measures in moments, not in years. A single shared silence can last longer than a lifetime of noise.", book = "", author = "Quiet truth" },
